"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { formatName } from "@/lib/utils"
import { Package, Calendar, User, FileText, Building2, LayoutGrid, List, Hash } from "lucide-react"
import { ASSET_TYPE_MAP } from "@/lib/asset-types"
import type { Asset, AssetAssignment } from "./page"
import { AppTablePage } from "@/components/app/app-table-page"
import { toast } from "sonner"
import { StatCard } from "@/components/ui/stat-card"
import { EmptyState } from "@/components/ui/patterns"

interface AssetsContentProps {
  initialAssignments: AssetAssignment[]
  initialError?: string | null
}

export function AssetsContent({ initialAssignments, initialError }: AssetsContentProps) {
  const [assignments] = useState<AssetAssignment[]>(initialAssignments)
  const [viewMode, setViewMode] = useState<"list" | "card">("list")

  useEffect(() => {
    if (initialError) {
      toast.error(initialError)
    }
  }, [initialError])

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    })
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "assigned":
        return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400"
      case "maintenance":
        return "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400"
      case "available":
        return "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400"
      default:
        return "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400"
    }
  }

  const getAssetTypeLabel = (assetTypeCode: string) => {
    return ASSET_TYPE_MAP[assetTypeCode]?.label || assetTypeCode
  }

  const getAssignmentTypeLabel = (assignment: AssetAssignment) => {
    if (assignment.id.startsWith("shared-")) {
      if (assignment.asset?.assignment_type === "department") {
        return "Department"
      } else if (assignment.asset?.assignment_type === "office") {
        return "Office"
      }
    }
    return "Personal"
  }

  const getAssignmentTypeBadgeColor = (type: string) => {
    switch (type) {
      case "Personal":
        return "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400"
      case "Department":
        return "bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-400"
      case "Office":
        return "bg-orange-100 text-orange-800 dark:bg-orange-900/30 dark:text-orange-400"
      default:
        return "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400"
    }
  }

  return (
    <AppTablePage
      title="My Assets"
      description="View your currently assigned assets and equipment"
      icon={Package}
      actions={
        <div className="flex items-center gap-2">
          <Button
            variant={viewMode === "list" ? "default" : "outline"}
            size="sm"
            onClick={() => setViewMode("list")}
            className="gap-2"
          >
            <List className="h-4 w-4" />
            List
          </Button>
          <Button
            variant={viewMode === "card" ? "default" : "outline"}
            size="sm"
            onClick={() => setViewMode("card")}
            className="gap-2"
          >
            <LayoutGrid className="h-4 w-4" />
            Card
          </Button>
        </div>
      }
      stats={
        <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
          <StatCard
            title="Active Assets"
            value={assignments.length}
            icon={Package}
            iconBgColor="bg-blue-100 dark:bg-blue-900/30"
            iconColor="text-blue-600 dark:text-blue-400"
          />
        </div>
      }
    >
      {/* Assets List/Grid */}
      {assignments.length > 0 ? (
        viewMode === "list" ? (
          <Card className="border-2">
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="w-[50px]">S/N</TableHead>
                    <TableHead>Asset Name</TableHead>
                    <TableHead>Unique Code</TableHead>
                    <TableHead>Model</TableHead>
                    <TableHead>Serial Number</TableHead>
                    <TableHead>Year</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Assignment Type</TableHead>
                    <TableHead>Assigned</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {assignments.map((assignment, index) => {
                    const assignmentType = getAssignmentTypeLabel(assignment)
                    return (
                      <TableRow key={assignment.id}>
                        <TableCell className="font-medium">{index + 1}</TableCell>
                        <TableCell className="font-medium">
                          {getAssetTypeLabel(assignment.asset?.asset_type || "")}
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-1.5">
                            <Hash className="text-muted-foreground h-3.5 w-3.5" />
                            <span className="font-mono text-sm">{assignment.asset?.unique_code || "-"}</span>
                          </div>
                        </TableCell>
                        <TableCell>{assignment.asset?.asset_model || "-"}</TableCell>
                        <TableCell>
                          {assignment.asset?.serial_number ? (
                            <span className="font-mono text-sm">{assignment.asset.serial_number}</span>
                          ) : (
                            "-"
                          )}
                        </TableCell>
                        <TableCell>{assignment.asset?.acquisition_year || "-"}</TableCell>
                        <TableCell>
                          <Badge className={getStatusColor(assignment.asset?.status || "available")}>
                            {assignment.asset?.status || "available"}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <Badge className={getAssignmentTypeBadgeColor(assignmentType)}>{assignmentType}</Badge>
                        </TableCell>
                        <TableCell className="text-muted-foreground text-sm">
                          {formatDate(assignment.assigned_at)}
                        </TableCell>
                      </TableRow>
                    )
                  })}
                </TableBody>
              </Table>
            </div>
          </Card>
        ) : (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {assignments.map((assignment) => {
              const assignmentType = getAssignmentTypeLabel(assignment)
              return (
                <Card key={assignment.id} className="border-2 shadow-lg transition-shadow hover:shadow-xl">
                  <CardHeader className="from-primary/5 to-background border-b bg-gradient-to-r">
                    <div className="flex items-start justify-between">
                      <div className="flex items-start gap-3">
                        <div className="bg-primary/10 rounded-lg p-3">
                          <Package className="text-primary h-6 w-6" />
                        </div>
                        <div className="min-w-0 flex-1">
                          <CardTitle className="text-lg">
                            {getAssetTypeLabel(assignment.asset?.asset_type || "")}
                          </CardTitle>
                          <CardDescription className="mt-1 flex items-center gap-1.5">
                            <Hash className="h-3.5 w-3.5" />
                            <span className="font-mono text-xs">{assignment.asset?.unique_code || "-"}</span>
                          </CardDescription>
                        </div>
                      </div>
                      <div className="flex flex-col gap-2">
                        <Badge className={getStatusColor(assignment.asset?.status || "available")}>
                          {assignment.asset?.status || "available"}
                        </Badge>
                        <Badge className={getAssignmentTypeBadgeColor(assignmentType)}>{assignmentType}</Badge>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-3 p-6">
                    {assignment.asset?.asset_model && (
                      <div className="flex items-center gap-2 text-sm">
                        <FileText className="text-muted-foreground h-4 w-4" />
                        <span className="text-muted-foreground">Model:</span>
                        <span className="text-foreground font-medium">{assignment.asset.asset_model}</span>
                      </div>
                    )}

                    {assignment.asset?.serial_number && (
                      <div className="flex items-center gap-2 text-sm">
                        <FileText className="text-muted-foreground h-4 w-4" />
                        <span className="text-muted-foreground">Serial:</span>
                        <span className="text-foreground font-mono">{assignment.asset.serial_number}</span>
                      </div>
                    )}

                    {assignment.asset?.acquisition_year && (
                      <div className="flex items-center gap-2 text-sm">
                        <Calendar className="text-muted-foreground h-4 w-4" />
                        <span className="text-muted-foreground">Year:</span>
                        <span className="text-foreground font-medium">{assignment.asset.acquisition_year}</span>
                      </div>
                    )}

                    <div className="flex items-center gap-2 text-sm">
                      <Calendar className="text-muted-foreground h-4 w-4" />
                      <span className="text-muted-foreground">Assigned:</span>
                      <span className="text-foreground">{formatDate(assignment.assigned_at)}</span>
                    </div>

                    {assignment.department ? (
                      <div className="flex items-center gap-2 text-sm">
                        <Building2 className="text-muted-foreground h-4 w-4" />
                        <span className="text-muted-foreground">Department:</span>
                        <span className="text-foreground font-medium">{assignment.department}</span>
                      </div>
                    ) : (
                      assignment.assigner && (
                        <div className="flex items-center gap-2 text-sm">
                          <User className="text-muted-foreground h-4 w-4" />
                          <span className="text-muted-foreground">Assigned by:</span>
                          <span className="text-foreground">
                            {formatName(assignment.assigner.first_name)} {formatName(assignment.assigner.last_name)}
                          </span>
                        </div>
                      )
                    )}

                    {assignment.assignment_notes && (
                      <div className="bg-muted/50 mt-4 rounded-lg p-3">
                        <p className="text-foreground mb-1 text-sm font-medium">Notes:</p>
                        <p className="text-muted-foreground text-sm">{assignment.assignment_notes}</p>
                      </div>
                    )}
                  </CardContent>
                </Card>
              )
            })}
          </div>
        )
      ) : (
        <EmptyState
          title="No Assets Assigned"
          description="You don't have any assets assigned to you at the moment."
          icon={Package}
        />
      )}
    </AppTablePage>
  )
}

"use client"

import { useState } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Clock, LogIn, LogOut } from "lucide-react"
import { useToast } from "@/hooks/use-toast"
import type { AttendanceRecord } from "./page"
import { PageHeader, PageWrapper } from "@/components/layout"

import { logger } from "@/lib/logger"

const log = logger("dashboard-attendance-attendance-content")


interface AttendanceContentProps {
  initialTodayRecord: AttendanceRecord | null
  initialRecentRecords: AttendanceRecord[]
}

export function AttendanceContent({ initialTodayRecord, initialRecentRecords }: AttendanceContentProps) {
  const [todayRecord, setTodayRecord] = useState<AttendanceRecord | null>(initialTodayRecord)
  const [recentRecords, setRecentRecords] = useState<AttendanceRecord[]>(initialRecentRecords)
  const [actionLoading, setActionLoading] = useState(false)
  const { toast } = useToast()

  async function fetchAttendanceData() {
    try {
      const response = await fetch("/api/hr/attendance/records")
      const data = await response.json()
      if (response.ok && data.data) {
        const today = new Date().toISOString().split("T")[0]
        const todayRec = data.data.find((r: AttendanceRecord) => r.date === today)
        setTodayRecord(todayRec || null)
        setRecentRecords(data.data.slice(0, 7))
      }
    } catch (error) {
      log.error("Error fetching attendance:", error)
    }
  }

  async function handleClockIn() {
    setActionLoading(true)
    try {
      const response = await fetch("/api/hr/attendance/clock-in", {
        method: "POST",
      })

      const data = await response.json()

      if (response.ok) {
        toast({
          title: "Success",
          description: "Clocked in successfully",
        })
        fetchAttendanceData()
      } else {
        toast({
          title: "Error",
          description: data.error || "Failed to clock in",
          variant: "destructive",
        })
      }
    } catch {
      toast({
        title: "Error",
        description: "An error occurred",
        variant: "destructive",
      })
    } finally {
      setActionLoading(false)
    }
  }

  async function handleClockOut() {
    setActionLoading(true)
    try {
      const response = await fetch("/api/hr/attendance/clock-out", {
        method: "POST",
      })

      const data = await response.json()

      if (response.ok) {
        toast({
          title: "Success",
          description: "Clocked out successfully",
        })
        fetchAttendanceData()
      } else {
        toast({
          title: "Error",
          description: data.error || "Failed to clock out",
          variant: "destructive",
        })
      }
    } catch {
      toast({
        title: "Error",
        description: "An error occurred",
        variant: "destructive",
      })
    } finally {
      setActionLoading(false)
    }
  }

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title="Attendance"
        description="Track your work hours"
        icon={Clock}
        backLink={{ href: "/profile", label: "Back to Dashboard" }}
      />

      {/* Clock In/Out Card */}
      <Card>
        <CardHeader>
          <CardTitle>Today's Attendance</CardTitle>
          <CardDescription>
            {new Date().toLocaleDateString("en-US", {
              weekday: "long",
              year: "numeric",
              month: "long",
              day: "numeric",
            })}
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {todayRecord ? (
              <div className="space-y-4">
                <div className="flex items-center justify-between rounded-lg bg-gray-50 p-4">
                  <div className="flex items-center gap-4">
                    <LogIn className="h-5 w-5 text-green-500" />
                    <div>
                      <p className="font-medium">Clock In</p>
                      <p className="text-2xl font-bold">{todayRecord.clock_in}</p>
                    </div>
                  </div>
                  {todayRecord.clock_out && (
                    <div className="flex items-center gap-4">
                      <LogOut className="h-5 w-5 text-red-500" />
                      <div>
                        <p className="font-medium">Clock Out</p>
                        <p className="text-2xl font-bold">{todayRecord.clock_out}</p>
                      </div>
                    </div>
                  )}
                </div>

                {todayRecord.total_hours && (
                  <div className="rounded-lg bg-blue-50 p-4 text-center">
                    <p className="text-muted-foreground text-sm">Total Work Hours</p>
                    <p className="text-3xl font-bold text-blue-600">{todayRecord.total_hours.toFixed(2)} hrs</p>
                  </div>
                )}

                {!todayRecord.clock_out && (
                  <Button onClick={handleClockOut} disabled={actionLoading} className="w-full" variant="destructive">
                    <LogOut className="mr-2 h-4 w-4" />
                    Clock Out
                  </Button>
                )}
              </div>
            ) : (
              <div className="space-y-4 text-center">
                <Clock className="text-muted-foreground mx-auto h-16 w-16" />
                <p className="text-muted-foreground">You haven't clocked in today</p>
                <Button onClick={handleClockIn} disabled={actionLoading} className="w-full">
                  <LogIn className="mr-2 h-4 w-4" />
                  Clock In
                </Button>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Recent Attendance */}
      <Card>
        <CardHeader>
          <CardTitle>Recent Attendance</CardTitle>
          <CardDescription>Your attendance history for the past week</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-2">
            {recentRecords.map((record) => (
              <div key={record.id} className="flex items-center justify-between rounded-lg border p-3">
                <div>
                  <p className="font-medium">{new Date(record.date).toLocaleDateString()}</p>
                  <p className="text-muted-foreground text-sm">
                    {record.clock_in} - {record.clock_out || "In Progress"}
                  </p>
                </div>
                <div className="text-right">
                  {record.total_hours ? (
                    <>
                      <p className="font-bold">{record.total_hours.toFixed(2)} hrs</p>
                      <Badge variant="outline" className="mt-1">
                        {record.status}
                      </Badge>
                    </>
                  ) : (
                    <Badge variant="outline">In Progress</Badge>
                  )}
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </PageWrapper>
  )
}

"use client"

import { useMemo, useRef, useState } from "react"
import { toast } from "sonner"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { PageHeader, PageWrapper } from "@/components/layout"
import { FileCode2 } from "lucide-react"
import type { CorrespondenceRecord } from "@/types/correspondence"
import { CorrespondenceStats } from "@/components/correspondence/correspondence-stats"
import { CreateReferenceDialog } from "@/components/correspondence/create-reference-dialog"
import { CorrespondenceTable } from "@/components/correspondence/correspondence-table"

interface DepartmentCodeOption {
  department_name: string
  department_code: string
}

interface PortalCorrespondenceContentProps {
  userId: string
  currentViewerName: string
  currentViewerDepartment: string
  currentViewerRole?: string
  isDepartmentLead?: boolean
  initialRecords: CorrespondenceRecord[]
  departmentCodes: DepartmentCodeOption[]
}

export function PortalCorrespondenceContent({
  currentViewerName,
  currentViewerDepartment,
  isDepartmentLead,
  initialRecords,
  departmentCodes,
}: PortalCorrespondenceContentProps) {
  const initialDepartment = departmentCodes.some((d) => d.department_name === currentViewerDepartment)
    ? currentViewerDepartment
    : ""

  const [records, setRecords] = useState<CorrespondenceRecord[]>(initialRecords)
  const [isSaving, setIsSaving] = useState(false)
  const [createOpen, setCreateOpen] = useState(false)
  const [dispatchingId, setDispatchingId] = useState<string | null>(null)
  const [linkingId, setLinkingId] = useState<string | null>(null)
  const pendingRef = useRef<HTMLDivElement | null>(null)
  const [linkReference, setLinkReference] = useState<Record<string, string>>({})
  const [form, setForm] = useState({
    department_name: initialDepartment,
    letter_type: "external",
    category: "notice",
    subject: "",
    recipient_name: "",
    sender_name: currentViewerName,
    action_required: false,
    due_date: "",
    metadata_text: "",
  })

  const stats = useMemo(
    () => ({
      total: records.length,
      open: records.filter((r) => ["open", "draft", "under_review", "assigned_action_pending"].includes(r.status))
        .length,
      closed: records.filter((r) => ["closed", "sent", "filed"].includes(r.status)).length,
      incoming: records.filter((r) => r.direction === "incoming").length,
    }),
    [records]
  )

  const isLead = Boolean(isDepartmentLead)
  const pendingRecords = useMemo(
    () => records.filter((r) => ["open", "under_review", "assigned_action_pending"].includes(r.status)),
    [records]
  )

  async function refreshRecords() {
    const res = await fetch("/api/correspondence/records", { cache: "no-store" })
    const json = await res.json()
    setRecords(json.data || [])
  }

  async function createRecord(e: React.FormEvent) {
    e.preventDefault()
    if (!form.subject.trim()) {
      toast.error("Subject is required")
      return
    }
    if (!form.department_name) {
      toast.error("Department is required")
      return
    }

    setIsSaving(true)
    try {
      const metadata = form.metadata_text.trim() ? { notes: form.metadata_text.trim() } : null
      const res = await fetch("/api/correspondence/records", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          department_name: form.department_name,
          letter_type: form.letter_type,
          category: form.category,
          subject: form.subject,
          recipient_name: form.recipient_name || null,
          sender_name: form.sender_name || null,
          action_required: form.action_required,
          due_date: form.due_date || null,
          metadata,
        }),
      })
      const body = await res.json()
      if (!res.ok) throw new Error(body.error || "Failed to create correspondence")
      toast.success("Correspondence created")
      setCreateOpen(false)
      setForm({
        department_name: initialDepartment,
        letter_type: "external",
        category: "notice",
        subject: "",
        recipient_name: "",
        sender_name: currentViewerName,
        action_required: false,
        due_date: "",
        metadata_text: "",
      })
      await refreshRecords()
    } catch (error: any) {
      toast.error(error.message || "Failed to create correspondence")
    } finally {
      setIsSaving(false)
    }
  }

  async function updateStatus(recordId: string, status: string) {
    try {
      const res = await fetch(`/api/correspondence/records/${recordId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status }),
      })
      const body = await res.json()
      if (!res.ok) throw new Error(body.error || "Failed to update status")
      toast.success("Status updated")
      await refreshRecords()
    } catch (error: any) {
      toast.error(error.message || "Failed to update status")
    }
  }

  async function dispatchRecord(recordId: string) {
    setDispatchingId(recordId)
    try {
      const res = await fetch(`/api/correspondence/records/${recordId}/dispatch`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ final_status: "sent", dispatch_method: "email" }),
      })
      const body = await res.json()
      if (!res.ok) throw new Error(body.error || "Failed to dispatch correspondence")
      toast.success("Correspondence dispatched")
      await refreshRecords()
    } catch (error: any) {
      toast.error(error.message || "Failed to dispatch correspondence")
    } finally {
      setDispatchingId(null)
    }
  }

  async function linkResponse(recordId: string) {
    const incomingReferenceId = linkReference[recordId]
    if (!incomingReferenceId) {
      toast.error("Select an incoming reference first")
      return
    }
    setLinkingId(recordId)
    try {
      const res = await fetch(`/api/correspondence/records/${recordId}/link-response`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ incoming_reference_id: incomingReferenceId }),
      })
      const body = await res.json()
      if (!res.ok) throw new Error(body.error || "Failed to link response")
      toast.success("Outgoing reference linked to incoming correspondence")
      await refreshRecords()
    } catch (error: any) {
      toast.error(error.message || "Failed to link response")
    } finally {
      setLinkingId(null)
    }
  }

  const incomingOptions = records.filter((r) => r.direction === "incoming")

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title="Reference Generator"
        description="Create and manage correspondence references."
        icon={FileCode2}
        backLink={{ href: "/profile", label: "Back to Home" }}
        actions={
          <>
            {isLead && pendingRecords.length > 0 && (
              <Button
                variant="outline"
                onClick={() => pendingRef.current?.scrollIntoView({ behavior: "smooth", block: "start" })}
              >
                Pending ({pendingRecords.length})
              </Button>
            )}
            <CreateReferenceDialog
              open={createOpen}
              onOpenChange={setCreateOpen}
              form={form}
              onFormChange={setForm}
              onSubmit={createRecord}
              isSaving={isSaving}
              departmentCodes={departmentCodes}
            />
          </>
        }
      />

      <CorrespondenceStats {...stats} />

      {isLead && pendingRecords.length > 0 && (
        <Card ref={pendingRef}>
          <CardHeader>
            <CardTitle>Pending Items</CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            {pendingRecords.map((record) => (
              <div key={record.id} className="flex items-center justify-between rounded border p-3">
                <div>
                  <p className="font-medium">{record.reference_number}</p>
                  <p className="text-muted-foreground text-xs">{record.subject}</p>
                </div>
                <Badge variant="secondary">{record.status}</Badge>
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      <CorrespondenceTable
        records={records}
        incomingOptions={incomingOptions}
        linkReference={linkReference}
        onLinkReferenceChange={(id, value) => setLinkReference((prev) => ({ ...prev, [id]: value }))}
        dispatchingId={dispatchingId}
        linkingId={linkingId}
        onUpdateStatus={updateStatus}
        onDispatch={dispatchRecord}
        onLinkResponse={linkResponse}
      />
    </PageWrapper>
  )
}

import { createClient } from "@/lib/supabase/server"
import { resolveOneDriveAccessScope } from "@/lib/onedrive/access"
import type { Documentation } from "./page"

import { logger } from "@/lib/logger"

const log = logger("documentation-data")


export async function getDocumentationData() {
  const supabase = await createClient()

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const { data, error } = await supabase
    .from("user_documentation")
    .select("*")
    .eq("user_id", user.id)
    .order("updated_at", { ascending: false })

  if (error) {
    log.error("Error loading documentation:", error)
  }

  const oneDriveScope = await resolveOneDriveAccessScope(supabase as any, user.id)

  return {
    docs: (data || []) as Documentation[],
    userId: user.id,
    departmentDocs: oneDriveScope
      ? {
          initialPath: oneDriveScope.defaultPath,
          rootLabel: oneDriveScope.rootLabel,
          enabled: true,
        }
      : {
          initialPath: "/Projects",
          rootLabel: "Projects",
          enabled: false,
        },
  }
}

