"use client"

import { useMemo, useState } from "react"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Input } from "@/components/ui/input"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { FeedbackForm } from "@/components/feedback-form"
import { FeedbackEditModal } from "@/components/feedback-edit-modal"
import { AppTablePage } from "@/components/app/app-table-page"
import { Edit2, MessageSquare, Plus, Search, Trash2 } from "lucide-react"
import type { Feedback } from "./page"
import { writeAuditLogClient } from "@/lib/audit/client"

import { logger } from "@/lib/logger"

const log = logger("feedback-feedback-content")

interface FeedbackContentProps {
  initialFeedback: Feedback[]
  userId: string
}

export function FeedbackContent({ initialFeedback, userId }: FeedbackContentProps) {
  const [userFeedback, setUserFeedback] = useState<Feedback[]>(initialFeedback)
  const [searchQuery, setSearchQuery] = useState("")
  const [isSubmitOpen, setIsSubmitOpen] = useState(false)
  const [selectedFeedback, setSelectedFeedback] = useState<Feedback | null>(null)
  const [showEditModal, setShowEditModal] = useState(false)
  const [pendingDeleteId, setPendingDeleteId] = useState<string | null>(null)

  const filteredFeedback = useMemo(() => {
    if (!searchQuery) return userFeedback
    const query = searchQuery.toLowerCase()
    return userFeedback.filter(
      (item) =>
        item.title?.toLowerCase().includes(query) ||
        item.description?.toLowerCase().includes(query) ||
        item.feedback_type?.toLowerCase().includes(query) ||
        item.status?.toLowerCase().includes(query)
    )
  }, [userFeedback, searchQuery])

  const getTypeColor = (type: string) => {
    switch (type) {
      case "concern":
        return "bg-yellow-100 text-yellow-800"
      case "complaint":
        return "bg-red-100 text-red-800"
      case "suggestion":
        return "bg-blue-100 text-blue-800"
      case "required_item":
        return "bg-purple-100 text-purple-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "open":
        return "bg-green-100 text-green-800"
      case "in_progress":
        return "bg-blue-100 text-blue-800"
      case "resolved":
        return "bg-purple-100 text-purple-800"
      case "closed":
        return "bg-gray-100 text-gray-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  const handleFeedbackSubmitted = (newFeedback: Feedback) => {
    setUserFeedback((prev) => [newFeedback, ...prev])
    setIsSubmitOpen(false)
  }

  const handleDelete = async (id: string) => {
    const supabase = createClient()

    try {
      const feedbackToDelete = userFeedback.find((item) => item.id === id)
      const { error } = await supabase.from("feedback").delete().eq("id", id)
      if (error) throw error

      if (feedbackToDelete) {
        try {
          await writeAuditLogClient(
            supabase as any,
            {
              action: "delete",
              entityType: "feedback",
              entityId: id,
              oldValues: {
                feedback_type: feedbackToDelete.feedback_type,
                title: feedbackToDelete.title,
                description: feedbackToDelete.description,
                status: feedbackToDelete.status,
              },
              context: {
                source: "ui",
                route: "/feedback",
              },
            },
            { failOpen: true }
          )
        } catch (auditError) {
          log.error("Failed to log audit for feedback deletion:", auditError)
        }
      }

      setUserFeedback((prev) => prev.filter((item) => item.id !== id))
      toast.success("Feedback deleted successfully!")
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to delete feedback"
      toast.error(message)
    }
  }

  const handleEdit = (item: Feedback) => {
    setSelectedFeedback(item)
    setShowEditModal(true)
  }

  const handleSaveEdit = (updatedFeedback: Feedback) => {
    setUserFeedback((prev) => prev.map((item) => (item.id === updatedFeedback.id ? updatedFeedback : item)))
    setShowEditModal(false)
    setSelectedFeedback(null)
  }

  return (
    <AppTablePage
      title="Feedback & Suggestions"
      description="Share your concerns, complaints, suggestions, or required items with management"
      icon={MessageSquare}
      actions={
        <Button onClick={() => setIsSubmitOpen(true)} size="sm" className="gap-2">
          <Plus className="h-4 w-4" />
          Submit Feedback
        </Button>
      }
      filters={
        <div className="flex flex-wrap items-center gap-3">
          <div className="relative min-w-[200px] flex-1">
            <Search className="text-muted-foreground absolute top-2.5 left-2.5 h-4 w-4" />
            <Input
              placeholder="Search feedback..."
              className="pl-9 text-sm"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>
      }
    >
      {filteredFeedback.length === 0 ? (
        <Card className="border-2">
          <CardContent className="p-12 text-center">
            <MessageSquare className="text-muted-foreground mx-auto mb-4 h-16 w-16" />
            <h3 className="text-foreground mb-2 text-xl font-semibold">No Feedback Yet</h3>
            <p className="text-muted-foreground">
              {searchQuery ? "No feedback matches your search." : "Submit your first feedback to get started."}
            </p>
          </CardContent>
        </Card>
      ) : (
        <Card className="border-2">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-12">#</TableHead>
                  <TableHead>Title</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Created</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredFeedback.map((item, index) => (
                  <TableRow key={item.id} className="hover:bg-muted/50">
                    <TableCell className="text-muted-foreground font-medium">{index + 1}</TableCell>
                    <TableCell>
                      <div className="space-y-1">
                        <div className="text-foreground font-medium">{item.title}</div>
                        {item.description && (
                          <div className="text-muted-foreground line-clamp-2 text-xs">{item.description}</div>
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge className={getTypeColor(item.feedback_type)}>
                        {item.feedback_type.replaceAll("_", " ")}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge className={getStatusColor(item.status)}>{item.status.replaceAll("_", " ")}</Badge>
                    </TableCell>
                    <TableCell className="text-muted-foreground text-sm">
                      {new Date(item.created_at).toLocaleDateString()}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex items-center justify-end gap-2">
                        <Button variant="ghost" size="sm" onClick={() => handleEdit(item)}>
                          <Edit2 className="h-4 w-4" />
                        </Button>
                        <Button variant="ghost" size="sm" onClick={() => setPendingDeleteId(item.id)}>
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </Card>
      )}

      <Dialog open={isSubmitOpen} onOpenChange={setIsSubmitOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Submit Feedback</DialogTitle>
            <DialogDescription>Share your thoughts with management</DialogDescription>
          </DialogHeader>
          <FeedbackForm userId={userId} onFeedbackSubmitted={handleFeedbackSubmitted} variant="modal" />
        </DialogContent>
      </Dialog>

      {showEditModal && selectedFeedback && (
        <FeedbackEditModal
          feedback={selectedFeedback}
          onClose={() => {
            setShowEditModal(false)
            setSelectedFeedback(null)
          }}
          onSave={handleSaveEdit}
        />
      )}

      <AlertDialog open={pendingDeleteId !== null} onOpenChange={(open) => !open && setPendingDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Feedback</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this feedback? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                if (pendingDeleteId) handleDelete(pendingDeleteId)
                setPendingDeleteId(null)
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AppTablePage>
  )
}

﻿"use client"

import { useMemo, useState } from "react"
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { QUERY_KEYS } from "@/lib/query-keys"
import { TableSkeleton, QueryError } from "@/components/ui/query-states"
import { CalendarClock, Car, Paperclip, Plus } from "lucide-react"
import { toast } from "sonner"
import { PageHeader, PageWrapper } from "@/components/layout"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"

type FleetResource = {
  id: string
  name: string
  resource_type: string
  description?: string | null
  is_active: boolean
}

type FleetAttachment = {
  id: string
  file_name: string
  mime_type: string
  file_size: number
}

type FleetBooking = {
  id: string
  resource_id: string
  start_at: string
  end_at: string
  reason: string
  status: "pending" | "approved" | "rejected" | "cancelled"
  admin_note?: string | null
  created_at: string
  resource?: FleetResource | null
  attachments?: FleetAttachment[]
}

type FleetSchedule = {
  id: string
  resource_id: string
  start_at: string
  end_at: string
  status: "pending" | "approved"
}

const statusVariant: Record<FleetBooking["status"], "default" | "secondary" | "destructive" | "outline"> = {
  pending: "secondary",
  approved: "default",
  rejected: "destructive",
  cancelled: "outline",
}

function formatDateTime(value: string) {
  const parsed = new Date(value)
  if (Number.isNaN(parsed.getTime())) return value
  return parsed.toLocaleString()
}

function toLocalDateTimeInput(value?: string) {
  if (!value) return ""
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return ""
  const pad = (n: number) => String(n).padStart(2, "0")
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`
}

async function fetchFleetResources(): Promise<FleetResource[]> {
  const res = await fetch("/api/fleet/resources")
  if (!res.ok) throw new Error("Failed to load fleet resources")
  const payload = await res.json()
  return payload.data || []
}

async function fetchFleetBookings(): Promise<{ bookings: FleetBooking[]; schedule: FleetSchedule[] }> {
  const res = await fetch("/api/fleet/bookings")
  if (!res.ok) throw new Error("Failed to load fleet bookings")
  const payload = await res.json()
  return { bookings: payload.data || [], schedule: payload.resource_schedule || [] }
}

export function FleetContent() {
  const queryClient = useQueryClient()
  const [open, setOpen] = useState(false)
  const [cancelingId, setCancelingId] = useState<string | null>(null)

  const [resourceId, setResourceId] = useState("")
  const [startAt, setStartAt] = useState("")
  const [endAt, setEndAt] = useState("")
  const [reason, setReason] = useState("")
  const [files, setFiles] = useState<File[]>([])

  const canSubmit = resourceId && startAt && endAt && reason.trim().length >= 10

  const {
    data: resources = [],
    isLoading: resourcesLoading,
    isError: resourcesError,
  } = useQuery({
    queryKey: QUERY_KEYS.fleetResources(),
    queryFn: fetchFleetResources,
  })

  const {
    data: bookingsData,
    isLoading: bookingsLoading,
    isError: bookingsError,
    refetch,
  } = useQuery({
    queryKey: QUERY_KEYS.fleetBookings(),
    queryFn: fetchFleetBookings,
  })

  const bookings = bookingsData?.bookings ?? []
  const schedule = bookingsData?.schedule ?? []
  const loading = resourcesLoading || bookingsLoading
  const isError = resourcesError || bookingsError

  const selectedResourceSchedule = useMemo(() => {
    if (!resourceId) return []
    return schedule.filter((slot) => slot.resource_id === resourceId)
  }, [resourceId, schedule])

  const currentWindowConflicts = useMemo(() => {
    if (!resourceId || !startAt || !endAt) return []
    const start = new Date(startAt).getTime()
    const end = new Date(endAt).getTime()
    if (Number.isNaN(start) || Number.isNaN(end)) return []

    return selectedResourceSchedule.filter((slot) => {
      const slotStart = new Date(slot.start_at).getTime()
      const slotEnd = new Date(slot.end_at).getTime()
      return slotStart < end && slotEnd > start
    })
  }, [resourceId, startAt, endAt, selectedResourceSchedule])

  const { mutate: submitBooking, isPending: submitting } = useMutation({
    mutationFn: async (formData: FormData) => {
      const response = await fetch("/api/fleet/bookings", { method: "POST", body: formData })
      const payload = await response.json()
      if (!response.ok) throw new Error(payload.error || "Failed to submit booking")
      return payload
    },
    onSuccess: () => {
      toast.success("Booking application submitted")
      setOpen(false)
      setResourceId("")
      setStartAt("")
      setEndAt("")
      setReason("")
      setFiles([])
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.fleetBookings() })
    },
    onError: (error) => {
      toast.error(error instanceof Error ? error.message : "Failed to submit booking")
    },
  })

  function handleSubmit() {
    if (!canSubmit) {
      toast.error("Please complete all required fields. Reason must be at least 10 characters.")
      return
    }
    const formData = new FormData()
    formData.append("resource_id", resourceId)
    formData.append("start_at", new Date(startAt).toISOString())
    formData.append("end_at", new Date(endAt).toISOString())
    formData.append("reason", reason.trim())
    files.forEach((file) => formData.append("attachments", file))
    submitBooking(formData)
  }

  async function handleCancel(bookingId: string) {
    setCancelingId(bookingId)
    try {
      const response = await fetch(`/api/fleet/bookings/${bookingId}/cancel`, {
        method: "PATCH",
      })
      const payload = await response.json()
      if (!response.ok) throw new Error(payload.error || "Failed to cancel booking")
      toast.success("Booking cancelled")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.fleetBookings() })
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to cancel booking")
    } finally {
      setCancelingId(null)
    }
  }

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title="Fleet Booking"
        description="Book shared resources without time clashes. Reason is required; attachments are optional (PDF/images)."
        icon={Car}
          backLink={{ href: "/leave", label: "Back to HR" }}
      />

      <div className="grid gap-4 md:grid-cols-3">
        <Card className="md:col-span-2">
          <CardHeader className="flex flex-row items-center justify-between">
            <div>
              <CardTitle>My Applications</CardTitle>
              <CardDescription>Pending and approved requests block the slot for other users.</CardDescription>
            </div>
            <Button onClick={() => setOpen(true)}>
              <Plus className="mr-2 h-4 w-4" /> New Application
            </Button>
          </CardHeader>
          <CardContent className="space-y-3">
            {loading ? <TableSkeleton rows={3} cols={2} /> : null}
            {isError ? <QueryError message="Could not load fleet data." onRetry={refetch} /> : null}
            {!loading && !isError && bookings.length === 0 ? (
              <p className="text-muted-foreground text-sm">No fleet booking applications yet.</p>
            ) : null}
            {bookings.map((booking) => (
              <div key={booking.id} className="rounded border p-3">
                <div className="flex flex-wrap items-center justify-between gap-2">
                  <div>
                    <p className="font-medium">{booking.resource?.name || "Resource"}</p>
                    <p className="text-muted-foreground text-xs">
                      {formatDateTime(booking.start_at)} - {formatDateTime(booking.end_at)}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge variant={statusVariant[booking.status]}>{booking.status}</Badge>
                    {(booking.status === "pending" || booking.status === "approved") &&
                    new Date(booking.start_at).getTime() > Date.now() ? (
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleCancel(booking.id)}
                        disabled={cancelingId === booking.id}
                      >
                        {cancelingId === booking.id ? "Cancelling..." : "Cancel"}
                      </Button>
                    ) : null}
                  </div>
                </div>
                <p className="mt-2 text-sm">{booking.reason}</p>
                <div className="text-muted-foreground mt-2 flex items-center gap-3 text-xs">
                  <span className="inline-flex items-center gap-1">
                    <Paperclip className="h-3.5 w-3.5" /> {(booking.attachments || []).length} attachment(s)
                  </span>
                  {booking.admin_note ? <span>Admin note: {booking.admin_note}</span> : null}
                </div>
              </div>
            ))}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <CalendarClock className="h-4 w-4" /> Occupied Slots
            </CardTitle>
            <CardDescription>
              {resourceId
                ? "Shows pending/approved bookings for the selected resource."
                : "Select a resource in the modal to preview occupied slots."}
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-2">
            {selectedResourceSchedule.slice(0, 8).map((slot) => (
              <div key={slot.id} className="rounded border p-2 text-xs">
                <div className="flex items-center justify-between">
                  <span>{formatDateTime(slot.start_at)}</span>
                  <Badge variant={slot.status === "approved" ? "default" : "secondary"}>{slot.status}</Badge>
                </div>
                <div className="text-muted-foreground">to {formatDateTime(slot.end_at)}</div>
              </div>
            ))}
            {selectedResourceSchedule.length === 0 ? (
              <p className="text-muted-foreground text-xs">No occupied slots yet for selected resource.</p>
            ) : null}
          </CardContent>
        </Card>
      </div>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="sm:max-w-2xl">
          <DialogHeader>
            <DialogTitle>Fleet Booking Application</DialogTitle>
            <DialogDescription>
              Provide your date/time, reason, and optional supporting files (PDF/images).
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-2">
            <div className="space-y-2">
              <Label>Resource</Label>
              <Select value={resourceId} onValueChange={setResourceId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select resource" />
                </SelectTrigger>
                <SelectContent>
                  {resources.map((resource) => (
                    <SelectItem key={resource.id} value={resource.id}>
                      {resource.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="grid gap-4 sm:grid-cols-2">
              <div className="space-y-2">
                <Label>Start Date & Time</Label>
                <Input
                  type="datetime-local"
                  value={toLocalDateTimeInput(startAt)}
                  onChange={(e) => setStartAt(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>End Date & Time</Label>
                <Input
                  type="datetime-local"
                  value={toLocalDateTimeInput(endAt)}
                  onChange={(e) => setEndAt(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label>Reason (required)</Label>
              <Textarea
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                placeholder="State the business reason for this booking"
                rows={4}
              />
              <p className="text-muted-foreground text-xs">Minimum 10 characters</p>
            </div>

            <div className="space-y-2">
              <Label>Attachments (optional)</Label>
              <Input
                type="file"
                accept="application/pdf,image/jpeg,image/jpg,image/png,image/webp"
                multiple
                onChange={(e) => setFiles(Array.from(e.target.files || []))}
              />
              <p className="text-muted-foreground text-xs">Accepted: PDF, JPG, JPEG, PNG, WEBP (max 10MB each).</p>
            </div>

            {currentWindowConflicts.length > 0 ? (
              <div className="border-destructive/40 bg-destructive/5 rounded border p-3 text-sm">
                <p className="font-medium">Time clash detected</p>
                <p className="text-muted-foreground">This slot overlaps an existing pending/approved booking.</p>
              </div>
            ) : null}
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit} disabled={!canSubmit || submitting || currentWindowConflicts.length > 0}>
              {submitting ? "Submitting..." : "Submit Application"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </PageWrapper>
  )
}

"use client"

import { useState } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Progress } from "@/components/ui/progress"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Target, Plus, CheckCircle } from "lucide-react"
import { PageHeader, PageWrapper } from "@/components/layout"
import { toast } from "sonner"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import type { Goal } from "./page"

import { logger } from "@/lib/logger"

const log = logger("dashboard-goals-goals-content")


interface GoalsContentProps {
  initialGoals: Goal[]
  userId: string
}

export function GoalsContent({ initialGoals, userId }: GoalsContentProps) {
  const [goals, setGoals] = useState<Goal[]>(initialGoals)
  const [showAddDialog, setShowAddDialog] = useState(false)
  const [saving, setSaving] = useState(false)
  const [newGoal, setNewGoal] = useState({
    title: "",
    description: "",
    target_value: 100,
    priority: "medium",
    due_date: "",
  })

  async function fetchGoals() {
    try {
      const response = await fetch("/api/hr/performance/goals")
      const data = await response.json()
      if (data.goals) {
        setGoals(data.goals)
      }
    } catch (error) {
      log.error("Error fetching goals:", error)
    }
  }

  async function handleAddGoal() {
    setSaving(true)
    try {
      const response = await fetch("/api/hr/performance/goals", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...newGoal,
          user_id: userId,
        }),
      })

      if (!response.ok) {
        const data = await response.json()
        throw new Error(data.error || "Failed to create goal")
      }

      toast.success("Goal created successfully")

      setShowAddDialog(false)
      setNewGoal({ title: "", description: "", target_value: 100, priority: "medium", due_date: "" })
      fetchGoals()
    } catch (error: any) {
      toast.error(error.message)
    } finally {
      setSaving(false)
    }
  }

  async function updateGoalProgress(goalId: string, achievedValue: number) {
    try {
      const response = await fetch("/api/hr/performance/goals", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          id: goalId,
          achieved_value: achievedValue,
          status: achievedValue >= 100 ? "completed" : "in_progress",
        }),
      })

      if (!response.ok) throw new Error("Failed to update goal")

      toast.success("Goal progress updated")
      fetchGoals()
    } catch (error: any) {
      toast.error(error.message)
    }
  }

  function getStatusBadge(status: string) {
    const colors: { [key: string]: string } = {
      not_started: "bg-gray-100 text-gray-800",
      in_progress: "bg-blue-100 text-blue-800",
      completed: "bg-green-100 text-green-800",
      cancelled: "bg-red-100 text-red-800",
    }
    return colors[status] || "bg-gray-100 text-gray-800"
  }

  function getPriorityBadge(priority: string) {
    const colors: { [key: string]: string } = {
      low: "bg-gray-100 text-gray-800",
      medium: "bg-yellow-100 text-yellow-800",
      high: "bg-red-100 text-red-800",
    }
    return colors[priority] || "bg-gray-100 text-gray-800"
  }

  const inProgress = goals.filter((g) => g.status === "in_progress").length
  const completed = goals.filter((g) => g.status === "completed").length

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title="My Goals"
        description="Track and manage your performance goals"
        icon={Target}
        backLink={{ href: "/profile", label: "Back to Dashboard" }}
        actions={
          <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="mr-2 h-4 w-4" />
                Add Goal
              </Button>
            </DialogTrigger>
            <DialogContent className="max-h-[90vh] w-[95vw] max-w-lg overflow-y-auto">
              <DialogHeader>
                <DialogTitle>Create New Goal</DialogTitle>
                <DialogDescription>Set a new performance goal to track</DialogDescription>
              </DialogHeader>
              <div className="space-y-4 pt-4">
                <div className="space-y-2">
                  <Label>Title</Label>
                  <Input
                    value={newGoal.title}
                    onChange={(e) => setNewGoal({ ...newGoal, title: e.target.value })}
                    placeholder="e.g., Complete React certification"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Description</Label>
                  <Textarea
                    value={newGoal.description}
                    onChange={(e) => setNewGoal({ ...newGoal, description: e.target.value })}
                    placeholder="Describe your goal..."
                    rows={3}
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Priority</Label>
                    <Select
                      value={newGoal.priority}
                      onValueChange={(value) => setNewGoal({ ...newGoal, priority: value })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="low">Low</SelectItem>
                        <SelectItem value="medium">Medium</SelectItem>
                        <SelectItem value="high">High</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Due Date</Label>
                    <Input
                      type="date"
                      value={newGoal.due_date}
                      onChange={(e) => setNewGoal({ ...newGoal, due_date: e.target.value })}
                    />
                  </div>
                </div>
                <Button onClick={handleAddGoal} disabled={saving || !newGoal.title} className="w-full">
                  {saving ? "Creating..." : "Create Goal"}
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        }
      />

      {/* Summary */}
      <div className="mb-6 grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3 md:gap-4">
        <Card>
          <CardHeader className="px-3 pt-3 pb-1 sm:px-6 sm:pt-6 sm:pb-2">
            <CardTitle className="text-sm font-medium">Total Goals</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-lg font-bold sm:text-2xl">{goals.length}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="px-3 pt-3 pb-1 sm:px-6 sm:pt-6 sm:pb-2">
            <CardTitle className="text-sm font-medium">In Progress</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-lg font-bold text-blue-600 sm:text-2xl">{inProgress}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="px-3 pt-3 pb-1 sm:px-6 sm:pt-6 sm:pb-2">
            <CardTitle className="text-sm font-medium">Completed</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-lg font-bold text-green-600 sm:text-2xl">{completed}</div>
          </CardContent>
        </Card>
      </div>

      {/* Goals List */}
      {goals.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Target className="text-muted-foreground mx-auto mb-4 h-12 w-12" />
            <h3 className="text-lg font-semibold">No goals yet</h3>
            <p className="text-muted-foreground mb-4">Create your first performance goal to get started</p>
            <Button onClick={() => setShowAddDialog(true)}>
              <Plus className="mr-2 h-4 w-4" />
              Add Goal
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {goals.map((goal) => (
            <Card key={goal.id}>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <CardTitle className="flex items-center gap-2">
                    {goal.status === "completed" ? (
                      <CheckCircle className="h-5 w-5 text-green-500" />
                    ) : (
                      <Target className="h-5 w-5" />
                    )}
                    {goal.title}
                  </CardTitle>
                  <div className="flex gap-2">
                    <Badge className={getPriorityBadge(goal.priority)}>{goal.priority}</Badge>
                    <Badge className={getStatusBadge(goal.status)}>{goal.status.replace("_", " ")}</Badge>
                  </div>
                </div>
                {goal.description && <CardDescription>{goal.description}</CardDescription>}
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  <div>
                    <div className="mb-2 flex justify-between text-sm">
                      <span>Progress</span>
                      <span>{goal.achieved_value || 0}%</span>
                    </div>
                    <Progress value={goal.achieved_value || 0} />
                  </div>
                  {goal.status !== "completed" && (
                    <div className="flex gap-2">
                      <Input
                        type="number"
                        min="0"
                        max="100"
                        placeholder="Update progress %"
                        className="w-32"
                        onKeyDown={(e) => {
                          if (e.key === "Enter") {
                            updateGoalProgress(goal.id, parseInt((e.target as HTMLInputElement).value))
                          }
                        }}
                      />
                      <Button variant="outline" size="sm" onClick={() => updateGoalProgress(goal.id, 100)}>
                        Mark Complete
                      </Button>
                    </div>
                  )}
                  {goal.due_date && (
                    <p className="text-muted-foreground text-sm">Due: {new Date(goal.due_date).toLocaleDateString()}</p>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </PageWrapper>
  )
}

"use client"

import { useState } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Textarea } from "@/components/ui/textarea"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { Briefcase, Save, Edit2, Clock, Printer } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { formatName } from "@/lib/utils"
import { PageHeader, PageWrapper } from "@/components/layout"
import { writeAuditLogClient } from "@/lib/audit/client"
import { EmptyState } from "@/components/ui/patterns"
import { QUERY_KEYS } from "@/lib/query-keys"
import { PageLoader } from "@/components/ui/query-states"

import { logger } from "@/lib/logger"

const log = logger("job-description")

interface JobDescriptionData {
  jobDescription: string
  lastUpdated: string | null
  profile: {
    first_name: string | null
    last_name: string | null
    company_email: string | null
    department: string | null
    phone_number: string | null
    id: string
  } | null
}

async function fetchJobDescriptionData(): Promise<JobDescriptionData> {
  const supabase = createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) return { jobDescription: "", lastUpdated: null, profile: null }

  const { data: profileData, error } = await supabase
    .from("profiles")
    .select(
      "first_name, last_name, company_email, department, phone_number, job_description, job_description_updated_at"
    )
    .eq("id", user.id)
    .single()

  if (error) throw new Error(error.message)

  return {
    jobDescription: profileData?.job_description || "",
    lastUpdated: profileData?.job_description_updated_at || null,
    profile: profileData
      ? {
          first_name: profileData.first_name,
          last_name: profileData.last_name,
          company_email: profileData.company_email,
          department: profileData.department,
          phone_number: profileData.phone_number,
          id: user.id,
        }
      : null,
  }
}

export default function JobDescriptionPage() {
  const queryClient = useQueryClient()
  const [isEditing, setIsEditing] = useState(false)
  const [isSaving, setIsSaving] = useState(false)
  const [editText, setEditText] = useState("")

  const { data, isLoading } = useQuery({
    queryKey: QUERY_KEYS.appJobDescription(),
    queryFn: fetchJobDescriptionData,
  })

  const jobDescription = data?.jobDescription ?? ""
  const lastUpdated = data?.lastUpdated ?? null
  const profile = data?.profile ?? null

  const supabase = createClient()

  function openEdit() {
    setEditText(jobDescription)
    setIsEditing(true)
  }

  function cancelEdit() {
    setIsEditing(false)
  }

  const handleSave = async () => {
    setIsSaving(true)
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) throw new Error("Not authenticated")

      const { error } = await supabase
        .from("profiles")
        .update({
          job_description: editText,
          job_description_updated_at: new Date().toISOString(),
        })
        .eq("id", user.id)

      if (error) throw error

      await writeAuditLogClient(
        supabase as any,
        {
          action: "update",
          entityType: "job_description",
          entityId: user.id,
          newValues: { job_description: editText },
          context: {
            source: "ui",
            route: "/job-description",
            department: profile?.department || null,
            actorId: user.id,
          },
        },
        { failOpen: true }
      )

      toast.success("Job description saved successfully")
      setIsEditing(false)
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.appJobDescription() })
    } catch (error) {
      log.error("Error saving job description:", error)
      toast.error("Failed to save job description")
    } finally {
      setIsSaving(false)
    }
  }

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    })
  }

  const handlePrint = () => {
    window.print()
  }

  if (isLoading) return <PageLoader />

  return (
    <>
      <style>{`
        @media print {
          body {
            background: white !important;
          }
          .no-print {
            display: none !important;
          }
        }
      `}</style>
      <PageWrapper maxWidth="full" background="gradient" className="print:p-4">
        {/* Header */}
        <div className="no-print">
          <PageHeader
            title="My Job Description"
            description="Define and manage your role responsibilities"
            icon={Briefcase}
            backLink={{ href: "/profile", label: "Back to Dashboard" }}
            actions={
              !isEditing && jobDescription ? (
                <div className="flex gap-2">
                  <Button onClick={handlePrint} variant="outline" className="gap-2">
                    <Printer className="h-4 w-4" />
                    Print
                  </Button>
                  <Button onClick={openEdit} variant="outline" className="gap-2">
                    <Edit2 className="h-4 w-4" />
                    Edit
                  </Button>
                </div>
              ) : null
            }
          />
        </div>

        {/* Last Updated Info */}
        {lastUpdated && !isEditing && (
          <div className="text-muted-foreground no-print flex items-center gap-2 text-sm">
            <Clock className="h-4 w-4" />
            <span>Last updated: {formatDate(lastUpdated)}</span>
          </div>
        )}

        {/* Print Letterhead - Hidden on screen, visible when printing */}
        <div className="hidden print:mb-8 print:block print:border-b print:pb-4">
          <div className="flex items-start justify-between">
            <div>
              <img src="/acob-logo.webp" alt="ACOB Lighting" className="h-16 w-auto" />
            </div>
            <div className="text-right text-sm">
              {profile?.first_name && profile?.last_name && (
                <p className="mb-1 font-semibold">
                  {formatName(profile.first_name)} {formatName(profile.last_name)}
                </p>
              )}
              {profile?.company_email && <p className="mb-1">{profile.company_email}</p>}
              {profile?.department && <p className="mb-1">{profile.department}</p>}
              {profile?.phone_number && <p className="mb-1">{profile.phone_number}</p>}
              <p className="mt-2">
                {new Date().toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" })}
              </p>
            </div>
          </div>
        </div>

        {/* Main Card */}
        <Card className="border-2 shadow-lg print:border-0 print:shadow-none">
          <CardHeader className="bg-muted/30 border-b print:border-0 print:pb-2">
            <CardTitle className="flex items-center justify-between print:text-xl">
              <span className="print:hidden">Job Description</span>
              <span className="hidden print:block">Job Description</span>
              {!jobDescription && (
                <Badge variant="outline" className="bg-yellow-50 text-yellow-700 dark:bg-yellow-900/30 print:hidden">
                  Not Set
                </Badge>
              )}
            </CardTitle>
            <CardDescription className="print:hidden">
