  low: "text-gray-500",
  normal: "text-blue-500",
  high: "text-orange-500",
  urgent: "text-red-500",
}

function formatRelativeTime(dateString: string): string {
  const date = new Date(dateString)
  const now = new Date()
  const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000)

  if (diffInSeconds < 60) return "Just now"
  if (diffInSeconds < 3600) {
    const minutes = Math.floor(diffInSeconds / 60)
    return `${minutes} minute${minutes > 1 ? "s" : ""} ago`
  }
  if (diffInSeconds < 86400) {
    const hours = Math.floor(diffInSeconds / 3600)
    return `${hours} hour${hours > 1 ? "s" : ""} ago`
  }
  if (diffInSeconds < 604800) {
    const days = Math.floor(diffInSeconds / 86400)
    return `${days} day${days > 1 ? "s" : ""} ago`
  }

  return date.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })
}

function getInitials(name?: string): string {
  if (!name) return "?"
  const parts = name.split(" ")
  if (parts.length >= 2) {
    return `${parts[0][0]}${parts[1][0]}`.toUpperCase()
  }
  return name.substring(0, 2).toUpperCase()
}

interface NotificationContentProps {
  initialNotifications: Notification[]
  userId: string
}

export function NotificationContent({ initialNotifications, userId }: NotificationContentProps) {
  const router = useRouter()
  const [supabase] = useState(() => createClient())

  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications)
  const [activeTab, setActiveTab] = useState("all")
  const [searchQuery, setSearchQuery] = useState("")
  const [priorityFilter, setPriorityFilter] = useState("all")

  useEffect(() => {
    // Setup real-time subscription
    const subscription = supabase
      .channel("user_notifications")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "notifications",
          filter: `user_id=eq.${userId}`,
        },
        (payload) => {
          if (payload.eventType === "INSERT") {
            setNotifications((prev) => [payload.new as Notification, ...prev])
          } else if (payload.eventType === "UPDATE") {
            setNotifications((prev) => prev.map((n) => (n.id === payload.new.id ? (payload.new as Notification) : n)))
          } else if (payload.eventType === "DELETE") {
            setNotifications((prev) => prev.filter((n) => n.id !== payload.old.id))
          }
        }
      )
      .subscribe()

    return () => {
      subscription.unsubscribe()
    }
  }, [userId])

  const markAsRead = async (notificationId: string) => {
    try {
      const { error } = await supabase
        .from("notifications")
        .update({ read: true, read_at: new Date().toISOString() })
        .eq("id", notificationId)

      if (error) throw error

      setNotifications((prev) => prev.map((n) => (n.id === notificationId ? { ...n, read: true } : n)))
    } catch (error: any) {
      log.error("Error marking as read:", error)
      toast.error("Failed to mark as read")
    }
  }

  const markAllAsRead = async () => {
    try {
      const { error } = await supabase.rpc("mark_notifications_read", {
        p_user_id: userId,
        p_notification_ids: null,
      })

      if (error) throw error

      setNotifications((prev) => prev.map((n) => ({ ...n, read: true })))
      toast.success("All notifications marked as read")
    } catch (error: any) {
      log.error("Error:", error)
      toast.error("Failed to mark all as read")
    }
  }

  const deleteNotification = async (notificationId: string) => {
    try {
      const { error } = await supabase.from("notifications").delete().eq("id", notificationId)

      if (error) throw error

      setNotifications((prev) => prev.filter((n) => n.id !== notificationId))
      toast.success("Notification deleted")
    } catch (error: any) {
      log.error("Error:", error)
      toast.error("Failed to delete notification")
    }
  }

  const handleNotificationClick = async (notification: Notification) => {
    if (!notification.read) {
      await markAsRead(notification.id)
    }

    if (notification.action_url) {
      router.push(notification.action_url)
    }
  }

  const filteredNotifications = notifications.filter((n) => {
    if (activeTab === "unread" && n.read) return false
    if (activeTab !== "all" && activeTab !== "unread" && n.category !== activeTab) return false
    if (priorityFilter !== "all" && n.priority !== priorityFilter) return false

    if (searchQuery) {
      const query = searchQuery.toLowerCase()
      return (
        n.title.toLowerCase().includes(query) ||
        n.message.toLowerCase().includes(query) ||
        n.actor_name?.toLowerCase().includes(query)
      )
    }

    return true
  })

  const unreadCount = notifications.filter((n) => !n.read).length
  const categoryCounts = {
    all: notifications.length,
    unread: unreadCount,
    tasks: notifications.filter((n) => n.category === "tasks").length,
    assets: notifications.filter((n) => n.category === "assets").length,
    feedback: notifications.filter((n) => n.category === "feedback").length,
    mentions: notifications.filter((n) => n.category === "mentions").length,
  }

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title="Notifications"
        description="Stay updated with your tasks, assets, and more"
        icon={Bell}
        backLink={{ href: "/profile", label: "Back to Dashboard" }}
        actions={
          <div className="flex items-center gap-2">
          <Link href="/notifications/settings">
              <Button variant="outline" className="gap-2">
                <Settings className="h-4 w-4" />
                Notification Settings
              </Button>
            </Link>
            {unreadCount > 0 ? (
              <Button onClick={markAllAsRead} variant="outline" className="gap-2">
                <CheckCheck className="h-4 w-4" />
                Mark all read
              </Button>
            ) : null}
          </div>
        }
      />

      {/* Stats */}
      <div className="mb-6 grid grid-cols-2 gap-2 sm:grid-cols-4 sm:gap-3 md:gap-4">
        <Card>
          <CardContent className="p-3 sm:p-4">
            <div className="text-lg font-bold sm:text-2xl">{categoryCounts.all}</div>
            <div className="text-muted-foreground text-xs">Total</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-3 sm:p-4">
            <div className="text-lg font-bold text-blue-600 sm:text-2xl">{categoryCounts.unread}</div>
            <div className="text-muted-foreground text-xs">Unread</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-3 sm:p-4">
            <div className="text-lg font-bold text-green-600 sm:text-2xl">{categoryCounts.tasks}</div>
            <div className="text-muted-foreground text-xs">Tasks</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-3 sm:p-4">
            <div className="text-lg font-bold text-purple-600 sm:text-2xl">{categoryCounts.assets}</div>
            <div className="text-muted-foreground text-xs">Assets</div>
          </CardContent>
        </Card>
      </div>

      {/* Main Content */}
      <Card>
        <CardHeader className="border-b">
          <div className="flex flex-col gap-4 sm:flex-row">
            <div className="relative flex-1">
              <Search className="text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2" />
              <Input
                placeholder="Search notifications..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9"
              />
            </div>

            <Select value={priorityFilter} onValueChange={setPriorityFilter}>
              <SelectTrigger className="w-full sm:w-[180px]">
                <Filter className="mr-2 h-4 w-4" />
                <SelectValue placeholder="Priority" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Priorities</SelectItem>
                <SelectItem value="urgent">Urgent</SelectItem>
                <SelectItem value="high">High</SelectItem>
                <SelectItem value="normal">Normal</SelectItem>
                <SelectItem value="low">Low</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardHeader>

        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <div className="border-b px-4 py-3">
            <TabsList className="h-auto w-full justify-start gap-1 overflow-x-auto">
              <TabsTrigger value="all" className="px-4 py-2 whitespace-nowrap">
                All
                {categoryCounts.all > 0 && (
                  <Badge variant="secondary" className="ml-2">
                    {categoryCounts.all}
                  </Badge>
                )}
              </TabsTrigger>

              <TabsTrigger value="unread" className="px-4 py-2 whitespace-nowrap">
                Unread
                {categoryCounts.unread > 0 && (
                  <Badge variant="destructive" className="ml-2">
                    {categoryCounts.unread}
                  </Badge>
                )}
              </TabsTrigger>

              <TabsTrigger value="tasks" className="px-4 py-2 whitespace-nowrap">
                <User className="mr-1 h-4 w-4" />
                Tasks
                {categoryCounts.tasks > 0 && (
                  <Badge variant="secondary" className="ml-2">
                    {categoryCounts.tasks}
                  </Badge>
                )}
              </TabsTrigger>

              <TabsTrigger value="assets" className="px-4 py-2 whitespace-nowrap">
                <Package className="mr-1 h-4 w-4" />
                Assets
                {categoryCounts.assets > 0 && (
                  <Badge variant="secondary" className="ml-2">
                    {categoryCounts.assets}
                  </Badge>
                )}
              </TabsTrigger>
            </TabsList>
          </div>

          <TabsContent value={activeTab} className="mt-0">
            <ScrollArea className="h-[calc(100vh-400px)]">
              {filteredNotifications.length > 0 ? (
                <div className="divide-y">
                  {filteredNotifications.map((notification) => {
                    const Icon = typeIcons[notification.type as keyof typeof typeIcons] || Info

                    return (
                      <div
                        key={notification.id}
                        className={cn(
                          "group hover:bg-muted/30 relative cursor-pointer px-4 py-3 transition-all",
                          !notification.read && "bg-blue-50/30 dark:bg-blue-950/10"
                        )}
                        onClick={() => handleNotificationClick(notification)}
                      >
                        <div className="flex gap-3">
                          {notification.actor_avatar || notification.actor_name ? (
                            <Avatar className="h-9 w-9 shrink-0">
                              {notification.actor_avatar && (
                                <AvatarImage src={notification.actor_avatar} alt={notification.actor_name} />
                              )}
                              <AvatarFallback className="bg-primary/10 text-primary font-medium">
                                {getInitials(notification.actor_name)}
                              </AvatarFallback>
                            </Avatar>
                          ) : (
                            <div
                              className={cn(
                                "bg-muted flex h-9 w-9 shrink-0 items-center justify-center rounded-full",
                                priorityColors[notification.priority as keyof typeof priorityColors]
                              )}
                            >
                              <Icon className="h-4 w-4" />
                            </div>
                          )}

                          <div className="min-w-0 flex-1">
                            <div className="flex items-start justify-between gap-3">
                              <div className="flex-1">
                                <h3 className={cn("text-sm leading-tight", !notification.read && "font-semibold")}>
                                  {notification.title}
                                </h3>
                                <p className="text-muted-foreground mt-0.5 line-clamp-2 text-xs leading-snug">
                                  {notification.message}
                                </p>

                                <div className="mt-1.5 flex items-center gap-2.5">
                                  <span className="text-muted-foreground text-xs">
                                    {formatRelativeTime(notification.created_at)}
                                  </span>
                                  {notification.actor_name && (
                                    <>
                                      <span className="text-muted-foreground">|</span>
                                      <span className="text-muted-foreground text-xs">
                                        by {notification.actor_name}
                                      </span>
                                    </>
                                  )}
                                  <Badge variant="outline" className="text-xs">
                                    {notification.category}
                                  </Badge>
                                </div>

                                {notification.action_url && (
                                  <div className="text-primary mt-1 flex items-center gap-1 text-xs font-medium">
                                    View details
                                    <ChevronRight className="h-3 w-3" />
                                  </div>
                                )}
                              </div>
                            </div>

                            {/* Actions */}
                            <div className="mt-1.5 flex items-center gap-1.5 opacity-0 transition-opacity group-hover:opacity-100">
                              {!notification.read && (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  className="h-7 px-2 text-xs"
                                  onClick={(e) => {
                                    e.stopPropagation()
                                    markAsRead(notification.id)
                                  }}
                                >
                                  <CheckCheck className="mr-1 h-4 w-4" />
                                  Mark read
                                </Button>
                              )}

                              <Button
                                variant="ghost"
                                size="sm"
                                className="text-destructive hover:text-destructive hover:bg-destructive/10 h-7 px-2 text-xs"
                                onClick={(e) => {
                                  e.stopPropagation()
                                  deleteNotification(notification.id)
                                }}
                              >
                                <Trash2 className="mr-1 h-4 w-4" />
                                Delete
                              </Button>
                            </div>
                          </div>
                        </div>
                      </div>
                    )
                  })}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center px-4 py-16">
                  <div className="bg-muted mb-4 rounded-full p-6">
                    <Bell className="text-muted-foreground h-16 w-16 opacity-50" />
                  </div>
                  <h3 className="mb-2 text-lg font-semibold">
                    {searchQuery ? "No matching notifications" : "No notifications"}
                  </h3>
                  <p className="text-muted-foreground max-w-md text-center text-sm">
                    {searchQuery
                      ? "Try adjusting your search terms or filters"
                      : "You're all caught up! We'll notify you when something important happens."}
                  </p>
                </div>
              )}
            </ScrollArea>
          </TabsContent>
        </Tabs>
      </Card>
    </PageWrapper>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { NotificationContent } from "./notification-content"

import { logger } from "@/lib/logger"

const log = logger("notification")


export interface Notification {
  id: string
  user_id: string
  type: string
  category: string
  priority: string
  title: string
  message: string
  data?: any
  action_url?: string | null
  actor_name?: string
  actor_avatar?: string
  read: boolean
  read_at?: string
  created_at: string
}

async function getNotificationData() {
  const supabase = await createClient()

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const { data, error } = await supabase
    .from("notifications")
    .select("*")
    .eq("user_id", user.id)
    .order("created_at", { ascending: false })

  if (error) {
    log.error("Error loading notifications:", error)
  }

  return {
    notifications: (data || []) as Notification[],
    userId: user.id,
  }
}

export default async function NotificationPage() {
  const data = await getNotificationData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  const notificationData = data as { notifications: Notification[]; userId: string }

  return <NotificationContent initialNotifications={notificationData.notifications} userId={notificationData.userId} />
}

"use client"

import { useState } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { QUERY_KEYS } from "@/lib/query-keys"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Calendar, FileText, MoreVertical, Trash2, CheckCircle, Edit, Printer } from "lucide-react"
import { toast } from "sonner"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import {
  addMonths,
  addYears,
  addQuarters,
  format,
  parseISO,
  differenceInDays,
  startOfDay,
  isValid,
  isBefore,
} from "date-fns"
import { PageHeader } from "@/components/layout/page-header"
import { PageLoader } from "@/components/ui/query-states"
import { ScheduleList } from "@/components/payments/schedule-list"
import { PaymentEditDialog } from "@/components/payments/payment-edit-dialog"
import { PaymentUploadDialog } from "@/components/payments/payment-upload-dialog"
import { PrintReceiptDialog } from "@/components/payments/print-receipt-dialog"
import { PaymentInfoCard } from "@/components/payments/payment-info-card"
import { PaymentMetaCard } from "@/components/payments/payment-meta-card"
import { usePaymentSchedule } from "@/components/payments/use-payment-schedule"
import { logger } from "@/lib/logger"
import type {
  Payment,
  Department,
  Category,
  PaymentDocument,
  PaymentEditFormData,
} from "@/components/payments/payment-types"

const log = logger("payments")

interface PaymentPageData {
  payment: Payment | null
  departments: Department[]
  categories: Category[]
}

async function fetchPaymentPageData(id: string): Promise<PaymentPageData> {
  const [paymentRes, deptRes, catRes] = await Promise.all([
    fetch(`/api/payments/${id}`),
    fetch("/api/departments"),
    fetch("/api/payments/categories"),
  ])

  const paymentJson = await paymentRes.json()
  const payment: Payment | null = paymentRes.ok ? (paymentJson.data ?? null) : null
  if (!paymentRes.ok) {
    throw new Error(paymentJson.error ?? "Failed to fetch payment details")
  }

  const departments: Department[] = deptRes.ok ? ((await deptRes.json()).data ?? []) : []
  const categories: Category[] = catRes.ok ? ((await catRes.json()).data ?? []) : []

  return { payment, departments, categories }
}

export default function PaymentDetailsPage({ params }: { params: { id: string } }) {
  const router = useRouter()
  const queryClient = useQueryClient()

  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false)
  const [deleteLoading, setDeleteLoading] = useState(false)

  // Upload State
  const [uploadDialogOpen, setUploadDialogOpen] = useState(false)
  const [uploadDate, setUploadDate] = useState<Date | null>(null)
  const [uploadType, setUploadType] = useState<"invoice" | "receipt">("invoice")
  const [uploading, setUploading] = useState(false)
  const [replaceDocumentId, setReplaceDocumentId] = useState<string | null>(null)

  // Edit State
  const [editDialogOpen, setEditDialogOpen] = useState(false)
  const [printDialogOpen, setPrintDialogOpen] = useState(false)
  const [updating, setUpdating] = useState(false)
  const [editFormData, setEditFormData] = useState<PaymentEditFormData>({
    department_id: "",
    payment_type: "",
    category: "",
    title: "",
    description: "",
    amount: "",
    currency: "NGN",
    recurrence_period: "monthly",
    next_payment_due: "",
    payment_date: "",
    issuer_name: "",
    issuer_phone_number: "",
    issuer_address: "",
    payment_reference: "",
    notes: "",
  })

  const { data: pageData, isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.appPaymentDetail(params.id),
    queryFn: () => fetchPaymentPageData(params.id),
  })

  const payment = pageData?.payment ?? null
  const departments = pageData?.departments ?? []
  const categories = pageData?.categories ?? []

  const schedule = usePaymentSchedule(payment)

  const downloadFile = async (url: string, filename: string) => {
    try {
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch file")

      const blob = await response.blob()
      const blobUrl = window.URL.createObjectURL(blob)
      const link = document.createElement("a")
      link.href = blobUrl
      link.download = filename
      link.style.display = "none"
      document.body.appendChild(link)
      link.click()

      setTimeout(() => {
        document.body.removeChild(link)
        window.URL.revokeObjectURL(blobUrl)
      }, 100)
    } catch (error) {
      log.error("Error downloading file:", error)
      throw error
    }
  }

  const handleViewDocument = async (e: React.MouseEvent, doc?: PaymentDocument) => {
    e.preventDefault()
    if (!doc) return

    try {
      const supabase = createClient()
      const { data, error } = await supabase.storage.from("payment_documents").createSignedUrl(doc.file_path, 3600)
      if (data?.signedUrl) {
        const filename = doc.file_name || doc.file_path.split("/").pop() || "document.pdf"
        await downloadFile(data.signedUrl, filename)
        toast.success("Document downloaded successfully")
      } else {
        toast.error("Could not get secure document URL")
        if (error) log.error("Error signing URL:", error)
      }
    } catch (error) {
      log.error("Error downloading document:", error)
      toast.error("Error downloading document")
    }
  }

  const handleEditClick = () => {
    if (!payment) return
    setEditFormData({
      department_id: payment.department_id,
      payment_type: payment.payment_type,
      category: payment.category,
      title: payment.title,
      description: payment.description || "",
      amount: payment.amount.toString(),
      currency: payment.currency,
      recurrence_period: payment.recurrence_period || "monthly",
      next_payment_due: payment.next_payment_due ? format(parseISO(payment.next_payment_due), "yyyy-MM-dd") : "",
      payment_date: payment.payment_date ? format(parseISO(payment.payment_date), "yyyy-MM-dd") : "",
      issuer_name: payment.issuer_name || "",
      issuer_phone_number: payment.issuer_phone_number || "",
      issuer_address: payment.issuer_address || "",
      payment_reference: payment.payment_reference || "",
      notes: payment.notes || "",
    })
    setEditDialogOpen(true)
  }

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!editFormData.issuer_name || !editFormData.issuer_phone_number) {
      toast.error("Issuer Name and Phone are required.")
      return
    }

    try {
      setUpdating(true)
      const payload = {
        ...editFormData,
        payment_type: editFormData.payment_type,
        category: editFormData.category,
        amount: parseFloat(editFormData.amount),
        next_payment_due: editFormData.next_payment_due || null,
        payment_date: editFormData.payment_date || null,
      }

      const response = await fetch(`/api/payments/${params.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      })

      if (response.ok) {
        toast.success("Payment updated successfully")
        setEditDialogOpen(false)
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.appPaymentDetail(params.id) })
      } else {
        const data = await response.json()
        toast.error(data.error || "Failed to update payment")
      }
    } catch (error) {
      toast.error("Error updating payment")
    } finally {
      setUpdating(false)
    }
  }

  const handleDelete = async () => {
    try {
      setDeleteLoading(true)
      const response = await fetch(`/api/payments/${params.id}`, { method: "DELETE" })

      if (response.ok) {
        toast.success("Payment deleted successfully")
        router.push("/payments")
      } else {
        const data = await response.json()
        toast.error(data.error || "Failed to delete payment")
      }
    } catch (error) {
      toast.error("Error deleting payment")
    } finally {
      setDeleteLoading(false)
      setDeleteDialogOpen(false)
    }
  }

  const markAsPaid = async (targetDate?: Date) => {
    if (!payment) return

    if (payment.payment_type === "recurring" && payment.next_payment_due && payment.recurrence_period) {
      const dateToPay = targetDate instanceof Date ? targetDate : parseISO(payment.next_payment_due)
      const dateStr = format(dateToPay, "yyyy-MM-dd")
      const hasReceipt = payment.documents?.some((d) => d.applicable_date === dateStr && d.document_type === "receipt")

      if (!hasReceipt) {
        toast.error("Please upload a payment receipt first.", {
          action: { label: "Upload", onClick: () => handleUploadClick(dateToPay, "receipt") },
          duration: 5000,
        })
        handleUploadClick(dateToPay, "receipt")
        return
      }

      const currentDue = parseISO(payment.next_payment_due)
      let nextDue: Date
      switch (payment.recurrence_period) {
        case "monthly":
          nextDue = addMonths(currentDue, 1)
          break
        case "quarterly":
          nextDue = addQuarters(currentDue, 1)
          break
        case "yearly":
          nextDue = addYears(currentDue, 1)
          break
        default:
          nextDue = addMonths(currentDue, 1)
      }

      try {
        const response = await fetch(`/api/payments/${params.id}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            next_payment_due: format(nextDue, "yyyy-MM-dd"),
            last_payment_date: format(dateToPay, "yyyy-MM-dd"),
            status: "due",
            amount_paid: (payment.amount_paid || 0) + payment.amount,
          }),
        })

        if (response.ok) {
          toast.success("Payment recorded! Schedule advanced.")
          queryClient.invalidateQueries({ queryKey: QUERY_KEYS.appPaymentDetail(params.id) })
        } else {
          toast.error("Failed to update payment")
        }
      } catch (error) {
        toast.error("Error processing payment")
      }
    } else {
      updateStatus("paid")
    }
  }

  const updateStatus = async (newStatus: string) => {
    if (!payment) return
    try {
      const response = await fetch(`/api/payments/${params.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          status: newStatus,
          amount_paid: newStatus === "paid" ? payment.amount : newStatus === "due" ? 0 : payment.amount_paid,
        }),
      })

      if (response.ok) {
        toast.success(`Payment marked as ${newStatus}`)
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.appPaymentDetail(params.id) })
      } else {
        toast.error("Failed to update status")
      }
    } catch (error) {
      toast.error("Error updating status")
    }
  }

  const handleUploadClick = (date: Date, type: "invoice" | "receipt") => {
    setUploadDate(date)
    setUploadType(type)
    setReplaceDocumentId(null)
    setUploadDialogOpen(true)
  }

  const handleReplaceClick = (date: Date, type: "invoice" | "receipt", docId: string) => {
    setUploadDate(date)
    setUploadType(type)
    setReplaceDocumentId(docId)
    setUploadDialogOpen(true)
  }

  const handleFileUpload = async (e: React.FormEvent, inputRef: React.RefObject<HTMLInputElement>) => {
    e.preventDefault()
    if (!inputRef.current?.files?.[0] || !uploadDate) return

    const file = inputRef.current.files[0]
    const formData = new FormData()
    formData.append("file", file)
    formData.append("document_type", uploadType)
    formData.append("applicable_date", format(uploadDate, "yyyy-MM-dd"))

    if (replaceDocumentId) {
      formData.append("replace_document_id", replaceDocumentId)
    }

    setUploading(true)
    try {
      const response = await fetch(`/api/payments/${params.id}/documents`, { method: "POST", body: formData })

      if (response.ok) {
        toast.success(replaceDocumentId ? `${uploadType} replaced successfully` : `${uploadType} uploaded successfully`)
        setUploadDialogOpen(false)
        setReplaceDocumentId(null)
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.appPaymentDetail(params.id) })
      } else {
        const data = await response.json()
        toast.error(data.error || "Upload failed")
      }
    } catch (error) {
      toast.error("Error uploading file")
    } finally {
      setUploading(false)
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "paid":
        return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400"
      case "due":
        return "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400"
      case "overdue":
        return "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400"
      case "cancelled":
        return "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400"
      default:
        return ""
    }
  }

  const formatCurrency = (amount: number, currency: string = "NGN") => {
    return new Intl.NumberFormat("en-NG", { style: "currency", currency }).format(amount)
  }

  const getRealStatus = (p: Payment): "due" | "paid" | "overdue" | "cancelled" => {
    if (p.status === "paid" || p.status === "cancelled") return p.status

    const dateStr = p.payment_type === "recurring" ? p.next_payment_due : p.payment_date
    if (!dateStr) return "due"

    const date = parseISO(dateStr)
    if (!isValid(date)) return "due"

    const today = startOfDay(new Date())
    const daysDiff = differenceInDays(date, today)

    if (isBefore(date, today)) return "overdue"
    if (daysDiff <= 7) return "due"
    return "paid"
  }

  if (loading) return <PageLoader />

  if (!payment) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center gap-4">
        <p className="text-muted-foreground">Payment not found</p>
        <Link href="/payments">
          <Button variant="outline">Back to Payments</Button>
        </Link>
      </div>
    )
  }

  const realStatus = getRealStatus(payment)

  const hasReceiptForMark = (() => {
    if (payment.payment_type === "one-time") {
      return payment.documents?.some((d) => d.document_type === "receipt") ?? false
    } else if (payment.next_payment_due) {
      const dateStr = format(parseISO(payment.next_payment_due), "yyyy-MM-dd")
      return payment.documents?.some((d) => d.applicable_date === dateStr && d.document_type === "receipt") ?? false
    }
    return false
  })()

  return (
    <div className="from-background via-background to-muted/20 min-h-screen bg-gradient-to-br p-4 md:p-6">
      <div className="mx-auto max-w-5xl space-y-6">
        <PageHeader
          title={payment.title}
          description={
            payment.payment_type === "recurring"
              ? `Repeats ${payment.recurrence_period}`
              : `One-time payment on ${payment.payment_date ? format(parseISO(payment.payment_date), "PPP") : "N/A"}`
          }
          backLink={{ href: "/payments", label: "Back to Payments" }}
          actions={
            <div className="flex flex-wrap gap-2">
              <Badge className={getStatusColor(realStatus)}>{realStatus}</Badge>
              {payment.payment_type === "recurring" && payment.next_payment_due && (
                <Badge
                  variant="outline"
                  className="border-primary/20 text-primary bg-primary/5 border-2 px-2 py-0.5 text-sm font-medium"
                >
                  Next Due: {format(parseISO(payment.next_payment_due), "MMM d, yyyy")}
                </Badge>
              )}
              {(realStatus === "due" || realStatus === "overdue") && hasReceiptForMark && (
                <Button onClick={() => markAsPaid()}>
                  <CheckCircle className="mr-2 h-4 w-4" />
                  {payment.payment_type === "recurring" ? "Mark Current Due as Paid" : "Mark as Paid"}
                </Button>
              )}
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" size="icon">
                    <MoreVertical className="h-4 w-4" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuItem onClick={handleEditClick}>
                    <Edit className="mr-2 h-4 w-4" />
                    Edit Payment
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setPrintDialogOpen(true)}>
                    <Printer className="mr-2 h-4 w-4" />
                    Print Receipt
                  </DropdownMenuItem>
                  <DropdownMenuItem
                    className="text-red-600 focus:text-red-600"
                    onClick={() => setDeleteDialogOpen(true)}
                  >
                    <Trash2 className="mr-2 h-4 w-4" />
                    Delete Payment
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          }
        />

        <div className="grid gap-6 md:grid-cols-3">
          <div className="space-y-6 md:col-span-2">
            {payment.payment_type === "recurring" && (
              <>
                <Card>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <Calendar className="h-5 w-5" />
                      Upcoming Schedule
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <ScheduleList
                      items={schedule.filter((i) => i.status !== "paid")}
                      onUpload={handleUploadClick}
                      onView={handleViewDocument}
                      onMarkPaid={markAsPaid}
                      onReplace={handleReplaceClick}
                    />
                  </CardContent>
                </Card>

                {schedule.some((i) => i.status === "paid") && (
                  <Card className="mt-6">
                    <CardHeader>
                      <CardTitle className="flex items-center gap-2">
                        <FileText className="h-5 w-5" />
                        Payment History
                      </CardTitle>
                    </CardHeader>
                    <CardContent>
                      <ScheduleList
                        items={schedule.filter((i) => i.status === "paid")}
                        onUpload={handleUploadClick}
                        onView={handleViewDocument}
                        onReplace={handleReplaceClick}
                      />
                    </CardContent>
                  </Card>
                )}
              </>
            )}

            <PaymentInfoCard payment={payment} formatCurrency={formatCurrency} />
          </div>

          <div className="space-y-6">
            <PaymentMetaCard payment={payment} />
          </div>
        </div>
      </div>

      <PaymentEditDialog
        open={editDialogOpen}
        onOpenChange={setEditDialogOpen}
        formData={editFormData}
        onFormDataChange={setEditFormData}
        onSubmit={handleUpdate}
        updating={updating}
        departments={departments}
        categories={categories}
        showPaymentTypeField={true}
      />

      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
            <AlertDialogDescription>
              This action cannot be undone. This will permanently delete the payment record and remove it from our
              servers.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction className="bg-red-600 hover:bg-red-700" onClick={handleDelete} disabled={deleteLoading}>
              {deleteLoading ? "Deleting..." : "Delete"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <PaymentUploadDialog
        open={uploadDialogOpen}
        onOpenChange={(open) => {
          setUploadDialogOpen(open)
          if (!open) setReplaceDocumentId(null)
        }}
        uploadDate={uploadDate}
        uploadType={uploadType}
        uploading={uploading}
        replaceDocumentId={replaceDocumentId}
        onSubmit={handleFileUpload}
      />

      <PrintReceiptDialog
        open={printDialogOpen}
        onOpenChange={setPrintDialogOpen}
        schedule={schedule}
        onViewDocument={handleViewDocument}
      />
    </div>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { PaymentsTable } from "@/components/payments/payments-table"
import { logger } from "@/lib/logger"

const log = logger("payments-page")

interface Payment {
  id: string
  department_id: string
  title: string
  amount: number
  currency: string
  status: "due" | "paid" | "overdue" | "cancelled"
  payment_type: "one-time" | "recurring"
  recurrence_period?: "monthly" | "quarterly" | "yearly"
  next_payment_due?: string
  payment_date?: string
  category: string
  description?: string
  issuer_name?: string
  issuer_phone_number?: string
  issuer_address?: string
  payment_reference?: string
  amount_paid?: number
  created_at: string
  department?: {
    name: string
  }
  documents?: {
    id: string
    document_type: string
    file_path: string
    file_name?: string
    applicable_date?: string
  }[]
}

interface Department {
  id: string
  name: string
}

interface Category {
  id: string
  name: string
}

async function getPaymentsData() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  // Fetch user profile with department info
  const { data: profile } = await dataClient
    .from("profiles")
    .select("department, department_id")
    .eq("id", user.id)
    .single()

  let currentUserDepartmentId: string | null = null
  const isAdmin = false

  const resolveDepartmentCandidates = (department: string | null | undefined): string[] => {
    const raw = String(department || "").trim()
    if (!raw) return []
    if (raw.toLowerCase() === "finance") return ["Accounts", raw]
    return [raw]
  }

  if (profile) {
    currentUserDepartmentId = (profile as any).department_id || null
    if (!currentUserDepartmentId) {
      const candidates = resolveDepartmentCandidates(profile.department)
      if (candidates.length > 0) {
        const { data: dept } = await dataClient
          .from("departments")
          .select("id, name")
          .in("name", candidates)
          .limit(1)
          .maybeSingle()
        if (dept) {
          currentUserDepartmentId = dept.id
        }
      }
    }
  }

  // Build payments query - ALWAYS filter by user's department for user-facing page
  let paymentsQuery = dataClient
    .from("department_payments")
    .select(
      `
      *,
      department:departments(name),
      documents:payment_documents(id, document_type, file_path, file_name, applicable_date)
    `
    )
    .order("created_at", { ascending: false })

  // Always filter by user's department on the user-facing page
  if (currentUserDepartmentId) {
    paymentsQuery = paymentsQuery.eq("department_id", currentUserDepartmentId)
  }

  const { data: payments, error: paymentsError } = await paymentsQuery
  let loadError: string | null = null

  if (paymentsError) {
    log.error({ err: paymentsError }, "Error loading payments")
    loadError = "Failed to load payments"
  }

  // Fetch departments (just user's department for the dropdown in create form)
  const { data: departments } = await dataClient
    .from("departments")
    .select("id, name")
    .eq("id", currentUserDepartmentId || "")

  // Fetch categories
  const { data: categories } = await dataClient.from("payment_categories").select("id, name").order("name")

  return {
    payments: (payments || []) as Payment[],
    departments: (departments || []) as Department[],
    categories: (categories || []) as Category[],
    loadError,
    currentUser: {
      id: user.id,
      department_id: currentUserDepartmentId,
