import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { ProfileContent } from "./profile-content"

export interface UserProfile {
  id: string
  first_name: string
  last_name: string
  other_names: string | null
  company_email: string
  department: string
  company_role: string | null
  role: string
  phone_number: string | null
  additional_phone: string | null
  residential_address: string | null
  office_location: string | null
  is_admin: boolean
  is_department_lead: boolean
  lead_departments: string[]
  employment_date: string | null
  created_at: string
  updated_at: string
}

export interface Task {
  id: string
  title: string
  description: string | null
  status: string
  priority: string
  department: string | null
  due_date: string | null
  created_at: string
  assignment_type?: "individual" | "multiple" | "department"
}

export interface Asset {
  id: string
  asset_name?: string
  asset_type: string
  asset_model: string | null
  serial_number: string | null
  unique_code: string | null
  status: string
  assigned_at: string
  assignment_type?: "individual" | "department" | "office"
  department?: string
  office_location?: string
}

export interface Documentation {
  id: string
  title: string
  category: string | null
  created_at: string
}

export interface Feedback {
  id: string
  feedback_type: string
  title: string
  description: string | null
  status: string
  created_at: string
}

async function getProfileData() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)
  const loadErrors: string[] = []

  // Get current user
  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const userId = user.id

  // Load profile
  const { data: profileData, error: profileError } = await dataClient
    .from("profiles")
    .select("*")
    .eq("id", userId)
    .single()

  if (profileError || !profileData) {
    return { profile: null, tasks: [], assets: [], documentation: [], feedback: [] }
  }

  let resolvedDepartment = (profileData as any).department || null
  if ((profileData as any).department_id) {
    const { data: deptById } = await dataClient
      .from("departments")
      .select("name")
      .eq("id", (profileData as any).department_id)
      .maybeSingle()
    if (deptById?.name) resolvedDepartment = deptById.name
  }
  if (String(resolvedDepartment || "").toLowerCase() === "finance") {
    resolvedDepartment = "Accounts"
  }

  // Load tasks assigned to user (individual, multiple-user, and department tasks)
  const { data: individualTasks, error: individualTasksError } = await dataClient
    .from("tasks")
    .select("*")
    .eq("assigned_to", userId)
    .order("created_at", { ascending: false })
  if (individualTasksError) loadErrors.push("tasks")

  // Load multiple-user tasks
  const { data: taskAssignments, error: taskAssignmentsError } = await dataClient
    .from("task_assignments")
    .select("task_id")
    .eq("user_id", userId)
  if (taskAssignmentsError) loadErrors.push("tasks")

  let multipleUserTasks: Task[] = []
  if (taskAssignments && taskAssignments.length > 0) {
    const taskIds = taskAssignments.map((ta: any) => ta.task_id)
    const { data: tasksData, error: tasksDataError } = await dataClient
      .from("tasks")
      .select("*")
      .in("id", taskIds)
      .eq("assignment_type", "multiple")
      .order("created_at", { ascending: false })
    if (tasksData) multipleUserTasks = tasksData
    if (tasksDataError) loadErrors.push("tasks")
  }

  // Load department tasks
  const { data: departmentTasks, error: departmentTasksError } = await dataClient
    .from("tasks")
    .select("*")
    .eq("department", resolvedDepartment)
    .eq("assignment_type", "department")
    .order("created_at", { ascending: false })
  if (departmentTasksError) loadErrors.push("tasks")

  const allTasks = [...(individualTasks || []), ...multipleUserTasks, ...(departmentTasks || [])]

  // Load assets assigned to user (individual)
  const { data: individualAssignments, error: individualAssignmentsError } = await dataClient
    .from("asset_assignments")
    .select(
      `
      assigned_at,
      asset:assets(
        id,
        asset_type,
        asset_model,
        serial_number,
        status,
        unique_code,
        created_at,
        deleted_at
      )
    `
    )
    .eq("assigned_to", userId)
    .eq("is_current", true)
  if (individualAssignmentsError) loadErrors.push("assets")

  // Load department and office assets (separate queries to avoid filter parsing issues with commas in names)
  const [departmentAssetsRes, officeAssetsRes] = await Promise.all([
    resolvedDepartment
      ? dataClient
          .from("assets")
          .select("*")
          .eq("status", "assigned")
          .is("deleted_at", null)
          .eq("assignment_type", "department")
          .eq("department", resolvedDepartment)
      : Promise.resolve({ data: [] } as any),
    profileData.office_location
      ? dataClient
          .from("assets")
          .select("*")
          .eq("status", "assigned")
          .is("deleted_at", null)
          .eq("assignment_type", "office")
          .eq("office_location", profileData.office_location)
      : Promise.resolve({ data: [] } as any),
  ])
  if (departmentAssetsRes.error || officeAssetsRes.error) loadErrors.push("assets")
  const sharedAssets = [...(departmentAssetsRes.data || []), ...(officeAssetsRes.data || [])]

  let allAssets: Asset[] = []

  // Process individual assignments
  if (individualAssignments) {
    const indAssets = individualAssignments
      .map((a: any) => ({
        ...a.asset,
        assigned_at: a.assigned_at,
        assignment_type: "individual" as const,
      }))
      .filter((asset: any) => asset && !asset.deleted_at)
    allAssets = [...allAssets, ...indAssets]
  }

  // Process shared assets
  if (sharedAssets) {
    const shAssets = sharedAssets.map((a: any) => ({
      ...a,
      assigned_at: a.created_at, // Use created_at for shared assets
      assignment_type: a.assignment_type,
    }))
    allAssets = [...allAssets, ...shAssets]
  }

  // Load documentation created by user
  const { data: docsData, error: docsError } = await dataClient
    .from("user_documentation")
    .select("id, title, category, created_at")
    .eq("user_id", userId)
    .order("created_at", { ascending: false })
  if (docsError) loadErrors.push("documentation")

  // Load feedback submitted by user
  const { data: feedbackData, error: feedbackError } = await dataClient
    .from("feedback")
    .select("*")
    .eq("user_id", userId)
    .order("created_at", { ascending: false })
  if (feedbackError) loadErrors.push("feedback")

  const loadError = loadErrors.length > 0 ? "Some profile sections failed to load. Please refresh." : null

  return {
    profile: profileData as UserProfile,
    tasks: allTasks as Task[],
    assets: allAssets as Asset[],
    documentation: (docsData || []) as Documentation[],
    feedback: (feedbackData || []) as Feedback[],
    loadError,
  }
}

export default async function ProfilePage() {
  const data = await getProfileData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  // Type assertion since we've checked for redirect above
  const profileData = data as {
    profile: UserProfile | null
    tasks: Task[]
    assets: Asset[]
    documentation: Documentation[]
    feedback: Feedback[]
    loadError?: string | null
  }

  return (
    <ProfileContent
      profile={profileData.profile}
      tasks={profileData.tasks}
      assets={profileData.assets}
      documentation={profileData.documentation}
      feedback={profileData.feedback}
      initialError={profileData.loadError}
    />
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { ProjectsContent } from "./projects-content"

import { logger } from "@/lib/logger"

const log = logger("projects")


export interface Project {
  id: string
  project_name: string
  location: string
  deployment_start_date: string
  deployment_end_date: string
  capacity_w?: number
  technology_type?: string
  description?: string
  status: string
  created_at: string
  project_manager?: {
    first_name: string
    last_name: string
  }
  created_by_user?: {
    first_name: string
    last_name: string
  }
}

async function getProjectsData() {
  const supabase = await createClient()

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  // Get projects where user is a member, manager, or creator
  const { data: memberProjects, error: memberError } = await supabase
    .from("project_members")
    .select("project_id")
    .eq("user_id", user.id)
    .eq("is_active", true)

  if (memberError) {
    log.error("Error loading member projects:", memberError)
  }

  const projectIds = memberProjects?.map((m) => m.project_id) || []

  const { data, error } = await supabase
    .from("projects")
    .select(
      `
      id,
      project_name,
      location,
      deployment_start_date,
      deployment_end_date,
      capacity_w,
      technology_type,
      description,
      status,
      created_at,
      project_manager:profiles!projects_project_manager_id_fkey (
        first_name,
        last_name
      ),
      created_by_user:profiles!projects_created_by_fkey (
        first_name,
        last_name
      )
    `
    )
    .or(`id.in.(${projectIds.join(",")}),project_manager_id.eq.${user.id},created_by.eq.${user.id}`)
    .order("created_at", { ascending: false })

  if (error) {
    log.error("Error loading projects:", error)
  }

  return {
    projects: (data as any) || [],
  }
}

export default async function ProjectsPage() {
  const data = await getProjectsData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  const projectsData = data as { projects: Project[] }

  return <ProjectsContent initialProjects={projectsData.projects} />
}

"use client"

import { useState, useEffect } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { createClient } from "@/lib/supabase/client"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"
import { toast } from "sonner"
import { fetchWeeklyReportLockState } from "@/lib/weekly-report-lock"
import { FileBarChart } from "lucide-react"
import { AdminTablePage } from "@/components/admin/admin-table-page"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { WeeklyReportDialog } from "@/components/dashboard/reports/weekly-report-dialog"
import { WeeklyReportFilters } from "./_components/weekly-report-filters"
import {
  exportAllToPPTX,
  sortReportsByDepartment,
  type WeeklyPptxMode,
  type WeeklyPptxTheme,
  type WeeklyReport,
} from "@/lib/export-utils"
import { QUERY_KEYS } from "@/lib/query-keys"
import { ReportTable } from "./_components/report-table"
import { PptxModeDialog } from "./_components/pptx-mode-dialog"
import { ReportExportActions } from "./_components/report-export-actions"

interface UserProfile {
  id: string
  department: string | null
  role: string
  is_department_lead: boolean
}

async function fetchProfileAndDepts(supabase: ReturnType<typeof createClient>) {
  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) return { profile: null, allDepartments: [] }

  const { data: p } = await supabase
    .from("profiles")
    .select("id, department, role, is_department_lead")
    .eq("id", user.id)
    .single()

  const { data: depts } = await supabase.from("profiles").select("department").not("department", "is", null)
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const uniqueDepts = Array.from(new Set(depts?.map((d: any) => d.department).filter(Boolean))) as string[]

  return { profile: p as UserProfile | null, allDepartments: uniqueDepts.sort() }
}

async function fetchReports(
  supabase: ReturnType<typeof createClient>,
  profile: UserProfile | null,
  weekFilter: number,
  yearFilter: number,
  deptFilter: string
): Promise<WeeklyReport[]> {
  if (!profile) return []

  let query = supabase
    .from("weekly_reports")
    .select("*, profiles:user_id ( first_name, last_name )")
    .eq("status", "submitted")
    .eq("week_number", weekFilter)
    .eq("year", yearFilter)
    .order("department", { ascending: true })

  const effectiveDept = profile?.is_department_lead ? profile.department || "all" : deptFilter
  if (effectiveDept !== "all") {
    query = query.eq("department", effectiveDept)
  }

  const { data, error } = await query
  if (error) throw new Error(error.message)
  return sortReportsByDepartment(data || [])
}

export default function WeeklyReportsPortal() {
  const currentOfficeWeek = getCurrentOfficeWeek()
  const [searchQuery, setSearchQuery] = useState("")
  const [deptFilter, setDeptFilter] = useState("all")
  const [yearFilter, setYearFilter] = useState(currentOfficeWeek.year)
  const [weekFilter, setWeekFilter] = useState(currentOfficeWeek.week)
  const [isDialogOpen, setIsDialogOpen] = useState(false)
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [selectedReportParams, setSelectedReportParams] = useState<any>(null)
  const [expandedRows, setExpandedRows] = useState<Set<string>>(new Set())
  const [pptxModeDialogOpen, setPptxModeDialogOpen] = useState(false)
  const [pendingPptxExport, setPendingPptxExport] = useState<
    { kind: "single"; report: WeeklyReport } | { kind: "all" } | null
  >(null)
  const [isFilteredWeekLocked, setIsFilteredWeekLocked] = useState(false)
  const [meetingDate, setMeetingDate] = useState<string | undefined>(undefined)
  const [pendingDeleteId, setPendingDeleteId] = useState<string | null>(null)

  const supabase = createClient()
  const queryClient = useQueryClient()

  const { data: profileData } = useQuery({
    queryKey: ["portal-weekly-reports-profile"],
    queryFn: () => fetchProfileAndDepts(supabase),
  })

  const profile = profileData?.profile ?? null
  const allDepartments = profileData?.allDepartments ?? []

  useEffect(() => {
    if (profile?.is_department_lead && profile.department) {
      setDeptFilter(profile.department || "all")
    }
  }, [profile?.id])

  const {
    data: reports = [],
    isLoading: loading,
    refetch: refetchReports,
  } = useQuery({
    queryKey: QUERY_KEYS.weeklyReports({ week: weekFilter, year: yearFilter, dept: deptFilter }),
    queryFn: () => fetchReports(supabase, profile, weekFilter, yearFilter, deptFilter),
    enabled: !!profile,
  })

  useEffect(() => {
    const loadFilteredWeekLock = async () => {
      const state = await fetchWeeklyReportLockState(supabase, weekFilter, yearFilter)
      setIsFilteredWeekLocked(state.isLocked)
      setMeetingDate(state.meetingDate || undefined)
    }
    loadFilteredWeekLock()
  }, [weekFilter, yearFilter])

  const handleDelete = async (id: string) => {
    const target = reports.find((r) => r.id === id)
    if (target) {
      const lock = await fetchWeeklyReportLockState(supabase, target.week_number, target.year)
      if (lock.isLocked) {
        toast.error("This report week is locked. Delete is no longer allowed.")
        return
      }
    }
    try {
      const { error } = await supabase.from("weekly_reports").delete().eq("id", id)
      if (error) throw error
      toast.success("Report deleted")
      queryClient.invalidateQueries({
        queryKey: QUERY_KEYS.weeklyReports({ week: weekFilter, year: yearFilter, dept: deptFilter }),
      })
    } catch {
      toast.error("Failed to delete report")
    }
  }

  const toggleRow = (id: string) => {
    const next = new Set(expandedRows)
    if (next.has(id)) next.delete(id)
    else next.add(id)
    setExpandedRows(next)
  }

  const filteredReports = reports.filter(
    (r) =>
      r.department.toLowerCase().includes(searchQuery.toLowerCase()) ||
      r.work_done?.toLowerCase().includes(searchQuery.toLowerCase())
  )

  const openAllPptxModeDialog = () => {
    setPendingPptxExport({ kind: "all" })
    setPptxModeDialogOpen(true)
  }

  const openSinglePptxModeDialog = (report: WeeklyReport) => {
    setPendingPptxExport({ kind: "single", report })
    setPptxModeDialogOpen(true)
  }

  const runPptxExport = async (mode: WeeklyPptxMode, theme: WeeklyPptxTheme = "light") => {
    if (!pendingPptxExport) return
    if (pendingPptxExport.kind === "all") {
      await exportAllToPPTX(filteredReports, weekFilter, yearFilter, mode, theme, meetingDate)
    } else {
      const { exportToPPTX } = await import("@/lib/export-utils")
      await exportToPPTX(pendingPptxExport.report, mode, theme, meetingDate)
    }
    setPptxModeDialogOpen(false)
    setPendingPptxExport(null)
  }

  const isLead =
    Boolean(profile?.is_department_lead) || ["admin", "super_admin", "developer"].includes(profile?.role || "")

  return (
    <AdminTablePage
      title="Weekly Departmental Reports"
      description="Browse weekly updates and progress from all departments"
      icon={FileBarChart}
      backLinkHref="/reports"
      backLinkLabel="Back to Reports"
      actions={
        <ReportExportActions
          filteredReports={filteredReports}
          weekFilter={weekFilter}
          yearFilter={yearFilter}
          meetingDate={meetingDate}
          isLead={isLead}
          onOpenPptxDialog={openAllPptxModeDialog}
          onSubmitNew={() => {
            setSelectedReportParams({ week: weekFilter, year: yearFilter, dept: profile?.department })
            setIsDialogOpen(true)
          }}
        />
      }
      filters={
        <WeeklyReportFilters
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          weekFilter={weekFilter}
          onWeekChange={setWeekFilter}
          yearFilter={yearFilter}
          onYearChange={setYearFilter}
          deptFilter={deptFilter}
          onDeptChange={setDeptFilter}
          allDepartments={allDepartments}
          isDepartmentLead={Boolean(profile?.is_department_lead)}
          loading={loading}
          onRefresh={() => refetchReports()}
        />
      }
    >
      <ReportTable
        reports={filteredReports}
        loading={loading}
        expandedRows={expandedRows}
        onToggleRow={toggleRow}
        meetingDate={meetingDate}
        isFilteredWeekLocked={isFilteredWeekLocked}
        currentUserDepartment={profile?.department}
        onEdit={(report) => {
          setSelectedReportParams({
            week: report.week_number,
            year: report.year,
            dept: report.department,
          })
          setIsDialogOpen(true)
        }}
        onDelete={(id) => setPendingDeleteId(id)}
        onOpenPptxDialog={openSinglePptxModeDialog}
      />

      <WeeklyReportDialog
        isOpen={isDialogOpen}
        onClose={() => {
          setIsDialogOpen(false)
          setSelectedReportParams(null)
        }}
        onSuccess={() =>
          queryClient.invalidateQueries({
            queryKey: QUERY_KEYS.weeklyReports({ week: weekFilter, year: yearFilter, dept: deptFilter }),
          })
        }
        initialData={selectedReportParams}
      />

      <AlertDialog open={pendingDeleteId !== null} onOpenChange={(open) => !open && setPendingDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Report</AlertDialogTitle>
            <AlertDialogDescription>Are you sure? This action cannot be undone.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                if (pendingDeleteId) handleDelete(pendingDeleteId)
                setPendingDeleteId(null)
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <PptxModeDialog
        isOpen={pptxModeDialogOpen}
        onOpenChange={(open) => {
          setPptxModeDialogOpen(open)
          if (!open) setPendingPptxExport(null)
