import { logger } from "@/lib/logger"

const log = logger("assets-issues")

interface AssetIssue {
  id: string
  asset_id: string
  description: string
  resolved: boolean
  created_at: string
  resolved_at?: string
  resolved_by?: string
  created_by: string
  asset?: {
    unique_code: string
    asset_type: string
    status: string
    assignment_type?: string
    department?: string
    office_location?: string
    current_assignment?: {
      type?: "individual" | "department" | "office"
      department?: string
      office_location?: string
      user?: {
        first_name: string
        last_name: string
      }
    }
  }
  creator?: {
    first_name: string
    last_name: string
  }
  resolver?: {
    first_name: string
    last_name: string
  }
}

async function fetchAssetIssues(): Promise<AssetIssue[]> {
  const supabase = createClient()
  const { data: issuesData, error: issuesError } = await supabase
    .from("asset_issues")
    .select("*")
    .order("created_at", { ascending: false })

  if (issuesError) throw new Error(issuesError.message)

  const issuesWithDetails = await Promise.all(
    (issuesData || []).map(async (issue) => {
      const { data: assetData } = await supabase
        .from("assets")
        .select("unique_code, asset_type, status, assignment_type, department, office_location")
        .eq("id", issue.asset_id)
        .single()

      let assignmentData = null
      if (assetData) {
        const { data: assignment } = await supabase
          .from("asset_assignments")
          .select("assigned_to, department, office_location")
          .eq("asset_id", issue.asset_id)
          .eq("is_current", true)
          .maybeSingle()

        if (assignment) {
          if (assignment.assigned_to) {
            const { data: userData } = await supabase
              .from("profiles")
              .select("first_name, last_name")
              .eq("id", assignment.assigned_to)
              .single()
            assignmentData = {
              type: "individual",
              user: userData,
              department: assignment.department,
              office_location: assignment.office_location,
            }
          } else if (assignment.department) {
            assignmentData = { type: "department", department: assignment.department }
          } else if (assignment.office_location) {
            assignmentData = { type: "office", office_location: assignment.office_location }
          }
        } else if (
          assetData.status === "assigned" ||
          assetData.status === "retired" ||
          assetData.status === "maintenance"
        ) {
          if (assetData.assignment_type === "department" && assetData.department) {
            assignmentData = { type: "department", department: assetData.department }
          } else if (assetData.assignment_type === "office" && assetData.office_location) {
            assignmentData = { type: "office", office_location: assetData.office_location }
          }
        }
      }

      const { data: creatorData } = await supabase
        .from("profiles")
        .select("first_name, last_name")
        .eq("id", issue.created_by)
        .single()

      let resolverData = null
      if (issue.resolved_by) {
        const { data } = await supabase
          .from("profiles")
          .select("first_name, last_name")
          .eq("id", issue.resolved_by)
          .single()
        resolverData = data
      }

      return {
        ...issue,
        asset: { ...assetData, current_assignment: assignmentData },
        creator: creatorData,
        resolver: resolverData,
      }
    })
  )

  return issuesWithDetails as AssetIssue[]
}

export default function AssetIssuesPage() {
  const [searchQuery, setSearchQuery] = useState("")
  const [statusFilter, setStatusFilter] = useState("unresolved")
  const [assetTypeFilter, setAssetTypeFilter] = useState("all")
  const [pendingDeleteId, setPendingDeleteId] = useState<string | null>(null)
  const queryClient = useQueryClient()

  const { data: issues = [], isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.adminAssetIssues(),
    queryFn: fetchAssetIssues,
  })

  const handleToggleResolved = async (issue: AssetIssue) => {
    try {
      const supabase = createClient()
      const { error } = await supabase.from("asset_issues").update({ resolved: !issue.resolved }).eq("id", issue.id)
      if (error) throw error
      toast.success(issue.resolved ? "Issue marked as unresolved" : "Issue marked as resolved")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminAssetIssues() })
    } catch (error: any) {
      log.error("Error toggling issue:", error)
      toast.error("Failed to update issue")
    }
  }

  const handleDeleteIssue = async (issueId: string) => {
    try {
      const supabase = createClient()
      const { error } = await supabase.from("asset_issues").delete().eq("id", issueId)
      if (error) throw error
      toast.success("Issue deleted")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminAssetIssues() })
    } catch (error: any) {
      log.error("Error deleting issue:", error)
      toast.error("Failed to delete issue")
    }
  }

  const filteredIssues = issues.filter((issue) => {
    const matchesSearch =
      searchQuery === "" ||
      issue.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      issue.asset?.unique_code.toLowerCase().includes(searchQuery.toLowerCase())

    const matchesStatus =
      statusFilter === "all" ||
      (statusFilter === "resolved" && issue.resolved) ||
      (statusFilter === "unresolved" && !issue.resolved)

    const matchesAssetType = assetTypeFilter === "all" || issue.asset?.asset_type === assetTypeFilter

    return matchesSearch && matchesStatus && matchesAssetType
  })

  const stats = {
    total: issues.length,
    unresolved: issues.filter((i) => !i.resolved).length,
    resolved: issues.filter((i) => i.resolved).length,
  }

  return (
    <AdminTablePage
      title="Asset Issues"
      description="Track and manage all asset issues across the organization"
      icon={AlertCircle}
      stats={
        <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3 md:gap-4">
          <StatCard title="Total Issues" value={stats.total} icon={AlertCircle} description="All tracked issues" />
          <StatCard
            title="Unresolved Issues"
            value={stats.unresolved}
            icon={AlertCircle}
            iconBgColor="bg-orange-100 dark:bg-orange-900/30"
            iconColor="text-orange-600 dark:text-orange-400"
            description="Requiring attention"
          />
          <StatCard
            title="Resolved Issues"
            value={stats.resolved}
            icon={CheckCircle2}
            iconBgColor="bg-green-100 dark:bg-green-900/30"
            iconColor="text-green-600 dark:text-green-400"
            description="Successfully fixed"
          />
        </div>
      }
      filters={
        <ListToolbar
          search={
            <div className="relative w-full min-w-0 flex-1 sm:max-w-md">
              <Search className="text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2 transform" />
              <Input
                placeholder="Search issues or asset codes..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
          }
          filters={
            <div className="grid w-full grid-cols-1 gap-3 sm:grid-cols-2">
              <SearchableSelect
                value={statusFilter}
                onValueChange={setStatusFilter}
                placeholder="Filter by status"
                searchPlaceholder="Search status..."
                icon={<Filter className="h-4 w-4" />}
                options={[
                  { value: "all", label: "All Issues" },
                  {
                    value: "unresolved",
                    label: "Unresolved",
                    icon: <AlertCircle className="h-3 w-3 text-orange-500" />,
                  },
                  {
                    value: "resolved",
                    label: "Resolved",
                    icon: <CheckCircle2 className="h-3 w-3 text-green-500" />,
                  },
                ]}
              />
              <SearchableSelect
                value={assetTypeFilter}
                onValueChange={setAssetTypeFilter}
                placeholder="All Asset Types"
                searchPlaceholder="Search asset types..."
                icon={<Package className="h-4 w-4" />}
                options={[
                  { value: "all", label: "All Asset Types" },
                  ...Object.entries(ASSET_TYPE_MAP).map(([key, value]) => ({
                    value: key,
                    label: value.label,
                  })),
                ]}
              />
            </div>
          }
        />
      }
    >
      <Card>
        <CardHeader>
          <CardTitle>Issues List ({filteredIssues.length})</CardTitle>
          <CardDescription>
            {statusFilter === "unresolved"
              ? "Showing unresolved issues requiring attention"
              : statusFilter === "resolved"
                ? "Showing resolved issues"
                : "Showing all issues"}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <TableSkeleton rows={5} cols={7} />
          ) : filteredIssues.length === 0 ? (
            <EmptyState
              icon={AlertCircle}
              title="No issues found"
              description={
                searchQuery || statusFilter !== "all" || assetTypeFilter !== "all"
                  ? "No issues match your filters."
                  : "No issues tracked yet."
              }
            />
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="w-[50px]">Status</TableHead>
                    <TableHead>Asset</TableHead>
                    <TableHead>Issue Description</TableHead>
                    <TableHead>Assigned To</TableHead>
                    <TableHead>Reported By</TableHead>
                    <TableHead>Date</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredIssues.map((issue) => (
                    <TableRow
                      key={issue.id}
                      className={
                        issue.resolved ? "bg-green-50/50 dark:bg-green-950/10" : "bg-orange-50/50 dark:bg-orange-950/10"
                      }
                    >
                      <TableCell>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleToggleResolved(issue)}
                          className="h-8 w-8 p-0"
                        >
                          {issue.resolved ? (
                            <CheckCircle2 className="h-5 w-5 text-green-600" />
                          ) : (
                            <div className="h-5 w-5 rounded-full border-2 border-orange-500" />
                          )}
                        </Button>
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-2">
                          <div className="bg-primary/10 rounded p-1.5">
                            <Package className="text-primary h-3 w-3" />
                          </div>
                          <div>
                            <div className="font-mono text-xs font-medium">{issue.asset?.unique_code}</div>
                            <div className="text-muted-foreground text-xs">
                              {ASSET_TYPE_MAP[issue.asset?.asset_type || ""]?.label || issue.asset?.asset_type}
                            </div>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        <div className="max-w-md">
                          <p
                            className={`text-sm ${
                              issue.resolved ? "text-muted-foreground line-through" : "text-foreground"
                            }`}
                          >
                            {issue.description}
                          </p>
                          {issue.resolved && issue.resolved_at && (
                            <div className="mt-1 flex items-center gap-1 text-xs text-green-600">
                              <CheckCircle2 className="h-3 w-3" />
                              <span>
                                Resolved {new Date(issue.resolved_at).toLocaleDateString()}
                                {issue.resolver && (
                                  <span>
                                    {" "}
                                    by {formatName(issue.resolver.first_name)} {formatName(issue.resolver.last_name)}
                                  </span>
                                )}
                              </span>
                            </div>
                          )}
                        </div>
                      </TableCell>
                      <TableCell>
                        {issue.asset?.current_assignment ? (
                          issue.asset.current_assignment.type === "individual" &&
                          issue.asset.current_assignment.user ? (
                            <div className="flex items-center gap-1.5">
                              <User className="text-muted-foreground h-3 w-3" />
                              <span className="text-sm">
                                {formatName(issue.asset.current_assignment.user.first_name)}{" "}
                                {formatName(issue.asset.current_assignment.user.last_name)}
                              </span>
                            </div>
                          ) : issue.asset.current_assignment.type === "department" &&
                            issue.asset.current_assignment.department ? (
                            <div className="flex items-center gap-1.5">
                              <span className="text-sm">{issue.asset.current_assignment.department}</span>
                            </div>
                          ) : issue.asset.current_assignment.type === "office" &&
                            issue.asset.current_assignment.office_location ? (
                            <div className="flex items-center gap-1.5">
                              <span className="text-sm">{issue.asset.current_assignment.office_location}</span>
                            </div>
                          ) : (
                            <span className="text-muted-foreground text-sm">-</span>
                          )
                        ) : (
                          <span className="text-muted-foreground text-sm">Unassigned</span>
                        )}
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-1.5">
                          <User className="text-muted-foreground h-3 w-3" />
                          <span className="text-sm">
                            {issue.creator
                              ? `${formatName(issue.creator.first_name)} ${formatName(issue.creator.last_name)}`
                              : "Unknown"}
                          </span>
                        </div>
                      </TableCell>
                      <TableCell>
                        <div className="text-muted-foreground flex items-center gap-1.5 text-sm">
                          <Calendar className="h-3 w-3" />
                          {new Date(issue.created_at).toLocaleDateString()}
                        </div>
                      </TableCell>
                      <TableCell className="text-right">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setPendingDeleteId(issue.id)}
                          className="text-destructive hover:text-destructive h-8 w-8 p-0"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      <AlertDialog open={pendingDeleteId !== null} onOpenChange={(open) => !open && setPendingDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Issue</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this issue? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                if (pendingDeleteId) handleDeleteIssue(pendingDeleteId)
                setPendingDeleteId(null)
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AdminTablePage>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { AdminAssetsContent, type Asset, type Employee, type UserProfile } from "./admin-assets-content"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"
import { listAssignableProfiles } from "@/lib/workforce/assignment-policy"

import { logger } from "@/lib/logger"

const log = logger("assets")


async function getAdminAssetsData() {
  const supabase = await createClient()

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return { redirect: "/profile" as const }
  }

  const userProfile: UserProfile = {
    role: scope.role,
    admin_domains: scope.adminDomains,
    is_department_lead: scope.isDepartmentLead,
    lead_departments: scope.leadDepartments,
    managed_departments: scope.managedDepartments,
    managed_offices: scope.managedOffices,
  }
  const departmentScope = getDepartmentScope(scope, "general")

  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  // Fetch assets
  let { data: assetsData, error: assetsError } = await dataClient
    .from("assets")
    .select("*")
    .order("created_at", { ascending: false })

  if (assetsError && dataClient !== supabase) {
    // Fall back to user-scoped client if service-role query fails due env/config drift.
    const fallback = await supabase.from("assets").select("*").order("created_at", { ascending: false })
    assetsData = fallback.data
    assetsError = fallback.error
  }

  if (assetsError) {
    log.error("Error loading assets:", assetsError)
    return { assets: [], employees: [], departments: [], userProfile, loadError: "Failed to load admin assets" }
  }

  // Fetch current assignments for all assets
  const { data: assignmentsData } = await dataClient
    .from("asset_assignments")
    .select("asset_id, assigned_to, department, office_location, assignment_type")
    .eq("is_current", true)

  // Fetch user details for assignments
  const assignedUserIds = (assignmentsData || []).map((a: any) => a.assigned_to).filter(Boolean)

  let assignmentUsersMap = new Map()
  if (assignedUserIds.length > 0) {
    const { data: usersData } = await dataClient
      .from("profiles")
      .select("id, first_name, last_name, department")
      .in("id", assignedUserIds)

    assignmentUsersMap = new Map(usersData?.map((u) => [u.id, u]))
  }

  // Fetch employees - leads can only see employees in their departments
  const { data: employeeData } = await listAssignableProfiles(dataClient, {
    select: "id, first_name, last_name, company_email, department, employment_status",
    departmentScope,
    allowLegacyNullStatus: false,
  })
  const employees = (employeeData || []) as Employee[]

  // Fetch unresolved issue counts
  const { data: issuesData } = await dataClient.from("asset_issues").select("asset_id, resolved")

  const issueCountsByAsset: Record<string, number> = {}
  ;(issuesData || []).forEach((issue: any) => {
    if (!issue.resolved) {
      issueCountsByAsset[issue.asset_id] = (issueCountsByAsset[issue.asset_id] || 0) + 1
    }
  })

  // Filter assets for leads
  let filteredAssets = assetsData || []
  if (departmentScope) {
    const deptUserIds = employees.map((s) => s.id)
    filteredAssets = filteredAssets.filter((asset) => {
      const assignment = (assignmentsData || []).find((a: any) => a.asset_id === asset.id)
      if (!assignment) return false

      if (assignment.assigned_to && deptUserIds.includes(assignment.assigned_to)) return true
      if (assignment.department && departmentScope.includes(assignment.department)) return true
      if (assignment.office_location && scope.managedOffices.includes(assignment.office_location)) return true
      return false
    })
  }

  // Combine assets with assignments and issue counts
  const assets: Asset[] = filteredAssets.map((asset) => {
    const assignment = (assignmentsData || []).find((a: any) => a.asset_id === asset.id)
    return {
      ...asset,
      current_assignment: assignment
        ? {
            assigned_to: assignment.assigned_to,
            department: assignment.department,
            office_location: assignment.office_location,
            assignment_type: assignment.assignment_type,
            user: assignment.assigned_to ? assignmentUsersMap.get(assignment.assigned_to) : null,
          }
        : undefined,
      unresolved_issues_count: issueCountsByAsset[asset.id] || 0,
    }
  })

  // Get departments list
  const departments = departmentScope
    ? departmentScope
    : Array.from(new Set(employees.map((s) => s.department).filter(Boolean)))

  return { assets, employees, departments, userProfile, loadError: null }
}

export default async function AdminAssetsPage() {
  const data = await getAdminAssetsData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  const pageData = data as {
    assets: Asset[]
    employees: Employee[]
    departments: string[]
    userProfile: UserProfile
    loadError?: string | null
  }

  return (
    <AdminAssetsContent
      initialAssets={pageData.assets}
      initialEmployees={pageData.employees}
      initialDepartments={pageData.departments}
      userProfile={pageData.userProfile}
      initialError={pageData.loadError}
    />
  )
}

"use client"

import { useMemo, useState } from "react"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { FileText, LayoutGrid, List, ScrollText, Download } from "lucide-react"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { AdminTablePage } from "@/components/admin/admin-table-page"
import { normalizeAuditAction } from "@/lib/audit/core"
import { AuditLogFilters } from "@/components/audit/AuditLogFilters"
import { AuditLogTable } from "@/components/audit/AuditLogTable"
import { AuditLogCard } from "@/components/audit/AuditLogCard"
import { AuditLogDetailPanel } from "@/components/audit/AuditLogDetailPanel"
import { exportAuditLogsToExcel, exportAuditLogsToPDF, exportAuditLogsToWord } from "@/lib/audit/audit-log-export"
import { HIDDEN_ACTIONS } from "@/lib/audit/audit-log-display"
import { logger } from "@/lib/logger"
import type { AuditLog, AuditLogFiltersState, EmployeeMember, UserProfile } from "./types"

// Re-export types consumed by page.tsx
export type { AuditLog, EmployeeMember, UserProfile }

const log = logger("audit-logs")

interface AdminAuditLogsContentProps {
  initialLogs: AuditLog[]
  initialTotalCount: number
  initialemployee: EmployeeMember[]
  initialDepartments: string[]
  userProfile: UserProfile
}

const DEFAULT_FILTERS: AuditLogFiltersState = {
  searchQuery: "",
  actionFilter: "all",
  entityFilter: "all",
  dateFilter: "all",
  departmentFilter: "all",
  employeeFilter: "all",
  customStartDate: "",
  customEndDate: "",
}

export function AdminAuditLogsContent({
  initialLogs,
  initialTotalCount,
  initialemployee,
  initialDepartments,
  userProfile,
}: AdminAuditLogsContentProps) {
  const scopedDepartments = userProfile.managed_departments ?? userProfile.lead_departments ?? []

  const [logs, setLogs] = useState<AuditLog[]>(initialLogs)
  const [totalCount, setTotalCount] = useState<number>(initialTotalCount)
  const [isLoading, setIsLoading] = useState(false)
  const [filters, setFilters] = useState<AuditLogFiltersState>(DEFAULT_FILTERS)
  const [viewMode, setViewMode] = useState<"list" | "card">("list")
  const [selectedLog, setSelectedLog] = useState<AuditLog | null>(null)
  const [isDetailsOpen, setIsDetailsOpen] = useState(false)

  const employee = initialemployee
  const departments = initialDepartments
  const supabase = createClient()

  function handleFilterChange<K extends keyof AuditLogFiltersState>(key: K, value: AuditLogFiltersState[K]) {
    setFilters((prev) => ({ ...prev, [key]: value }))
  }

  // -------------------------------------------------------------------------
  // Client-side refresh (manual only — initial data comes from server props)
  // -------------------------------------------------------------------------
  const loadLogs = async () => {
    setIsLoading(true)
    try {
      const { count } = await supabase
        .from("audit_logs")
        .select("id", { count: "exact", head: true })
        .not("action", "in", '("sync","migrate","update_schema","migration")')

      setTotalCount(count || 0)

      const { data: logsData, error: logsError } = await supabase
        .from("audit_logs")
        .select("*")
        .not("action", "in", '("sync","migrate","update_schema","migration")')
        .order("created_at", { ascending: false })
        .limit(500)

      if (logsError) {
        log.error("Audit logs error details:", logsError)
        if (logsError.message.includes("relation") && logsError.message.includes("does not exist")) {
          toast.error("Audit logs table not found. Please run the database migration first.")
        } else if (logsError.code === "PGRST301" || logsError.message.includes("permission")) {
          toast.error("Permission denied. You may not have access to view audit logs.")
        } else {
          toast.error(`Failed to load audit logs: ${logsError.message}`)
        }
        throw logsError
      }

      if (logsData && logsData.length > 0) {
        const userIdsSet = new Set(logsData.map((l) => l.user_id).filter(Boolean))
        const { data: usersData } = await supabase
          .from("profiles")
          .select("id, first_name, last_name, company_email, employee_number")
          .in("id", Array.from(userIdsSet))

        const usersMap = new Map(usersData?.map((u) => [u.id, u]))

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const mapped = logsData.map((l: any) => {
          const rawAction = l.action || l.operation?.toLowerCase() || "update"
          const action = normalizeAuditAction(rawAction).action
          const entity_type = l.entity_type || l.table_name || "unknown"
          const entity_id = l.record_id || l.entity_id
          const old_values = l.metadata?.old_values || l.old_values
          const new_values = l.metadata?.new_values || l.new_values
          return {
            id: l.id,
            user_id: l.user_id,
            action,
            entity_type,
            entity_id,
            old_values,
            new_values,
            metadata: l.metadata || {},
            created_at: l.created_at,
            user: l.user_id ? usersMap.get(l.user_id) : null,
          }
        })

        setLogs(mapped as AuditLog[])
      } else {
        setLogs([])
      }
    } catch (error) {
      log.error("Error loading audit logs:", error)
      toast.error("Failed to refresh audit logs")
    } finally {
      setIsLoading(false)
    }
  }

  // -------------------------------------------------------------------------
  // Filtered view — pure derivation, no state
  // -------------------------------------------------------------------------
  const filteredLogs = useMemo(() => {
    const {
      searchQuery,
      actionFilter,
      entityFilter,
      dateFilter,
      departmentFilter,
      employeeFilter,
      customStartDate,
      customEndDate,
    } = filters

    return logs.filter((entry) => {
      const action = (entry.action || "unknown").toLowerCase()
      if (HIDDEN_ACTIONS.includes(action as (typeof HIDDEN_ACTIONS)[number])) return false

      const q = searchQuery.toLowerCase()
      const matchesSearch =
        (entry.entity_type || "").toLowerCase().includes(q) ||
        (entry.action || "").toLowerCase().includes(q) ||
        (typeof entry.metadata?.event === "string" ? entry.metadata.event.toLowerCase().includes(q) : false) ||
        (entry.user as { first_name?: string } | undefined)?.first_name?.toLowerCase().includes(q) ||
        (entry.user as { last_name?: string } | undefined)?.last_name?.toLowerCase().includes(q)

      const matchesAction = actionFilter === "all" || entry.action === actionFilter
      const matchesEntity = entityFilter === "all" || entry.entity_type === entityFilter

      let matchesDepartment = true
      if (userProfile?.is_department_lead) {
        if (scopedDepartments.length > 0) {
          const userDept = employee.find((s) => s.id === entry.user_id)?.department
          matchesDepartment = userDept ? scopedDepartments.includes(userDept) : false
        }
      } else {
        matchesDepartment =
          departmentFilter === "all" ||
          (entry.user ? employee.find((s) => s.id === entry.user_id)?.department === departmentFilter : false)
      }

      const matchesEmployee = employeeFilter === "all" || entry.user_id === employeeFilter

      let matchesDate = true
      if (dateFilter !== "all") {
        const logDate = new Date(entry.created_at)
        const now = new Date()
        const daysDiff = Math.floor((now.getTime() - logDate.getTime()) / (1000 * 60 * 60 * 24))
        switch (dateFilter) {
          case "today":
            matchesDate = daysDiff === 0
            break
          case "week":
            matchesDate = daysDiff <= 7
            break
          case "month":
            matchesDate = daysDiff <= 30
            break
          case "custom":
            if (customStartDate && customEndDate) {
              const start = new Date(customStartDate)
              const end = new Date(customEndDate)
              end.setHours(23, 59, 59, 999)
              matchesDate = logDate >= start && logDate <= end
            } else if (customStartDate) {
              matchesDate = logDate >= new Date(customStartDate)
            } else if (customEndDate) {
              const end = new Date(customEndDate)
              end.setHours(23, 59, 59, 999)
              matchesDate = logDate <= end
            }
            break
        }
      }

      return matchesSearch && matchesAction && matchesEntity && matchesDate && matchesDepartment && matchesEmployee
    })
  }, [logs, filters, userProfile, employee, scopedDepartments])

  const stats = useMemo(
    () => ({
      total: totalCount,
      creates: logs.filter((l) => l.action === "create").length,
      updates: logs.filter((l) => l.action === "update").length,
      deletes: logs.filter((l) => l.action === "delete").length,
    }),
    [logs, totalCount]
  )

  return (
    <AdminTablePage
      title="Audit Logs"
      description="Complete audit trail of all system activities"
      icon={ScrollText}
      actions={
        <div className="flex items-center rounded-lg border p-1">
          <Button
            variant={viewMode === "list" ? "default" : "ghost"}
            size="sm"
            onClick={() => setViewMode("list")}
            className="gap-1 sm:gap-2"
          >
            <List className="h-4 w-4" />
            <span className="hidden sm:inline">List</span>
          </Button>
          <Button
            variant={viewMode === "card" ? "default" : "ghost"}
            size="sm"
            onClick={() => setViewMode("card")}
            className="gap-1 sm:gap-2"
          >
            <LayoutGrid className="h-4 w-4" />
            <span className="hidden sm:inline">Card</span>
          </Button>
        </div>
      }
      stats={
        <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-4 md:gap-4">
          {[
            { label: "Total Actions", value: stats.total, color: "blue" },
            { label: "Creates", value: stats.creates, color: "green" },
            { label: "Updates", value: stats.updates, color: "blue" },
            { label: "Deletes", value: stats.deletes, color: "red" },
          ].map(({ label, value, color }) => (
            <Card key={label} className="border-2">
              <CardContent className="p-3 sm:p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-muted-foreground text-sm font-medium">{label}</p>
                    <p className="text-foreground mt-1 text-lg font-bold sm:mt-2 sm:text-3xl">{value}</p>
                  </div>
                  <div className={`rounded-lg bg-${color}-100 p-3 dark:bg-${color}-900/30`}>
                    <ScrollText className={`h-6 w-6 text-${color}-600 dark:text-${color}-400`} />
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      }
      filters={
        <AuditLogFilters
          filters={filters}
          onFilterChange={handleFilterChange}
          employee={employee}
          departments={departments}
          userProfile={userProfile}
          scopedDepartments={scopedDepartments}
        />
      }
      filtersInCard={false}
    >
      {/* Export bar */}
      <Card className="border-2">
        <CardContent className="p-4">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div className="flex items-center gap-2">
              <Download className="text-muted-foreground h-4 w-4" />
              <span className="text-foreground text-sm font-medium">Export Filtered Data:</span>
            </div>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={() => exportAuditLogsToExcel(filteredLogs)}
                className="gap-2"
                disabled={filteredLogs.length === 0 || isLoading}
              >
                <FileText className="h-4 w-4" />
                Excel (.xlsx)
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => exportAuditLogsToPDF(filteredLogs)}
                className="gap-2"
                disabled={filteredLogs.length === 0 || isLoading}
              >
                <FileText className="h-4 w-4" />
                PDF
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => exportAuditLogsToWord(filteredLogs)}
                className="gap-2"
                disabled={filteredLogs.length === 0 || isLoading}
              >
                <FileText className="h-4 w-4" />
                Word (.docx)
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Log list or cards */}
      {filteredLogs.length > 0 ? (
        viewMode === "list" ? (
          <AuditLogTable
            logs={filteredLogs}
            onViewDetails={(l) => {
              setSelectedLog(l)
              setIsDetailsOpen(true)
            }}
          />
        ) : (
          <div className="space-y-3">
            {filteredLogs.map((l) => (
              <AuditLogCard
                key={l.id}
                log={l}
                onViewDetails={(entry) => {
                  setSelectedLog(entry)
                  setIsDetailsOpen(true)
                }}
              />
            ))}
          </div>
        )
      ) : (
        <Card className="border-2">
          <CardContent className="p-12 text-center">
            <ScrollText className="text-muted-foreground mx-auto mb-4 h-16 w-16" />
            <h3 className="text-foreground mb-2 text-xl font-semibold">No Audit Logs Found</h3>
            <p className="text-muted-foreground">
              {Object.entries(filters).some(
                ([k, v]) => k !== "customStartDate" && k !== "customEndDate" && v !== "all" && v !== ""
              )
                ? "No logs match your filters"
                : "No audit logs available yet"}
            </p>
          </CardContent>
        </Card>
      )}

      {/* Pagination */}
      {filteredLogs.length > 0 && (
        <div className="text-muted-foreground text-center text-sm">
          Showing {filteredLogs.length} of {totalCount} total logs
          {totalCount > logs.length && ` (limited to last ${logs.length} entries)`}
        </div>
      )}

      {/* Detail dialog */}
      <AuditLogDetailPanel log={selectedLog} open={isDetailsOpen} onClose={() => setIsDetailsOpen(false)} />
    </AdminTablePage>
  )

  // expose for manual refresh button if needed
  void loadLogs
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { CommunicationsComposer } from "@/app/admin/communications/_components/communications-composer"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"
import { resolveAdminScope } from "@/lib/admin/rbac"

export default async function CommunicationsBroadcastPage() {
  const supabase = await createClient()

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    redirect("/auth/login")
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("role, full_name, department, company_email, additional_email")
    .eq("id", user.id)
    .single()

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!profile || !scope) {
    redirect("/admin")
  }

  const { data: employees } = await applyAssignableStatusFilter(
    supabase
      .from("profiles")
      .select("id, full_name, company_email, additional_email, department, employment_status")
      .or("company_email.not.is.null,additional_email.not.is.null")
      .order("full_name"),
    { allowLegacyNullStatus: false }
  )

  return (
    <CommunicationsComposer
      employees={employees || []}
      mode="communications"
      currentUser={{
        id: user.id,
        full_name: profile?.full_name || null,
        department: profile?.department || null,
        email: profile?.company_email || profile?.additional_email || user.email || null,
      }}
    />
  )
}

"use client"

import { useMemo, useState } from "react"
import { toast } from "sonner"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { ChevronDown, ChevronUp } from "lucide-react"
import type { CorrespondenceRecord } from "@/types/correspondence"

interface EmployeeOption {
  id: string
  first_name: string | null
  last_name: string | null
  department: string | null
  role: string | null
}

interface DepartmentCodeOption {
  department_name: string
  department_code: string
  is_active: boolean
}

interface AdminCorrespondenceContentProps {
  initialRecords: CorrespondenceRecord[]
  employees: EmployeeOption[]
  departmentCodes: DepartmentCodeOption[]
}

export function AdminCorrespondenceContent({
  initialRecords,
  employees,
  departmentCodes,
}: AdminCorrespondenceContentProps) {
  const [records, setRecords] = useState<CorrespondenceRecord[]>(initialRecords)
  const [loadingRecordId, setLoadingRecordId] = useState<string | null>(null)
  const [assignments, setAssignments] = useState<Record<string, string>>({})
  const [statusFilter, setStatusFilter] = useState<string>("all")
  const [codeForm, setCodeForm] = useState({ department_name: "", department_code: "" })
  const [showMappings, setShowMappings] = useState(false)

  const filteredRecords = useMemo(() => {
    if (statusFilter === "all") return records
    return records.filter((record) => record.status === statusFilter)
  }, [records, statusFilter])

  const stats = useMemo(() => {
    return {
      total: records.length,
      underReview: records.filter((r) => r.status === "under_review").length,
      awaitingAction: records.filter((r) => r.status === "assigned_action_pending").length,
      approved: records.filter((r) => r.status === "approved").length,
      finalized: records.filter((r) => ["sent", "filed", "closed"].includes(r.status)).length,
    }
  }, [records])

  async function refresh() {
    const res = await fetch("/api/correspondence/records", { cache: "no-store" })
    const json = await res.json()
    setRecords(json.data || [])
  }

  async function assignOfficer(recordId: string) {
    const responsibleOfficerId = assignments[recordId]
    if (!responsibleOfficerId) {
      toast.error("Select an officer first")
      return
    }

    setLoadingRecordId(recordId)
    try {
      const res = await fetch(`/api/correspondence/records/${recordId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          responsible_officer_id: responsibleOfficerId,
          status: "assigned_action_pending",
        }),
      })

      const body = await res.json()
      if (!res.ok) {
        throw new Error(body.error || "Failed to assign officer")
      }

      toast.success("Responsible officer assigned")
      await refresh()
    } catch (error: any) {
      toast.error(error.message || "Failed to assign officer")
    } finally {
      setLoadingRecordId(null)
    }
  }

  async function decide(recordId: string, decision: "approved" | "rejected" | "returned_for_correction") {
    setLoadingRecordId(recordId)
    try {
      const res = await fetch(`/api/correspondence/records/${recordId}/approvals`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ decision }),
      })

      const body = await res.json()
      if (!res.ok) {
        throw new Error(body.error || "Failed to apply decision")
      }

      toast.success(`Record ${decision.replaceAll("_", " ")}`)
      await refresh()
    } catch (error: any) {
      toast.error(error.message || "Failed to apply decision")
    } finally {
      setLoadingRecordId(null)
    }
  }

  async function dispatch(recordId: string, finalStatus: "sent" | "filed") {
    setLoadingRecordId(recordId)
    try {
      const res = await fetch(`/api/correspondence/records/${recordId}/dispatch`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          final_status: finalStatus,
          dispatch_method: "email",
        }),
      })

      const body = await res.json()
      if (!res.ok) {
        throw new Error(body.error || "Failed to finalize dispatch")
      }

      toast.success(`Record marked ${finalStatus}`)
      await refresh()
    } catch (error: any) {
      toast.error(error.message || "Failed to finalize dispatch")
    } finally {
      setLoadingRecordId(null)
    }
  }

  async function updateDepartmentCode(e: React.FormEvent) {
    e.preventDefault()
    if (!codeForm.department_name.trim() || !codeForm.department_code.trim()) {
      toast.error("Department name and code are required")
      return
    }

    try {
      const res = await fetch("/api/correspondence/department-codes", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          department_name: codeForm.department_name.trim(),
          department_code: codeForm.department_code.trim().toUpperCase(),
          is_active: true,
        }),
      })

      const body = await res.json()
      if (!res.ok) {
        throw new Error(body.error || "Failed to update department code")
      }

      toast.success("Department code updated")
      setCodeForm({ department_name: "", department_code: "" })
    } catch (error: any) {
      toast.error(error.message || "Failed to update department code")
    }
  }

  return (
    <div className="space-y-6 p-6">
      <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-5 md:gap-4">
        <Card>
          <CardHeader>
            <CardTitle className="text-sm">Total</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-lg font-bold sm:text-2xl">{stats.total}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-sm">Under Review</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-lg font-bold sm:text-2xl">{stats.underReview}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-sm">Assigned Action</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-lg font-bold sm:text-2xl">{stats.awaitingAction}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-sm">Approved</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-lg font-bold sm:text-2xl">{stats.approved}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-sm">Finalized</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-lg font-bold sm:text-2xl">{stats.finalized}</p>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Department Code Management</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <form onSubmit={updateDepartmentCode} className="grid gap-4 md:grid-cols-3">
            <div className="space-y-2">
              <Label>Department Name</Label>
              <Input
                value={codeForm.department_name}
                onChange={(e) => setCodeForm((prev) => ({ ...prev, department_name: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label>Department Code</Label>
              <Input
                value={codeForm.department_code}
                onChange={(e) => setCodeForm((prev) => ({ ...prev, department_code: e.target.value }))}
              />
            </div>
            <div className="flex items-end">
              <Button type="submit">Save Code</Button>
            </div>
          </form>

          <div className="space-y-3">
            <Button
              type="button"
              variant="ghost"
              className="text-muted-foreground h-8 px-0 text-sm"
              onClick={() => setShowMappings((prev) => !prev)}
            >
              Active mappings: {departmentCodes.filter((item) => item.is_active).length}
              {showMappings ? <ChevronUp className="ml-2 h-4 w-4" /> : <ChevronDown className="ml-2 h-4 w-4" />}
            </Button>

            {showMappings && (
              <div className="rounded-md border">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Department</TableHead>
                      <TableHead>Code</TableHead>
                      <TableHead>Status</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {departmentCodes.map((item) => (
                      <TableRow key={item.department_name}>
                        <TableCell className="font-medium">{item.department_name}</TableCell>
                        <TableCell>{item.department_code}</TableCell>
                        <TableCell>
                          <Badge variant={item.is_active ? "default" : "outline"}>
                            {item.is_active ? "Active" : "Inactive"}
                          </Badge>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>Reference Generator Queue</CardTitle>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[220px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All statuses</SelectItem>
              <SelectItem value="draft">Draft</SelectItem>
              <SelectItem value="under_review">Under review</SelectItem>
              <SelectItem value="approved">Approved</SelectItem>
              <SelectItem value="rejected">Rejected</SelectItem>
              <SelectItem value="returned_for_correction">Returned for correction</SelectItem>
              <SelectItem value="assigned_action_pending">Assigned action pending</SelectItem>
              <SelectItem value="open">Open</SelectItem>
              <SelectItem value="sent">Sent</SelectItem>
              <SelectItem value="filed">Filed</SelectItem>
            </SelectContent>
          </Select>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Reference</TableHead>
                <TableHead>Direction</TableHead>
                <TableHead>Department</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Officer</TableHead>
                <TableHead>Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredRecords.map((record) => (
                <TableRow key={record.id}>
                  <TableCell>
                    <div className="font-medium">{record.reference_number}</div>
                    <div className="text-muted-foreground text-xs">{record.subject}</div>
                  </TableCell>
                  <TableCell>
                    <Badge variant="outline">{record.direction}</Badge>
                  </TableCell>
                  <TableCell>{record.department_name || record.assigned_department_name || "-"}</TableCell>
                  <TableCell>
                    <Badge>{record.status}</Badge>
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-2">
                      <Select
                        value={assignments[record.id] || ""}
                        onValueChange={(value) => setAssignments((prev) => ({ ...prev, [record.id]: value }))}
                      >
                        <SelectTrigger className="w-[220px]">
                          <SelectValue placeholder="Assign officer" />
                        </SelectTrigger>
                        <SelectContent>
                          {employees
                            .filter((employee) => {
                              const dept = record.department_name || record.assigned_department_name
                              if (!dept) return true
                              return !employee.department || employee.department === dept
                            })
                            .map((employee) => (
                              <SelectItem key={employee.id} value={employee.id}>
                                {(employee.first_name || "") + " " + (employee.last_name || "")}
                              </SelectItem>
                            ))}
                        </SelectContent>
                      </Select>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => assignOfficer(record.id)}
                        disabled={loadingRecordId === record.id}
                      >
                        Assign
                      </Button>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="flex flex-wrap gap-2">
                      {record.status === "under_review" && (
                        <>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => decide(record.id, "approved")}
                            disabled={loadingRecordId === record.id}
                          >
                            Approve
                          </Button>
                          <Button
                            size="sm"
                            variant="destructive"
                            onClick={() => decide(record.id, "rejected")}
                            disabled={loadingRecordId === record.id}
                          >
                            Reject
                          </Button>
                          <Button
                            size="sm"
                            variant="secondary"
                            onClick={() => decide(record.id, "returned_for_correction")}
                            disabled={loadingRecordId === record.id}
                          >
                            Return
                          </Button>
                        </>
                      )}
                      {record.status === "approved" && (
                        <>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => dispatch(record.id, "sent")}
                            disabled={loadingRecordId === record.id}
                          >
                            Mark Sent
                          </Button>
                          <Button
                            size="sm"
                            variant="secondary"
                            onClick={() => dispatch(record.id, "filed")}
                            disabled={loadingRecordId === record.id}
                          >
                            Mark Filed
                          </Button>
                        </>
                      )}
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  )
}

import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { PageHeader, PageWrapper } from "@/components/layout"
import { AlertTriangle, Bug, ShieldAlert } from "lucide-react"
import { StatCard } from "@/components/ui/stat-card"
import { EmptyState, ErrorState } from "@/components/ui/patterns"
import { UiErrorsContent, type UiErrorRow } from "./ui-errors-content"

import { logger } from "@/lib/logger"

const log = logger("dev-ui-errors")


export default async function DevUiErrorsPage() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const { data: logs, error } = await dataClient
    .from("audit_logs")
    .select("id, created_at, error_details, metadata, user_id")
    .eq("action", "client_error")
    .eq("entity_type", "ui_runtime")
    .order("created_at", { ascending: false })
    .limit(500)

  if (error) {
    log.error("Error loading UI telemetry logs:", error)
  }

  const userIds = Array.from(new Set((logs || []).map((l: any) => l.user_id).filter(Boolean)))
  let usersMap = new Map<string, { first_name?: string; last_name?: string; company_email?: string }>()

  if (userIds.length > 0) {
    const { data: users } = await dataClient
      .from("profiles")
      .select("id, first_name, last_name, company_email")
      .in("id", userIds)
    usersMap = new Map((users || []).map((u: any) => [u.id, u]))
  }

  const rows: UiErrorRow[] = (logs || []).map((log: any) => {
    const meta = log.metadata && typeof log.metadata === "object" ? log.metadata : {}
    const source = String((meta as any).source || "unknown")
    const route = String((meta as any).route || (meta as any).href || "")
    const user = log.user_id ? usersMap.get(log.user_id) : null
    const userName =
      user?.first_name && user?.last_name
        ? `${user.first_name} ${user.last_name}`
        : user?.company_email || (log.user_id ? "Authenticated User" : "Anonymous")

    return {
      id: log.id,
      created_at: log.created_at,
      message: String(log.error_details || "Unknown error"),
      source,
      route,
      user_name: userName,
    }
  })

  const stats = {
    total: rows.length,
    last24h: rows.filter((r) => new Date(r.created_at).getTime() > Date.now() - 24 * 60 * 60 * 1000).length,
    boundaries: rows.filter((r) => r.source.includes("error_boundary")).length,
  }

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title="UI Error Monitor"
        description="Centralized frontend runtime errors captured from all pages during beta"
        icon={Bug}
        backLink={{ href: "/admin/dev", label: "Back to DEV" }}
      />

      <div className="mb-6 grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3 md:gap-4">
        <StatCard title="Total Captured" value={stats.total} icon={Bug} />
        <StatCard title="Last 24h" value={stats.last24h} icon={AlertTriangle} />
        <StatCard title="Boundary Catches" value={stats.boundaries} icon={ShieldAlert} />
      </div>

      {error ? (
        <ErrorState
          title="Failed to load logs from backend storage"
          description="Check server logs and verify audit log access configuration."
          className="mb-6"
        />
      ) : null}

      {rows.length === 0 ? (
        <EmptyState
          title="No UI errors captured yet"
          description="Client runtime errors will appear here once telemetry events are recorded."
          icon={AlertTriangle}
        />
      ) : (
        <UiErrorsContent rows={rows} />
      )}
    </PageWrapper>
  )
}

import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"
import { resolveOneDriveAccessScope } from "@/lib/onedrive/access"
import type { Documentation, UserProfile, employeeMember } from "./admin-documentation-content"

import { logger } from "@/lib/logger"

const log = logger("documentation-data")


export async function getAdminDocumentationData() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return { redirect: "/profile" as const }
  }
  const departmentScope = getDepartmentScope(scope, "general")

  const userProfile: UserProfile = {
    role: scope.role as any,
    lead_departments: scope.leadDepartments,
    managed_departments: scope.managedDepartments,
  }

  let documentation: Documentation[] = []
  let employee: employeeMember[] = []

  let docsQuery = dataClient.from("user_documentation").select("*").order("created_at", { ascending: false })

  if (departmentScope) {
    const { data: deptUsers } =
      departmentScope.length > 0
        ? await dataClient.from("profiles").select("id").in("department", departmentScope)
        : { data: [] as { id: string }[] }

    const userIds = deptUsers?.map((u) => u.id) || []
    if (userIds.length > 0) {
      docsQuery = docsQuery.in("user_id", userIds)
    } else {
      return {
        documentation: [],
        employee: [],
        userProfile,
        departmentDocs: { initialPath: "/Projects", rootLabel: "Projects", enabled: false, lockToInitialPath: false },
      }
    }
  }

  const { data: docsData, error: docsError } = await docsQuery

  if (docsError) {
    log.error("Documentation error:", docsError)
    return {
      documentation: [],
      employee: [],
      userProfile,
      departmentDocs: { initialPath: "/Projects", rootLabel: "Projects", enabled: false, lockToInitialPath: false },
    }
  }

  if (docsData && docsData.length > 0) {
    const userIdsSet = new Set(docsData.map((doc) => doc.user_id).filter(Boolean))
    const uniqueUserIds = Array.from(userIdsSet)

    const { data: usersData } = await dataClient
      .from("profiles")
      .select("id, first_name, last_name, company_email, department, role")
      .in("id", uniqueUserIds)

    const usersMap = new Map(usersData?.map((profile) => [profile.id, profile]))

    documentation = docsData.map((doc) => ({
      ...doc,
      user: doc.user_id ? usersMap.get(doc.user_id) : undefined,
    })) as Documentation[]
  }

  let employeeQuery = dataClient
    .from("profiles")
    .select("id, first_name, last_name, department")
    .order("last_name", { ascending: true })
  if (departmentScope) {
    employeeQuery =
      departmentScope.length > 0 ? employeeQuery.in("department", departmentScope) : employeeQuery.eq("id", "__none__")
  }
  const { data: employeeData } = await employeeQuery

  employee = employeeData || []
  const oneDriveScope = await resolveOneDriveAccessScope(supabase as any, user.id)

  return {
    documentation,
    employee,
    userProfile,
    departmentDocs: oneDriveScope
      ? {
          initialPath: oneDriveScope.defaultPath,
          rootLabel: oneDriveScope.rootLabel,
          enabled: true,
          lockToInitialPath: !oneDriveScope.isAdminLike,
        }
      : {
          initialPath: "/Projects",
          rootLabel: "Projects",
          enabled: false,
          lockToInitialPath: false,
        },
  }
}

