interface AdminPaymentPageData {
  payment: Payment
  departments: Department[]
  categories: Category[]
}

async function fetchAdminPaymentPageData(id: string): Promise<AdminPaymentPageData> {
  const [paymentRes, deptRes, catRes] = await Promise.all([
    fetch(`/api/payments/${id}`),
    fetch("/api/departments"),
    fetch("/api/payments/categories"),
  ])
  const paymentJson = paymentRes.ok ? await paymentRes.json() : null
  const deptJson = deptRes.ok ? await deptRes.json() : null
  const catJson = catRes.ok ? await catRes.json() : null
  if (!paymentJson?.data) throw new Error("Failed to load payment")
  return {
    payment: paymentJson.data,
    departments: deptJson?.data || [],
    categories: catJson?.data || [],
  }
}

export default function PaymentDetailsPage({ params }: { params: { id: string } }) {
  const router = useRouter()
  const queryClient = useQueryClient()

  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false)
  const [deleteLoading, setDeleteLoading] = useState(false)

  // Upload State
  const [uploadDialogOpen, setUploadDialogOpen] = useState(false)
  const [uploadDate, setUploadDate] = useState<Date | null>(null)
  const [uploadType, setUploadType] = useState<"invoice" | "receipt">("invoice")
  const [uploading, setUploading] = useState(false)
  const [replaceDocumentId, setReplaceDocumentId] = useState<string | null>(null)

  // Edit State
  const [editDialogOpen, setEditDialogOpen] = useState(false)
  const [printDialogOpen, setPrintDialogOpen] = useState(false)
  const [updating, setUpdating] = useState(false)
  const [editFormData, setEditFormData] = useState<PaymentEditFormData>({
    department_id: "",
    payment_type: "",
    category: "",
    title: "",
    description: "",
    amount: "",
    currency: "NGN",
    recurrence_period: "monthly",
    next_payment_due: "",
    payment_date: "",
    issuer_name: "",
    issuer_phone_number: "",
    issuer_address: "",
    payment_reference: "",
    notes: "",
  })

  const { data: pageData, isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.adminPaymentDetail(params.id),
    queryFn: () => fetchAdminPaymentPageData(params.id),
  })

  const payment = pageData?.payment ?? null
  const departments = pageData?.departments ?? []
  const categories = pageData?.categories ?? []

  const schedule = usePaymentSchedule(payment)

  const downloadFile = async (url: string, filename: string) => {
    try {
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch file")

      const blob = await response.blob()
      const blobUrl = window.URL.createObjectURL(blob)
      const link = document.createElement("a")
      link.href = blobUrl
      link.download = filename
      link.style.display = "none"
      document.body.appendChild(link)
      link.click()

      setTimeout(() => {
        document.body.removeChild(link)
        window.URL.revokeObjectURL(blobUrl)
      }, 100)
    } catch (error) {
      log.error("Error downloading file:", error)
      throw error
    }
  }

  const handleViewDocument = async (e: React.MouseEvent, doc?: PaymentDocument) => {
    e.preventDefault()
    if (!doc) return

    try {
      const supabase = createClient()
      const { data, error } = await supabase.storage.from("payment_documents").createSignedUrl(doc.file_path, 3600)
      if (data?.signedUrl) {
        const filename = doc.file_name || doc.file_path.split("/").pop() || "document.pdf"
        await downloadFile(data.signedUrl, filename)
        toast.success("Document downloaded successfully")
      } else {
        toast.error("Could not get secure document URL")
        if (error) log.error("Error signing URL:", error)
      }
    } catch (error) {
      log.error("Error downloading document:", error)
      toast.error("Error downloading document")
    }
  }

  const handleEditClick = () => {
    if (!payment) return
    setEditFormData({
      department_id: payment.department_id,
      payment_type: "",
      category: payment.category as "one-time" | "recurring",
      title: payment.title,
      description: payment.description || "",
      amount: payment.amount.toString(),
      currency: payment.currency,
      recurrence_period: payment.recurrence_period || "monthly",
      next_payment_due: payment.next_payment_due ? format(parseISO(payment.next_payment_due), "yyyy-MM-dd") : "",
      payment_date: payment.payment_date ? format(parseISO(payment.payment_date), "yyyy-MM-dd") : "",
      issuer_name: payment.issuer_name || "",
      issuer_phone_number: payment.issuer_phone_number || "",
      issuer_address: payment.issuer_address || "",
      payment_reference: payment.payment_reference || "",
      notes: payment.notes || "",
    })
    setEditDialogOpen(true)
  }

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault()

    if (!editFormData.issuer_name || !editFormData.issuer_phone_number) {
      toast.error("Issuer Name and Phone are required.")
      return
    }

    try {
      setUpdating(true)
      const payload = {
        ...editFormData,
        amount: parseFloat(editFormData.amount),
        next_payment_due: editFormData.next_payment_due || null,
        payment_date: editFormData.payment_date || null,
      }

      const response = await fetch(`/api/payments/${params.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      })

      if (response.ok) {
        toast.success("Payment updated successfully")
        setEditDialogOpen(false)
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminPaymentDetail(params.id) })
      } else {
        const data = await response.json()
        toast.error(data.error || "Failed to update payment")
      }
    } catch (error) {
      toast.error("Error updating payment")
    } finally {
      setUpdating(false)
    }
  }

  const handleDelete = async () => {
    try {
      setDeleteLoading(true)
      const response = await fetch(`/api/payments/${params.id}`, { method: "DELETE" })

      if (response.ok) {
        toast.success("Payment deleted successfully")
        router.push("/admin/finance/payments")
      } else {
        const data = await response.json()
        toast.error(data.error || "Failed to delete payment")
      }
    } catch (error) {
      toast.error("Error deleting payment")
    } finally {
      setDeleteLoading(false)
      setDeleteDialogOpen(false)
    }
  }

  const markAsPaid = async (targetDate?: Date) => {
    if (!payment) return

    const dateToPay = targetDate instanceof Date ? targetDate : parseISO(payment.next_payment_due!)

    if (payment.payment_type === "recurring" && payment.next_payment_due && payment.recurrence_period) {
      const dateStr = format(dateToPay, "yyyy-MM-dd")
      const hasReceipt = payment.documents?.some((d) => d.applicable_date === dateStr && d.document_type === "receipt")

      if (!hasReceipt) {
        toast.error("Please upload a payment receipt first.", {
          action: { label: "Upload", onClick: () => handleUploadClick(dateToPay, "receipt") },
          duration: 5000,
        })
        handleUploadClick(dateToPay, "receipt")
        return
      }

      const currentDue = parseISO(payment.next_payment_due)
      let nextDue: Date
      switch (payment.recurrence_period) {
        case "monthly":
          nextDue = addMonths(currentDue, 1)
          break
        case "quarterly":
          nextDue = addQuarters(currentDue, 1)
          break
        case "yearly":
          nextDue = addYears(currentDue, 1)
          break
        default:
          nextDue = addMonths(currentDue, 1)
      }

      try {
        const response = await fetch(`/api/payments/${params.id}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            next_payment_due: format(nextDue, "yyyy-MM-dd"),
            last_payment_date: format(dateToPay, "yyyy-MM-dd"),
            status: "due",
            amount_paid: (payment.amount_paid || 0) + payment.amount,
          }),
        })

        if (response.ok) {
          toast.success("Payment recorded! Schedule advanced.")
          queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminPaymentDetail(params.id) })
        } else {
          toast.error("Failed to update payment")
        }
      } catch (error) {
        toast.error("Error processing payment")
      }
    } else {
      updateStatus("paid")
    }
  }

  const updateStatus = async (newStatus: string) => {
    if (!payment) return
    try {
      const response = await fetch(`/api/payments/${params.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          status: newStatus,
          amount_paid: newStatus === "paid" ? payment.amount : newStatus === "due" ? 0 : payment.amount_paid,
        }),
      })

      if (response.ok) {
        toast.success(`Payment marked as ${newStatus}`)
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminPaymentDetail(params.id) })
      } else {
        toast.error("Failed to update status")
      }
    } catch (error) {
      toast.error("Error updating status")
    }
  }

  const handleUploadClick = (date: Date, type: "invoice" | "receipt") => {
    setUploadDate(date)
    setUploadType(type)
    setReplaceDocumentId(null)
    setUploadDialogOpen(true)
  }

  const handleReplaceClick = (date: Date, type: "invoice" | "receipt", docId: string) => {
    setUploadDate(date)
    setUploadType(type)
    setReplaceDocumentId(docId)
    setUploadDialogOpen(true)
  }

  const handleFileUpload = async (e: React.FormEvent, inputRef: React.RefObject<HTMLInputElement>) => {
    e.preventDefault()
    if (!inputRef.current?.files?.[0] || !uploadDate) return

    const file = inputRef.current.files[0]
    const formData = new FormData()
    formData.append("file", file)
    formData.append("document_type", uploadType)
    formData.append("applicable_date", format(uploadDate, "yyyy-MM-dd"))

    if (replaceDocumentId) {
      formData.append("replace_document_id", replaceDocumentId)
    }

    setUploading(true)
    try {
      const response = await fetch(`/api/payments/${params.id}/documents`, { method: "POST", body: formData })

      if (response.ok) {
        toast.success(replaceDocumentId ? `${uploadType} replaced successfully` : `${uploadType} uploaded successfully`)
        setUploadDialogOpen(false)
        setReplaceDocumentId(null)
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminPaymentDetail(params.id) })
      } else {
        const data = await response.json()
        toast.error(data.error || "Upload failed")
      }
    } catch (error) {
      toast.error("Error uploading file")
    } finally {
      setUploading(false)
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "paid":
        return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400"
      case "due":
        return "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400"
      case "overdue":
        return "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400"
      case "cancelled":
        return "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400"
      default:
        return ""
    }
  }

  const formatCurrency = (amount: number, currency: string = "NGN") => {
    return new Intl.NumberFormat("en-NG", { style: "currency", currency }).format(amount)
  }

  const getRealStatus = (p: Payment): "due" | "paid" | "overdue" | "cancelled" => {
    if (p.status === "paid" || p.status === "cancelled") return p.status

    const dateStr = p.payment_type === "recurring" ? p.next_payment_due : p.payment_date
    if (!dateStr) return "due"

    const date = parseISO(dateStr)
    if (!isValid(date)) return "due"

    const today = startOfDay(new Date())
    const daysDiff = differenceInDays(date, today)

    if (isBefore(date, today)) return "overdue"
    if (daysDiff <= 7) return "due"
    return "paid"
  }

  if (loading) return <PageLoader />

  if (!payment) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center gap-4">
        <p className="text-muted-foreground">Payment not found</p>
        <Link href="/admin/finance/payments">
          <Button variant="outline">Back to Payments</Button>
        </Link>
      </div>
    )
  }

  const realStatus = getRealStatus(payment)

  const hasReceiptForMark = (() => {
    if (payment.payment_type === "one-time") {
      return payment.documents?.some((d) => d.document_type === "receipt") ?? false
    } else if (payment.next_payment_due) {
      const dateStr = format(parseISO(payment.next_payment_due), "yyyy-MM-dd")
      return payment.documents?.some((d) => d.applicable_date === dateStr && d.document_type === "receipt") ?? false
    }
    return false
  })()

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title={payment.title}
        description={
          payment.payment_type === "recurring"
            ? `Repeats ${payment.recurrence_period}`
            : `One-time payment on ${payment.payment_date ? format(parseISO(payment.payment_date), "PPP") : "N/A"}`
        }
        icon={CreditCard}
        backLink={{ href: "/admin/finance/payments", label: "Back to Payments" }}
        actions={
          <div className="flex flex-wrap items-center gap-2">
            <Badge className={getStatusColor(realStatus)}>{realStatus}</Badge>
            {payment.payment_type === "recurring" && payment.next_payment_due && (
              <Badge
                variant="outline"
                className="border-primary/20 text-primary bg-primary/5 border-2 px-2 py-0.5 text-sm font-medium"
              >
                Next Due: {format(parseISO(payment.next_payment_due), "MMM d, yyyy")}
              </Badge>
            )}
            {(realStatus === "due" || realStatus === "overdue") && hasReceiptForMark && (
              <Button onClick={() => markAsPaid()}>
                <CheckCircle className="mr-2 h-4 w-4" />
                {payment.payment_type === "recurring" ? "Mark Current Due as Paid" : "Mark as Paid"}
              </Button>
            )}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="icon">
                  <MoreVertical className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem onClick={handleEditClick}>
                  <Edit className="mr-2 h-4 w-4" />
                  Edit Payment
                </DropdownMenuItem>
                <DropdownMenuItem onClick={() => setPrintDialogOpen(true)}>
                  <Printer className="mr-2 h-4 w-4" />
                  Print Receipt
                </DropdownMenuItem>
                <DropdownMenuItem className="text-red-600 focus:text-red-600" onClick={() => setDeleteDialogOpen(true)}>
                  <Trash2 className="mr-2 h-4 w-4" />
                  Delete Payment
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        }
      />

      <div className="mx-auto max-w-5xl space-y-6">
        <div className="grid gap-6 md:grid-cols-3">
          <div className="space-y-6 md:col-span-2">
            {payment.payment_type === "recurring" && (
              <>
                <Card>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <Calendar className="h-5 w-5" />
                      Upcoming Schedule
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <ScheduleList
                      items={schedule.filter((i) => i.status !== "paid")}
                      onUpload={handleUploadClick}
                      onView={handleViewDocument}
                      onMarkPaid={markAsPaid}
                      onReplace={handleReplaceClick}
                    />
                  </CardContent>
                </Card>

                {schedule.some((i) => i.status === "paid") && (
                  <Card className="mt-6">
                    <CardHeader>
                      <CardTitle className="flex items-center gap-2">
                        <FileText className="h-5 w-5" />
                        Payment History
                      </CardTitle>
                    </CardHeader>
                    <CardContent>
                      <ScheduleList
                        items={schedule.filter((i) => i.status === "paid")}
                        onUpload={handleUploadClick}
                        onView={handleViewDocument}
                        onReplace={handleReplaceClick}
                      />
                    </CardContent>
                  </Card>
                )}
              </>
            )}

            <PaymentInfoCard payment={payment} formatCurrency={formatCurrency} />
          </div>

          <div className="space-y-6">
            <PaymentMetaCard payment={payment} />
          </div>
        </div>
      </div>

      <PaymentEditDialog
        open={editDialogOpen}
        onOpenChange={setEditDialogOpen}
        formData={editFormData}
        onFormDataChange={setEditFormData}
        onSubmit={handleUpdate}
        updating={updating}
        departments={departments}
        categories={categories}
        showPaymentTypeField={false}
      />

      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
            <AlertDialogDescription>
              This action cannot be undone. This will permanently delete the payment record and remove it from our
              servers.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction className="bg-red-600 hover:bg-red-700" onClick={handleDelete} disabled={deleteLoading}>
              {deleteLoading ? "Deleting..." : "Delete"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <PaymentUploadDialog
        open={uploadDialogOpen}
        onOpenChange={(open) => {
          setUploadDialogOpen(open)
          if (!open) setReplaceDocumentId(null)
        }}
        uploadDate={uploadDate}
        uploadType={uploadType}
        uploading={uploading}
        replaceDocumentId={replaceDocumentId}
        onSubmit={handleFileUpload}
      />

      <PrintReceiptDialog
        open={printDialogOpen}
        onOpenChange={setPrintDialogOpen}
        schedule={schedule}
        onViewDocument={handleViewDocument}
      />
    </PageWrapper>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { PaymentsTable } from "@/components/payments/payments-table"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"

import { logger } from "@/lib/logger"

const log = logger("finance-payments")


interface Payment {
  id: string
  department_id: string
  title: string
  amount: number
  currency: string
  status: "due" | "paid" | "overdue" | "cancelled"
  payment_type: "one-time" | "recurring"
  recurrence_period?: "monthly" | "quarterly" | "yearly"
  next_payment_due?: string
  payment_date?: string
  category: string
  description?: string
  issuer_name?: string
  issuer_phone_number?: string
  issuer_address?: string
  payment_reference?: string
  amount_paid?: number
  created_at: string
  department?: {
    name: string
  }
  documents?: {
    id: string
    document_type: string
    file_path: string
    file_name?: string
    applicable_date?: string
  }[]
}

interface Department {
  id: string
  name: string
}

interface Category {
  id: string
  name: string
}

async function getPaymentsData() {
  const supabase = await createClient()

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return { redirect: "/profile" as const }
  }
  const dataClient = getServiceRoleClientOrFallback(supabase as any)
  const departmentScope = getDepartmentScope(scope, "finance")

  let paymentsQuery = dataClient
    .from("department_payments")
    .select(
      `
      *,
      department:departments(name),
      documents:payment_documents(id, document_type, file_path, file_name, applicable_date)
    `
    )
    .order("created_at", { ascending: false })

  if (departmentScope) {
    const { data: scopedDepartments } = await dataClient.from("departments").select("id").in("name", departmentScope)
    const departmentIds = (scopedDepartments || []).map((dept) => dept.id)
    paymentsQuery =
      departmentIds.length > 0 ? paymentsQuery.in("department_id", departmentIds) : paymentsQuery.eq("id", "__none__")
  }

  const { data: payments, error: paymentsError } = await paymentsQuery

  if (paymentsError) {
    log.error("Error loading payments:", paymentsError)
  }

  let departmentsQuery = dataClient.from("departments").select("id, name").order("name")
  if (departmentScope) {
    departmentsQuery =
      departmentScope.length > 0 ? departmentsQuery.in("name", departmentScope) : departmentsQuery.eq("id", "__none__")
  }
  const { data: departments } = await departmentsQuery

  // Fetch categories
  const { data: categories } = await dataClient.from("payment_categories").select("id, name").order("name")

  return {
    payments: (payments || []) as Payment[],
    departments: (departments || []) as Department[],
    categories: (categories || []) as Category[],
    currentUser: {
      id: user.id,
      department_id: null, // Admin doesn't have a specific department filter
      isAdmin: true,
    },
  }
}

export default async function AdminPaymentsPage() {
  const data = await getPaymentsData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  const paymentsData = data as {
    payments: Payment[]
    departments: Department[]
    categories: Category[]
    currentUser: { id: string; department_id: string | null; isAdmin: boolean }
  }

  return (
    <PaymentsTable
      initialPayments={paymentsData.payments}
      initialDepartments={paymentsData.departments}
      initialCategories={paymentsData.categories}
      currentUser={paymentsData.currentUser}
      basePath="/admin/finance/payments"
    />
  )
}

"use client"

import { useState } from "react"
import { useQuery } from "@tanstack/react-query"
import { createClient } from "@/lib/supabase/client"
import { QUERY_KEYS } from "@/lib/query-keys"
import { AdminTablePage } from "@/components/admin/admin-table-page"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { StatCard } from "@/components/ui/stat-card"
import { EmptyState } from "@/components/ui/patterns"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { TrendingUp, TrendingDown, DollarSign, Calendar, BarChart3 } from "lucide-react"
import { PageLoader } from "@/components/ui/query-states"

import { logger } from "@/lib/logger"

const log = logger("finance-reports")

interface ReportData {
  totalRevenue: number
  totalExpenses: number
  netIncome: number
  paymentsByMonth: { month: string; amount: number }[]
  paymentsByCategory: { category: string; amount: number }[]
}

async function fetchFinanceReportData(): Promise<ReportData> {
  const supabase = createClient()

  const { data: payments, error } = await supabase
    .from("department_payments")
    .select("*")
    .order("created_at", { ascending: false })

  if (error) {
    if (error.code === "42P01") {
      return { totalRevenue: 0, totalExpenses: 0, netIncome: 0, paymentsByMonth: [], paymentsByCategory: [] }
    }
    throw new Error(error.message)
  }

  const allPayments = payments || []

  const totalExpenses = allPayments.reduce((sum, p) => sum + (p.amount || 0), 0)

  const categoryMap = new Map<string, number>()
  allPayments.forEach((p) => {
    const cat = p.category || "Other"
    categoryMap.set(cat, (categoryMap.get(cat) || 0) + (p.amount || 0))
  })
  const paymentsByCategory = Array.from(categoryMap.entries())
    .map(([category, amount]) => ({ category, amount }))
    .sort((a, b) => b.amount - a.amount)
    .slice(0, 10)

  const monthMap = new Map<string, number>()
  allPayments.forEach((p) => {
    const date = new Date(p.created_at)
    const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`
    monthMap.set(monthKey, (monthMap.get(monthKey) || 0) + (p.amount || 0))
  })
  const paymentsByMonth = Array.from(monthMap.entries())
    .map(([month, amount]) => ({ month, amount }))
    .sort((a, b) => a.month.localeCompare(b.month))
    .slice(-12)

  return {
    totalRevenue: 0, // Would come from invoices
    totalExpenses,
    netIncome: -totalExpenses, // Simplified
    paymentsByMonth,
    paymentsByCategory,
  }
}

export default function FinanceReportsPage() {
  const [period, setPeriod] = useState("year")

  const { data, isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.adminFinanceReports(),
    queryFn: fetchFinanceReportData,
  })

  const reportData = data ?? {
    totalRevenue: 0,
    totalExpenses: 0,
    netIncome: 0,
    paymentsByMonth: [],
    paymentsByCategory: [],
  }

  function formatCurrency(amount: number) {
    return new Intl.NumberFormat("en-NG", {
      style: "currency",
      currency: "NGN",
    }).format(amount)
  }

  function formatMonth(monthStr: string) {
    const [year, month] = monthStr.split("-")
    const date = new Date(parseInt(year), parseInt(month) - 1)
    return date.toLocaleDateString("en-NG", { month: "short", year: "numeric" })
  }

  return (
    <AdminTablePage
      title="Financial Reports"
      description="Analytics and insights for your finances"
      icon={BarChart3}
      backLinkHref="/admin/finance"
      backLinkLabel="Back to Finance"
      actions={
        <Select value={period} onValueChange={setPeriod}>
          <SelectTrigger className="w-[180px]">
            <Calendar className="mr-2 h-4 w-4" />
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="month">This Month</SelectItem>
            <SelectItem value="quarter">This Quarter</SelectItem>
            <SelectItem value="year">This Year</SelectItem>
            <SelectItem value="all">All Time</SelectItem>
          </SelectContent>
        </Select>
      }
      stats={
        <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3 md:gap-4">
          <StatCard
            title="Total Revenue"
            value={formatCurrency(reportData.totalRevenue)}
            icon={TrendingUp}
            iconBgColor="bg-green-100 dark:bg-green-900/30"
            iconColor="text-green-600 dark:text-green-400"
            description="From invoices"
          />
          <StatCard
            title="Total Expenses"
            value={formatCurrency(reportData.totalExpenses)}
            icon={TrendingDown}
            iconBgColor="bg-red-100 dark:bg-red-900/30"
            iconColor="text-red-600 dark:text-red-400"
            description="From payments & bills"
          />
          <StatCard
            title="Net Income"
            value={formatCurrency(reportData.netIncome)}
            icon={DollarSign}
            iconBgColor={
              reportData.netIncome >= 0 ? "bg-green-100 dark:bg-green-900/30" : "bg-red-100 dark:bg-red-900/30"
            }
            iconColor={
              reportData.netIncome >= 0 ? "text-green-600 dark:text-green-400" : "text-red-600 dark:text-red-400"
            }
            description="Revenue - Expenses"
          />
        </div>
      }
    >
      {loading ? (
        <PageLoader />
      ) : (
        <>
          {/* Charts/Tables */}
          <div className="grid gap-6 lg:grid-cols-2">
            {/* Expenses by Month */}
            <Card>
              <CardHeader>
                <CardTitle>Expenses by Month</CardTitle>
                <CardDescription>Monthly payment trends</CardDescription>
              </CardHeader>
              <CardContent>
                {reportData.paymentsByMonth.length === 0 ? (
                  <EmptyState
                    title="No data available"
                    description="No monthly expense data was found for this period."
                  />
                ) : (
                  <div className="space-y-4">
                    {reportData.paymentsByMonth.map((item) => (
                      <div key={item.month} className="flex items-center justify-between">
                        <span className="text-sm">{formatMonth(item.month)}</span>
                        <div className="flex items-center gap-4">
                          <div className="bg-muted h-2 w-32 overflow-hidden rounded-full">
                            <div
                              className="bg-primary h-full rounded-full"
                              style={{
                                width: `${Math.min(100, (item.amount / Math.max(...reportData.paymentsByMonth.map((m) => m.amount))) * 100)}%`,
                              }}
                            />
                          </div>
                          <span className="w-32 text-right text-sm font-medium">{formatCurrency(item.amount)}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Expenses by Category */}
            <Card>
              <CardHeader>
                <CardTitle>Expenses by Category</CardTitle>
                <CardDescription>Where your money goes</CardDescription>
              </CardHeader>
              <CardContent>
                {reportData.paymentsByCategory.length === 0 ? (
                  <EmptyState
                    title="No data available"
                    description="No category expense data was found for this period."
                  />
                ) : (
                  <div className="space-y-4">
                    {reportData.paymentsByCategory.map((item) => (
                      <div key={item.category} className="flex items-center justify-between">
                        <span className="text-sm">{item.category}</span>
                        <div className="flex items-center gap-4">
                          <div className="bg-muted h-2 w-32 overflow-hidden rounded-full">
                            <div
                              className="h-full rounded-full bg-blue-500"
                              style={{
                                width: `${(item.amount / reportData.totalExpenses) * 100}%`,
                              }}
                            />
                          </div>
                          <span className="w-32 text-right text-sm font-medium">{formatCurrency(item.amount)}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </>
      )}
    </AdminTablePage>
  )
}

"use client"

import { Fragment, useState } from "react"
