const log = logger("hr-employees-admin-employee-content")

async function fetchAllEmployees(): Promise<Employee[]> {
  const supabase = createClient()
  const { data, error } = await supabase.from("profiles").select("*").order("last_name", { ascending: true })
  if (error) throw new Error(error.message)
  return data || []
}

export interface Employee {
  id: string
  employee_number: string | null
  first_name: string
  last_name: string
  other_names: string | null
  company_email: string
  additional_email: string | null
  department: string
  company_role: string | null
  role: UserRole
  admin_domains?: string[] | null
  phone_number: string | null
  additional_phone: string | null
  residential_address: string | null
  office_location: string | null
  bank_name: string | null
  bank_account_number: string | null
  bank_account_name: string | null
  date_of_birth: string | null
  employment_date: string | null
  is_admin: boolean
  is_department_lead: boolean
  lead_departments: string[]
  employment_status: EmploymentStatus
  created_at: string
}

export interface UserProfile {
  role: UserRole
  is_department_lead?: boolean
  managed_departments?: string[]
}

interface AdminEmployeeContentProps {
  initialEmployees: Employee[]
  userProfile: UserProfile
}

export function AdminEmployeeContent({ initialEmployees, userProfile }: AdminEmployeeContentProps) {
  const { departments: DEPARTMENTS } = useDepartments()
  const searchParams = useSearchParams()
  const [employees, setEmployees] = useState<Employee[]>(initialEmployees)
  const [isLoading, setIsLoading] = useState(false)
  const [searchQuery, setSearchQuery] = useState("")
  const [departmentFilter, setDepartmentFilter] = useState<string[]>([])
  const [employeeFilter, setEmployeeFilter] = useState<string[]>([])
  const [roleFilter, setRoleFilter] = useState<string[]>([])
  const [statusFilter, setStatusFilter] = useState<string[]>(["active", "suspended", "on_leave"])
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: "asc" | "desc" }>({
    key: "last_name",
    direction: "asc",
  })
  const [viewMode, setViewMode] = useState<"list" | "card">("list")
  const [selectedEmployee, setSelectedEmployee] = useState<Employee | null>(null)
  const [isSaving, setIsSaving] = useState(false)

  const [isViewDialogOpen, setIsViewDialogOpen] = useState(false)
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false)
  const [isDeleting, setIsDeleting] = useState(false)
  const [assignedItems, setAssignedItems] = useState<{
    tasks: any[]
    taskAssignments: any[]
    assets: any[]
    projects: any[]
    projectMemberships: any[]
    feedback: any[]
    documentation: any[]
  }>({
    tasks: [],
    taskAssignments: [],
    assets: [],
    projects: [],
    projectMemberships: [],
    feedback: [],
    documentation: [],
  })
  const [modalViewMode, setModalViewMode] = useState<"profile" | "employment" | "edit" | "signature" | "status">(
    "profile"
  )

  // Export dialog state
  const [exportEmployeeDialogOpen, setExportEmployeeDialogOpen] = useState(false)
  const [exportType, setExportType] = useState<"excel" | "pdf" | "word" | null>(null)
  const [selectedColumns, setSelectedColumns] = useState<Record<string, boolean>>({
    "#": true,
    "Employee No.": true,
    "Last Name": true,
    "First Name": true,
    "Other Names": true,
    Email: true,
    "Additional Email": true,
    Department: true,
    Role: true,
    Position: true,
    "Phone Number": true,
    "Residential Address": true,
    "Office Location": true,
    "Employment Date": true,
    "Lead Departments": true,
    "Created At": true,
  })
  const [viewEmployeeProfile, setViewEmployeeProfile] = useState<any>(null)
  const [viewEmployeeData, setViewEmployeeData] = useState<{
    tasks: any[]
    assets: any[]
    documentation: any[]
  }>({ tasks: [], assets: [], documentation: [] })
  const [isCreateUserDialogOpen, setIsCreateUserDialogOpen] = useState(false)
  const [isCreatingUser, setIsCreatingUser] = useState(false)
  const [createUserForm, setCreateUserForm] = useState({
    firstName: "",
    lastName: "",
    otherNames: "",
    email: "",
    department: "",
    companyRole: "",
    phoneNumber: "",
    role: "employee" as UserRole,
    admin_domains: [] as string[],
    employeeNumber: "",
  })

  // Form states
  const [editForm, setEditForm] = useState({
    role: "employee" as UserRole,
    admin_domains: [] as string[],
    is_department_lead: false,
    department: "",
    office_location: "",
    company_role: "",
    lead_departments: [] as string[],
    // Expanded fields
    employee_number: "",
    first_name: "",
    last_name: "",
    other_names: "",
    company_email: "",
    additional_email: "",
    phone_number: "",
    additional_phone: "",
    residential_address: "",
    bank_name: "",
    bank_account_number: "",
    bank_account_name: "",
    date_of_birth: "",
    employment_date: "",
    job_description: "",
  })
  const [showMoreOptions, setShowMoreOptions] = useState(false)

  const supabase = createClient()
  const queryClient = useQueryClient()
  const canManageUsers = ["developer", "super_admin", "admin"].includes(userProfile?.role || "")

  const { data: fetchedEmployees } = useQuery({
    queryKey: QUERY_KEYS.adminEmployees(),
    queryFn: fetchAllEmployees,
    initialData: initialEmployees,
  })

  // Keep employees state in sync with query result
  useEffect(() => {
    if (fetchedEmployees) setEmployees(fetchedEmployees)
  }, [fetchedEmployees])

  // Handle userId from search params (for edit dialog)
  useEffect(() => {
    const userId = searchParams?.get("userId")
    if (userId && employees.length > 0 && !isViewDialogOpen) {
      const user = employees.find((s) => s.id === userId)
      if (user) {
        handleEditEmployee(user)
      }
    }
  }, [searchParams, employees, isViewDialogOpen])

  const loadData = () => {
    queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminEmployees() })
  }

  const handleEditEmployee = async (employee: Employee) => {
    if (!canManageUsers) {
      toast.error("You can view users but cannot edit them")
      return
    }

    try {
      setSelectedEmployee(employee)

      // Load full profile data to get all fields
      const { data: fullProfile } = await supabase.from("profiles").select("*").eq("id", employee.id).single()

      if (fullProfile) {
        setEditForm({
          role: fullProfile.role || "employee",
          admin_domains: Array.isArray(fullProfile.admin_domains) ? fullProfile.admin_domains : [],
          is_department_lead: Boolean(fullProfile.is_department_lead),
          department: fullProfile.department || "",
          office_location: fullProfile.office_location || "",
          company_role: fullProfile.company_role || "",
          lead_departments: fullProfile.lead_departments || [],
          // Expanded fields
          employee_number: fullProfile.employee_number || "",
          first_name: fullProfile.first_name || "",
          last_name: fullProfile.last_name || "",
          other_names: fullProfile.other_names || "",
          company_email: fullProfile.company_email || "",
          additional_email: fullProfile.additional_email || "",
          phone_number: fullProfile.phone_number || "",
          additional_phone: fullProfile.additional_phone || "",
          residential_address: fullProfile.residential_address || "",
          bank_name: fullProfile.bank_name || "",
          bank_account_number: fullProfile.bank_account_number || "",
          bank_account_name: fullProfile.bank_account_name || "",
          date_of_birth: fullProfile.date_of_birth || "",
          employment_date: fullProfile.employment_date || "",
          job_description: fullProfile.job_description || "",
        })
      } else {
        // Fallback to basic fields if full profile not found
        setEditForm({
          role: employee.role,
          admin_domains: Array.isArray(employee.admin_domains) ? employee.admin_domains : [],
          is_department_lead: Boolean(employee.is_department_lead),
          department: employee.department,
          office_location: employee.office_location || "",
          company_role: employee.company_role || "",
          lead_departments: employee.lead_departments || [],
          employee_number: employee.employee_number || "",
          first_name: employee.first_name || "",
          last_name: employee.last_name || "",
          other_names: employee.other_names || "",
          company_email: employee.company_email || "",
          additional_email: employee.additional_email || "",
          phone_number: employee.phone_number || "",
          additional_phone: "",
          residential_address: employee.residential_address || "",
          bank_name: "",
          bank_account_number: "",
          bank_account_name: "",
          date_of_birth: "",
          employment_date: "",
          job_description: "",
        })
      }

      setShowMoreOptions(false) // Reset expanded state

      // Set profile states so the unified modal has data
      setSelectedEmployee(employee)
      setViewEmployeeProfile(employee as any)
      setModalViewMode("edit")
      setIsViewDialogOpen(true)
    } catch (error: any) {
      log.error({ err: String(error) }, "error loading employees for edit")
      toast.error("Failed to load employees details")
    }
  }

  const handleViewEmployeeSignature = async (employee: Employee) => {
    try {
      setSelectedEmployee(employee)

      setModalViewMode("signature")
      setIsViewDialogOpen(true)
      setViewEmployeeProfile(employee as any)

      // Load full profile data for signature
      const { data: profileData } = await supabase.from("profiles").select("*").eq("id", employee.id).single()

      if (profileData) {
        const fullProfile = profileData as any
        setSelectedEmployee(fullProfile)
        // If we're in view dialog, update the viewEmployeeProfile too
        if (isViewDialogOpen) {
          setViewEmployeeProfile(fullProfile)
        }
      }
    } catch (error: any) {
      log.error({ err: String(error) }, "error loading profile for signature")
      toast.error("Failed to load profile data")
    }
  }

  const handleViewEmployeeDetails = async (employee: Employee) => {
    try {
      setSelectedEmployee(employee)
      setModalViewMode("profile") // Always reset to profile when opening fresh
      // Clear stale profile immediately so the modal never shows the previous
      // employee's data while the new fetch is in flight.
      setViewEmployeeProfile(null)
      setViewEmployeeData({ tasks: [], assets: [], documentation: [] })
      setIsViewDialogOpen(true)

      const response = await fetch(`/api/admin/hr/employees/${employee.id}/overview`, { cache: "no-store" })
      const payload = (await response.json().catch(() => ({}))) as {
        error?: string
        profile?: any
        related?: { tasks?: any[]; assets?: any[]; documentation?: any[] }
      }

      if (!response.ok) throw new Error(payload.error || "Failed to load employee details")
      if (!payload.profile) throw new Error("Employee profile not found")

      setViewEmployeeProfile(payload.profile)
      setViewEmployeeData({
        tasks: payload.related?.tasks || [],
        assets: payload.related?.assets || [],
        documentation: payload.related?.documentation || [],
      })
    } catch (error: any) {
      log.error({ err: String(error) }, "error loading employee details")
      toast.error("Failed to load employees details")
    }
  }

  const checkAssignedItems = async (employee: Employee) => {
    try {
      const [
        tasksResult,
        taskAssignmentsResult,
        assetsResult,
        projectsResult,
        projectMembersResult,
        feedbackResult,
        docsResult,
      ] = await Promise.all([
        // Tasks assigned to this user
        supabase.from("tasks").select("id, title, status").eq("assigned_to", employee.id),
        // Task assignments (multiple user assignments)
        supabase
          .from("task_assignments")
          .select("id, task_id, Task:tasks(id, title, status)")
          .eq("user_id", employee.id),
        // Current asset assignments
        supabase
          .from("asset_assignments")
          .select("id, Asset:assets(id, asset_name, asset_type, unique_code, serial_number)")
          .eq("assigned_to", employee.id)
          .eq("is_current", true),
        // Projects managed or created by this user
        supabase
          .from("projects")
          .select("id, project_name, status")
          .or(`project_manager_id.eq.${employee.id},created_by.eq.${employee.id}`),
        // Active project memberships
        supabase
          .from("project_members")
          .select("id, Project:projects(id, project_name)")
          .eq("user_id", employee.id)
          .eq("is_active", true),
        // Feedback submitted by this user
        supabase.from("feedback").select("id, title, status").eq("user_id", employee.id),
        // User documentation
        supabase.from("user_documentation").select("id, title").eq("user_id", employee.id),
      ])

      const assigned = {
        tasks: tasksResult.data || [],
        taskAssignments: taskAssignmentsResult.data || [],
        assets: assetsResult.data || [],
        projects: projectsResult.data || [],
        projectMemberships: projectMembersResult.data || [],
        feedback: feedbackResult.data || [],
        documentation: docsResult.data || [],
      }

      setAssignedItems(assigned)
      return assigned
    } catch (error: any) {
      log.error({ err: String(error) }, "error checking assigned items")
      toast.error("Failed to check assigned items")
      return null
    }
  }

  const handleDeleteEmployee = async (employee: Employee) => {
    setSelectedEmployee(employee)
    toast.error("User deletion is disabled. Suspend or deactivate the employee instead.")
  }

  const confirmDeleteEmployee = async () => {
    if (!selectedEmployee) return
    toast.error("User deletion is disabled. Suspend or deactivate the employee instead.")
    setIsDeleteDialogOpen(false)
  }

  const handleSaveEmployee = async () => {
    if (isSaving) return // Prevent duplicate submissions
    setIsSaving(true)
    try {
      if (!canManageUsers) {
        toast.error("You can view users but cannot edit them")
        setIsSaving(false)
        return
      }

      if (!selectedEmployee) {
        setIsSaving(false)
        return
      }

      const {
        data: { user },
      } = await supabase.auth.getUser()

      if (user && selectedEmployee.id === user.id && editForm.role !== selectedEmployee.role) {
        toast.error("You cannot change your own role from the HR employee editor")
        setIsSaving(false)
        return
      }

      // Check if user can assign this role
      if (userProfile && !canAssignRoles(userProfile.role, editForm.role)) {
        toast.error("You don't have permission to assign this role")
        setIsSaving(false)
        return
      }

      if (editForm.role === "developer" && !canManageDeveloperAccounts(userProfile?.role || "")) {
        toast.error("Only super admin or developer can assign the developer role")
        setIsSaving(false)
        return
      }

      if (selectedEmployee.role === "developer" && !canManageDeveloperAccounts(userProfile?.role || "")) {
        toast.error("Only super admin or developer can modify a developer account")
        setIsSaving(false)
        return
      }

      if (selectedEmployee.role === "developer" && editForm.role !== "developer") {
        const { count, error: developerCountError } = await supabase
          .from("profiles")
          .select("id", { count: "exact", head: true })
          .eq("role", "developer")

        if (developerCountError) throw developerCountError

        if ((count || 0) <= 1) {
          toast.error("Cannot downgrade the last developer account")
          setIsSaving(false)
          return
        }
      }

      if (
        (selectedEmployee.role === "super_admin" || editForm.role === "super_admin") &&
        !canManageSuperAdminAccounts(userProfile?.role || "")
      ) {
        toast.error("Only super admin can manage super admin accounts")
        setIsSaving(false)
        return
      }

      if (selectedEmployee.role === "super_admin" && editForm.role !== "super_admin") {
        const { count, error: superAdminCountError } = await supabase
          .from("profiles")
          .select("id", { count: "exact", head: true })
          .eq("role", "super_admin")

        if (superAdminCountError) throw superAdminCountError

        if ((count || 0) <= 1) {
          toast.error("Cannot downgrade the last super admin account")
          setIsSaving(false)
          return
        }
      }

      const trimmedAdditionalEmail = editForm.additional_email.trim()
      if (trimmedAdditionalEmail && !formValidation.isEmail(trimmedAdditionalEmail)) {
        toast.error("Additional email must be a valid email address")
        setIsSaving(false)
        return
      }

      if (editForm.is_department_lead && editForm.lead_departments.length !== 1) {
        toast.error("A department lead must have exactly one lead department")
        setIsSaving(false)
        return
      }

      if (editForm.is_department_lead && editForm.lead_departments[0] !== editForm.department) {
        toast.error("A department lead can only lead their own department")
        setIsSaving(false)
        return
      }
      if (editForm.role === "admin" && editForm.admin_domains.length === 0) {
        toast.error("Admin role requires at least one admin domain")
        setIsSaving(false)
        return
      }

      const isLead = editForm.is_department_lead

      // Build update object with all fields
      const updateData: any = {
        role: editForm.role,
        admin_domains: editForm.role === "admin" ? editForm.admin_domains : null,
        department: editForm.department,
        office_location: editForm.office_location || null,
        company_role: editForm.company_role || null,
        is_department_lead: isLead,
        lead_departments: isLead ? editForm.lead_departments : [],
        updated_at: new Date().toISOString(),
        // Always include expanded fields if they exist in form state
        first_name: editForm.first_name || null,
        last_name: editForm.last_name || null,
        other_names: editForm.other_names || null,
        additional_email: trimmedAdditionalEmail || null,
        phone_number: editForm.phone_number || null,
        additional_phone: editForm.additional_phone || null,
        residential_address: editForm.residential_address || null,
        bank_name: editForm.bank_name || null,
        bank_account_number: editForm.bank_account_number || null,
        bank_account_name: editForm.bank_account_name || null,
        date_of_birth: editForm.date_of_birth || null,
        employment_date: editForm.employment_date || null,
        job_description: editForm.job_description || null,
      }

      const { error } = await supabase.from("profiles").update(updateData).eq("id", selectedEmployee.id)

      if (error) throw error

      toast.success("Employee updated successfully")

      // If we're in the unified view modal, switch back to profile mode and refresh data
      if (isViewDialogOpen) {
        setModalViewMode("profile")
        // Refresh the viewEmployeeProfile to show updated data immediately
        const { data: updatedProfile } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", selectedEmployee.id)
          .single()

        if (updatedProfile) {
          setViewEmployeeProfile(updatedProfile as any)
        }
      }

      loadData()
    } catch (error: any) {
      log.error({ err: String(error) }, "error updating employee")
      toast.error(error?.message || "Failed to update employees member")
    } finally {
      setIsSaving(false)
    }
  }

  const handleCreateUser = async () => {
    if (isCreatingUser) return
    setIsCreatingUser(true)

    try {
      if (!canManageUsers) {
        toast.error("You can view users but cannot create users")
        setIsCreatingUser(false)
        return
      }

      // Validate required fields
      if (!createUserForm.firstName.trim() || !createUserForm.lastName.trim() || !createUserForm.email.trim()) {
        toast.error("First name, last name, and email are required")
        setIsCreatingUser(false)
        return
      }

      // Validate email domain
      if (!formValidation.isCompanyEmail(createUserForm.email)) {
        toast.error("Only @acoblighting.com and @org.acoblighting.com emails are allowed")
        setIsCreatingUser(false)
        return
      }

      // Validate employee number (required and format check)
      if (!createUserForm.employeeNumber.trim()) {
        toast.error("Employee number is required")
        setIsCreatingUser(false)
        return
      }

      // Validate employee number format: ACOB/YEAR/NUMBER (e.g., ACOB/2026/058)
      const empNumPattern = /^ACOB\/[0-9]{4}\/[0-9]{3}$/
      if (!empNumPattern.test(createUserForm.employeeNumber.trim())) {
        toast.error("Employee number must be in format: ACOB/YEAR/NUMBER (e.g., ACOB/2026/058)")
        setIsCreatingUser(false)
        return
      }

      // Check if user can assign this role
      if (userProfile && !canAssignRoles(userProfile.role, createUserForm.role)) {
        toast.error("You don't have permission to assign this role")
        setIsCreatingUser(false)
        return
      }
      if (createUserForm.role === "admin" && createUserForm.admin_domains.length === 0) {
        toast.error("Admin role requires at least one admin domain")
        setIsCreatingUser(false)
        return
      }

      const response = await fetch("/api/admin/create-user", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(createUserForm),
      })

      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.error || "Failed to create user")
      }

      toast.success("User created successfully! They can now login with their email and receive an OTP.")
      setIsCreateUserDialogOpen(false)
      setCreateUserForm({
        firstName: "",
        lastName: "",
        otherNames: "",
        email: "",
        department: "",
        companyRole: "",
        phoneNumber: "",
        role: "employee",
        admin_domains: [],
        employeeNumber: "",
      })
      loadData()
    } catch (error: any) {
      log.error({ err: String(error) }, "error creating user")
      toast.error(error.message || "Failed to create user")
    } finally {
      setIsCreatingUser(false)
    }
  }

  const filteredEmployees = employees
    .filter((member) => {
      const matchesSearch =
        (member.first_name || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
        (member.last_name || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
        (member.company_email || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
        (member.additional_email || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
        (member.company_role || "").toLowerCase().includes(searchQuery.toLowerCase())

      const matchesDepartment = departmentFilter.length === 0 || departmentFilter.includes(member.department)

      const matchesEmployee = employeeFilter.length === 0 || employeeFilter.includes(member.id)

      const matchesRole = roleFilter.length === 0 || roleFilter.includes(member.role)

      const matchesStatus = statusFilter.length === 0 || statusFilter.includes(member.employment_status || "active")

      return matchesSearch && matchesDepartment && matchesEmployee && matchesRole && matchesStatus
    })
    .sort((a, b) => {
      const { key, direction } = sortConfig

      if (key === "employee_number") {
        const empNoA = (a.employee_number || "").toLowerCase()
        const empNoB = (b.employee_number || "").toLowerCase()
        return direction === "asc" ? empNoA.localeCompare(empNoB) : empNoB.localeCompare(empNoA)
      }

      const lastNameA = formatName(a.last_name).toLowerCase()
      const lastNameB = formatName(b.last_name).toLowerCase()

      if (direction === "asc") {
        return lastNameA.localeCompare(lastNameB)
      } else {
        return lastNameB.localeCompare(lastNameA)
      }
    })

  const departments = Array.from(new Set(employees.map((s) => s.department).filter(Boolean))) as string[]

  const roles: UserRole[] = ["visitor", "employee", "admin", "super_admin", "developer"]

  const stats = {
    total: employees.length,
    admins: employees.filter((s) => ["developer", "super_admin", "admin"].includes(s.role)).length,
    leads: employees.filter((s) => s.is_department_lead).length,
    employees: employees.filter((s) => s.role === "employee").length,
  }

  // Export functions
  const handleExportClick = (type: "excel" | "pdf" | "word") => {
    setExportType(type)
    setExportEmployeeDialogOpen(true)
  }

  const getAvailableRoles = (): UserRole[] => {
    if (!userProfile) return []
    return getAssignableRolesForActor(userProfile.role) as UserRole[]
  }

  if (isLoading) {
    return (
      <div className="from-background via-background to-muted/20 flex min-h-screen w-full items-center justify-center bg-gradient-to-br">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="text-primary h-8 w-8 animate-spin" />
          <p className="text-muted-foreground text-sm">Loading employees...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="from-background via-background to-muted/20 min-h-screen w-full overflow-x-hidden bg-gradient-to-br">
      <div className="mx-auto max-w-7xl space-y-6 p-4 md:p-8">
        {/* Header */}
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 className="text-foreground flex items-center gap-2 text-2xl font-bold sm:gap-3 sm:text-3xl">
              <Users className="text-primary h-6 w-6 sm:h-8 sm:w-8" />
              Employee Management
            </h1>
            <p className="text-muted-foreground mt-2 text-sm sm:text-base">
              View and manage employees members, roles, and permissions
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Link href="/admin/hr">
              <Button variant="outline" className="gap-2" size="sm">
                <ArrowLeft className="h-4 w-4" />
                Back to HR
              </Button>
            </Link>
            {canManageUsers && <PendingApplicationsModal onEmployeeCreated={loadData} />}
            {canManageUsers && (
              <Button onClick={() => setIsCreateUserDialogOpen(true)} className="gap-2" size="sm">
                <Plus className="h-4 w-4" />
                <span className="hidden sm:inline">Create User</span>
              </Button>
            )}
            <div className="flex items-center rounded-lg border p-1">
              <Button
                variant={viewMode === "list" ? "default" : "ghost"}
                size="sm"
                onClick={() => setViewMode("list")}
                className="gap-1 sm:gap-2"
              >
                <List className="h-4 w-4" />
                <span className="hidden sm:inline">List</span>
              </Button>
              <Button
                variant={viewMode === "card" ? "default" : "ghost"}
                size="sm"
                onClick={() => setViewMode("card")}
                className="gap-1 sm:gap-2"
              >
                <LayoutGrid className="h-4 w-4" />
                <span className="hidden sm:inline">Card</span>
              </Button>
            </div>
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-4">
          <Card className="border-2">
            <CardContent className="p-2.5">
              <div className="flex items-center justify-between">
                <div className="min-w-0 flex-1">
                  <p className="text-muted-foreground truncate text-[10px] font-medium">Total Employee</p>
                  <p className="text-foreground mt-0.5 text-base font-bold md:text-2xl">{stats.total}</p>
                </div>
                <div className="ml-1 shrink-0 rounded-lg bg-blue-100 p-1.5 dark:bg-blue-900/30">
                  <Users className="h-3.5 w-3.5 text-blue-600 dark:text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-2">
            <CardContent className="p-2.5">
              <div className="flex items-center justify-between">
                <div className="min-w-0 flex-1">
                  <p className="text-muted-foreground truncate text-[10px] font-medium">Admins</p>
                  <p className="text-foreground mt-0.5 text-base font-bold md:text-2xl">{stats.admins}</p>
                </div>
                <div className="ml-1 flex-shrink-0 rounded-lg bg-red-100 p-1.5 dark:bg-red-900/30">
                  <Shield className="h-3.5 w-3.5 text-red-600 dark:text-red-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-2">
            <CardContent className="p-2.5">
              <div className="flex items-center justify-between">
                <div className="min-w-0 flex-1">
                  <p className="text-muted-foreground truncate text-[10px] font-medium">Leads</p>
                  <p className="text-foreground mt-0.5 text-base font-bold md:text-2xl">{stats.leads}</p>
                </div>
                <div className="ml-1 flex-shrink-0 rounded-lg bg-purple-100 p-1.5 dark:bg-purple-900/30">
                  <UserCog className="h-3.5 w-3.5 text-purple-600 dark:text-purple-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-2">
            <CardContent className="p-2.5">
              <div className="flex items-center justify-between">
                <div className="min-w-0 flex-1">
                  <p className="text-muted-foreground truncate text-[10px] font-medium">Employee Members</p>
                  <p className="text-foreground mt-0.5 text-base font-bold md:text-2xl">{stats.employees}</p>
                </div>
                <div className="ml-1 flex-shrink-0 rounded-lg bg-green-100 p-1.5 dark:bg-green-900/30">
                  <Users className="h-3.5 w-3.5 text-green-600 dark:text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Export Buttons */}
        <Card className="border-2">
          <CardContent className="p-4">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
              <div className="flex items-center gap-2">
                <Download className="text-muted-foreground h-4 w-4" />
                <span className="text-foreground text-sm font-medium">Export Filtered Employee:</span>
              </div>
              <div className="flex flex-wrap gap-2">
                <Link href="/admin/hr/employees/offboarding-conflicts">
                  <Button variant="secondary" size="sm" className="gap-2">
                    <AlertTriangle className="h-4 w-4" />
                    Offboarding Conflicts
                  </Button>
                </Link>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleExportClick("excel")}
                  className="flex-1 gap-2 sm:flex-none"
                  disabled={filteredEmployees.length === 0}
                >
                  <FileText className="h-4 w-4" />
                  <span className="text-xs sm:text-sm">Excel (.xlsx)</span>
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleExportClick("pdf")}
                  className="flex-1 gap-2 sm:flex-none"
                  disabled={filteredEmployees.length === 0}
                >
                  <FileText className="h-4 w-4" />
                  <span className="text-xs sm:text-sm">PDF</span>
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleExportClick("word")}
                  className="flex-1 gap-2 sm:flex-none"
                  disabled={filteredEmployees.length === 0}
                >
                  <FileText className="h-4 w-4" />
                  <span className="text-xs sm:text-sm">Word (.docx)</span>
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Filters */}
        <EmployeeFilterBar
          filters={{ searchQuery, departmentFilter, employeeFilter, roleFilter, statusFilter }}
          onFilterChange={(updated) => {
            if (updated.searchQuery !== undefined) setSearchQuery(updated.searchQuery)
            if (updated.departmentFilter !== undefined) setDepartmentFilter(updated.departmentFilter)
            if (updated.employeeFilter !== undefined) setEmployeeFilter(updated.employeeFilter)
            if (updated.roleFilter !== undefined) setRoleFilter(updated.roleFilter)
            if (updated.statusFilter !== undefined) setStatusFilter(updated.statusFilter)
          }}
          departments={departments}
          employees={employees}
          roles={roles}
        />

        {/* Employee List */}
        <EmployeeListView
          employees={filteredEmployees}
          viewMode={viewMode}
          sortConfig={sortConfig}
          onSortChange={setSortConfig}
          onViewDetails={handleViewEmployeeDetails}
          hasActiveFilters={
            Boolean(searchQuery) || departmentFilter.length > 0 || roleFilter.length > 0 || employeeFilter.length > 0
          }
          getRoleBadgeColor={getRoleBadgeColor}
          getRoleDisplayName={getRoleDisplayName}
        />
      </div>

      {/* Create User Dialog */}
      <CreateUserDialog
        isOpen={isCreateUserDialogOpen}
        onOpenChange={setIsCreateUserDialogOpen}
        form={createUserForm}
        setForm={setCreateUserForm}
        onCreate={handleCreateUser}
        isCreating={isCreatingUser}
        canManageUsers={canManageUsers}
        userProfile={userProfile}
      />

      {/* View Details Dialog */}
      <EmployeeViewModal
        isOpen={isViewDialogOpen}
        onOpenChange={setIsViewDialogOpen}
        employee={viewEmployeeProfile}
        assignedItems={assignedItems}
        modalViewMode={modalViewMode}
        setModalViewMode={setModalViewMode}
        onSave={handleSaveEmployee}
        isSaving={isSaving}
        editForm={editForm}
        setEditForm={setEditForm}
        showMoreOptions={showMoreOptions}
        setShowMoreOptions={setShowMoreOptions}
        userProfile={userProfile}
        viewEmployeeData={viewEmployeeData}
        onEditEmployee={handleEditEmployee}
        onSignature={handleViewEmployeeSignature}
        loadData={loadData}
        setViewEmployeeProfile={setViewEmployeeProfile}
        canManageUsers={canManageUsers}
        getAvailableRoles={getAvailableRoles}
      />

      {/* Deletion Disabled Dialog */}
      <EmployeeDeletionDialog
        isOpen={isDeleteDialogOpen}
        onOpenChange={setIsDeleteDialogOpen}
        employee={selectedEmployee}
        assignedItems={assignedItems}
        onDelete={confirmDeleteEmployee}
        isDeleting={isDeleting}
      />

      {/* Export Column Selection Dialog */}
      <EmployeeExportDialog
        isOpen={exportEmployeeDialogOpen}
        onOpenChange={setExportEmployeeDialogOpen}
        exportType={exportType}
        setExportType={setExportType}
        selectedColumns={selectedColumns}
        setSelectedColumns={setSelectedColumns}
        onConfirm={async () => {
          const rows = buildEmployeeExportRows(filteredEmployees, { selectedColumns })
          const filename = `employees-export-${new Date().toISOString().split("T")[0]}`
          if (exportType === "excel") await exportEmployeesToExcel(rows, filename)
          else if (exportType === "pdf") await exportEmployeesToPDF(filteredEmployees, { selectedColumns }, filename)
          else if (exportType === "word") await exportEmployeesToWord(rows, filename)
          setExportEmployeeDialogOpen(false)
        }}
      />
    </div>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { AdminEmployeeContent, type Employee, type UserProfile } from "./admin-employee-content"
import { resolveAdminScope } from "@/lib/admin/rbac"
import { logger } from "@/lib/logger"

const log = logger("admin-employees")

async function getAdminEmployeeData() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return { redirect: "/profile" as const }
  }
  const userProfile: UserProfile = {
    role: scope.role as any,
    managed_departments: scope.managedDepartments,
  }

  // Fetch employees - all leads can view users; mutation is restricted in the UI and backend.
  const query = dataClient.from("profiles").select("*").order("last_name", { ascending: true })

  const { data: employeeData, error: employeeError } = await query

  if (employeeError) {
    log.error({ err: employeeError }, "Error loading employees")
    return { employees: [], userProfile }
  }

  return {
    employees: (employeeData || []) as Employee[],
    userProfile,
  }
}

export default async function AdminEmployeePage() {
  const data = await getAdminEmployeeData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  const pageData = data as {
    employees: Employee[]
    userProfile: UserProfile
  }

  return <AdminEmployeeContent initialEmployees={pageData.employees} userProfile={pageData.userProfile} />
}

"use client"

import { useState, useEffect } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Button } from "@/components/ui/button"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Badge } from "@/components/ui/badge"
import { Input } from "@/components/ui/input"
import { Loader2, CheckCircle, UserPlus, ChevronRight, ShieldCheck, Hash } from "lucide-react"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { format } from "date-fns"
import { cn, formatName, formatFullName } from "@/lib/utils"
import { QUERY_KEYS } from "@/lib/query-keys"

import { logger } from "@/lib/logger"

const log = logger("hr-employees-pending-applications-modal")

interface PendingUser {
  id: string
  first_name: string
  last_name: string
  other_names?: string
  department: string
  company_role: string
  company_email: string
  personal_email: string
  phone_number: string
  residential_address: string
  office_location?: string
  created_at: string
  status: string
}

interface PendingApplicationsModalProps {
  onEmployeeCreated: () => void
}

async function fetchPendingApplications(supabase: ReturnType<typeof createClient>): Promise<PendingUser[]> {
  const { data, error } = await supabase
    .from("pending_users")
    .select("*")
    .eq("status", "pending")
    .order("created_at", { ascending: false })

  if (error) throw new Error(error.message)
  return data || []
}

export function PendingApplicationsModal({ onEmployeeCreated }: PendingApplicationsModalProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [selectedUser, setSelectedUser] = useState<PendingUser | null>(null)
  const [isProcessing, setIsProcessing] = useState(false)
  const [pendingReject, setPendingReject] = useState(false)
  const [employeeId, setEmployeeId] = useState("")
  const [hireDate, setHireDate] = useState(new Date().toISOString().split("T")[0])

  const supabase = createClient()
  const queryClient = useQueryClient()

  const { data: pendingUsers = [], isLoading } = useQuery({
    queryKey: QUERY_KEYS.pendingApplications(),
    queryFn: () => fetchPendingApplications(supabase),
    enabled: isOpen,
  })

  // Auto-select first user when data loads
  useEffect(() => {
    if (pendingUsers.length > 0 && !selectedUser) {
      handleUserSelect(pendingUsers[0])
    }
  }, [pendingUsers])

  const fetchSuggestedId = async () => {
    try {
      const { data: lastProfile } = await supabase
        .from("profiles")
        .select("employee_number")
        .not("employee_number", "is", null)
        .order("created_at", { ascending: false })
        .limit(1)
        .single()

      let nextIdNumber = 1
      const currentYear = new Date().getFullYear()

      if (lastProfile && lastProfile.employee_number) {
        const parts = lastProfile.employee_number.split("/")
        if (parts.length === 3) {
          const lastNum = parseInt(parts[2], 10)
          if (!isNaN(lastNum)) {
            nextIdNumber = lastNum + 1
          }
        }
      }
      setEmployeeId(`ACOB/${currentYear}/${nextIdNumber.toString().padStart(3, "0")}`)
    } catch (err) {
      log.error("Error suggesting ID:", err)
      setEmployeeId(`ACOB/${new Date().getFullYear()}/001`)
    }
  }

  const handleUserSelect = (user: PendingUser) => {
    setSelectedUser(user)
    fetchSuggestedId()
  }

  const handleApprove = async () => {
    if (!selectedUser) return

    // Validate ID format before sending
    const empNumPattern = /^ACOB\/[0-9]{4}\/[0-9]{3}$/
    if (employeeId && !empNumPattern.test(employeeId)) {
      toast.error("Employee ID MUST be in format: ACOB/YEAR/NUMBER (e.g., ACOB/2026/001)")
      return
    }

    setIsProcessing(true)

    try {
      const response = await fetch("/api/admin/approve-user", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          pendingUserId: selectedUser.id,
          employeeId: employeeId,
          hireDate: hireDate,
        }),
      })

      const result = await response.json()

      if (!response.ok) {
        throw new Error(result.error || "Failed to approve user")
      }

      toast.success("User approved and account created successfully")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.pendingApplications() })
      const remaining = pendingUsers.filter((u) => u.id !== selectedUser.id)
      if (remaining.length > 0) {
        handleUserSelect(remaining[0])
      } else {
        setSelectedUser(null)
        setEmployeeId("")
      }
      onEmployeeCreated()
    } catch (error: any) {
      log.error("Approval error:", error)
      toast.error(error.message || "Failed to approve user")
    } finally {
      setIsProcessing(false)
    }
  }

  const handleReject = async () => {
    if (!selectedUser) return

    setIsProcessing(true)
    try {
      const { error } = await supabase.from("pending_users").delete().eq("id", selectedUser.id)

      if (error) throw error

      toast.success("Application rejected")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.pendingApplications() })
      const remaining = pendingUsers.filter((u) => u.id !== selectedUser.id)
      if (remaining.length > 0) {
        handleUserSelect(remaining[0])
      } else {
        setSelectedUser(null)
        setEmployeeId("")
      }
    } catch (error: any) {
      log.error("Rejection error:", error)
      toast.error("Failed to reject application")
    } finally {
      setIsProcessing(false)
    }
  }

  const DetailRow = ({ label, value }: { label: string; value: string | null | undefined }) => (
    <div className="border-border hover:bg-muted/50 grid grid-cols-4 border-b transition-colors">
      <div className="border-border bg-muted/40 flex items-center border-r p-3">
        <span className="text-muted-foreground text-xs font-bold uppercase">{label}</span>
      </div>
      <div className="bg-background col-span-3 flex items-center p-3">
        <span className="text-foreground text-sm font-medium">{value || "—"}</span>
      </div>
    </div>
  )

  return (
    <Dialog open={isOpen} onOpenChange={setIsOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" className="h-9 gap-2">
          <UserPlus className="h-4 w-4" />
          Review Applications
          {pendingUsers.length > 0 && (
            <Badge variant="destructive" className="ml-1 h-5 px-1.5 text-[10px]">
              {pendingUsers.length}
            </Badge>
          )}
        </Button>
      </DialogTrigger>
      <DialogContent className="border-border bg-background text-foreground flex h-[85vh] max-w-6xl flex-col overflow-hidden p-0 font-sans shadow-2xl">
        <div className="sr-only">
          <DialogTitle>Pending Onboarding Applications</DialogTitle>
          <DialogDescription>Review and approve system access for new employees.</DialogDescription>
        </div>
        <div className="flex min-h-0 flex-1">
          {/* List Column (Standard Sidebar) */}
          <aside className="border-border bg-muted/10 flex w-[300px] flex-col border-r">
            <div className="border-border bg-background border-b p-6">
              <h2 className="text-lg font-bold tracking-tight">Queue</h2>
              <p className="text-muted-foreground text-xs font-medium">Verification Needed</p>
            </div>
            <ScrollArea className="flex-1">
              <div className="divide-border divide-y">
                {isLoading ? (
                  <div className="flex flex-col items-center justify-center gap-4 p-12 opacity-50">
                    <Loader2 className="text-primary h-6 w-6 animate-spin" />
                    <p className="text-xs font-medium">Loading...</p>
                  </div>
                ) : pendingUsers.length === 0 ? (
                  <div className="space-y-3 p-12 text-center opacity-40">
                    <CheckCircle className="mx-auto h-8 w-8" />
                    <p className="text-xs font-medium">Queue is empty</p>
                  </div>
                ) : (
                  pendingUsers.map((user) => (
                    <button
                      key={user.id}
                      onClick={() => handleUserSelect(user)}
                      className={cn(
                        "group relative flex w-full items-center justify-between px-6 py-4 text-left transition-all",
                        selectedUser?.id === user.id
                          ? "bg-muted border-l-primary border-l-4 shadow-sm"
                          : "hover:bg-muted/50 border-l-4 border-l-transparent"
                      )}
                    >
                      <div className="min-w-0">
                        <div
                          className={cn(
                            "truncate text-sm font-bold transition-colors",
                            selectedUser?.id === user.id ? "text-primary" : "text-foreground"
                          )}
                        >
                          {formatName(user.first_name)} {formatName(user.last_name)}
                        </div>
                        <div className="text-muted-foreground mt-1 text-[11px] font-medium">
                          Applied {format(new Date(user.created_at), "MMM d, yyyy")}
                        </div>
                      </div>
                      <ChevronRight
                        className={cn(
                          "h-3 w-3 transition-transform",
                          selectedUser?.id === user.id ? "text-primary translate-x-1" : "text-muted-foreground/30"
                        )}
                      />
                    </button>
                  ))
                )}
              </div>
            </ScrollArea>
          </aside>

          {/* Content Column (Standard Details) */}
          <main className="bg-background relative flex flex-1 flex-col">
            {selectedUser ? (
              <>
                <ScrollArea className="flex-1">
                  <div className="max-w-4xl p-10 pb-32">
                    <div className="mb-6 flex items-center justify-between">
                      <h2 className="text-xl font-bold tracking-tight">Applicant Verification Profile</h2>
                      <div className="flex items-center gap-3">
                        <div className="flex flex-col items-end">
                          <span className="text-muted-foreground mb-1 text-[10px] font-bold uppercase">Hire Date</span>
                          <Input
                            type="date"
                            value={hireDate}
                            onChange={(e) => setHireDate(e.target.value)}
                            className="bg-primary/5 border-primary/20 focus-visible:ring-primary h-9 w-40 font-mono text-xs font-bold"
                          />
                        </div>
                        <div className="flex flex-col items-end">
                          <span className="text-muted-foreground mb-1 text-[10px] font-bold uppercase">Assign ID</span>
                          <div className="relative w-44">
                            <Hash className="text-primary absolute top-2.5 left-2.5 h-3.5 w-3.5" />
                            <Input
                              value={employeeId}
                              onChange={(e) => setEmployeeId(e.target.value)}
                              className="bg-primary/5 border-primary/20 focus-visible:ring-primary h-9 pl-8 font-mono text-xs font-bold"
                              placeholder="ACOB/2026/001"
                            />
                          </div>
                        </div>
                        <Badge variant="outline" className="mb-1 self-end py-0.5 text-[10px] font-bold">
                          PENDING APPROVAL
                        </Badge>
                      </div>
                    </div>

                    {/* Table Grid with full borders */}
                    <div className="border-border overflow-hidden rounded-lg border shadow-sm">
                      <DetailRow label="First Name" value={formatName(selectedUser.first_name)} />
                      <DetailRow label="Last Name" value={formatName(selectedUser.last_name)} />
                      <DetailRow label="Other Names" value={formatName(selectedUser.other_names)} />
                      <div className="border-border grid grid-cols-1 border-b">
                        <div className="bg-muted/20 text-muted-foreground border-border border-b p-2 text-[10px] font-bold uppercase">
                          Organizational Data
                        </div>
                        <div className="grid grid-cols-1">
                          <DetailRow label="Department" value={selectedUser.department} />
                          <DetailRow label="Company Role" value={selectedUser.company_role} />
                          <DetailRow label="System Email" value={selectedUser.company_email} />
                          <DetailRow label="Assigned ID" value={employeeId} />
                          <DetailRow label="Office Location" value={selectedUser.office_location || "N/A"} />
                        </div>
                      </div>
                      <div className="grid grid-cols-1">
                        <div className="bg-muted/20 text-muted-foreground border-border border-b p-2 text-[10px] font-bold uppercase">
                          Personal & Contact
                        </div>
                        <div className="grid grid-cols-1">
                          <DetailRow label="Phone Number" value={selectedUser.phone_number} />
                          <DetailRow label="Personal Email" value={selectedUser.personal_email} />
                          <DetailRow label="Address" value={selectedUser.residential_address} />
                          <DetailRow
                            label="Application Date"
                            value={format(new Date(selectedUser.created_at), "PPPP")}
                          />
                        </div>
                      </div>
                    </div>

                    <div className="bg-muted/40 border-border mt-10 flex items-start gap-4 rounded-lg border p-5">
                      <ShieldCheck className="text-muted-foreground mt-0.5 h-5 w-5 shrink-0" />
                      <div className="space-y-1">
                        <p className="text-sm font-bold">Admin Notice</p>
                        <p className="text-muted-foreground text-xs leading-relaxed">
                          Ensure all data fields match official documentation. Approval will automatically update the HR
                          database and broadcast welcome emails.
                        </p>
                      </div>
                    </div>
                  </div>
                </ScrollArea>

                {/* Fixed Footer Actions */}
                <div className="bg-background border-border absolute right-0 bottom-0 left-0 z-10 flex justify-end gap-3 border-t p-6">
                  <Button
                    variant="outline"
                    onClick={() => setPendingReject(true)}
                    disabled={isProcessing}
                    className="h-10 px-6 font-semibold"
                  >
                    {isProcessing ? <Loader2 className="h-3 w-3 animate-spin" /> : "Reject Candidate"}
                  </Button>
                  <Button
                    onClick={handleApprove}
                    disabled={isProcessing}
                    className="bg-primary h-10 px-10 font-bold shadow-sm"
                  >
                    {isProcessing ? (
                      <>
                        <Loader2 className="mr-2 h-3 w-3 animate-spin" />
                        Processing
                      </>
                    ) : (
                      "Confirm & Approve"
                    )}
                  </Button>
                </div>
              </>
            ) : (
              <div className="flex flex-1 flex-col items-center justify-center p-12 text-center opacity-30">
                <UserPlus className="mb-4 h-10 w-10" />
                <h3 className="text-sm font-medium">Select an application from the queue</h3>
              </div>
            )}
          </main>
        </div>
      </DialogContent>

      <AlertDialog open={pendingReject} onOpenChange={(open) => !open && setPendingReject(false)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Reject Application</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to reject this application? This cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                setPendingReject(false)
                handleReject()
              }}
            >
              Reject
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </Dialog>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { SignatureCreator } from "@/components/signature-creator"
import { buttonVariants } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import { ArrowLeft } from "lucide-react"
import Link from "next/link"
import { resolveAdminScope } from "@/lib/admin/rbac"

export default async function AdminEmployeeSignaturePage({ params }: { params: { userId: string } }) {
  const supabase = await createClient()

  const { data, error } = await supabase.auth.getUser()
  if (error || !data?.user) {
    redirect("/auth/login")
  }

  const scope = await resolveAdminScope(supabase as any, data.user.id)
  if (!scope) {
    redirect("/profile")
  }

  // Fetch the target user's profile
  const { data: profile } = await supabase.from("profiles").select("*").eq("id", params.userId).single()

  if (!profile) {
    redirect("/admin/hr/employees")
  }

  return (
    <div className="bg-background min-h-screen">
      <div className="mx-auto max-w-6xl p-6">
        <div className="mb-8">
          <Link href="/admin/hr/employees" className={cn(buttonVariants({ variant: "ghost" }), "mb-4")}>
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Employees
          </Link>
          <h1 className="text-foreground text-3xl font-bold">
            Email Signature - {profile.first_name} {profile.last_name}
          </h1>
          <p className="text-muted-foreground">View and manage signature for this employee</p>
        </div>

        <SignatureCreator profile={profile} />
      </div>
    </div>
  )
}

"use client"

import { useState } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { toast } from "sonner"
import { CalendarCheck2, CheckCircle2, Paperclip, Plus, XCircle } from "lucide-react"
import { AdminTablePage } from "@/components/admin/admin-table-page"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { StatCard } from "@/components/ui/stat-card"
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Textarea } from "@/components/ui/textarea"
import { QUERY_KEYS } from "@/lib/query-keys"
import { TableSkeleton } from "@/components/ui/query-states"

type FleetResource = {
  id: string
  name: string
  resource_type: string
  description?: string | null
  is_active: boolean
}

type FleetBooking = {
  id: string
  resource_id: string
  start_at: string
  end_at: string
  reason: string
  status: "pending" | "approved" | "rejected" | "cancelled"
  admin_note?: string | null
  requester?: { id: string; full_name?: string | null; company_email?: string | null } | null
  reviewer?: { id: string; full_name?: string | null } | null
  resource?: FleetResource | null
  attachment_count?: number
}

type FleetAttachment = {
  id: string
  file_name: string
  mime_type: string
  file_size: number
  signed_url?: string | null
}

function formatDateTime(value: string) {
  const parsed = new Date(value)
  if (Number.isNaN(parsed.getTime())) return value
  return parsed.toLocaleString()
}

async function fetchFleetResources(): Promise<FleetResource[]> {
  const response = await fetch("/api/admin/hr/fleet/resources")
  const payload = await response.json()
  if (!response.ok) throw new Error(payload.error || "Failed to load resources")
  return payload.data || []
}

async function fetchFleetBookings(status?: string): Promise<FleetBooking[]> {
  const statusParam = status === "pending" ? "?status=pending" : ""
  const response = await fetch(`/api/admin/hr/fleet/bookings${statusParam}`)
  const payload = await response.json()
  if (!response.ok) throw new Error(payload.error || "Failed to load bookings")
  return payload.data || []
}

export default function AdminFleetPage() {
  const queryClient = useQueryClient()
  const [tab, setTab] = useState<"pending" | "all">("pending")

  const [resourceName, setResourceName] = useState("")
  const [resourceType, setResourceType] = useState("general")
  const [resourceDescription, setResourceDescription] = useState("")
  const [savingResource, setSavingResource] = useState(false)

  const [selectedBooking, setSelectedBooking] = useState<FleetBooking | null>(null)
  const [attachments, setAttachments] = useState<FleetAttachment[]>([])
  const [reviewing, setReviewing] = useState(false)
  const [adminNote, setAdminNote] = useState("")

  const { data: resources = [], isLoading: loadingResources } = useQuery({
    queryKey: QUERY_KEYS.adminFleetResources(),
    queryFn: fetchFleetResources,
  })

  const { data: bookings = [], isLoading: loadingBookings } = useQuery({
    queryKey: QUERY_KEYS.adminFleetBookings(tab),
    queryFn: () => fetchFleetBookings(tab),
  })

  const loading = loadingResources || loadingBookings

  async function createResource() {
    setSavingResource(true)
    try {
      const response = await fetch("/api/admin/hr/fleet/resources", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: resourceName,
          resource_type: resourceType,
          description: resourceDescription,
        }),
      })
      const payload = await response.json()
      if (!response.ok) throw new Error(payload.error || "Failed to create resource")

      toast.success("Resource created")
      setResourceName("")
      setResourceType("general")
      setResourceDescription("")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminFleetResources() })
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to create resource")
    } finally {
      setSavingResource(false)
    }
  }

  async function toggleResource(resource: FleetResource) {
    try {
      const response = await fetch("/api/admin/hr/fleet/resources", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: resource.id, is_active: !resource.is_active }),
      })
      const payload = await response.json()
      if (!response.ok) throw new Error(payload.error || "Failed to update resource")
      toast.success(`Resource ${resource.is_active ? "deactivated" : "activated"}`)
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminFleetResources() })
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to update resource")
    }
  }

  async function openReview(booking: FleetBooking) {
    setSelectedBooking(booking)
    setAdminNote(booking.admin_note || "")
    setAttachments([])

    try {
      const response = await fetch(`/api/fleet/bookings/${booking.id}/attachments`)
      const payload = await response.json()
      if (!response.ok) throw new Error(payload.error || "Failed to load attachments")
      setAttachments(payload.data || [])
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to load attachments")
    }
  }

  async function review(action: "approve" | "reject") {
    if (!selectedBooking) return
    setReviewing(true)
    try {
      const response = await fetch(`/api/admin/hr/fleet/bookings/${selectedBooking.id}/review`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action, admin_note: adminNote }),
      })
      const payload = await response.json()
      if (!response.ok) throw new Error(payload.error || "Review failed")
      toast.success(`Booking ${action}d`)
      setSelectedBooking(null)
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminFleetBookings(tab) })
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Review failed")
    } finally {
      setReviewing(false)
    }
  }

  const pendingCount = bookings.filter((booking) => booking.status === "pending").length
  const approvedCount = bookings.filter((booking) => booking.status === "approved").length
  const rejectedCount = bookings.filter((booking) => booking.status === "rejected").length

  return (
    <AdminTablePage
      title="Fleet Booking Admin"
      description="Manage bookable resources and review booking applications"
      icon={CalendarCheck2}
      backLinkHref="/admin/hr"
      backLinkLabel="Back to HR Dashboard"
      stats={
        <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3 md:gap-4">
          <StatCard title="Pending" value={pendingCount} icon={CalendarCheck2} />
          <StatCard title="Approved" value={approvedCount} icon={CheckCircle2} />
          <StatCard title="Rejected" value={rejectedCount} icon={XCircle} />
        </div>
      }
    >
      <div className="grid gap-4 lg:grid-cols-3">
        <Card>
          <CardHeader>
            <CardTitle>New Resource</CardTitle>
            <CardDescription>Create additional bookable items for Fleet module.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="space-y-2">
              <Label>Name</Label>
              <Input
                value={resourceName}
                onChange={(e) => setResourceName(e.target.value)}
                placeholder="Delivery Car"
              />
            </div>
            <div className="space-y-2">
              <Label>Type</Label>
              <Input value={resourceType} onChange={(e) => setResourceType(e.target.value)} placeholder="vehicle" />
            </div>
            <div className="space-y-2">
              <Label>Description</Label>
              <Textarea
                value={resourceDescription}
                onChange={(e) => setResourceDescription(e.target.value)}
                placeholder="Optional description"
                rows={3}
              />
            </div>
            <Button
              onClick={createResource}
              disabled={savingResource || resourceName.trim().length < 2}
              className="w-full"
            >
              <Plus className="mr-2 h-4 w-4" /> {savingResource ? "Saving..." : "Create Resource"}
            </Button>
          </CardContent>
        </Card>

        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle>Resources</CardTitle>
            <CardDescription>Activate/deactivate resources available for booking.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-2">
            {loadingResources ? (
              <TableSkeleton rows={3} cols={2} />
            ) : (
              <>
                {resources.map((resource) => (
                  <div key={resource.id} className="flex items-center justify-between rounded border p-3">
                    <div>
                      <p className="font-medium">{resource.name}</p>
                      <p className="text-muted-foreground text-xs">{resource.resource_type}</p>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge variant={resource.is_active ? "default" : "outline"}>
                        {resource.is_active ? "Active" : "Inactive"}
                      </Badge>
                      <Button variant="outline" size="sm" onClick={() => toggleResource(resource)}>
                        {resource.is_active ? "Deactivate" : "Activate"}
                      </Button>
                    </div>
                  </div>
                ))}
                {resources.length === 0 ? <p className="text-muted-foreground text-sm">No resources found.</p> : null}
              </>
            )}
          </CardContent>
        </Card>
      </div>

      <Card className="mt-4">
        <CardHeader>
          <CardTitle>Booking Applications</CardTitle>
          <CardDescription>Review pending requests and inspect reason/attachments before action.</CardDescription>
          <Tabs value={tab} onValueChange={(value) => setTab(value as "pending" | "all")}>
            <TabsList>
              <TabsTrigger value="pending">Pending</TabsTrigger>
              <TabsTrigger value="all">All</TabsTrigger>
            </TabsList>
          </Tabs>
        </CardHeader>
        <CardContent className="space-y-3">
          {loadingBookings ? <TableSkeleton rows={3} cols={3} /> : null}
          {!loadingBookings && bookings.length === 0 ? (
            <p className="text-muted-foreground text-sm">No bookings found.</p>
          ) : null}

          {bookings.map((booking) => (
            <div key={booking.id} className="rounded border p-3">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <div>
                  <p className="font-medium">{booking.resource?.name || "Resource"}</p>
                  <p className="text-muted-foreground text-xs">
                    {formatDateTime(booking.start_at)} - {formatDateTime(booking.end_at)}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  <Badge
                    variant={
                      booking.status === "approved"
                        ? "default"
                        : booking.status === "pending"
                          ? "secondary"
                          : booking.status === "rejected"
                            ? "destructive"
                            : "outline"
                    }
                  >
                    {booking.status}
                  </Badge>
                  <Button variant="outline" size="sm" onClick={() => openReview(booking)}>
                    Review
                  </Button>
                </div>
              </div>
              <p className="mt-2 text-sm">{booking.reason}</p>
              <div className="text-muted-foreground mt-2 text-xs">
                <p>Requester: {booking.requester?.full_name || booking.requester?.company_email || "Employee"}</p>
                <p className="inline-flex items-center gap-1">
                  <Paperclip className="h-3.5 w-3.5" /> {booking.attachment_count || 0} attachment(s)
                </p>
              </div>
            </div>
          ))}
        </CardContent>
      </Card>

      <Dialog open={Boolean(selectedBooking)} onOpenChange={(open) => (!open ? setSelectedBooking(null) : null)}>
        <DialogContent className="sm:max-w-2xl">
          <DialogHeader>
            <DialogTitle>Review Fleet Application</DialogTitle>
            <DialogDescription>Confirm the reason and supporting files before approval.</DialogDescription>
          </DialogHeader>

          {selectedBooking ? (
            <div className="space-y-4 py-2">
              <div className="rounded border p-3">
                <p className="font-medium">{selectedBooking.resource?.name || "Resource"}</p>
                <p className="text-muted-foreground text-xs">
                  {formatDateTime(selectedBooking.start_at)} - {formatDateTime(selectedBooking.end_at)}
                </p>
                <p className="mt-2 text-sm">{selectedBooking.reason}</p>
              </div>

              <div className="space-y-2">
                <Label>Attachments</Label>
                {attachments.length === 0 ? (
                  <p className="text-muted-foreground text-sm">No attachments provided.</p>
                ) : null}
                {attachments.map((file) => (
                  <div key={file.id} className="flex items-center justify-between rounded border p-2 text-sm">
                    <div>
                      <p>{file.file_name}</p>
                      <p className="text-muted-foreground text-xs">
                        {file.mime_type} • {(file.file_size / 1024).toFixed(1)} KB
                      </p>
                    </div>
                    {file.signed_url ? (
                      <a
                        href={file.signed_url}
                        target="_blank"
                        rel="noreferrer"
                        className="text-primary text-sm underline"
                      >
                        Open
                      </a>
                    ) : (
                      <span className="text-muted-foreground text-xs">Unavailable</span>
                    )}
                  </div>
                ))}
              </div>

              <div className="space-y-2">
                <Label>Admin Note</Label>
                <Textarea value={adminNote} onChange={(e) => setAdminNote(e.target.value)} rows={3} />
              </div>
            </div>
          ) : null}

          <DialogFooter>
            <Button variant="outline" onClick={() => setSelectedBooking(null)}>
              Close
            </Button>
            {selectedBooking?.status === "pending" ? (
              <>
                <Button variant="destructive" onClick={() => review("reject")} disabled={reviewing}>
                  Reject
                </Button>
                <Button onClick={() => review("approve")} disabled={reviewing}>
                  Approve
                </Button>
              </>
            ) : null}
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </AdminTablePage>
  )
}

"use client"

import { useEffect, useState } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { SearchableSelect } from "@/components/ui/searchable-select"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { CheckCircle, XCircle, Loader2, PlayCircle, FlaskConical, SkipForward, Route } from "lucide-react"
import { toast } from "sonner"
import { createClient } from "@/lib/supabase/client"
import { cn } from "@/lib/utils"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"
import { logger } from "@/lib/logger"

const log = logger("leave-flow-test")

type StepResult = {
  step: string
  status: "ok" | "error" | "skipped"
  detail?: string
  data?: unknown
}

type TestResult = {
  ok: boolean
  steps: StepResult[]
  leave_request_id?: string | null
  error?: string
}

type DiagRow = {
  requester_kind: string
  stage_order: number
  approver_role_code: string
  resolved: boolean
  resolved_user_id?: string | null
  resolved_name?: string | null
  fail_reason?: string
}

type DiagnosticsResult = {
  results: DiagRow[]
  broken_count: number
  total: number
}

const FIX_HINTS: Record<string, string> = {
  md: 'Set someone\'s profile: is_department_lead = true AND department = "Executive Management" (or add "Executive Management" to their lead_departments array)',
  hcs: 'Set someone\'s profile: is_department_lead = true AND department = "Corporate Services" (or add it to lead_departments)',
  admin_hr_lead:
    'Set someone\'s profile: is_department_lead = true AND department = "Admin & HR" (or add it to lead_departments)',
  department_lead:
    "Dynamic — the requester's department needs someone with is_department_lead = true, or a department_head_id set in the departments table",
  reliever: "Dynamic per request — no fix needed",
}

export function LeaveFlowTestContent() {
  const supabase = createClient()

  const [employees, setEmployees] = useState<{ value: string; label: string }[]>([])
  const [leaveTypes, setLeaveTypes] = useState<{ value: string; label: string }[]>([])
  const [requesterId, setRequesterId] = useState("")
  const [relieverId, setRelieverId] = useState("")
  const [leaveTypeId, setLeaveTypeId] = useState("")
  const [cleanup, setCleanup] = useState(true)
  const [running, setRunning] = useState(false)
  const [result, setResult] = useState<TestResult | null>(null)

  const [diagnosticsRunning, setDiagnosticsRunning] = useState(false)
  const [diagnosticsResult, setDiagnosticsResult] = useState<DiagnosticsResult | null>(null)

  useEffect(() => {
    async function load() {
      const [profilesRes, typesRes] = await Promise.all([
        applyAssignableStatusFilter(
          supabase.from("profiles").select("id, full_name, first_name, last_name, company_email").order("first_name"),
          { allowLegacyNullStatus: false }
        ),
        supabase.from("leave_types").select("id, name").order("name"),
      ])

      const profileOptions = (profilesRes.data || []).map((p: any) => ({
        value: p.id,
        label: p.full_name?.trim() || `${p.first_name || ""} ${p.last_name || ""}`.trim() || p.company_email || p.id,
      }))

      const typeOptions = (typesRes.data || []).map((t: any) => ({
        value: t.id,
        label: t.name,
      }))

      setEmployees(profileOptions)
      setLeaveTypes(typeOptions)
    }

    load().catch((err) => log.error({ err: String(err) }, "load failed"))
  }, [])

  async function runTest() {
    if (!requesterId || !relieverId || !leaveTypeId) {
      toast.error("Please fill in all three fields")
      return
    }
    if (requesterId === relieverId) {
      toast.error("Requester and reliever must be different people")
      return
    }

    setRunning(true)
    setResult(null)

    try {
      const res = await fetch("/api/dev/leave-flow-test", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          requester_id: requesterId,
          reliever_id: relieverId,
          leave_type_id: leaveTypeId,
          cleanup,
        }),
      })

      const payload: TestResult = await res.json()
      setResult(payload)

      if (payload.ok) {
        toast.success("All stages passed ✓")
      } else {
        toast.error("One or more stages failed — check results below")
      }
    } catch (e: any) {
      toast.error(e.message || "Network error")
    } finally {
      setRunning(false)
    }
  }

  async function runDiagnostics() {
    setDiagnosticsRunning(true)
    setDiagnosticsResult(null)

    try {
      const res = await fetch("/api/dev/leave-route-diagnostics")

      const payload: DiagnosticsResult = await res.json()
      setDiagnosticsResult(payload)

      if (payload.broken_count === 0) {
        toast.success("All routes are fully configured ✓")
      } else {
        toast.error(`${payload.broken_count} broken stage(s) found — see details below`)
      }
    } catch (e: any) {
      toast.error(e.message || "Network error")
    } finally {
      setDiagnosticsRunning(false)
    }
  }

  const passCount = result?.steps.filter((s) => s.status === "ok").length ?? 0
  const failCount = result?.steps.filter((s) => s.status === "error").length ?? 0

  const brokenRoutesCount = diagnosticsResult?.broken_count ?? 0
  const diagByKind = diagnosticsResult
    ? (diagnosticsResult.results || []).reduce<Record<string, DiagRow[]>>((acc, row) => {
        acc[row.requester_kind] = acc[row.requester_kind] || []
        acc[row.requester_kind].push(row)
        return acc
      }, {})
    : {}

  return (
    <div className="space-y-6">
      {/* Config card */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FlaskConical className="h-5 w-5" />
            Leave Flow Test
          </CardTitle>
          <CardDescription>
            Simulates a full leave request → reliever → dept lead → HR approval using service-role — no need to log into
            multiple accounts. A test leave request is created 7 days from now for 3 days.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div className="space-y-2">
              <Label>Requester (employee requesting leave)</Label>
              <SearchableSelect
                value={requesterId}
                onValueChange={setRequesterId}
                options={employees}
                placeholder="Select requester"
                searchPlaceholder="Search employee..."
              />
            </div>

            <div className="space-y-2">
              <Label>Reliever (employee covering)</Label>
              <SearchableSelect
                value={relieverId}
                onValueChange={setRelieverId}
                options={employees.filter((e) => e.value !== requesterId)}
                placeholder="Select reliever"
                searchPlaceholder="Search employee..."
              />
            </div>

            <div className="space-y-2">
              <Label>Leave Type</Label>
              <Select value={leaveTypeId} onValueChange={setLeaveTypeId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select leave type" />
                </SelectTrigger>
                <SelectContent>
                  {leaveTypes.map((t) => (
                    <SelectItem key={t.value} value={t.value}>
                      {t.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex items-end gap-3 pb-1">
              <Switch checked={cleanup} onCheckedChange={setCleanup} id="cleanup-toggle" />
              <Label htmlFor="cleanup-toggle" className="cursor-pointer">
                Delete test request after run
              </Label>
            </div>
          </div>

          <div className="flex items-center gap-4 pt-2">
            <Button
              onClick={runTest}
              disabled={running || !requesterId || !relieverId || !leaveTypeId}
              className="gap-2"
            >
              {running ? <Loader2 className="h-4 w-4 animate-spin" /> : <PlayCircle className="h-4 w-4" />}
              {running ? "Running…" : "Run Full Flow Test"}
            </Button>

            {result && (
              <div className="flex gap-3 text-sm">
                <span className="flex items-center gap-1 text-green-600">
                  <CheckCircle className="h-4 w-4" /> {passCount} passed
                </span>
                <span className="flex items-center gap-1 text-red-500">
                  <XCircle className="h-4 w-4" /> {failCount} failed
                </span>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Results */}
      {result && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              {result.ok ? (
                <CheckCircle className="h-5 w-5 text-green-500" />
              ) : (
                <XCircle className="h-5 w-5 text-red-500" />
              )}
              {result.ok ? "All Stages Passed" : "Flow Failed"}
            </CardTitle>
            {result.leave_request_id && (
              <CardDescription>
                Test request preserved (cleanup=off): <code className="text-xs">{result.leave_request_id}</code>
              </CardDescription>
            )}
            {result.error && <p className="text-destructive text-sm">{result.error}</p>}
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {result.steps.map((step, i) => (
                <div
                  key={i}
                  className={cn(
                    "flex items-start gap-3 rounded-md border px-3 py-2 text-sm",
                    step.status === "ok" && "border-green-200 bg-green-50 dark:border-green-800 dark:bg-green-950/30",
                    step.status === "error" && "border-red-200 bg-red-50 dark:border-red-800 dark:bg-red-950/30",
                    step.status === "skipped" && "bg-muted/40 border-dashed"
                  )}
                >
                  <div className="mt-0.5 shrink-0">
                    {step.status === "ok" && <CheckCircle className="h-4 w-4 text-green-600" />}
                    {step.status === "error" && <XCircle className="h-4 w-4 text-red-500" />}
                    {step.status === "skipped" && <SkipForward className="text-muted-foreground h-4 w-4" />}
                  </div>
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2">
                      <code className="text-xs font-medium">{step.step}</code>
                      <Badge
                        variant={
                          step.status === "ok" ? "default" : step.status === "error" ? "destructive" : "secondary"
                        }
                        className="text-xs"
                      >
                        {step.status}
                      </Badge>
                    </div>
                    {step.detail && <p className="text-muted-foreground mt-0.5 text-xs">{step.detail}</p>}
                    {step.data !== undefined && (
                      <pre className="bg-muted mt-1 max-h-32 overflow-auto rounded p-2 text-xs">
                        {JSON.stringify(step.data as Record<string, unknown>, null, 2)}
                      </pre>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Route Diagnostics card */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Route className="h-5 w-5" />
            Route Diagnostics
          </CardTitle>
          <CardDescription>
            Checks every approval stage in your DB and reports which roles are missing an assigned approver. Run this
            first to understand what needs configuring before running the flow test.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center gap-4">
            <Button onClick={runDiagnostics} disabled={diagnosticsRunning} className="gap-2">
              {diagnosticsRunning ? <Loader2 className="h-4 w-4 animate-spin" /> : <Route className="h-4 w-4" />}
              {diagnosticsRunning ? "Checking…" : "Check All Routes"}
            </Button>

            {diagnosticsResult && (
              <span className={cn("text-sm font-medium", brokenRoutesCount === 0 ? "text-green-600" : "text-red-500")}>
                {brokenRoutesCount === 0
                  ? `✓ All ${diagnosticsResult.total} stage(s) configured`
                  : `✗ ${brokenRoutesCount} of ${diagnosticsResult.total} stage(s) broken`}
              </span>
            )}
          </div>

          {diagnosticsResult && Object.keys(diagByKind).length > 0 && (
            <div className="space-y-4">
              {Object.entries(diagByKind).map(([kind, rows]) => {
                const broken = rows.filter((r) => !r.resolved)
                return (
                  <div key={kind}>
                    <div className="mb-1 flex items-center gap-2">
                      <span className="text-sm font-semibold capitalize">{kind.replace(/_/g, " ")}</span>
                      {broken.length > 0 ? (
                        <Badge variant="destructive" className="text-xs">
                          {broken.length} broken
                        </Badge>
                      ) : (
                        <Badge variant="default" className="text-xs">
                          OK
                        </Badge>
                      )}
                    </div>
                    <div className="space-y-1">
                      {rows.map((row, i) => (
                        <div
                          key={i}
                          className={cn(
                            "rounded-md border px-3 py-2 text-xs",
                            row.resolved
                              ? "border-green-200 bg-green-50 dark:border-green-800 dark:bg-green-950/30"
                              : "border-red-200 bg-red-50 dark:border-red-800 dark:bg-red-950/30"
                          )}
                        >
                          <div className="flex items-start gap-2">
                            {row.resolved ? (
                              <CheckCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-green-600" />
                            ) : (
                              <XCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-red-500" />
                            )}
                            <div className="min-w-0 flex-1">
                              <span className="font-mono font-medium">
                                Stage {row.stage_order}: {row.approver_role_code}
                              </span>
                              {row.resolved ? (
                                <span className="text-muted-foreground ml-2">
                                  → {row.resolved_name || row.resolved_user_id}
                                </span>
                              ) : (
                                <div className="mt-1 space-y-1">
                                  <p className="text-red-600 dark:text-red-400">{row.fail_reason}</p>
                                  {FIX_HINTS[row.approver_role_code] && (
                                    <p className="text-amber-700 dark:text-amber-400">
                                      <strong>Fix:</strong> {FIX_HINTS[row.approver_role_code]}
                                    </p>
                                  )}
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { useState } from "react"
import { useQuery } from "@tanstack/react-query"
import { createClient } from "@/lib/supabase/client"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Star, FileText } from "lucide-react"
import { useRouter } from "next/navigation"
import { toast } from "sonner"
import { PageHeader } from "@/components/layout/page-header"
import { FormFieldGroup } from "@/components/ui/patterns"
import { QUERY_KEYS } from "@/lib/query-keys"
import { PageLoader } from "@/components/ui/query-states"

import { logger } from "@/lib/logger"

const log = logger("hr-performance-create")

interface User {
  id: string
  first_name: string
  last_name: string
  department_id: string
}

interface ReviewCycle {
  id: string
  name: string
  review_type: string
}

interface PerformanceCreateData {
  users: User[]
  cycles: ReviewCycle[]
}

async function fetchPerformanceCreateData(supabase: ReturnType<typeof createClient>): Promise<PerformanceCreateData> {
  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) throw new Error("Not authenticated")

  const { data: profile } = await supabase
    .from("profiles")
    .select("role, is_department_lead, department_id")
    .eq("id", user.id)
    .single()

  let usersQuery = supabase.from("profiles").select("id, first_name, last_name, department_id").neq("id", user.id)

  if (profile?.is_department_lead && !["developer", "admin", "super_admin"].includes(profile.role)) {
    usersQuery = usersQuery.eq("department_id", profile.department_id)
  }

  const { data: usersData } = await usersQuery

  const cyclesResponse = await fetch("/api/hr/performance/cycles")
  const cyclesData = await cyclesResponse.json()

  return {
    users: usersData || [],
    cycles: cyclesData.cycles || [],
  }
}

export default function CreateReviewPage() {
  const router = useRouter()
  const supabase = createClient()
  const [saving, setSaving] = useState(false)
  const [formData, setFormData] = useState({
    user_id: "",
    review_cycle_id: "",
    overall_rating: 0,
    strengths: "",
    areas_for_improvement: "",
    goals_achieved: 0,
    goals_total: 0,
    manager_comments: "",
  })

  const { data, isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.performanceCreateData(),
    queryFn: () => fetchPerformanceCreateData(supabase),
  })

  const users = data?.users ?? []
  const cycles = data?.cycles ?? []

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setSaving(true)

    try {
      const response = await fetch("/api/hr/performance/reviews", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      })

      const responseData = await response.json()

      if (!response.ok) {
        throw new Error(responseData.error || "Failed to create review")
      }

      toast.success("Performance review created successfully")

      router.push("/hr")
    } catch (error: any) {
      toast.error(error.message)
    } finally {
      setSaving(false)
    }
  }

  function renderRatingSelector() {
    return (
      <div className="flex gap-2">
        {[1, 2, 3, 4, 5].map((rating) => (
          <button
            key={rating}
            type="button"
            onClick={() => setFormData({ ...formData, overall_rating: rating })}
            className="p-1"
          >
            <Star
              className={`h-8 w-8 transition-colors ${
                rating <= formData.overall_rating
                  ? "fill-yellow-500 text-yellow-500"
                  : "text-gray-300 hover:text-yellow-300"
              }`}
            />
          </button>
        ))}
      </div>
    )
  }

  if (loading) return <PageLoader />

  return (
    <div className="container mx-auto max-w-2xl p-6">
      <PageHeader
        title="Create Performance Review"
        description="Evaluate an employee's performance"
        backLink={{ href: "/admin/hr", label: "Back to HR Dashboard" }}
        className="mb-6"
      />

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            Review Form
          </CardTitle>
          <CardDescription>Complete review details and submit for records.</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Employee Selection */}
            <FormFieldGroup label="Employee">
              <Select value={formData.user_id} onValueChange={(value) => setFormData({ ...formData, user_id: value })}>
                <SelectTrigger>
                  <SelectValue placeholder="Select employee" />
                </SelectTrigger>
                <SelectContent>
                  {users.map((user) => (
                    <SelectItem key={user.id} value={user.id}>
                      {user.first_name} {user.last_name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </FormFieldGroup>

            {/* Review Cycle */}
            <FormFieldGroup label="Review Cycle">
              <Select
                value={formData.review_cycle_id}
                onValueChange={(value) => setFormData({ ...formData, review_cycle_id: value })}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select review cycle" />
                </SelectTrigger>
                <SelectContent>
                  {cycles.map((cycle) => (
                    <SelectItem key={cycle.id} value={cycle.id}>
                      {cycle.name} ({cycle.review_type})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </FormFieldGroup>

            {/* Overall Rating */}
            <FormFieldGroup label="Overall Rating">
              {renderRatingSelector()}
              <p className="text-muted-foreground text-sm">
                {formData.overall_rating === 0 ? "Click to rate" : `${formData.overall_rating} out of 5`}
              </p>
            </FormFieldGroup>

            {/* Goals */}
            <div className="grid grid-cols-2 gap-4">
              <FormFieldGroup label="Goals Achieved">
                <Input
                  type="number"
                  min="0"
                  value={formData.goals_achieved}
                  onChange={(e) => setFormData({ ...formData, goals_achieved: parseInt(e.target.value) || 0 })}
                />
              </FormFieldGroup>
              <FormFieldGroup label="Total Goals">
                <Input
                  type="number"
                  min="0"
                  value={formData.goals_total}
                  onChange={(e) => setFormData({ ...formData, goals_total: parseInt(e.target.value) || 0 })}
                />
              </FormFieldGroup>
            </div>

            {/* Strengths */}
            <FormFieldGroup label="Strengths">
              <Textarea
                value={formData.strengths}
                onChange={(e) => setFormData({ ...formData, strengths: e.target.value })}
                placeholder="What does this employee do well?"
                rows={3}
              />
            </FormFieldGroup>

            {/* Areas for Improvement */}
            <FormFieldGroup label="Areas for Improvement">
              <Textarea
                value={formData.areas_for_improvement}
                onChange={(e) => setFormData({ ...formData, areas_for_improvement: e.target.value })}
                placeholder="What areas need development?"
                rows={3}
              />
            </FormFieldGroup>

            {/* Manager Comments */}
            <FormFieldGroup label="Additional Comments">
              <Textarea
                value={formData.manager_comments}
                onChange={(e) => setFormData({ ...formData, manager_comments: e.target.value })}
                placeholder="Any other feedback or notes..."
                rows={3}
              />
            </FormFieldGroup>

            <Button type="submit" className="w-full" disabled={saving || !formData.user_id || !formData.overall_rating}>
              {saving ? "Saving..." : "Submit Review"}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { useState } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
