const log = logger("reports-action-tracker-action-tracker-co")

interface ActionTask {
  id: string
  title: string
  description?: string
  status: string
  priority: string
  department: string
  due_date?: string
  week_number: number
  year: number
  original_week?: number
  work_item_number?: string
}

interface ActionTrackerContentProps {
  initialDepartments: string[]
  scopedDepartments?: string[]
  editableDepartments?: string[]
  canGlobalEdit?: boolean
}

async function fetchAdminActionTrackerTasks(
  supabase: ReturnType<typeof createClient>,
  weekFilter: number,
  yearFilter: number,
  deptFilter: string,
  scopedDepartments: string[]
): Promise<ActionTask[]> {
  let query = supabase
    .from("tasks")
    .select("*")
    .eq("category", "weekly_action")
    .eq("week_number", weekFilter)
    .eq("year", yearFilter)
    .order("department", { ascending: true })
    .order("created_at", { ascending: true })

  if (scopedDepartments.length > 0) {
    query = query.in("department", scopedDepartments)
  }

  if (deptFilter !== "all") {
    query = query.eq("department", deptFilter)
  }

  const { data, error } = await query
  if (error) throw new Error(error.message)
  return data || []
}

export function ActionTrackerContent({
  initialDepartments,
  scopedDepartments = [],
  editableDepartments = [],
  canGlobalEdit = false,
}: ActionTrackerContentProps) {
  const currentOfficeWeek = getCurrentOfficeWeek()
  const searchParams = useSearchParams()
  const queryClient = useQueryClient()
  const [expandedDepts, setExpandedDepts] = useState<Set<string>>(new Set())
  const [isFormOpen, setIsFormOpen] = useState(false)
  const [editingTask, setEditingTask] = useState<ActionTask | null>(null)

  const [weekFilter, setWeekFilter] = useState(() => {
    const w = searchParams.get("week")
    return w ? parseInt(w) : currentOfficeWeek.week
  })
  const [yearFilter, setYearFilter] = useState(() => {
    const y = searchParams.get("year")
    return y ? parseInt(y) : currentOfficeWeek.year
  })
  const [deptFilter, setDeptFilter] = useState(() => {
    const d = searchParams.get("dept")
    return d || "all"
  })
  const [searchQuery, setSearchQuery] = useState("")
  const [pendingDeleteId, setPendingDeleteId] = useState<string | null>(null)

  const supabase = createClient()
  const canMutateTask = (task: ActionTask) => canGlobalEdit || editableDepartments.includes(task.department)

  const {
    data: tasks = [],
    isLoading: loading,
    refetch: refetchTasks,
  } = useQuery({
    queryKey: QUERY_KEYS.adminActionTrackerTasks({ weekFilter, yearFilter, deptFilter, scopedDepartments }),
    queryFn: () => fetchAdminActionTrackerTasks(supabase, weekFilter, yearFilter, deptFilter, scopedDepartments),
  })

  const { data: lockState } = useQuery({
    queryKey: QUERY_KEYS.adminWeeklyReportLockState(weekFilter, yearFilter),
    queryFn: () => fetchWeeklyReportLockState(supabase, weekFilter, yearFilter),
  })

  const tasksQueryKey = QUERY_KEYS.adminActionTrackerTasks({ weekFilter, yearFilter, deptFilter, scopedDepartments })

  const handleStatusChange = async (taskId: string, newStatus: string) => {
    const targetTask = tasks.find((task) => task.id === taskId)
    if (targetTask && !canMutateTask(targetTask)) {
      toast.error("You can only edit actions in your departments")
      return
    }

    const previousTasks = [...tasks]
    queryClient.setQueryData(
      tasksQueryKey,
      tasks.map((t) => (t.id === taskId ? { ...t, status: newStatus } : t))
    )

    try {
      const { error } = await supabase
        .from("tasks")
        .update({ status: newStatus, updated_at: new Date().toISOString() })
        .eq("id", taskId)

      if (error) throw error
      toast.success("Status updated")
    } catch (error) {
      log.error({ err: String(error) }, "error")
      queryClient.setQueryData(tasksQueryKey, previousTasks)
      toast.error("Failed to update status")
    }
  }

  const handleDelete = async (id: string) => {
    const targetTask = tasks.find((task) => task.id === id)
    if (targetTask && !canMutateTask(targetTask)) {
      toast.error("You can only delete actions in your departments")
      return
    }
    try {
      const { error } = await supabase.from("tasks").delete().eq("id", id)
      if (error) throw error
      toast.success("Action deleted")
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminActionTrackerTasks() })
    } catch {
      toast.error("Failed to delete")
    }
  }

  const handleEdit = (task: ActionTask) => {
    if (!canMutateTask(task)) {
      toast.error("You can only edit actions in your departments")
      return
    }
    setEditingTask(task)
    setIsFormOpen(true)
  }

  const toggleDept = (dept: string) => {
    const next = new Set(expandedDepts)
    if (next.has(dept)) next.delete(dept)
    else next.add(dept)
    setExpandedDepts(next)
  }

  const filteredTasks = tasks.filter(
    (t) =>
      t.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      t.description?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      t.department.toLowerCase().includes(searchQuery.toLowerCase())
  )

  const stats = {
    total: tasks.length,
    completed: tasks.filter((t) => t.status === "completed").length,
    pending: tasks.filter((t) => t.status !== "completed").length,
    notStarted: tasks.filter((t) => t.status === "not_started").length,
    inProgress: tasks.filter((t) => t.status === "in_progress").length,
  }

  const getDeptStatus = (dept: string) => {
    const deptActions = tasks.filter((t) => t.department === dept)
    if (deptActions.length === 0)
      return { label: "Pending", color: "bg-slate-100 text-slate-600 dark:bg-slate-900/40 dark:text-slate-400" }
    if (deptActions.every((a) => a.status === "completed"))
      return { label: "Finished", color: "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" }
    if (deptActions.some((a) => a.status === "in_progress" || a.status === "completed"))
      return { label: "Started", color: "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400" }
    return { label: "Pending", color: "bg-slate-100 text-slate-600 dark:bg-slate-900/40 dark:text-slate-400" }
  }

  const statusColor = (status: string) => {
    if (status === "completed") return "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400"
    if (status === "in_progress") return "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400"
    if (status === "not_started") return "bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400"
    return "bg-slate-100 text-slate-600 dark:bg-slate-900/40 dark:text-slate-400"
  }

  const actionItemsForExport: ActionItem[] = tasks.map((t) => ({
    id: t.id,
    title: t.title,
    description: t.description,
    department: t.department,
    status: t.status,
    week_number: t.week_number,
    year: t.year,
  }))

  return (
    <AdminTablePage
      title="Action Tracker"
      description="Monitor and manage weekly departmental actions"
      icon={FileSpreadsheet}
      backLinkHref="/admin/reports"
      backLinkLabel="Back to Reports"
      actions={
        tasks.length > 0 ? (
          <ActionTrackerExportButtons
            items={actionItemsForExport}
            weekFilter={weekFilter}
            yearFilter={yearFilter}
            meetingDate={lockState?.meetingDate}
          />
        ) : null
      }
      stats={
        <ActionTrackerStats
          total={stats.total}
          completed={stats.completed}
          pending={stats.pending}
          notStarted={stats.notStarted}
          inProgress={stats.inProgress}
        />
      }
      filters={
        <ActionTrackerFilters
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          weekFilter={weekFilter}
          onWeekChange={setWeekFilter}
          yearFilter={yearFilter}
          onYearChange={setYearFilter}
          deptFilter={deptFilter}
          onDeptChange={setDeptFilter}
          departments={initialDepartments}
          loading={loading}
          onRefresh={() => refetchTasks()}
        />
      }
    >
      <ActionTrackerTable
        tasks={filteredTasks}
        loading={loading}
        expandedDepts={expandedDepts}
        onToggleDept={toggleDept}
        weekFilter={weekFilter}
        yearFilter={yearFilter}
        meetingDate={lockState?.meetingDate}
        canMutateTask={canMutateTask}
        onStatusChange={handleStatusChange}
        onEdit={handleEdit}
        onDeleteRequest={setPendingDeleteId}
        getDeptStatus={getDeptStatus}
        statusColor={statusColor}
      />

      <ActionFormDialog
        isOpen={isFormOpen}
        onClose={() => setIsFormOpen(false)}
        onComplete={() => queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminActionTrackerTasks() })}
        departments={canGlobalEdit ? initialDepartments : editableDepartments}
        editingAction={editingTask}
        defaultWeek={weekFilter}
        defaultYear={yearFilter}
      />

      <AlertDialog open={pendingDeleteId !== null} onOpenChange={(open) => !open && setPendingDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Action</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this action? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                if (pendingDeleteId) handleDelete(pendingDeleteId)
                setPendingDeleteId(null)
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AdminTablePage>
  )
}

import { Suspense } from "react"
import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { ActionTrackerContent } from "./action-tracker-content"
import { resolveAdminScope } from "@/lib/admin/rbac"

export default async function ActionTrackerPage() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    redirect("/auth/login")
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    redirect("/profile")
  }

  // Fetch departments for filtering
  const { data: employeeData } = await dataClient.from("profiles").select("department").not("department", "is", null)

  const departments = Array.from(new Set(employeeData?.map((s: any) => s.department).filter(Boolean))) as string[]
  departments.sort()

  return (
    <Suspense fallback={<div className="flex justify-center py-20">Loading Tracker...</div>}>
      <ActionTrackerContent
        initialDepartments={departments}
        scopedDepartments={[]}
        editableDepartments={scope.isAdminLike ? [] : scope.managedDepartments || []}
        canGlobalEdit={scope.isAdminLike}
      />
    </Suspense>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { WeeklyReportsContent } from "./weekly-reports-content"
import { resolveAdminScope } from "@/lib/admin/rbac"

export default async function WeeklyReportsPage() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    redirect("/auth/login")
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    redirect("/profile")
  }

  // Fetch departments for filtering and presenter options for week setup.
  const { data: employeeData } = await dataClient
    .from("profiles")
    .select("id, full_name, department")
    .not("department", "is", null)

  const departments = Array.from(new Set(employeeData?.map((s: any) => s.department).filter(Boolean))) as string[]
  departments.sort()

  const employees = (employeeData || [])
    .filter((row: any) => row?.id && row?.full_name && row?.department)
    .map((row: any) => ({
      id: String(row.id),
      full_name: String(row.full_name),
      department: String(row.department),
    }))
    .sort((a, b) => a.full_name.localeCompare(b.full_name))

  return (
    <WeeklyReportsContent
      initialDepartments={departments}
      employees={employees}
      scopedDepartments={[]}
      editableDepartments={scope.isAdminLike ? [] : scope.managedDepartments || []}
      currentUser={{
        id: user.id,
        role: scope.role,
        department: scope.department,
        is_department_lead: scope.isDepartmentLead,
        lead_departments: scope.leadDepartments,
        admin_domains: scope.adminDomains,
      }}
    />
  )
}

"use client"

import { useState } from "react"
import { useRouter } from "next/navigation"
import { useQuery } from "@tanstack/react-query"
import { QUERY_KEYS } from "@/lib/query-keys"
import { createClient } from "@/lib/supabase/client"
import { PageHeader, PageWrapper } from "@/components/layout"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { UserPlus, Mail } from "lucide-react"
import { toast } from "sonner"
import { getAssignableRolesForActor } from "@/lib/role-management"
import { FormFieldGroup } from "@/components/ui/patterns"

import { logger } from "@/lib/logger"

const log = logger("settings-users-invite")

async function fetchCurrentUserRole(): Promise<string> {
  const supabase = createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) return ""
  const { data: me } = await supabase.from("profiles").select("role").eq("id", user.id).single()
  return me?.role || ""
}

export default function InviteUserPage() {
  const router = useRouter()
  const [sending, setSending] = useState(false)
  const [formData, setFormData] = useState({
    email: "",
    first_name: "",
    last_name: "",
    role: "employee",
    department: "",
  })

  const { data: currentUserRole = "" } = useQuery({
    queryKey: QUERY_KEYS.adminCurrentUserRole(),
    queryFn: fetchCurrentUserRole,
  })

  const roleOptions = getAssignableRolesForActor(currentUserRole)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()

    if (!formData.email) {
      toast.error("Email is required")
      return
    }

    setSending(true)

    try {
      const response = await fetch("/api/admin/users/invite", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      })

      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.error || "Failed to invite user")
      }

      toast.success(`Invitation sent to ${formData.email}`)
      router.push("/admin/settings/users")
    } catch (error: any) {
      log.error("Error inviting user:", error)
      toast.error(error.message || "Failed to invite user")
    } finally {
      setSending(false)
    }
  }

  return (
    <PageWrapper maxWidth="form" background="gradient">
      <PageHeader
        title="Invite User"
        description="Send an invitation to a new team member"
        icon={UserPlus}
        backLink={{ href: "/admin/settings/users", label: "Back to Users" }}
      />
      <form onSubmit={handleSubmit}>
        <Card>
          <CardHeader>
            <CardTitle>User Details</CardTitle>
            <CardDescription>Enter the new user's information</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <FormFieldGroup label="Email Address *">
              <Input
                id="email"
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                placeholder="user@company.com"
                required
              />
            </FormFieldGroup>

            <div className="grid gap-4 sm:grid-cols-2">
              <FormFieldGroup label="First Name">
                <Input
                  id="first_name"
                  value={formData.first_name}
                  onChange={(e) => setFormData({ ...formData, first_name: e.target.value })}
                  placeholder="First name"
                />
              </FormFieldGroup>
              <FormFieldGroup label="Last Name">
                <Input
                  id="last_name"
                  value={formData.last_name}
                  onChange={(e) => setFormData({ ...formData, last_name: e.target.value })}
                  placeholder="Last name"
                />
              </FormFieldGroup>
            </div>

            <div className="grid gap-4 sm:grid-cols-2">
              <FormFieldGroup label="Role">
                <Select value={formData.role} onValueChange={(v) => setFormData({ ...formData, role: v })}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {roleOptions.map((role) => (
                      <SelectItem key={role} value={role}>
                        {role === "super_admin" ? "Super Admin" : role.charAt(0).toUpperCase() + role.slice(1)}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </FormFieldGroup>
              <FormFieldGroup label="Department">
                <Input
                  id="department"
                  value={formData.department}
                  onChange={(e) => setFormData({ ...formData, department: e.target.value })}
                  placeholder="e.g., Engineering"
                />
              </FormFieldGroup>
            </div>
          </CardContent>
        </Card>

        <div className="mt-6 flex justify-end gap-4">
          <Button type="button" variant="outline" onClick={() => router.push("/admin/settings/users")}>
            Cancel
          </Button>
          <Button type="submit" disabled={sending}>
            <Mail className="mr-2 h-4 w-4" />
            Send Invitation
          </Button>
        </div>
      </form>
    </PageWrapper>
  )
}

"use client"

import { useEffect, useState } from "react"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { QUERY_KEYS } from "@/lib/query-keys"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Users, Search, Filter, Shield, UserPlus } from "lucide-react"
import Link from "next/link"
import { toast } from "sonner"
import { AdminTablePage } from "@/components/admin/admin-table-page"
import { StatCard } from "@/components/ui/stat-card"
import { ListToolbar } from "@/components/ui/patterns"
import { useSearchParams } from "next/navigation"
import { logger } from "@/lib/logger"
import { isValidRole } from "./_lib/role-helpers"
import { fetchUsersSettingsData, fetchAllUsersForPicker, formatDate, type User } from "./_lib/queries"
import { EditUserDialog } from "./_components/edit-user-dialog"
import { AddUserToRoleDialog } from "./_components/add-user-to-role-dialog"
import { UsersTable } from "./_components/users-table"

const log = logger("settings-users")

export default function UsersPage() {
  const queryClient = useQueryClient()
  const searchParams = useSearchParams()
  const [searchQuery, setSearchQuery] = useState("")
  const [roleFilter, setRoleFilter] = useState<string>("all")
  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [editingUser, setEditingUser] = useState<User | null>(null)
  const [formData, setFormData] = useState({ role: "", employment_status: "active", admin_domains: [] as string[] })

  const { data: settingsData, isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.adminUsersSettings(),
    queryFn: fetchUsersSettingsData,
  })

  const users: User[] = settingsData?.users ?? []
  const currentUserRole: string = settingsData?.currentUserRole ?? ""

  useEffect(() => {
    const roleParam = searchParams.get("role")
    if (roleParam && (roleParam === "all" || isValidRole(roleParam))) {
      setRoleFilter(roleParam)
    }
  }, [searchParams])

  async function handleUpdateRole(e: React.FormEvent) {
    e.preventDefault()
    if (!editingUser) return
    try {
      if (formData.role === "admin" && formData.admin_domains.length === 0) {
        throw new Error("Admin role requires at least one domain")
      }
      const response = await fetch("/api/admin/users/role", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          targetUserId: editingUser.id,
          role: formData.role,
          employment_status: formData.employment_status,
          admin_domains: formData.role === "admin" ? formData.admin_domains : [],
        }),
      })
      const result = await response.json()
      if (!response.ok) throw new Error(result.error || "Failed to update")
      toast.success("User updated")
      setIsDialogOpen(false)
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminUsersSettings() })
    } catch (error: any) {
      toast.error(error.message || "Failed to update")
    }
  }

  function openEdit(user: User) {
    setEditingUser(user)
    setFormData({
      role: user.role,
      employment_status: user.employment_status || (user.is_active ? "active" : "suspended"),
      admin_domains: Array.isArray(user.admin_domains) ? user.admin_domains : [],
    })
    setIsDialogOpen(true)
  }

  const filtered = users.filter((u) => {
    const name = `${u.first_name || ""} ${u.last_name || ""} ${u.email || ""}`.toLowerCase()
    return name.includes(searchQuery.toLowerCase()) && (roleFilter === "all" || u.role === roleFilter)
  })

  const stats = {
    total: users.length,
    active: users.filter((u) => u.is_active).length,
    admins: users.filter((u) => ["developer", "admin", "super_admin"].includes(u.role)).length,
  }

  const roles = Array.from(new Set(users.map((u) => u.role)))

  const [isAddUserDialogOpen, setIsAddUserDialogOpen] = useState(false)
  const [userToAdd, setUserToAdd] = useState<string>("")
  const [availableUsers, setAvailableUsers] = useState<User[]>([])
  const [addUserWarning, setAddUserWarning] = useState<string | null>(null)

  function openAddUserDialog() {
    fetchAllUsersForPicker().then(setAvailableUsers)
    setAddUserWarning(null)
    setUserToAdd("")
    setIsAddUserDialogOpen(true)
  }

  function handleUserSelect(userId: string) {
    setUserToAdd(userId)
    const user = availableUsers.find((u) => u.id === userId)
    if (!user) return
    if (user.role === roleFilter) {
      setAddUserWarning(`${user.first_name} is already a ${roleFilter}.`)
    } else {
      setAddUserWarning(`User will be removed from "${user.role}" role and assigned to "${roleFilter}".`)
    }
  }

  async function handleAddUserToRole() {
    if (!userToAdd || roleFilter === "all") return
    try {
      const response = await fetch("/api/admin/users/role", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ targetUserId: userToAdd, role: roleFilter }),
      })
      const result = await response.json()
      if (!response.ok) throw new Error(result.error || "Failed to update role")
      toast.success(`User role updated to ${roleFilter}`)
      setIsAddUserDialogOpen(false)
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.adminUsersSettings() })
    } catch (error: any) {
      log.error("Error adding user to role:", error)
      toast.error(error.message || "Failed to update role")
    }
  }

  return (
    <AdminTablePage
      title="User Management"
      description="Manage user accounts and roles."
      icon={Users}
      backLinkHref="/admin/settings"
      backLinkLabel="Back to Settings"
      actions={
        <div className="flex gap-2">
          {roleFilter !== "all" && (
            <Button onClick={openAddUserDialog} variant="secondary">
              <UserPlus className="mr-2 h-4 w-4" />
              Add User to {roleFilter.replace("_", " ")}
            </Button>
          )}
          <Link href="/admin/settings/users/invite">
            <Button>
              <UserPlus className="mr-2 h-4 w-4" />
              Invite User
            </Button>
          </Link>
        </div>
      }
      stats={
        <div className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3 md:gap-4">
          <StatCard title="Total Users" value={stats.total} icon={Users} />
          <StatCard title="Active" value={stats.active} icon={Users} />
          <StatCard title="Admins" value={stats.admins} icon={Shield} />
        </div>
      }
      filters={
        <ListToolbar
          search={
            <div className="relative flex-1">
              <Search className="text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2" />
              <Input
                placeholder="Search by name or email..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9"
              />
            </div>
          }
          filters={
            <Select value={roleFilter} onValueChange={setRoleFilter}>
              <SelectTrigger className="w-[180px]">
                <Filter className="mr-2 h-4 w-4" />
                <SelectValue placeholder="Filter by role" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Roles</SelectItem>
                {roles.map((r) => (
                  <SelectItem key={r} value={r} className="capitalize">
                    {r.replace("_", " ")}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          }
        />
      }
    >
      <UsersTable users={filtered} loading={loading} onEdit={openEdit} formatDate={formatDate} />

      <EditUserDialog
        open={isDialogOpen}
        onOpenChange={setIsDialogOpen}
        editingUser={editingUser}
        formData={formData}
        onFormDataChange={setFormData}
        onSubmit={handleUpdateRole}
        currentUserRole={currentUserRole}
      />

      <AddUserToRoleDialog
        open={isAddUserDialogOpen}
        onOpenChange={setIsAddUserDialogOpen}
        roleFilter={roleFilter}
        userToAdd={userToAdd}
        onUserSelect={handleUserSelect}
        availableUsers={availableUsers}
        addUserWarning={addUserWarning}
        onConfirm={handleAddUserToRole}
      />
    </AdminTablePage>
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"
import {
  AdminTasksContent,
  type Task,
  type employee,
  type Project,
  type UserProfile,
} from "./management/admin-tasks-content"
import { listAssignableProfiles } from "@/lib/workforce/assignment-policy"

import { logger } from "@/lib/logger"

const log = logger("tasks")


async function getAdminTasksData() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return { redirect: "/auth/login" as const }
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return { redirect: "/profile" as const }
  }
  const departmentScope = getDepartmentScope(scope, "general")

  const userProfile: UserProfile = {
    id: user.id,
    role: scope.role,
    department: scope.department,
    lead_departments: scope.leadDepartments,
    managed_departments: scope.managedDepartments,
  }

  // Build query based on role - exclude weekly action tracker items
  const tasksQuery = dataClient
    .from("tasks")
    .select("*")
    .neq("category", "weekly_action")
    .order("created_at", { ascending: false })

  // Fetch employee - leads can only see employee in their departments
  const [tasksResult, employeeResult, projectsResult] = await Promise.all([
    tasksQuery,
    listAssignableProfiles(dataClient, {
      select:
        "id, first_name, last_name, company_email, department, employment_status, is_department_lead, lead_departments",
      departmentScope,
      allowLegacyNullStatus: false,
    }),
    dataClient.from("projects").select("id, project_name").order("project_name", { ascending: true }),
  ])

  if (tasksResult.error || employeeResult.error || projectsResult.error) {
    log.error("Error loading data:", tasksResult.error || employeeResult.error || projectsResult.error)
    return { tasks: [], employee: [], projects: [], departments: [], userProfile }
  }

  // 1. Collect all IDs for batch queries
  const allTaskIds = tasksResult.data?.map((t: any) => t.id) || []
  const allIndivUserIds = Array.from(
    new Set(
      tasksResult.data
        ?.filter((t: any) => t.assignment_type === "individual" && t.assigned_to)
        .map((t: any) => t.assigned_to) || []
    )
  ) as string[]

  // 2. Fetch profiles for individual assignments
  const { data: indivProfiles } =
    allIndivUserIds.length > 0
      ? await dataClient.from("profiles").select("id, first_name, last_name, department").in("id", allIndivUserIds)
      : { data: [] }
  const indivProfileMap = new Map(indivProfiles?.map((p: any) => [p.id, p]))

  // 3. Fetch task assignments for multiple tasks
  const multTaskIds = tasksResult.data?.filter((t: any) => t.assignment_type === "multiple").map((t: any) => t.id) || []
  const { data: allTaskAssignments } =
    multTaskIds.length > 0
      ? await dataClient.from("task_assignments").select("task_id, user_id").in("task_id", multTaskIds)
      : { data: [] }

  // 4. Fetch profiles for multiple assigned users
  const multUserIds = Array.from(new Set(allTaskAssignments?.map((a: any) => a.user_id) || []))
  const { data: multProfiles } =
    multUserIds.length > 0
      ? await dataClient.from("profiles").select("id, first_name, last_name, department").in("id", multUserIds)
      : { data: [] }
  const multProfileMap = new Map(multProfiles?.map((p: any) => [p.id, p]))

  // 5. Fetch all completions
  const { data: allCompletions } =
    allTaskIds.length > 0
      ? await dataClient.from("task_user_completion").select("task_id, user_id").in("task_id", allTaskIds)
      : { data: [] }

  // Grouping logic
  const assignmentsByTask = new Map()
  allTaskAssignments?.forEach((a: any) => {
    if (!assignmentsByTask.has(a.task_id)) assignmentsByTask.set(a.task_id, [])
    assignmentsByTask.get(a.task_id).push(a.user_id)
  })

  const completionsByTask = new Map()
  allCompletions?.forEach((c: any) => {
    if (!completionsByTask.has(c.task_id)) completionsByTask.set(c.task_id, new Set())
    completionsByTask.get(c.task_id).add(c.user_id)
  })

  // 6. Reconstruct tasksWithUsers
  const tasksWithUsers = (tasksResult.data || []).map((task: any) => {
    const taskData: any = { ...task }

    if (task.assignment_type === "individual" && task.assigned_to) {
      taskData.assigned_to_user = indivProfileMap.get(task.assigned_to)
    }

    if (task.assignment_type === "multiple") {
      const userIds = assignmentsByTask.get(task.id) || []
      const taskComps = completionsByTask.get(task.id) || new Set()
      taskData.assigned_users = userIds.map((uid: string) => {
        const prof = multProfileMap.get(uid)
        return {
          ...prof,
          completed: taskComps.has(uid),
        }
      })
    }
    return taskData
  })

  // For leads, filter tasks strictly by their departments
  let filteredTasks = tasksWithUsers || []
  if (departmentScope) {
    filteredTasks = filteredTasks.filter((task: any) => {
      if (task.department && departmentScope.includes(task.department)) {
        return true
      }
      if (task.assigned_to_user?.department && departmentScope.includes(task.assigned_to_user.department)) {
        return true
      }
      if (task.assigned_users && task.assigned_users.length > 0) {
        return task.assigned_users.some((u: any) => u.department && departmentScope.includes(u.department))
      }
      return false
    })
  }

  // Get unique departments
  let departments: string[] = []
  if (departmentScope) {
    departments = [...departmentScope].sort()
  } else {
    departments = Array.from(new Set(employeeResult.data?.map((s: any) => s.department).filter(Boolean))) as string[]
    departments.sort()
  }

  return {
    tasks: filteredTasks as Task[],
    employee: (employeeResult.data || []) as employee[],
    projects: (projectsResult.data || []) as Project[],
    departments,
    userProfile,
  }
}

export default async function AdminTasksPage() {
  const data = await getAdminTasksData()

  if ("redirect" in data && data.redirect) {
    redirect(data.redirect)
  }

  const pageData = data as {
    tasks: Task[]
    employee: employee[]
    projects: Project[]
    departments: string[]
    userProfile: UserProfile
  }

  return (
    <AdminTasksContent
      initialTasks={pageData.tasks}
      initialemployee={pageData.employee}
      initialProjects={pageData.projects}
      initialDepartments={pageData.departments}
      userProfile={pageData.userProfile}
    />
  )
}

import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { AdminCorrespondenceContent } from "../../correspondence/admin-correspondence-content"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"

async function getData() {
  const supabase = await createClient()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) {
    return { redirectTo: "/auth/login" as const }
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return { redirectTo: "/profile" as const }
  }

  const departmentScope = getDepartmentScope(scope, "general")

  const recordsQuery = dataClient.from("correspondence_records").select("*").order("created_at", { ascending: false })

  let employeesQuery = dataClient
    .from("profiles")
    .select("id, first_name, last_name, department, role")
    .order("last_name", { ascending: true })

  if (departmentScope) {
    employeesQuery =
      departmentScope.length > 0
        ? employeesQuery.in("department", departmentScope)
        : employeesQuery.eq("id", "__none__")
  }

  const [{ data: records }, { data: employees }, { data: departmentCodes }] = await Promise.all([
    recordsQuery,
    employeesQuery,
    dataClient
      .from("correspondence_department_codes")
      .select("department_name, department_code, is_active")
      .order("department_name", { ascending: true }),
  ])

  const scopedRecords =
    departmentScope && departmentScope.length > 0
      ? (records || []).filter(
          (record: any) =>
            departmentScope.includes(record.department_name) ||
            departmentScope.includes(record.assigned_department_name)
        )
      : departmentScope
        ? []
        : records || []

  return {
    records: scopedRecords,
    employees: employees || [],
    departmentCodes: departmentCodes || [],
  }
}

export default async function AdminReferenceGeneratorPage() {
  const data = await getData()

  if ("redirectTo" in data) {
    redirect(data.redirectTo || "/auth/login")
  }

  return (
    <AdminCorrespondenceContent
      initialRecords={data.records as any}
      employees={data.employees as any}
      departmentCodes={data.departmentCodes as any}
    />
  )
}

import { createClient } from "@supabase/supabase-js"
import { NextResponse } from "next/server"
import { createClient as createServerClient } from "@/lib/supabase/server"
import { rateLimit, getClientId } from "@/lib/rate-limit"
import { logger } from "@/lib/logger"
import { renderWelcomeEmail } from "@/lib/email-templates/welcome"
import { renderInternalNotificationEmail } from "@/lib/email-templates/internal-notification"
import { resolveActiveLeadRecipients, sendNotificationEmail } from "@/lib/notifications/email-gateway"
import { isSystemNotificationChannelEnabled, resolveChannelEligibleUserIds } from "@/lib/notifications/delivery-policy"
import { withSubjectPrefix } from "@/lib/notifications/subject-policy"
import { syncEmploymentStatusToAuth } from "@/lib/supabase/admin"
import { writeAuditLog } from "@/lib/audit/write-audit"
import { ORG } from "@/config/constants"

const log = logger("approve-user")

export async function POST(req: Request) {
  const rl = rateLimit(`approve-user:${getClientId(req)}`, { limit: 20, windowSec: 600 })
  if (!rl.allowed) {
    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 })
  }

  // 1. Verify Caller is an Admin
  const supabase = await createServerClient()
  const {
    data: { user: caller },
  } = await supabase.auth.getUser()

  if (!caller) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const { data: callerProfile } = await supabase.from("profiles").select("role").eq("id", caller.id).single()
  if (!callerProfile || !["developer", "super_admin", "admin"].includes(callerProfile.role)) {
    return NextResponse.json({ error: "Forbidden: Admin access required" }, { status: 403 })
  }

  log.info({ callerId: caller.id }, "Starting approval process")
  try {
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
    const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

    if (!supabaseUrl || !supabaseServiceKey) {
      log.error("Missing Supabase environment variables")
      return NextResponse.json({ error: "System configuration error: Missing database keys" }, { status: 500 })
    }

    const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey, {
      auth: { autoRefreshToken: false, persistSession: false },
    })

    const body = await req.json()
    const { pendingUserId, employeeId: manualEmployeeId, hireDate } = body

    if (!pendingUserId) {
      return NextResponse.json({ error: "Missing pendingUserId" }, { status: 400 })
    }

    // 1. Fetch Pending User Details
    const { data: pendingUser, error: fetchError } = await supabaseAdmin
      .from("pending_users")
      .select("*")
      .eq("id", pendingUserId)
      .single()

    if (fetchError || !pendingUser) {
      return NextResponse.json({ error: "Pending user not found" }, { status: 404 })
    }

    // 1b. Validate Required Fields
    const requiredFields = ["company_email", "personal_email", "first_name", "last_name", "department", "company_role"]
    const missingFields = requiredFields.filter((field) => !pendingUser[field])

    if (missingFields.length > 0) {
      return NextResponse.json({ error: `Missing required user data: ${missingFields.join(", ")}` }, { status: 422 })
    }

    // 2. Determine Employee ID — use DB sequence for atomic, collision-free generation
    let employeeId = manualEmployeeId
    const currentYear = new Date().getFullYear()

    if (employeeId) {
      const empNumPattern = /^ACOB\/[0-9]{4}\/[0-9]{3}$/
      if (!empNumPattern.test(employeeId)) {
        return NextResponse.json(
          { error: "Employee number must be in format: ACOB/YEAR/NUMBER (e.g., ACOB/2026/058)" },
          { status: 400 }
        )
      }
    }

    if (!employeeId) {
      // next_employee_number() calls nextval() on a sequence — fully atomic, no race condition
      const { data: seqRow, error: seqError } = await supabaseAdmin.rpc("next_employee_number")
      if (seqError || !seqRow) {
        throw new Error(`Failed to generate employee number: ${seqError?.message ?? "unknown error"}`)
      }
      employeeId = seqRow as string
    }

    const tempPassword = `Welcome${currentYear}!`
    const portalUrl = ORG.MAIL_PORTAL_URL

    // 3. Create or Update Auth User
    // First check if user already exists
    const { data: existingProfile } = await supabaseAdmin
      .from("profiles")
      .select("id")
      .eq("company_email", pendingUser.company_email)
      .maybeSingle()

    let authUserId = existingProfile?.id

    if (!authUserId) {
      const { data: newAuthUser, error: authError } = await supabaseAdmin.auth.admin.createUser({
        email: pendingUser.company_email,
        password: tempPassword,
        email_confirm: true,
        user_metadata: {
          first_name: pendingUser.first_name,
          last_name: pendingUser.last_name,
          full_name: `${pendingUser.first_name} ${pendingUser.last_name}`,
        },
      })

      if (authError) {
        throw new Error(`Auth creation failed: ${authError.message}`)
      }
      authUserId = newAuthUser.user.id
    } else {
      const { error: updateAuthError } = await supabaseAdmin.auth.admin.updateUserById(authUserId, {
        password: tempPassword,
        email_confirm: true,
      })
      if (updateAuthError) {
        throw new Error(`Auth update failed: ${updateAuthError.message}`)
      }
    }

    // 4 & 5. Atomically upsert profile + delete from pending_users in one DB transaction.
    // If either step fails, both roll back — no ghost users, no orphaned profiles.
    const { error: approvalError } = await supabaseAdmin.rpc("atomic_complete_user_approval", {
      p_auth_user_id: authUserId,
      p_pending_user_id: pendingUserId,
      p_employee_number: employeeId,
      p_first_name: pendingUser.first_name,
      p_last_name: pendingUser.last_name,
      p_other_names: pendingUser.other_names ?? null,
      p_department: pendingUser.department,
      p_company_role: pendingUser.company_role,
      p_company_email: pendingUser.company_email,
      p_personal_email: pendingUser.personal_email,
      p_phone_number: pendingUser.phone_number ?? null,
      p_additional_phone: pendingUser.additional_phone_number ?? null,
      p_residential_address: pendingUser.residential_address ?? null,
      p_office_location: pendingUser.office_location ?? null,
      p_employment_date: hireDate ?? null,
    })

    if (approvalError) {
      // Clean up orphaned auth user if we just created one
      if (!existingProfile && authUserId) {
        await supabaseAdmin.auth.admin
          .deleteUser(authUserId)
          .catch((e) => log.error({ err: String(e) }, "Failed to clean up orphaned auth user"))
      }
      throw new Error(`Profile creation failed: ${approvalError.message}`)
    }

    // 6. Send Welcome Email
    try {
      const onboardingMailEnabled = await isSystemNotificationChannelEnabled(supabaseAdmin, "onboarding", "email")
      if (onboardingMailEnabled) {
        await sendNotificationEmail({
          to: [pendingUser.personal_email],
          subject: withSubjectPrefix("Onboarding", "Welcome to ACOB - Login Credentials"),
          html: renderWelcomeEmail({ pendingUser, employeeId, tempPassword, portalUrl }),
        })
      }
    } catch (emailError) {
      log.error({ err: String(emailError) }, "Failed to send welcome email")
    }

    // 7. Send Internal Confirmation Email to Department Leads
    try {
      const onboardingMailEnabled = await isSystemNotificationChannelEnabled(supabaseAdmin, "onboarding", "email")
      if (onboardingMailEnabled) {
        const leadRecipients = await resolveActiveLeadRecipients(supabaseAdmin)
        const leadIds = leadRecipients.map((lead) => lead.id)
        const allowedLeadIds = await resolveChannelEligibleUserIds(supabaseAdmin, {
          userIds: leadIds,
          notificationKey: "onboarding",
          channel: "email",
        })
        const allowedIdSet = new Set(allowedLeadIds)
        const leadEmails = leadRecipients.filter((lead) => allowedIdSet.has(lead.id)).flatMap((lead) => lead.emails)

        if (leadEmails.length > 0) {
          await sendNotificationEmail({
            to: leadEmails,
            subject: withSubjectPrefix(
              "Onboarding",
              `New Employee Onboarded - ${pendingUser.first_name.replace(/[\r\n]/g, "")} ${pendingUser.last_name.replace(/[\r\n]/g, "")}`
            ),
            html: renderInternalNotificationEmail({ pendingUser, employeeId }),
          })
        }
      }
    } catch (emailError) {
      log.error({ err: String(emailError) }, "Failed to send stakeholder notification emails")
    }

    // Sync employment_status into JWT metadata so middleware doesn't need a DB query
    await syncEmploymentStatusToAuth(authUserId!, "active")

    // Audit: new employee onboarding is a critical action
    const supabaseForAudit = await createServerClient()
    await writeAuditLog(
      supabaseForAudit,
      {
        action: "create",
        entityType: "profile",
        entityId: authUserId!,
        context: { actorId: caller.id, source: "api" as const },
        newValues: {
          employee_number: employeeId,
          company_email: pendingUser.company_email,
          department: pendingUser.department,
          role: "employee",
          employment_status: "active",
        },
        metadata: { source: "approve-user", pending_user_id: pendingUserId },
      },
      { failOpen: true }
    )

    return NextResponse.json({ success: true, employeeId })
  } catch (error: any) {
    log.error({ err: String(error) }, "Approval process failed")
    // Redact internal error details from the client
    const message = error.message?.includes("Auth creation failed")
      ? error.message
      : "An unexpected error occurred during the approval process. Please check system logs."
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { canAccessAdminSection, resolveAdminScope } from "@/lib/admin/rbac"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { createClient } from "@/lib/supabase/server"
import { writeAuditLog } from "@/lib/audit/write-audit"

type AssignmentType = "individual" | "department" | "office"

interface AssetFormPayload {
  asset_type: string
  acquisition_year: number
  asset_model?: string
  serial_number?: string
  status: string
  notes?: string
  assignment_type: AssignmentType
  assigned_to?: string
  assignment_department?: string
  office_location?: string
  assignment_notes?: string
  assigned_by?: string
  assigned_at?: string
}

interface SaveAssetPayload {
  mode: "create" | "update"
  assetForm: AssetFormPayload
  quantity?: number
  selectedAsset?: {
    id: string
    status: string
  } | null
  originalAssetForm?: {
    assigned_to?: string
    assignment_department?: string
    office_location?: string
  } | null
}

async function buildAssignmentData(
  dataClient: any,
  assetId: string,
  userId: string,
  form: AssetFormPayload
): Promise<{ ok: true; data: Record<string, any> } | { ok: false; error: string }> {
  if (form.assignment_type === "individual" && !form.assigned_to) {
    return { ok: false, error: "Please select a user" }
  }
  if (form.assignment_type === "department" && !form.assignment_department) {
    return { ok: false, error: "Please select a department" }
  }
  if (form.assignment_type === "office" && !form.office_location) {
    return { ok: false, error: "Please select an office location" }
  }

  const assignment: Record<string, any> = {
    asset_id: assetId,
    assigned_by: form.assigned_by || userId,
    assigned_at: form.assigned_at ? new Date(form.assigned_at).toISOString() : new Date().toISOString(),
    is_current: true,
    assignment_notes: form.assignment_notes || null,
    assignment_type: form.assignment_type,
  }

  if (form.assignment_type === "individual") {
    assignment.assigned_to = form.assigned_to
    const { data: profile, error } = await dataClient
      .from("profiles")
      .select("department")
      .eq("id", form.assigned_to)
      .single()
    if (error) return { ok: false, error: `Failed to resolve assignee department: ${error.message}` }
    assignment.department = profile?.department || null
  } else if (form.assignment_type === "department") {
    assignment.department = form.assignment_department
  } else if (form.assignment_type === "office") {
    assignment.office_location = form.office_location
  }

  return { ok: true, data: assignment }
}

async function closeCurrentAssetAssignments(dataClient: any, assetId: string, handoverNotes: string): Promise<void> {
  const { error: closeError } = await dataClient
    .from("asset_assignments")
    .update({
      is_current: false,
      handed_over_at: new Date().toISOString(),
      handover_notes: handoverNotes,
    })
    .eq("asset_id", assetId)
    .eq("is_current", true)

  if (closeError) {
    throw new Error(`Failed to close current assignment: ${closeError.message}`)
  }
}

export async function POST(request: NextRequest) {
  const supabase = await createClient()
  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope || !scope.isAdminLike || !canAccessAdminSection(scope, "assets")) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const payload = (await request.json().catch(() => null)) as SaveAssetPayload | null
  const mode = payload?.mode
  const form = payload?.assetForm

  if (!mode || !form) {
    return NextResponse.json({ error: "Invalid payload" }, { status: 400 })
  }

  if (!String(form.asset_type || "").trim()) {
    return NextResponse.json({ error: "Please select an asset type" }, { status: 400 })
  }

  const dataClient = getServiceRoleClientOrFallback(supabase as any)
  const createdCodes: string[] = []

  try {
    if (mode === "update") {
      const selected = payload?.selectedAsset
      if (!selected?.id) {
        return NextResponse.json({ error: "Asset id is required for update" }, { status: 400 })
      }

      const { error: updateError } = await dataClient
        .from("assets")
        .update({
          status: form.status,
          notes: form.notes || null,
          asset_model: form.asset_model || null,
          serial_number: form.serial_number || null,
          acquisition_year: form.acquisition_year,
        })
        .eq("id", selected.id)

      if (updateError) throw new Error(updateError.message)

      if (selected.status === "assigned" && form.status !== "assigned") {
        await closeCurrentAssetAssignments(dataClient, selected.id, `Status changed to ${form.status}`)
      }

      const original = payload?.originalAssetForm || {}
      const isAssigneeChanged =
        selected.status === "assigned" &&
        form.status === "assigned" &&
        (form.assigned_to !== (original.assigned_to || "") ||
          form.assignment_department !== (original.assignment_department || "") ||
          form.office_location !== (original.office_location || ""))

      if (isAssigneeChanged) {
        const assignmentData = await buildAssignmentData(dataClient, selected.id, user.id, form)
        if (!assignmentData.ok) return NextResponse.json({ error: assignmentData.error }, { status: 400 })

        const { error: rpcError } = await dataClient.rpc("reassign_asset", {
          p_asset_id: selected.id,
          p_new_assignment_type: form.assignment_type,
          p_assigned_to: assignmentData.data.assigned_to || null,
          p_department: assignmentData.data.department || null,
          p_office_location: assignmentData.data.office_location || null,
          p_assigned_by: assignmentData.data.assigned_by,
          p_assigned_at: assignmentData.data.assigned_at,
          p_assignment_notes: assignmentData.data.assignment_notes,
          p_handover_notes: "Reassigned via Edit",
          p_new_status: form.status,
        })
        if (rpcError) throw new Error(rpcError.message)
      } else if (selected.status !== "assigned" && form.status === "assigned") {
        const assignmentData = await buildAssignmentData(dataClient, selected.id, user.id, form)
        if (!assignmentData.ok) return NextResponse.json({ error: assignmentData.error }, { status: 400 })

        await closeCurrentAssetAssignments(dataClient, selected.id, "Reassigned via Edit")

        const { error: assignError } = await dataClient.from("asset_assignments").insert(assignmentData.data)
        if (assignError) throw new Error(assignError.message)

        const { error: assetFieldsError } = await dataClient
          .from("assets")
          .update({
            assignment_type: form.assignment_type,
            department: assignmentData.data.department || null,
            office_location: assignmentData.data.office_location || null,
          })
          .eq("id", selected.id)
        if (assetFieldsError) throw new Error(assetFieldsError.message)
      }

      return NextResponse.json({ message: "Asset updated successfully" })
    }

    const rawQuantity = Number(payload?.quantity ?? 1)
    if (!Number.isInteger(rawQuantity) || rawQuantity < 1 || rawQuantity > 100) {
      return NextResponse.json({ error: "Quantity must be an integer between 1 and 100" }, { status: 400 })
    }
    const quantity = rawQuantity

    if (quantity > 1 && String(form.serial_number || "").trim()) {
      return NextResponse.json(
        { error: "Serial number cannot be set when creating multiple assets in one batch" },
        { status: 400 }
      )
    }

    const { data: latestAsset, error: latestError } = await dataClient
      .from("assets")
      .select("acquisition_year")
      .eq("asset_type", form.asset_type)
      .order("acquisition_year", { ascending: false })
      .limit(1)
      .maybeSingle()
    if (latestError) throw new Error(latestError.message)

    if (latestAsset && form.acquisition_year < Number(latestAsset.acquisition_year || 0)) {
      return NextResponse.json(
        { error: `Year must be ${latestAsset.acquisition_year} or later for this asset type.` },
        { status: 400 }
      )
    }

    for (let i = 0; i < quantity; i++) {
      const { data: uniqueCodeData, error: serialError } = await dataClient.rpc("get_next_asset_serial", {
        asset_code: form.asset_type,
        year: form.acquisition_year,
      })
      if (serialError) throw new Error(serialError.message)

      const { data: newAsset, error: insertError } = await dataClient
        .from("assets")
        .insert({
          asset_type: form.asset_type,
          acquisition_year: form.acquisition_year,
          unique_code: uniqueCodeData,
          status: form.status,
          notes: form.notes || null,
          asset_model: form.asset_model || null,
          serial_number: quantity === 1 ? form.serial_number || null : null,
          created_by: user.id,
        })
        .select("id")
        .single()
      if (insertError) throw new Error(insertError.message)

      if (form.status === "assigned" && newAsset?.id) {
        const assignmentData = await buildAssignmentData(dataClient, newAsset.id, user.id, form)
        if (!assignmentData.ok) return NextResponse.json({ error: assignmentData.error }, { status: 400 })

        const { error: assignError } = await dataClient.from("asset_assignments").insert(assignmentData.data)
        if (assignError) throw new Error(assignError.message)

        const { error: assetFieldsError } = await dataClient
          .from("assets")
          .update({
            assignment_type: form.assignment_type,
            department: assignmentData.data.department || null,
            office_location: assignmentData.data.office_location || null,
          })
          .eq("id", newAsset.id)
        if (assetFieldsError) throw new Error(assetFieldsError.message)
      }

      createdCodes.push(String(uniqueCodeData || ""))
    }

    const message =
      quantity === 1
        ? `Asset created successfully: ${createdCodes[0]}`
        : `${quantity} assets created successfully (${createdCodes[0]} - ${createdCodes[createdCodes.length - 1]})`

    await writeAuditLog(
      supabase,
      {
        action: "create",
        entityType: "asset",
        entityId: createdCodes[0] || "bulk",
        newValues: { asset_type: form.asset_type, quantity, createdCodes },
        context: { actorId: user.id, source: "api", route: "/api/admin/assets" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ message, createdCodes, createdCount: createdCodes.length })
  } catch (error: any) {
    const baseError = error?.message || "Failed to save asset"
    const errorMessage =
      createdCodes.length > 0 ? `Created ${createdCodes.length} asset(s) before failure. ${baseError}` : baseError
    return NextResponse.json({ error: errorMessage }, { status: 500 })
  }
}

import { NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"
import { listAssignableProfiles } from "@/lib/workforce/assignment-policy"

export async function GET() {
  const supabase = await createClient()
  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const departmentScope = getDepartmentScope(scope, "general")

  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  let { data: assetsData, error: assetsError } = await dataClient
    .from("assets")
    .select("*")
    .order("created_at", { ascending: false })

  if (assetsError && dataClient !== supabase) {
    const fallback = await supabase.from("assets").select("*").order("created_at", { ascending: false })
    assetsData = fallback.data
    assetsError = fallback.error
  }

  if (assetsError) {
    return NextResponse.json({ error: assetsError.message }, { status: 500 })
  }

  const { data: assignmentsData } = await dataClient
    .from("asset_assignments")
    .select("asset_id, assigned_to, department, office_location, assignment_type")
    .eq("is_current", true)

  const assignedUserIds = (assignmentsData || []).map((a: any) => a.assigned_to).filter(Boolean)

  let assignmentUsersMap = new Map<string, any>()
  if (assignedUserIds.length > 0) {
    const { data: usersData } = await dataClient
      .from("profiles")
      .select("id, first_name, last_name, department")
      .in("id", assignedUserIds)

    assignmentUsersMap = new Map((usersData || []).map((u) => [u.id, u]))
  }

  const { data: employeeData } = await listAssignableProfiles(dataClient, {
    select: "id, first_name, last_name, company_email, department, employment_status",
    departmentScope,
    allowLegacyNullStatus: false,
  })
  const employees = employeeData || []

  const { data: issuesData } = await dataClient.from("asset_issues").select("asset_id, resolved")

  const issueCountsByAsset: Record<string, number> = {}
  ;(issuesData || []).forEach((issue: any) => {
    if (!issue.resolved) {
      issueCountsByAsset[issue.asset_id] = (issueCountsByAsset[issue.asset_id] || 0) + 1
    }
  })

  let filteredAssets = assetsData || []
  if (departmentScope) {
    const deptUserIds = employees.map((s: any) => s.id)
    filteredAssets = filteredAssets.filter((asset: any) => {
      const assignment = (assignmentsData || []).find((a: any) => a.asset_id === asset.id)
      if (!assignment) return false

      if (assignment.assigned_to && deptUserIds.includes(assignment.assigned_to)) return true
      if (assignment.department && departmentScope.includes(assignment.department)) return true
      if (assignment.office_location && scope.managedOffices.includes(assignment.office_location)) return true
      return false
    })
  }

  const assets = filteredAssets.map((asset: any) => {
    const assignment = (assignmentsData || []).find((a: any) => a.asset_id === asset.id)
    return {
      ...asset,
      current_assignment: assignment
        ? {
            assigned_to: assignment.assigned_to,
            department: assignment.department,
            office_location: assignment.office_location,
            assignment_type: assignment.assignment_type,
            user: assignment.assigned_to ? assignmentUsersMap.get(assignment.assigned_to) : null,
          }
        : undefined,
      unresolved_issues_count: issueCountsByAsset[asset.id] || 0,
    }
  })

  return NextResponse.json({ assets, employees })
}

import { NextRequest, NextResponse } from "next/server"
import { canAccessAdminSection, resolveAdminScope } from "@/lib/admin/rbac"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { createClient } from "@/lib/supabase/server"
import { writeAuditLog } from "@/lib/audit/write-audit"

interface CreateAssetTypePayload {
  label?: string
  code?: string
  requiresSerialModel?: boolean
}

export async function GET() {
  const supabase = await createClient()
  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope || !canAccessAdminSection(scope, "assets")) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const dataClient = getServiceRoleClientOrFallback(supabase as any)
  let { data, error } = await dataClient
    .from("asset_types")
    .select("id, label, code, requires_serial_model")
    .order("label", {
      ascending: true,
    })

  if (error && dataClient !== supabase) {
    const fallback = await supabase
      .from("asset_types")
      .select("id, label, code, requires_serial_model")
      .order("label", { ascending: true })
    data = fallback.data
    error = fallback.error
  }

  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }

  return NextResponse.json({ data: data || [] })
}

export async function POST(request: NextRequest) {
  const supabase = await createClient()
  const {
    data: { user },
    error: userError,
  } = await supabase.auth.getUser()

  if (userError || !user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  if (!scope || !scope.isAdminLike || !canAccessAdminSection(scope, "assets")) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const payload = (await request.json().catch(() => null)) as CreateAssetTypePayload | null
  const label = String(payload?.label || "").trim()
  const code = String(payload?.code || "")
    .trim()
    .toUpperCase()
    .replace(/\s+/g, "")
  const requiresSerialModel = Boolean(payload?.requiresSerialModel)

  if (!label || !code) {
    return NextResponse.json({ error: "Both label and code are required" }, { status: 400 })
  }

  const dataClient = getServiceRoleClientOrFallback(supabase as any)
  const { data, error } = await dataClient
    .from("asset_types")
    .insert({
      label,
      code,
      requires_serial_model: requiresSerialModel,
      created_by: user.id,
    })
    .select("id, label, code, requires_serial_model")
    .single()

  if (error) {
    if (error.code === "23505") {
      return NextResponse.json({ error: "Asset type already exists", code: error.code }, { status: 409 })
    }
    return NextResponse.json({ error: error.message }, { status: 500 })
  }

  await writeAuditLog(
    supabase,
    {
      action: "create",
      entityType: "asset_type",
      entityId: data.id,
      newValues: { label, code, requires_serial_model: requiresSerialModel },
      context: { actorId: user.id, source: "api", route: "/api/admin/assets/types" },
    },
    { failOpen: true }
  )

  return NextResponse.json({ data }, { status: 201 })
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@supabase/supabase-js"
import { createClient as createServerClient } from "@/lib/supabase/server"
import { resolveAdminScope } from "@/lib/admin/rbac"
import {
  ASSIGNABLE_ROLES,
  canAssignRole,
  canManageDeveloperAccounts,
  canManageSuperAdminAccounts,
} from "@/lib/role-management"
import { formValidation } from "@/lib/validation"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("admin-create-user")

export const dynamic = "force-dynamic"

export async function POST(request: NextRequest) {
  // First, verify the caller is authenticated and has user-management privileges
  const supabase = await createServerClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) {
    return NextResponse.json({ success: false, error: "Unauthorized" }, { status: 401 })
  }

  const scope = await resolveAdminScope(supabase as any, user.id)
  const managedDepartments = scope?.managedDepartments || []
  const canManageUsers = !!scope && (scope.isAdminLike || managedDepartments.includes("Admin & HR"))
  if (!canManageUsers) {
    return NextResponse.json({ success: false, error: "Forbidden: Insufficient privileges" }, { status: 403 })
  }

  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
  const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

  if (!supabaseUrl || !supabaseServiceKey) {
    log.error("Missing required Supabase configuration")
    return NextResponse.json({ success: false, error: "Configuration error: Missing configuration" }, { status: 500 })
  }

  const serviceSupabase = createClient(supabaseUrl, supabaseServiceKey, {
    auth: {
      autoRefreshToken: false,
      persistSession: false,
    },
  })

  try {
    const body = await request.json()
    const { firstName, lastName, otherNames, email, department, companyRole, phoneNumber, role, employeeNumber } = body
    const adminDomains = Array.isArray(body?.admin_domains)
      ? body.admin_domains
          .map((value: unknown) =>
            String(value || "")
              .trim()
              .toLowerCase()
          )
          .filter(Boolean)
      : []
    const allowedAdminDomains = ["hr", "finance", "assets", "reports", "tasks", "projects", "communications"]

    // Validate role if provided
    const allowedRoles = [...ASSIGNABLE_ROLES]
    if (role && !allowedRoles.includes(role)) {
      return NextResponse.json(
        {
          success: false,
          error: `Invalid role. Allowed values: ${allowedRoles.join(", ")}`,
        },
        { status: 400 }
      )
    }

    if (role === "developer" && !canManageDeveloperAccounts(scope?.role || "")) {
      return NextResponse.json(
        { success: false, error: "Only super admin or developer can assign developer role" },
        { status: 403 }
      )
    }

    if (role === "super_admin" && !canManageSuperAdminAccounts(scope?.role || "")) {
      return NextResponse.json(
        { success: false, error: "Only super admin can assign super admin role" },
        { status: 403 }
      )
    }

    const targetRole = role || "employee"
    if (!canAssignRole(scope?.role || "", targetRole)) {
      return NextResponse.json(
        {
          success: false,
          error: "You do not have permission to assign this role.",
        },
        { status: 403 }
      )
    }
    if (targetRole === "admin") {
      if (adminDomains.length === 0) {
        return NextResponse.json(
          {
            success: false,
            error: "Admin role requires at least one admin domain.",
          },
          { status: 400 }
        )
      }
      if (adminDomains.some((value: string) => !allowedAdminDomains.includes(value))) {
        return NextResponse.json(
          {
            success: false,
            error: "Invalid admin domain supplied.",
          },
          { status: 400 }
        )
      }
    }

    // Validate required fields (department is optional for executives like MD)
    if (!firstName || !lastName || !email || !employeeNumber) {
      return NextResponse.json(
        {
          success: false,
          error: "First name, last name, email, and employee number are required",
        },
        { status: 400 }
      )
    }

    // Validate employee number format: ACOB/YEAR/NUMBER (e.g., ACOB/2026/058)
    const empNumPattern = /^ACOB\/[0-9]{4}\/[0-9]{3}$/
    if (!empNumPattern.test(employeeNumber)) {
      return NextResponse.json(
        {
          success: false,
          error: "Employee number must be in format: ACOB/YEAR/NUMBER (e.g., ACOB/2026/058)",
        },
        { status: 400 }
      )
    }

    // Validate email format and domain
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!emailRegex.test(email)) {
      return NextResponse.json(
        {
          success: false,
          error: "Invalid email format",
        },
        { status: 400 }
      )
    }

    if (!formValidation.isCompanyEmail(email)) {
      return NextResponse.json(
        {
          success: false,
          error: "Only @acoblighting.com and @org.acoblighting.com emails are allowed.",
        },
        { status: 400 }
      )
    }

    // Check if user already exists using the profile table (more direct)
    const { data: existingProfile } = await serviceSupabase
      .from("profiles")
      .select("id")
      .eq("company_email", email)
      .single()

    if (existingProfile) {
      return NextResponse.json(
        {
          success: false,
          error: "A user with this email already exists",
        },
        { status: 409 }
      )
    }

    // Create auth user without password - they will use OTP login
    const { data: authData, error: authError } = await serviceSupabase.auth.admin.createUser({
      email,
      email_confirm: false, // User will verify via OTP when they login
      user_metadata: {
        first_name: firstName,
        last_name: lastName,
        other_names: otherNames || "",
        department: department,
        phone_number: phoneNumber || "",
      },
    })

    if (authError) {
      return NextResponse.json(
        {
          success: false,
          error: authError.message,
        },
        { status: 400 }
      )
    }

    // Update profile with all details
    const { error: profileError } = await serviceSupabase
      .from("profiles")
      .update({
        first_name: firstName,
        last_name: lastName,
        other_names: otherNames || null,
        company_email: email,
        department: department,
        company_role: companyRole || null,
        phone_number: phoneNumber || null,
        role: targetRole,
        admin_domains: targetRole === "admin" ? adminDomains : null,
        is_department_lead: false,
        lead_departments: [],
        employment_status: "active", // Explicitly set employment status
        employee_number: employeeNumber || null, // Employee number (ACOB/YEAR/NUMBER)
      })
      .eq("id", authData.user.id)

    if (profileError) {
      log.error({ err: String(profileError) }, "[Create User] Profile update error:")
      // If profile update fails, try to delete the auth user
      await serviceSupabase.auth.admin.deleteUser(authData.user.id)
      return NextResponse.json(
        {
          success: false,
          error: `Database error: ${profileError.message}`,
        },
        { status: 500 }
      )
    }

    await writeAuditLog(
      supabase,
      {
        action: "create",
        entityType: "user",
        entityId: authData.user.id,
        newValues: { email, department, role: targetRole, employee_number: employeeNumber || null },
        context: { actorId: user.id, source: "api", route: "/api/admin/create-user" },
      },
      { failOpen: true }
    )

    return NextResponse.json(
      {
        success: true,
        message: "User created successfully. They can now login with their email and receive an OTP.",
        userId: authData.user.id,
        email: authData.user.email,
      },
      { status: 201 }
    )
  } catch (error) {
    log.error({ err: String(error) }, "[v0] Create user failed:")
    return NextResponse.json(
      {
        success: false,
        error: error instanceof Error ? error.message : "Internal server error",
      },
      { status: 500 }
    )
  }
}

