export async function PATCH(request: NextRequest) {
  try {
    const supabase = await createClient()
    const dataClient = getServiceRoleClientOrFallback(supabase)
    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const allowed = await canManageFleet(supabase, user.id)
    if (!allowed) return NextResponse.json({ error: "Forbidden" }, { status: 403 })

    const body = await request.json()
    const id = String(body?.id || "").trim()

    if (!id) {
      return NextResponse.json({ error: "Resource id is required" }, { status: 400 })
    }

    const patch: Record<string, any> = {}
    if (body?.name !== undefined) {
      const name = String(body.name || "").trim()
      if (name.length < 2) return NextResponse.json({ error: "Invalid resource name" }, { status: 400 })
      patch.name = name
    }
    if (body?.resource_type !== undefined) {
      patch.resource_type = String(body.resource_type || "general").trim() || "general"
    }
    if (body?.description !== undefined) {
      const desc = String(body.description || "").trim()
      patch.description = desc || null
    }
    if (body?.is_active !== undefined) {
      patch.is_active = Boolean(body.is_active)
    }

    if (Object.keys(patch).length === 0) {
      return NextResponse.json({ error: "No changes provided" }, { status: 400 })
    }

    const { data, error } = await dataClient
      .from("fleet_resources")
      .update(patch)
      .eq("id", id)
      .select("id, name, resource_type, description, is_active, created_at, updated_at")
      .single()

    if (error) return NextResponse.json({ error: error.message || "Failed to update resource" }, { status: 500 })

    await writeAuditLog(
      supabase,
      {
        action: "update",
        entityType: "fleet_resource",
        entityId: id,
        newValues: patch,
        context: { actorId: user.id, source: "api", route: "/api/admin/hr/fleet/resources" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ data })
  } catch (error) {
    const message = error instanceof Error ? error.message : "Internal server error"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { createClient } from "@/lib/supabase/server"
import { NextResponse } from "next/server"
import { createClient as createServiceClient } from "@supabase/supabase-js"
import { canAccessAdminSection, resolveAdminScope } from "@/lib/admin/rbac"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("import-csv")

export async function POST(request: Request) {
  try {
    const supabase = await createClient()

    // Verify user is authenticated
    const {
      data: { user },
      error: userError,
    } = await supabase.auth.getUser()

    if (userError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)
    if (!scope || !canAccessAdminSection(scope, "hr")) {
      return NextResponse.json({ error: "Forbidden: Admin access required" }, { status: 403 })
    }

    // Use service role key for admin operations
    const serviceSupabase = createServiceClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SERVICE_ROLE_KEY!
    )

    log.info("Starting CSV import via admin API")

    // Fetch CSV data from the provided URL
    const csvUrl =
      "https://hebbkx1anhila5yf.public.blob.vercel-storage.com/ACOB%20employee%20Details%20%28Responses%29s-w3SdRcPn4KaoAZk0lby8AEGY4Rzmri.csv"

    const response = await fetch(csvUrl)
    const csvText = await response.text()

    // Robust CSV parsing (handles quoted commas and escaped quotes)
    const parseCsv = (text: string): any[] => {
      const rows: string[] = []
      let cur = ""
      let inQuotes = false
      for (let i = 0; i < text.length; i++) {
        const c = text[i]
        const n = text[i + 1]
        if (c === '"') {
          if (inQuotes && n === '"') {
            cur += '"'
            i++
          } else {
            inQuotes = !inQuotes
          }
        } else if ((c === "\n" || c === "\r") && !inQuotes) {
          if (cur.length) rows.push(cur)
          cur = ""
          if (c === "\r" && n === "\n") i++
        } else {
          cur += c
        }
      }
      if (cur.length) rows.push(cur)

      const splitRow = (row: string): string[] => {
        const out: string[] = []
        let buf = ""
        let q = false
        for (let i = 0; i < row.length; i++) {
          const c = row[i]
          const n = row[i + 1]
          if (c === '"') {
            if (q && n === '"') {
              buf += '"'
              i++
            } else {
              q = !q
            }
          } else if (c === "," && !q) {
            out.push(buf)
            buf = ""
          } else {
            buf += c
          }
        }
        out.push(buf)
        return out.map((s) => s.trim())
      }

      if (rows.length === 0) return []
      const rawHeaders = splitRow(rows[0]).map((h) => h.replace(/^\uFEFF/, "").trim())
      const normalize = (s: string) => s.toLowerCase().replace(/[^a-z0-9]+/g, "")
      const headerIdxByNorm: Record<string, number> = {}
      rawHeaders.forEach((h, idx) => (headerIdxByNorm[normalize(h)] = idx))

      const result: any[] = []
      for (let r = 1; r < rows.length; r++) {
        const row = rows[r]
        if (!row || !row.trim()) continue
        const cols = splitRow(row)
        const rec: Record<string, string> = {}
        Object.entries(headerIdxByNorm).forEach(([norm, idx]) => {
          rec[norm] = (cols[idx] ?? "").trim()
        })
        result.push(rec)
      }
      return result
    }

    const records = parseCsv(csvText)

    log.info({ count: records.length }, "Parsed records from CSV")

    // Filter and import only company emails
    let importedCount = 0
    let skippedCount = 0
    const errors: string[] = []

    const norm = (s: string) => s.toLowerCase().replace(/[^a-z0-9]+/g, "")
    const get = (rec: any, headers: string[]): string => {
      for (const h of headers) {
        const key = norm(h)
        if (rec[key] !== undefined) return rec[key]
      }
      return ""
    }

    for (const record of records) {
      const originalEmailFromCsv = get(record, [
        "Company Email (or personal email if not available)",
        "Company Email",
        "Email",
      ])
        .toLowerCase()
        .trim()
      let email = originalEmailFromCsv

      // If personal or missing email, generate a company email using surname initial + '.' + first name
      const lastNameRaw = get(record, ["Last Name"]) || ""
      const firstNameRaw = get(record, ["First Name"]) || ""
      const normalizeName = (s: string) => s.trim().toLowerCase().replace(/\s+/g, " ")
      const lastName = normalizeName(lastNameRaw)
      const firstName = normalizeName(firstNameRaw)
      const isCompanyEmail = email.includes("@org.acoblighting.com") || email.includes("@acoblighting.com")
      if (!isCompanyEmail) {
        if (!lastName || !firstName) {
          log.warn({ email }, "Skipping record without name to generate email")
          skippedCount++
          continue
        }
        const initial = lastName[0]
        const generated = `${initial}.${firstName}@org.acoblighting.com`
        email = generated.toLowerCase()
      }

      try {
        // Check if user already exists
        // Try locate existing profile by current company email first
        let { data: existingUser } = await serviceSupabase
          .from("profiles")
          .select("id")
          .eq("company_email", email)
          .single()

        // If not found and CSV had a personal email, try match on that personal email
        if (!existingUser && originalEmailFromCsv && originalEmailFromCsv !== email) {
          const { data: existingByPersonal } = await serviceSupabase
            .from("profiles")
            .select("id")
            .eq("company_email", originalEmailFromCsv)
            .single()
          if (existingByPersonal) existingUser = existingByPersonal
        }

        const first_name = get(record, ["First Name"]) || ""
        const last_name = get(record, ["Last Name"]) || ""
        const other_names = get(record, ["Other Names (Optional)"]) || ""
        const department = get(record, ["Department (if applicable)", "Department"]) || ""
        const company_role = get(record, ["Company Role"]) || ""
        const phone_number = get(record, ["Phone number", "Phone Number"]) || ""
        const residential_address = get(record, ["Residential Address"]) || ""
        const office_location =
          get(record, [
            "Current Work Location (Office or Site – indicate site name & state if Site)",
            "Current Work Location",
            "Office Location",
          ]) || ""
        const device_allocated = get(record, ["Device allocated", "Device allocated "]) || ""
        const device_type = get(record, ["Desktop/ Laptop", "Desktop / Laptop", "Desktop", "Laptop"]) || ""

        if (existingUser) {
          // Update missing fields on existing profile
          const updatePayload: Record<string, string> = {}
          const maybeSet = (key: string, value: string) => {
            if (value && value.length > 0) updatePayload[key] = value
          }
          // Ensure company email on profile is the generated/company one
          maybeSet("company_email", email)
          maybeSet("first_name", first_name)
          maybeSet("last_name", last_name)
          maybeSet("other_names", other_names)
          maybeSet("department", department)
          maybeSet("company_role", company_role)
          maybeSet("phone_number", phone_number)
          maybeSet("residential_address", residential_address)
          maybeSet("office_location", office_location)
          maybeSet("device_allocated", device_allocated)
          maybeSet("device_type", device_type)

          if (Object.keys(updatePayload).length > 0) {
            const { error: updateErr } = await serviceSupabase
              .from("profiles")
              .update(updatePayload)
              .eq("id", existingUser.id)

            if (updateErr) {
              log.error({ email, err: updateErr.message }, "Update error")
              errors.push(`${email}: ${updateErr.message}`)
            } else {
              log.info({ email }, "Updated existing profile")
            }
          } else {
            log.info({ email }, "User already exists with full data, skipping")
          }
          continue
        }

        // Create auth user
        const { data: authData, error: authError } = await serviceSupabase.auth.admin.createUser({
          email,
          password: crypto.randomUUID().replace(/-/g, ""),
          email_confirm: true,
        })

        if (authError) {
          log.error({ email, err: authError.message }, "Auth user creation error")
          errors.push(`${email}: ${authError.message}`)
          continue
        }

        // Map fields with normalized header lookup
        // Insert profile
        const { error: profileError } = await serviceSupabase.from("profiles").insert({
          id: authData.user.id,
          company_email: email,
          first_name,
          last_name,
          other_names,
          department,
          company_role,
          phone_number,
          residential_address,
          office_location,
          device_allocated,
          device_type,
        })

        if (profileError) {
          log.error({ email, err: profileError.message }, "Profile insert error")
          errors.push(`${email}: ${profileError.message}`)
          continue
        }

        log.info({ email }, "Successfully imported")
        importedCount++
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : "Unknown error"
        log.error({ email, err: errorMessage }, "Error processing record")
        errors.push(`${email}: ${errorMessage}`)
      }
    }

    const summary = {
      imported: importedCount,
      skipped: skippedCount,
      total: records.length,
      errors: errors.slice(0, 10), // Return first 10 errors
      errorCount: errors.length,
    }

    log.info({ imported: importedCount, skipped: skippedCount, errors: errors.length }, "Import complete")

    await writeAuditLog(
      supabase,
      {
        action: "create",
        entityType: "user",
        entityId: "bulk-import",
        newValues: { imported: importedCount, skipped: skippedCount, total: records.length, errors: errors.length },
        context: { actorId: user.id, source: "api", route: "/api/admin/import-csv" },
      },
      { failOpen: true }
    )

    return NextResponse.json(
      {
        success: true,
        message: `Import complete. Imported: ${importedCount}, Skipped: ${skippedCount}`,
        ...summary,
      },
      { status: 200 }
    )
  } catch (error) {
    log.error({ err: String(error) }, "CSV import failed")
    return NextResponse.json(
      {
        success: false,
        error: error instanceof Error ? error.message : "Internal server error",
      },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { NOTIFICATION_KEYS, isNotificationKey } from "@/lib/notifications/delivery-policy"
import { writeAuditLog } from "@/lib/audit/write-audit"

type PolicyUpdatePayload = {
  notification_key: string
  in_app_enabled?: boolean
  email_enabled?: boolean
  in_app_mandatory?: boolean
  email_mandatory?: boolean
}

async function requirePrivilegedActor(supabase: any) {
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) return { user: null, error: NextResponse.json({ error: "Unauthorized" }, { status: 401 }) }

  const { data: profile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
  if (!["super_admin", "developer"].includes(profile?.role)) {
    return { user: null, error: NextResponse.json({ error: "Forbidden" }, { status: 403 }) }
  }

  return { user, error: null }
}

export async function GET() {
  try {
    const supabase = await createClient()
    const auth = await requirePrivilegedActor(supabase)
    if (auth.error) return auth.error

    const admin = getServiceRoleClientOrFallback(supabase as any)

    const { data, error } = await admin
      .from("notification_delivery_policies")
      .select(
        "notification_key, in_app_enabled, email_enabled, in_app_mandatory, email_mandatory, updated_by, updated_at"
      )
      .in("notification_key", [...NOTIFICATION_KEYS])
      .order("notification_key")

    if (error) return NextResponse.json({ error: error.message }, { status: 400 })

    return NextResponse.json({ policies: data || [] })
  } catch (error) {
    const message = error instanceof Error ? error.message : "An error occurred"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

export async function PUT(request: NextRequest) {
  try {
    const supabase = await createClient()
    const auth = await requirePrivilegedActor(supabase)
    if (auth.error) return auth.error

    const body = await request.json()
    const inputPolicies = Array.isArray(body?.policies) ? (body.policies as PolicyUpdatePayload[]) : []

    if (inputPolicies.length === 0) {
      return NextResponse.json({ error: "No policies provided" }, { status: 400 })
    }

    const payload = inputPolicies
      .filter((row) => isNotificationKey(String(row.notification_key || "")))
      .map((row) => ({
        notification_key: row.notification_key,
        in_app_enabled: row.in_app_enabled,
        email_enabled: row.email_enabled,
        in_app_mandatory: row.in_app_mandatory,
        email_mandatory: row.email_mandatory,
        updated_by: auth.user!.id,
        updated_at: new Date().toISOString(),
      }))

    if (payload.length === 0) {
      return NextResponse.json({ error: "No valid notification keys provided" }, { status: 400 })
    }

    for (const row of payload) {
      if (row.in_app_enabled === false && row.in_app_mandatory === true) {
        return NextResponse.json(
          { error: `In-app mandatory cannot be enabled while in-app delivery is disabled (${row.notification_key})` },
          { status: 400 }
        )
      }
      if (row.email_enabled === false && row.email_mandatory === true) {
        return NextResponse.json(
          { error: `Email mandatory cannot be enabled while email delivery is disabled (${row.notification_key})` },
          { status: 400 }
        )
      }
    }

    const admin = getServiceRoleClientOrFallback(supabase as any)

    const { error } = await admin.from("notification_delivery_policies").upsert(payload, {
      onConflict: "notification_key",
    })

    if (error) return NextResponse.json({ error: error.message }, { status: 400 })

    await writeAuditLog(
      supabase,
      {
        action: "update",
        entityType: "notification_policy",
        entityId: "bulk",
        newValues: { updated_keys: payload.map((r) => r.notification_key) },
        context: { actorId: auth.user!.id, source: "api", route: "/api/admin/settings/mail" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ ok: true })
  } catch (error) {
    const message = error instanceof Error ? error.message : "An error occurred"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import { NextResponse } from "next/server"
import {
  ASSIGNABLE_ROLES,
  canAssignRole,
  canManageDeveloperAccounts,
  canManageSuperAdminAccounts,
} from "@/lib/role-management"
import { rateLimit, getClientId } from "@/lib/rate-limit"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("admin-users-invite")

const SUPER_ADMIN_ROLE = "super_admin"
type AllowedRole = (typeof ASSIGNABLE_ROLES)[number]

function isValidRole(role: string): role is AllowedRole {
  return ASSIGNABLE_ROLES.includes(role as (typeof ASSIGNABLE_ROLES)[number])
}

export async function POST(request: Request) {
  const rl = rateLimit(`invite:${getClientId(request)}`, { limit: 10, windowSec: 600 })
  if (!rl.allowed) {
    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 })
  }

  try {
    const supabase = await createClient()

    // 1. Verify requester is admin
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const { data: profile, error: profileFetchError } = await supabase
      .from("profiles")
      .select("role")
      .eq("id", user.id)
      .single()

    if (profileFetchError) {
      log.error({ err: String(profileFetchError) }, "Error fetching requester profile:")
      return NextResponse.json({ error: "Internal server error" }, { status: 500 })
    }

    if (!["developer", SUPER_ADMIN_ROLE, "admin"].includes(profile?.role)) {
      return NextResponse.json({ error: "Forbidden: Admin access required" }, { status: 403 })
    }

    // 2. Parse body
    const { email: rawEmail, first_name, last_name, role, department } = await request.json()

    if (typeof rawEmail !== "string") {
      return NextResponse.json({ error: "Email is required" }, { status: 400 })
    }
    const email = rawEmail.trim()
    if (!email) {
      return NextResponse.json({ error: "Email is required" }, { status: 400 })
    }
    const emailNormalized = email.toLowerCase()

    // 3. Validate role against allowlist
    const roleProvided = role !== undefined
    if (roleProvided && !isValidRole(role)) {
      return NextResponse.json({ error: `Invalid role: ${role}` }, { status: 400 })
    }

    // 4. Role assignment guardrails
    if (roleProvided && !canAssignRole(profile?.role || "", role)) {
      return NextResponse.json({ error: "Forbidden: You cannot assign this role" }, { status: 403 })
    }

    // 5. Create admin client
    const supabaseAdmin = createAdminClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SERVICE_ROLE_KEY!,
      {
        auth: {
          autoRefreshToken: false,
          persistSession: false,
        },
      }
    )

    // 6. Check if user exists with pagination
    let existingUser = null
    let page = 1
    const perPage = 1000

    while (true) {
      const { data: usersPage, error: searchError } = await supabaseAdmin.auth.admin.listUsers({
        page,
        perPage,
      })

      if (searchError) {
        log.error({ err: String(searchError) }, "Error listing users:")
        return NextResponse.json({ error: "Failed to check existing users" }, { status: 500 })
      }

      // Find matching user (case-insensitive)
      const matchedUser = usersPage.users.find((u) => u.email?.toLowerCase() === emailNormalized)
      if (matchedUser) {
        existingUser = matchedUser
        break
      }

      // If we got fewer users than perPage, we've reached the end
      if (usersPage.users.length < perPage) {
        break
      }

      page++
    }

    let userId: string

    if (existingUser) {
      // User exists in Auth, just ensure profile is updated
      userId = existingUser.id
    } else {
      // Invite user
      const { data: inviteData, error: inviteError } = await supabaseAdmin.auth.admin.inviteUserByEmail(emailNormalized)

      if (inviteError) {
        throw inviteError
      }
      userId = inviteData.user.id
    }

    // 7. Create/Update Profile
    const roleToApply = roleProvided ? role : existingUser ? undefined : "employee"

    if (existingUser && roleToApply) {
      const { data: existingProfile } = await supabaseAdmin.from("profiles").select("role").eq("id", userId).single()

      if (existingProfile?.role === "developer" && !canManageDeveloperAccounts(profile?.role || "")) {
        return NextResponse.json(
          { error: "Only super admin or developer can modify developer accounts" },
          { status: 403 }
        )
      }

      if (existingProfile?.role === "developer" && roleToApply !== "developer") {
        const { count } = await supabaseAdmin
          .from("profiles")
          .select("id", { count: "exact", head: true })
          .eq("role", "developer")

        if ((count || 0) <= 1) {
          return NextResponse.json({ error: "Cannot downgrade the last developer account." }, { status: 400 })
        }
      }

      if (existingProfile?.role === "super_admin" && roleToApply !== "super_admin") {
        const { count } = await supabaseAdmin
          .from("profiles")
          .select("id", { count: "exact", head: true })
          .eq("role", "super_admin")

        if ((count || 0) <= 1) {
          return NextResponse.json({ error: "Cannot downgrade the last super admin account." }, { status: 400 })
        }
      }
    }

    if (roleToApply === "developer" && !canManageDeveloperAccounts(profile?.role || "")) {
      return NextResponse.json({ error: "Only super admin or developer can assign developer role" }, { status: 403 })
    }

    if (roleToApply === "super_admin" && !canManageSuperAdminAccounts(profile?.role || "")) {
      return NextResponse.json({ error: "Only super admin can assign super admin role" }, { status: 403 })
    }

    if (existingUser && existingUser.id === user.id && roleToApply && roleToApply !== profile?.role) {
      return NextResponse.json({ error: "You cannot change your own role." }, { status: 400 })
    }

    const profilePayload: any = {
      id: userId,
      company_email: emailNormalized,
      employment_status: "active",
    }

    if (roleToApply) {
      profilePayload.role = roleToApply
      // Role changes do NOT affect department lead status
    }
    if (first_name !== undefined) profilePayload.first_name = first_name
    if (last_name !== undefined) profilePayload.last_name = last_name
    if (department !== undefined) profilePayload.department = department

    const { error: profileError } = await supabaseAdmin.from("profiles").upsert(profilePayload)

    if (profileError) {
      throw profileError
    }

    // Audit: user invite/profile creation
    await writeAuditLog(supabase, {
      action: existingUser ? "update" : "create",
      entityType: "profile",
      entityId: userId,
      context: { actorId: user.id, source: "api" as const },
      newValues: {
        company_email: emailNormalized,
        ...(roleToApply ? { role: roleToApply } : {}),
        ...(department ? { department } : {}),
      },
      metadata: { source: "admin-users-invite", invited: !existingUser },
    }, { failOpen: true })

    return NextResponse.json({ success: true, userId })
  } catch (error: any) {
    log.error({ err: String(error) }, "Invite error:")
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

