export async function PATCH(request: NextRequest, { params }: { params: { id: string } }) {
  try {
    const { supabase, user, profile } = await getAuthContext()

    if (!user || !profile) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const { data: record, error } = await supabase
      .from("correspondence_records")
      .select("*")
      .eq("id", params.id)
      .single()

    if (error || !record) {
      return NextResponse.json({ error: "Record not found" }, { status: 404 })
    }

    if (!canAccessRecord(profile, user.id, record)) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }

    const body = await request.json()
    const nextStatus = body?.status ? String(body.status) : null
    const shouldCreateVersion = Boolean(body?.version_file_path || body?.change_summary)

    if (nextStatus && !CORRESPONDENCE_STATUSES.includes(nextStatus as any)) {
      return NextResponse.json({ error: "Invalid status" }, { status: 400 })
    }

    const allowedFields = [
      "status",
      "letter_type",
      "category",
      "subject",
      "recipient_name",
      "sender_name",
      "action_required",
      "due_date",
      "responsible_officer_id",
      "assigned_department_name",
      "source_mode",
      "metadata",
      "is_locked",
      "current_version",
    ]

    const updatePayload: Record<string, unknown> = {}
    for (const key of allowedFields) {
      if (key in body) {
        updatePayload[key] = body[key]
      }
    }

    if (shouldCreateVersion && !("current_version" in updatePayload)) {
      updatePayload.current_version = Number(record.current_version || 1) + 1
    }

    if (nextStatus === "approved") {
      updatePayload.approved_at = new Date().toISOString()
    }

    const { data: updated, error: updateError } = await supabase
      .from("correspondence_records")
      .update(updatePayload)
      .eq("id", params.id)
      .select("*")
      .single()

    if (updateError) throw updateError

    if (shouldCreateVersion) {
      await supabase.from("correspondence_versions").insert({
        correspondence_id: record.id,
        version_no: updated.current_version,
        file_path: body?.version_file_path ? String(body.version_file_path).trim() : null,
        change_summary: body?.change_summary ? String(body.change_summary).trim() : null,
        uploaded_by: user.id,
      })
    }

    if (nextStatus && nextStatus !== record.status) {
      await appendCorrespondenceEvent({
        correspondenceId: record.id,
        actorId: user.id,
        eventType: "status_changed",
        oldStatus: record.status,
        newStatus: nextStatus,
        details: {
          previous_status: record.status,
          updated_status: nextStatus,
        },
      })
    } else {
      await appendCorrespondenceEvent({
        correspondenceId: record.id,
        actorId: user.id,
        eventType: "record_updated",
        oldStatus: record.status,
        newStatus: updated.status,
        details: {
          changed_fields: Object.keys(updatePayload),
        },
      })
    }

    const auditAction = nextStatus && nextStatus !== record.status ? "status_change" : "update"

    await appendCorrespondenceAuditLog({
      actorId: user.id,
      action: auditAction,
      recordId: record.id,
      department: record.department_name || record.assigned_department_name || null,
      route: "/api/correspondence/records/[id]",
      critical: Boolean(nextStatus && nextStatus !== record.status),
      oldValues: {
        status: record.status,
        is_locked: record.is_locked,
      },
      newValues: {
        status: updated.status,
        is_locked: updated.is_locked,
      },
    })

    return NextResponse.json({ data: updated })
  } catch (error) {
    log.error({ err: String(error) }, "Error in PATCH /api/correspondence/records/[id]:")
    return NextResponse.json({ error: "Failed to update correspondence record" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import {
  appendCorrespondenceAuditLog,
  appendCorrespondenceEvent,
  canAccessDepartment,
  getAuthContext,
  getDepartmentCodeByName,
  isAdminRole,
} from "@/lib/correspondence/server"
import type { CorrespondenceDirection } from "@/types/correspondence"
import { logger } from "@/lib/logger"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"

const log = logger("correspondence-records")

export async function GET(request: NextRequest) {
  try {
    const { supabase, user, profile } = await getAuthContext()

    if (!user || !profile) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const searchParams = request.nextUrl.searchParams
    const direction = searchParams.get("direction")
    const status = searchParams.get("status")
    const department = searchParams.get("department")
    const dateFrom = searchParams.get("date_from")
    const dateTo = searchParams.get("date_to")

    let query = supabase.from("correspondence_records").select("*").order("created_at", { ascending: false })

    if (direction === "incoming" || direction === "outgoing") {
      query = query.eq("direction", direction)
    }

    if (status) {
      query = query.eq("status", status)
    }

    if (dateFrom) {
      query = query.gte("created_at", dateFrom)
    }

    if (dateTo) {
      query = query.lte("created_at", dateTo)
    }

    const { data, error } = await query
    if (error) throw error

    const filtered = (data || []).filter((record: any) => {
      if (!department) return true
      return record.department_name === department || record.assigned_department_name === department
    })

    return NextResponse.json({ data: filtered })
  } catch (error) {
    log.error({ err: String(error) }, "Error in GET /api/correspondence/records:")
    return NextResponse.json({ error: "Failed to fetch correspondence records" }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const { supabase, user, profile } = await getAuthContext()
    const dataClient = getServiceRoleClientOrFallback(supabase as any)

    if (!user || !profile) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const body = await request.json()
    const direction = "outgoing"
    const subject = String(body?.subject || "").trim()
    const profileDepartment = profile?.department ? String(profile.department).trim() : null
    const departmentName = body?.department_name ? String(body.department_name).trim() : profileDepartment
    const assignedDepartmentName = departmentName

    if (!subject) {
      return NextResponse.json({ error: "subject is required" }, { status: 400 })
    }

    if (direction === "outgoing" && !departmentName) {
      return NextResponse.json({ error: "department_name is required for outgoing correspondence" }, { status: 400 })
    }
    const resolvedDepartmentName = departmentName as string

    const departmentCode = await getDepartmentCodeByName(resolvedDepartmentName)
    if (!departmentCode) {
      return NextResponse.json(
        { error: `No active department code configured for ${resolvedDepartmentName}` },
        { status: 400 }
      )
    }

    if (profile.is_department_lead && !isAdminRole(profile.role)) {
      const accessDepartment = departmentName || assignedDepartmentName
      if (accessDepartment && !canAccessDepartment(profile, accessDepartment)) {
        return NextResponse.json({ error: "Forbidden: outside your department scope" }, { status: 403 })
      }
    }

    const initialStatus = "draft"
    const senderName =
      (body?.sender_name ? String(body.sender_name).trim() : "") ||
      profile?.full_name ||
      [profile?.first_name, profile?.last_name].filter(Boolean).join(" ").trim() ||
      user.email ||
      null

    const insertPayload: Record<string, unknown> = {
      direction,
      subject,
      department_name: resolvedDepartmentName,
      department_code: departmentCode,
      letter_type: body?.letter_type || null,
      category: body?.category || null,
      recipient_name: body?.recipient_name ? String(body.recipient_name).trim() : null,
      sender_name: senderName,
      action_required: Boolean(body?.action_required),
      due_date: body?.due_date || null,
      responsible_officer_id: body?.responsible_officer_id || null,
      assigned_department_name: assignedDepartmentName,
      source_mode: body?.source_mode || null,
      metadata: body?.metadata || null,
      status: initialStatus,
      originator_id: user.id,
      submitted_at: new Date().toISOString(),
      received_at: null,
    }

    const { data: created, error } = await dataClient
      .from("correspondence_records")
      .insert(insertPayload)
      .select("*")
      .single()

    if (error) throw error

    await appendCorrespondenceEvent({
      correspondenceId: created.id,
      actorId: user.id,
      eventType: "correspondence_created",
      newStatus: created.status,
      details: {
        direction,
        department_name: created.department_name,
        assigned_department_name: created.assigned_department_name,
      },
    })

    await appendCorrespondenceAuditLog({
      actorId: user.id,
      action: "correspondence_record_created",
      recordId: created.id,
      department: created.department_name || created.assigned_department_name || null,
      route: "/api/correspondence/records",
      critical: false,
      newValues: {
        reference_number: created.reference_number,
        direction: created.direction,
        status: created.status,
      },
    })

    try {
      const notifyDepartment = created.assigned_department_name || created.department_name
      if (notifyDepartment) {
        const { data: leadCandidates } = await dataClient
          .from("profiles")
          .select("id, role, lead_departments, department, is_department_lead")
          .eq("is_department_lead", true)

        const targetLead = (leadCandidates || []).find((p: any) => canAccessDepartment(p, notifyDepartment))

        if (targetLead?.id) {
          await supabase.rpc("create_notification", {
            p_user_id: targetLead.id,
            p_type: "task_assigned",
            p_category: "operations",
            p_title: "New correspondence logged",
            p_message: `${created.reference_number} - ${created.subject}`,
            p_priority: "normal",
            p_link_url: "/admin/correspondence",
            p_actor_id: user.id,
            p_entity_type: "correspondence_record",
            p_entity_id: created.id,
            p_rich_content: { direction: created.direction, status: created.status },
          })
        }
      }
    } catch (notifyError) {
      log.error({ err: String(notifyError) }, "Correspondence notification error:")
    }

    return NextResponse.json({ data: created }, { status: 201 })
  } catch (error) {
    log.error({ err: String(error) }, "Error in POST /api/correspondence/records:")
    const details = error as { message?: string; details?: string; hint?: string; code?: string }
    return NextResponse.json(
      {
        error: details?.message || "Failed to create correspondence record",
        details: details?.details || null,
        hint: details?.hint || null,
        code: details?.code || null,
      },
      { status: 500 }
    )
  }
}

import { createServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"
import { NextResponse } from "next/server"
import { getDepartmentScope, resolveAdminScope } from "@/lib/admin/rbac"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("departments")

export const dynamic = "force-dynamic"

// Helper function to create Supabase client
async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!, {
    cookies: {
      getAll() {
        return cookieStore.getAll()
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) => cookieStore.set(name, value, options))
        } catch {
          // The `setAll` method was called from a Server Component.
          // This can be ignored if you have middleware refreshing
          // user sessions.
        }
      },
    },
  })
}

// GET /api/departments/[id] - Get a single department
export async function GET(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)

    const { data: department, error } = await supabase.from("departments").select("*").eq("id", params.id).single()

    if (error) throw error

    if (scope) {
      const scopedDepartments = getDepartmentScope(scope, "general")
      if (scopedDepartments && !scopedDepartments.includes(department.name)) {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 })
      }
    } else {
      const { data: profile } = await supabase.from("profiles").select("department").eq("id", user.id).single()
      if (profile?.department && department.name !== profile.department) {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 })
      }
    }

    return NextResponse.json({ data: department })
  } catch (error) {
    log.error({ err: String(error) }, "Error fetching department:")
    return NextResponse.json({ error: "Failed to fetch department" }, { status: 500 })
  }
}

// PUT /api/departments/[id] - Update a department (admin-like only)
export async function PUT(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()

    // Check if user is admin
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)
    const managedDepartments = scope?.managedDepartments || []
    const canManageDepartments = !!scope && (scope.isAdminLike || managedDepartments.includes("Admin & HR"))
    if (!canManageDepartments) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }

    const body = await request.json()
    const { name, description, department_head_id } = body

    if (!name) {
      return NextResponse.json({ error: "Department name is required" }, { status: 400 })
    }

    const { data: department, error } = await supabase
      .from("departments")
      .update({
        name,
        description,
        department_head_id,
      })
      .eq("id", params.id)
      .select()
      .single()

    if (error) throw error

    await writeAuditLog(
      supabase as any,
      {
        action: "update",
        entityType: "department",
        entityId: params.id,
        newValues: { name, description, department_head_id },
        context: { actorId: user.id, source: "api", route: `/api/departments/${params.id}` },
      },
      { failOpen: true }
    )

    return NextResponse.json({ data: department })
  } catch (error) {
    log.error({ err: String(error) }, "Error updating department:")
    return NextResponse.json({ error: "Failed to update department" }, { status: 500 })
  }
}

// DELETE /api/departments/[id] - Soft delete a department (admin-like only)
export async function DELETE(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()

    // Check if user is admin
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)
    const managedDepartments = scope?.managedDepartments || []
    const canManageDepartments = !!scope && (scope.isAdminLike || managedDepartments.includes("Admin & HR"))
    if (!canManageDepartments) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }

    const { data: existingDepartment, error: fetchDepartmentError } = await supabase
      .from("departments")
      .select("id, name, is_active")
      .eq("id", params.id)
      .single()

    if (fetchDepartmentError || !existingDepartment) {
      return NextResponse.json({ error: "Department not found" }, { status: 404 })
    }

    const { count: assignedProfilesCount, error: countError } = await supabase
      .from("profiles")
      .select("id", { count: "exact", head: true })
      .eq("department", existingDepartment.name)

    if (countError) throw countError
    if ((assignedProfilesCount || 0) > 0) {
      return NextResponse.json(
        { error: "Cannot deactivate department while users are assigned to it" },
        { status: 409 }
      )
    }

    const { error } = await supabase
      .from("departments")
      .update({ is_active: false, updated_at: new Date().toISOString() })
      .eq("id", params.id)

    if (error) throw error

    await writeAuditLog(
      supabase as any,
      {
        action: "delete",
        entityType: "department",
        entityId: params.id,
        oldValues: { name: existingDepartment.name, is_active: true },
        context: { actorId: user.id, source: "api", route: `/api/departments/${params.id}` },
      },
      { failOpen: true }
    )

    return NextResponse.json({ success: true, soft_deleted: true })
  } catch (error) {
    log.error({ err: String(error) }, "Error soft deleting department:")
    return NextResponse.json({ error: "Failed to deactivate department" }, { status: 500 })
  }
}

