/**
 * POST /api/dev/help-desk-test
 * POST /api/dev/task-test
 *
 * Both live in this single route for simplicity.
 * Path: /api/dev/flow-tests
 *
 * Body: { kind: "help_desk" | "task", ...params }
 * Protected: developer role only.
 */

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"
import { DEPT_EXECUTIVE_MANAGEMENT, DEPT_CORPORATE_SERVICES } from "@/config/constants"

type StepResult = {
  step: string
  status: "ok" | "error" | "skipped"
  detail?: string
  data?: unknown
}

function ok(step: string, detail?: string, data?: unknown): StepResult {
  return { step, status: "ok", detail, data }
}
function err(step: string, detail: string): StepResult {
  return { step, status: "error", detail }
}

async function testHelpDesk(admin: any, body: any): Promise<{ ok: boolean; steps: StepResult[] }> {
  const steps: StepResult[] = []
  let ticketId: string | null = null
  const cleanup = body.cleanup !== false

  try {
    const { requester_id, service_department } = body
    const requestType = body.request_type === "procurement" ? "procurement" : "support"
    const supportMode = body.support_mode === "lead_review_required" ? "lead_review_required" : "open_queue"
    if (!requester_id || !service_department) {
      steps.push(err("validate_input", "requester_id and service_department are required"))
      return { ok: false, steps }
    }

    // Step 1: Load requester
    const { data: requester, error: reqErr } = await admin
      .from("profiles")
      .select("id, full_name, department")
      .eq("id", requester_id)
      .single()
    if (reqErr || !requester) {
      steps.push(err("load_requester", reqErr?.message || "Not found"))
      return { ok: false, steps }
    }
    steps.push(ok("load_requester", `Loaded: ${requester.full_name || requester.id}`))

    // Step 2: Create a test ticket for the selected flow.
    const now = new Date()
    const slaTarget = new Date(now.getTime() + 24 * 60 * 60 * 1000).toISOString()
    const { data: ticket, error: ticketErr } = await admin
      .from("help_desk_tickets")
      .insert({
        title: "[TEST] Automated help desk flow test",
        description: "Automated test ticket — safe to delete",
        service_department,
        request_type: requestType,
        priority: "medium",
        status:
          requestType === "procurement"
            ? "pending_approval"
            : supportMode === "lead_review_required"
              ? "pending_lead_review"
              : "department_queue",
        requester_id,
        created_by: requester_id,
        approval_required: requestType === "procurement",
        support_mode: requestType === "support" ? supportMode : null,
        handling_mode: requestType === "support" ? "queue" : "individual",
        requester_department: requester.department || null,
        submitted_at: now.toISOString(),
        sla_target_at: slaTarget,
        paused_at: requestType === "procurement" ? now.toISOString() : null,
      })
      .select()
      .single()

    if (ticketErr || !ticket) {
      steps.push(err("create_ticket", ticketErr?.message || "Insert returned no data"))
      return { ok: false, steps }
    }
    ticketId = ticket.id
    steps.push(ok("create_ticket", `Created ticket #${ticket.ticket_number || ticket.id}`))

    if (requestType === "procurement") {
      const { error: approvalSeedErr } = await admin.from("help_desk_approvals").insert([
        { ticket_id: ticketId, approval_stage: "department_lead", status: "pending" },
        { ticket_id: ticketId, approval_stage: "head_corporate_services", status: "pending" },
        { ticket_id: ticketId, approval_stage: "managing_director", status: "pending" },
      ])

      if (approvalSeedErr) {
        steps.push(err("seed_procurement_stages", approvalSeedErr.message))
        return { ok: false, steps }
      }
      steps.push(ok("seed_procurement_stages", "Seeded department lead, HCS, and MD approval stages"))
    }

    // Step 3: Find department lead
    const { data: profiles } = await applyAssignableStatusFilter(
      admin.from("profiles").select("id, full_name, role, is_department_lead, lead_departments, department"),
      { allowLegacyNullStatus: false }
    )

    const lead = (profiles || []).find((p: any) => {
      const managed = Array.isArray(p.lead_departments) ? p.lead_departments : []
      return p.is_department_lead && (p.department === service_department || managed.includes(service_department))
    })

    if (lead) {
      steps.push(ok("find_dept_lead", `Found: ${lead.full_name || lead.id}`))
    } else {
      steps.push({
        step: "find_dept_lead",
        status: "skipped",
        detail: `No department lead configured for "${service_department}" — ticket would appear unassigned`,
      })
    }

    if (requestType === "support") {
      if (supportMode === "lead_review_required") {
        if (lead) {
          const { error: releaseErr } = await admin
            .from("help_desk_tickets")
            .update({ status: "department_queue", handling_mode: "queue" })
            .eq("id", ticketId)
          if (releaseErr) steps.push(err("lead_release_to_queue", releaseErr.message))
          else
            steps.push(
              ok("lead_release_to_queue", `${lead.full_name || lead.id} released the ticket to department queue`)
            )
        } else {
          steps.push(err("lead_release_to_queue", `No department lead configured for "${service_department}"`))
        }
      } else {
        steps.push(ok("queue_entry", "Ticket entered department queue directly"))
      }

      // Step 4: Assign ticket to lead
      if (lead) {
        const { error: assignErr } = await admin
          .from("help_desk_tickets")
          .update({ assigned_to: lead.id, status: "in_progress", handling_mode: "individual" })
          .eq("id", ticketId)
        if (assignErr) steps.push(err("assign_ticket", assignErr.message))
        else steps.push(ok("assign_ticket", `Assigned to ${lead.full_name}`))
      }

      // Step 5: Close ticket
      const { error: closeErr } = await admin
        .from("help_desk_tickets")
        .update({ status: "resolved", resolved_at: new Date().toISOString() })
        .eq("id", ticketId)
      if (closeErr) steps.push(err("resolve_ticket", closeErr.message))
      else steps.push(ok("resolve_ticket", "Ticket marked resolved"))

      // Step 6: Verify
      const { data: final } = await admin.from("help_desk_tickets").select("status").eq("id", ticketId).single()
      if (final?.status === "resolved") steps.push(ok("verify_final_state", "status=resolved ✓"))
      else steps.push(err("verify_final_state", `Expected resolved, got ${final?.status}`))
    } else {
      const requesterLead = (profiles || []).find((p: any) => {
        const managed = Array.isArray(p.lead_departments) ? p.lead_departments : []
        return p.is_department_lead && (p.department === requester.department || managed.includes(requester.department))
      })
      const serviceLead = lead
      const hcs = (profiles || []).find((p: any) => {
        const managed = Array.isArray(p.lead_departments) ? p.lead_departments : []
        return (
          (["developer", "admin", "super_admin"].includes(p.role) || p.is_department_lead) &&
          (p.department === DEPT_CORPORATE_SERVICES || managed.includes(DEPT_CORPORATE_SERVICES))
        )
      })
      const md = (profiles || []).find((p: any) => {
        return (
          (["developer", "admin", "super_admin"].includes(p.role) && p.department === DEPT_EXECUTIVE_MANAGEMENT) ||
          p.role === "developer" ||
          p.role === "super_admin"
        )
      })

      if (requesterLead) {
        const { error: deptApproveErr } = await admin
          .from("help_desk_approvals")
          .update({
            status: "approved",
            approver_id: requesterLead.id,
            comments: "[TEST] Requester lead approved",
            decided_at: new Date().toISOString(),
          })
          .eq("ticket_id", ticketId)
          .eq("approval_stage", "requester_department_lead")
        if (deptApproveErr) steps.push(err("approve_requester_department_lead", deptApproveErr.message))
        else
          steps.push(
            ok(
              "approve_requester_department_lead",
              `${requesterLead.full_name || requesterLead.id} approved requester lead stage`
            )
          )
      } else {
        steps.push(
          err(
            "approve_requester_department_lead",
            `No requester department lead configured for "${requester.department}"`
          )
        )
      }

      if (serviceLead) {
        const { error: serviceApproveErr } = await admin
          .from("help_desk_approvals")
          .update({
            status: "approved",
            approver_id: serviceLead.id,
            comments: "[TEST] Service lead approved",
            decided_at: new Date().toISOString(),
          })
          .eq("ticket_id", ticketId)
          .eq("approval_stage", "service_department_lead")
        if (serviceApproveErr) steps.push(err("approve_service_department_lead", serviceApproveErr.message))
        else
          steps.push(
            ok(
              "approve_service_department_lead",
              `${serviceLead.full_name || serviceLead.id} approved service lead stage`
            )
          )
      } else {
        steps.push(
          err("approve_service_department_lead", `No service department lead configured for "${service_department}"`)
        )
      }

      if (hcs) {
        const { error: hcsApproveErr } = await admin
          .from("help_desk_approvals")
          .update({
            status: "approved",
            approver_id: hcs.id,
            comments: "[TEST] HCS approved",
            decided_at: new Date().toISOString(),
          })
          .eq("ticket_id", ticketId)
          .eq("approval_stage", "head_corporate_services")
        if (hcsApproveErr) steps.push(err("approve_head_corporate_services", hcsApproveErr.message))
        else steps.push(ok("approve_head_corporate_services", `${hcs.full_name || hcs.id} approved HCS stage`))
      } else {
        steps.push(err("approve_head_corporate_services", "No Corporate Services approver configured"))
      }

      if (md) {
        const { error: mdApproveErr } = await admin
          .from("help_desk_approvals")
          .update({
            status: "approved",
            approver_id: md.id,
            comments: "[TEST] MD approved",
            decided_at: new Date().toISOString(),
          })
          .eq("ticket_id", ticketId)
          .eq("approval_stage", "managing_director")
        if (mdApproveErr) steps.push(err("approve_managing_director", mdApproveErr.message))
        else steps.push(ok("approve_managing_director", `${md.full_name || md.id} approved MD stage`))
      } else {
        steps.push(err("approve_managing_director", "No managing director approver configured"))
      }

      const { error: finaliseErr } = await admin
        .from("help_desk_tickets")
        .update({
          status: "approved_for_procurement",
          resumed_at: new Date().toISOString(),
          paused_at: null,
        })
        .eq("id", ticketId)
      if (finaliseErr) {
        steps.push(err("finalise_procurement", finaliseErr.message))
      } else {
        steps.push(ok("finalise_procurement", "Ticket advanced to approved_for_procurement"))
      }

      const { data: final } = await admin.from("help_desk_tickets").select("status").eq("id", ticketId).single()
      if (final?.status === "approved_for_procurement") {
        steps.push(ok("verify_final_state", "status=approved_for_procurement ✓"))
      } else {
        steps.push(err("verify_final_state", `Expected approved_for_procurement, got ${final?.status}`))
      }
    }

    // Cleanup
    if (cleanup && ticketId) {
      try {
        await admin.from("help_desk_tickets").delete().eq("id", ticketId)
      } catch {
        /* ignore */
      }
      steps.push(ok("cleanup", `Deleted test ticket ${ticketId}`))
    }

    return { ok: steps.every((s) => s.status !== "error"), steps }
  } catch (e: any) {
    if (cleanup && ticketId) {
      try {
        await admin.from("help_desk_tickets").delete().eq("id", ticketId)
      } catch {
        /* ignore */
      }
    }
    return { ok: false, steps: [...steps, err("unexpected", e.message)] }
  }
}

async function testTask(admin: any, body: any): Promise<{ ok: boolean; steps: StepResult[] }> {
  const steps: StepResult[] = []
  let taskId: string | null = null
  const cleanup = body.cleanup !== false

  try {
    const { assigner_id, assignee_id } = body
    if (!assigner_id || !assignee_id) {
      steps.push(err("validate_input", "assigner_id and assignee_id are required"))
      return { ok: false, steps }
    }

    // Step 1: Load assigner
    const { data: assigner } = await admin
      .from("profiles")
      .select("id, full_name, department")
      .eq("id", assigner_id)
      .single()
    steps.push(assigner ? ok("load_assigner", `Loaded: ${assigner.full_name}`) : err("load_assigner", "Not found"))
    if (!assigner) return { ok: false, steps }

    // Step 2: Load assignee
    const { data: assignee } = await admin
      .from("profiles")
      .select("id, full_name, department")
      .eq("id", assignee_id)
      .single()
    steps.push(assignee ? ok("load_assignee", `Loaded: ${assignee.full_name}`) : err("load_assignee", "Not found"))
    if (!assignee) return { ok: false, steps }

    // Step 3: Create task
    const due = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10)
    const { data: task, error: taskErr } = await admin
      .from("tasks")
      .insert({
        title: "[TEST] Automated task flow test",
        description: "Automated test task — safe to delete",
        priority: "medium",
        status: "pending",
        assigned_to: assignee_id,
        assigned_by: assigner_id,
        department: assignee.department || null,
        due_date: due,
        assignment_type: "individual",
      })
      .select()
      .single()

    if (taskErr || !task) {
      steps.push(err("create_task", taskErr?.message || "Insert returned no data"))
      return { ok: false, steps }
    }
    taskId = task.id
    steps.push(ok("create_task", `Created task ${task.id}`))

    // Step 4: Move to in_progress
    const { error: startErr } = await admin.from("tasks").update({ status: "in_progress" }).eq("id", taskId)
    if (startErr) steps.push(err("start_task", startErr.message))
    else steps.push(ok("start_task", "Status → in_progress"))

    // Step 5: Complete task
    const { error: completeErr } = await admin
      .from("tasks")
      .update({ status: "completed", completed_at: new Date().toISOString() })
      .eq("id", taskId)
    if (completeErr) steps.push(err("complete_task", completeErr.message))
    else steps.push(ok("complete_task", "Status → completed"))

    // Step 6: Verify
    const { data: final } = await admin.from("tasks").select("status").eq("id", taskId).single()
    if (final?.status === "completed") steps.push(ok("verify_final_state", "status=completed ✓"))
    else steps.push(err("verify_final_state", `Expected completed, got ${final?.status}`))

    // Cleanup
    if (cleanup && taskId) {
      try {
        await admin.from("tasks").delete().eq("id", taskId)
      } catch {
        /* ignore */
      }
      steps.push(ok("cleanup", `Deleted test task ${taskId}`))
    }

    return { ok: steps.every((s) => s.status !== "error"), steps }
  } catch (e: any) {
    if (cleanup && taskId) {
      try {
        await admin.from("tasks").delete().eq("id", taskId)
      } catch {
        /* ignore */
      }
    }
    return { ok: false, steps: [...steps, err("unexpected", e.message)] }
  }
}

export async function POST(request: NextRequest) {
  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  const { data: p } = await supabase.from("profiles").select("role").eq("id", user.id).single()
  if (p?.role !== "developer") return NextResponse.json({ error: "Forbidden" }, { status: 403 })

  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY
  if (!url || !serviceKey)
    return NextResponse.json({ error: "SUPABASE_SERVICE_ROLE_KEY not configured" }, { status: 500 })

  const admin = createAdminClient(url, serviceKey, { auth: { autoRefreshToken: false, persistSession: false } })
  const body = await request.json()

  if (body.kind === "help_desk") {
    const result = await testHelpDesk(admin, body)
    return NextResponse.json(result)
  }

  if (body.kind === "task") {
    const result = await testTask(admin, body)
    return NextResponse.json(result)
  }

  return NextResponse.json({ error: "kind must be 'help_desk' or 'task'" }, { status: 400 })
}

/**
 * GET /api/dev/help-desk-route-diagnostics
 *
 * Validates help-desk routing prerequisites:
 * - support flow: department lead coverage per service department
 * - procurement flow: department lead + HCS + MD approver availability
 *
 * Protected: developer role only.
 */

import { NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"
import { DEPT_EXECUTIVE_MANAGEMENT, DEPT_CORPORATE_SERVICES } from "@/config/constants"

type DiagRow = {
  flow_kind: "support" | "procurement"
  stage_code:
    | "department_lead"
    | "requester_department_lead"
    | "service_department_lead"
    | "head_corporate_services"
    | "managing_director"
  scope: string
  resolved: boolean
  resolved_user_id?: string | null
  resolved_name?: string | null
  fail_reason?: string
}

function getManagedDepartments(profile: any): string[] {
  const managed = Array.isArray(profile?.lead_departments) ? profile.lead_departments.filter(Boolean) : []
  const withPrimary = profile?.department ? [profile.department, ...managed] : managed
  return Array.from(new Set(withPrimary))
}

function isLeadForDepartment(profile: any, departmentName: string): boolean {
  if (!profile?.is_department_lead) return false
  return getManagedDepartments(profile).includes(departmentName)
}

function isHcsCandidate(profile: any): boolean {
  if (!profile) return false
  const managed = Array.isArray(profile.lead_departments) ? profile.lead_departments : []
  return (
    (profile.role === "developer" ||
      profile.role === "super_admin" ||
      profile.role === "admin" ||
      profile.is_department_lead) &&
    (profile.department === DEPT_CORPORATE_SERVICES || managed.includes(DEPT_CORPORATE_SERVICES))
  )
}

function isMdCandidate(profile: any): boolean {
  if (!profile) return false
  return (
    ((profile.role === "developer" || profile.role === "super_admin" || profile.role === "admin") &&
      profile.department === DEPT_EXECUTIVE_MANAGEMENT) ||
    profile.role === "developer" ||
    profile.role === "super_admin"
  )
}

export async function GET() {
  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  const { data: actorProfile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
  if (actorProfile?.role !== "developer") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY
  if (!url || !serviceKey) {
    return NextResponse.json({ error: "SUPABASE_SERVICE_ROLE_KEY not configured" }, { status: 500 })
  }

  const admin = createAdminClient(url, serviceKey, {
    auth: { autoRefreshToken: false, persistSession: false },
  })

  const [departmentsRes, leadsRes] = await Promise.all([
    admin.from("departments").select("name").order("name"),
    applyAssignableStatusFilter(
      admin
        .from("profiles")
        .select("id, full_name, role, department, is_department_lead, lead_departments, employment_status"),
      { allowLegacyNullStatus: false }
    ),
  ])

  if (departmentsRes.error) {
    return NextResponse.json({ error: `Failed to load departments: ${departmentsRes.error.message}` }, { status: 500 })
  }
  if (leadsRes.error) {
    return NextResponse.json({ error: `Failed to load profiles: ${leadsRes.error.message}` }, { status: 500 })
  }

  const departments = (departmentsRes.data || []).map((d: any) => d.name).filter(Boolean)
  const profiles = leadsRes.data || []
  const leadProfiles = profiles.filter((p: any) => p.is_department_lead)
  const multiDepartmentLeadIds = new Set(
    leadProfiles.filter((p: any) => getManagedDepartments(p).length > 1).map((p: any) => p.id)
  )
  const rows: DiagRow[] = []

  for (const departmentName of departments) {
    const leadCandidate = profiles.find((p: any) => isLeadForDepartment(p, departmentName))
    const isConflict = Boolean(leadCandidate?.id && multiDepartmentLeadIds.has(leadCandidate.id))
    rows.push({
      flow_kind: "support",
      stage_code: "department_lead",
      scope: departmentName,
      resolved: Boolean(leadCandidate) && !isConflict,
      resolved_user_id: leadCandidate?.id ?? null,
      resolved_name: leadCandidate?.full_name ?? null,
      fail_reason: !leadCandidate
        ? `No active department lead for "${departmentName}"`
        : isConflict
          ? `${leadCandidate.full_name || leadCandidate.id} is assigned as lead for multiple departments; one person cannot lead more than one department`
          : undefined,
    })
  }

  for (const departmentName of departments) {
    const deptLead = profiles.find((p: any) => isLeadForDepartment(p, departmentName))
    const isConflict = Boolean(deptLead?.id && multiDepartmentLeadIds.has(deptLead.id))
    rows.push({
      flow_kind: "procurement",
      stage_code: "requester_department_lead",
      scope: departmentName,
      resolved: Boolean(deptLead) && !isConflict,
      resolved_user_id: deptLead?.id ?? null,
      resolved_name: deptLead?.full_name ?? null,
      fail_reason: !deptLead
        ? `No active department lead for "${departmentName}"`
        : isConflict
          ? `${deptLead.full_name || deptLead.id} is assigned as lead for multiple departments; one person cannot lead more than one department`
          : undefined,
    })
    rows.push({
      flow_kind: "procurement",
      stage_code: "service_department_lead",
      scope: departmentName,
      resolved: Boolean(deptLead) && !isConflict,
      resolved_user_id: deptLead?.id ?? null,
      resolved_name: deptLead?.full_name ?? null,
      fail_reason: !deptLead
        ? `No active department lead for "${departmentName}"`
        : isConflict
          ? `${deptLead.full_name || deptLead.id} is assigned as lead for multiple departments; one person cannot lead more than one department`
          : undefined,
    })
  }

  const hcsCandidate = profiles.find((p: any) => isHcsCandidate(p))
  rows.push({
    flow_kind: "procurement",
    stage_code: "head_corporate_services",
    scope: "global",
    resolved: Boolean(hcsCandidate),
    resolved_user_id: hcsCandidate?.id ?? null,
    resolved_name: hcsCandidate?.full_name ?? null,
    fail_reason: hcsCandidate
      ? undefined
      : "No active HCS approver candidate (Corporate Services lead/admin context) found",
  })

  const mdCandidate = profiles.find((p: any) => isMdCandidate(p))
  rows.push({
    flow_kind: "procurement",
    stage_code: "managing_director",
    scope: "global",
    resolved: Boolean(mdCandidate),
    resolved_user_id: mdCandidate?.id ?? null,
    resolved_name: mdCandidate?.full_name ?? null,
    fail_reason: mdCandidate ? undefined : "No active MD approver candidate found",
  })

  const broken = rows.filter((r) => !r.resolved)
  return NextResponse.json({ results: rows, broken_count: broken.length, total: rows.length })
}

/**
 * POST /api/dev/leave-flow-test
 *
 * Developer-only route that simulates the complete leave workflow end-to-end
 * using service-role privileges.  No real user passwords needed — the caller
 * just supplies:
 *   requester_id    – UUID of the employee requesting leave
 *   reliever_id     – UUID of the reliever
 *   leave_type_id   – UUID of the leave type to request
 *   mode            – "full-auto" | "step" (default "full-auto")
 *   cleanup         – boolean, delete the test request afterwards (default true)
 *
 * The response contains a step-by-step trace of what happened.
 *
 * PROTECTED: developer role only.
 */

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import {
  buildResolvedRouteSnapshot,
  classifyRequesterKind,
  getRouteStageByOrder,
  stageCodeForRole,
} from "@/lib/hr/leave-routing"
import { computeLeaveDates, getLeavePolicy, resolveProfileByIdentifier } from "@/lib/hr/leave-workflow"

type StepResult = {
  step: string
  status: "ok" | "error" | "skipped"
  detail?: string
  data?: unknown
}

function ok(step: string, detail?: string, data?: unknown): StepResult {
  return { step, status: "ok", detail, data }
}

function err(step: string, detail: string): StepResult {
  return { step, status: "error", detail }
}

export async function POST(request: NextRequest) {
  // ── Auth guard: developer only ──────────────────────────────────────────────
  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  const { data: actorProfile } = await supabase.from("profiles").select("role").eq("id", user.id).single()

  if (actorProfile?.role !== "developer") {
    return NextResponse.json({ error: "Forbidden: developer role required" }, { status: 403 })
  }

  // ── Service-role client ─────────────────────────────────────────────────────
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

  if (!url || !serviceKey) {
    return NextResponse.json({ error: "SUPABASE_SERVICE_ROLE_KEY is not configured on this server" }, { status: 500 })
  }

  const admin = createAdminClient(url, serviceKey, {
    auth: { autoRefreshToken: false, persistSession: false },
  })

  // ── Parse body ──────────────────────────────────────────────────────────────
  const body = await request.json()
  const {
    requester_id,
    reliever_id,
    leave_type_id,
    cleanup = true,
  } = body as {
    requester_id: string
    reliever_id: string
    leave_type_id: string
    cleanup?: boolean
  }

  if (!requester_id || !reliever_id || !leave_type_id) {
    return NextResponse.json({ error: "requester_id, reliever_id and leave_type_id are required" }, { status: 400 })
  }

  const steps: StepResult[] = []
  let leaveRequestId: string | null = null

  try {
    // ── Step 1: Load requester profile ──────────────────────────────────────────
    const { data: requester, error: reqErr } = await admin
      .from("profiles")
      .select(
        "id, full_name, first_name, last_name, department, department_id, is_department_lead, lead_departments, gender, employment_date, work_location, employment_type, marital_status, has_children, pregnancy_status"
      )
      .eq("id", requester_id)
      .single()

    if (reqErr || !requester) {
      steps.push(err("load_requester", `Profile not found: ${reqErr?.message}`))
      return NextResponse.json({ ok: false, steps })
    }
    steps.push(ok("load_requester", `Loaded: ${requester.full_name || requester.id}`))

    // ── Step 2: Load reliever profile ───────────────────────────────────────────
    const reliever = await resolveProfileByIdentifier(admin, reliever_id, "Reliever").catch((e: Error) => {
      steps.push(err("load_reliever", e.message))
      return null
    })
    if (!reliever) return NextResponse.json({ ok: false, steps })
    steps.push(ok("load_reliever", `Loaded: ${reliever.full_name || reliever.id}`))

    // ── Step 3: Build route snapshot ────────────────────────────────────────────
    const requesterKind = classifyRequesterKind(requester)
    let routeSnapshot: Awaited<ReturnType<typeof buildResolvedRouteSnapshot>> | null = null

    try {
      routeSnapshot = await buildResolvedRouteSnapshot({
        supabase: admin,
        requester,
        requesterId: requester_id,
        requesterKind,
        relieverId: reliever_id,
      })
      steps.push(
        ok(
          "build_route_snapshot",
          `${routeSnapshot.length} stages`,
          routeSnapshot.map((s) => ({ order: s.stage_order, stage: s.stage_code, approver: s.approver_user_id }))
        )
      )
    } catch (e: any) {
      steps.push(err("build_route_snapshot", e.message))
      return NextResponse.json({ ok: false, steps })
    }

    // ── Step 4: Compute leave dates ─────────────────────────────────────────────
    const policy = await getLeavePolicy(admin, leave_type_id)
    const startDate = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10) // 7 days from now
    const { endDate, resumeDate } = await computeLeaveDates({
      supabase: admin,
      startDate,
      daysCount: 3,
      accrualMode: policy.accrual_mode || "calendar_days",
      location: requester.work_location || "global",
    })
    steps.push(ok("compute_dates", `${startDate} → ${endDate}, resume ${resumeDate}`))

    // ── Step 5: Insert leave request ────────────────────────────────────────────
    const firstStage = getRouteStageByOrder(routeSnapshot, 1)
    if (!firstStage) {
      steps.push(err("create_request", "Route snapshot has no first stage"))
      return NextResponse.json({ ok: false, steps })
    }

    const deptLeadStage = routeSnapshot.find((s) => s.approver_role_code === "department_lead")

    const { data: newRequest, error: insertErr } = await admin
      .from("leave_requests")
      .insert({
        user_id: requester_id,
        leave_type_id,
        start_date: startDate,
        end_date: endDate,
        resume_date: resumeDate,
        days_count: 3,
        reason: "[TEST] Automated leave flow test — safe to delete",
        status: "pending",
        approval_stage: firstStage.stage_code,
        current_stage_code: firstStage.stage_code,
        current_stage_order: firstStage.stage_order,
        current_approver_user_id: firstStage.approver_user_id,
        requester_route_kind: requesterKind,
        route_snapshot: routeSnapshot,
        reliever_id: reliever_id,
        supervisor_id: deptLeadStage?.approver_user_id || null,
        handover_note: "[TEST] Handover note for automated flow test",
        requested_days_mode: policy.accrual_mode || "calendar_days",
        request_kind: "standard",
      })
      .select()
      .single()

    if (insertErr || !newRequest) {
      steps.push(err("create_request", insertErr?.message || "Insert returned no data"))
      return NextResponse.json({ ok: false, steps })
    }

    leaveRequestId = newRequest.id
    steps.push(ok("create_request", `Created request ${newRequest.id}`))

    // ── Step 6–N: Simulate each approval stage ──────────────────────────────────
    let currentStageOrder = firstStage.stage_order

    while (true) {
      const { data: current, error: fetchErr } = await admin
        .from("leave_requests")
        .select("*")
        .eq("id", leaveRequestId!)
        .single()

      if (fetchErr || !current) {
        steps.push(err(`advance_stage_${currentStageOrder}`, "Failed to re-fetch leave request"))
        break
      }

      const stageCode = current.current_stage_code || current.approval_stage
      const approverId = current.current_approver_user_id

      if (!approverId || ["completed", "approved", "rejected"].includes(current.status)) {
        break
      }

      const nextStageOrder = currentStageOrder + 1
      const nextStage = getRouteStageByOrder(routeSnapshot, nextStageOrder)
      const now = new Date().toISOString()

      // Upsert approval record
      await admin.from("leave_approvals").upsert(
        {
          leave_request_id: leaveRequestId,
          approver_id: approverId,
          approval_level: currentStageOrder,
          status: "approved",
          comments: `[TEST] Auto-approved at stage ${stageCode}`,
          approved_at: now,
          stage_code: stageCode,
          stage_order: currentStageOrder,
          reliever_revision: current.reliever_revision || 1,
          superseded: false,
        },
        { onConflict: "leave_request_id,approver_id,approval_level" }
      )

      if (nextStage && nextStage.approver_user_id) {
        // Advance to next stage
        const updates: Record<string, unknown> = {
          approval_stage: nextStage.stage_code,
          current_stage_code: nextStage.stage_code,
          current_stage_order: nextStage.stage_order,
          current_approver_user_id: nextStage.approver_user_id,
        }
        if (stageCode === stageCodeForRole("reliever")) updates.reliever_decision_at = now
        if (stageCode === stageCodeForRole("department_lead")) {
          updates.supervisor_decision_at = now
          updates.lead_reconfirm_required = false
        }
        if (stageCode === stageCodeForRole("admin_hr_lead") || stageCode === stageCodeForRole("hcs")) {
          updates.hr_decision_at = now
        }

        await admin.from("leave_requests").update(updates).eq("id", leaveRequestId!)
        steps.push(
          ok(`approve_stage_${currentStageOrder}`, `✓ ${stageCode} approved → advancing to ${nextStage.stage_code}`)
        )
      } else {
        // Final stage — mark approved
        await admin
          .from("leave_requests")
          .update({
            status: "approved",
            approval_stage: "completed",
            current_stage_code: "completed",
            approved_by: approverId,
            approved_at: now,
            hr_decision_at: now,
            lead_reconfirm_required: false,
          })
          .eq("id", leaveRequestId!)

        steps.push(ok(`approve_stage_${currentStageOrder}`, `✓ ${stageCode} approved (FINAL) → leave now APPROVED`))
        break
      }

      currentStageOrder = nextStageOrder
    }

    // ── Step 7: Verify final state ──────────────────────────────────────────────
    const { data: finalRequest } = await admin
      .from("leave_requests")
      .select("status, current_stage_code, approval_stage")
      .eq("id", leaveRequestId!)
      .single()

    if (finalRequest) {
      const approved = finalRequest.status === "approved"
      steps.push(
        approved
          ? ok("verify_final_state", `status=${finalRequest.status} stage=${finalRequest.current_stage_code}`)
          : err(
              "verify_final_state",
              `Expected approved, got status=${finalRequest.status} stage=${finalRequest.current_stage_code}`
            )
      )
    }

    // ── Step 8: Cleanup (optional) ──────────────────────────────────────────────
    if (cleanup && leaveRequestId) {
      await admin.from("leave_approvals").delete().eq("leave_request_id", leaveRequestId)
      await admin.from("leave_requests").delete().eq("id", leaveRequestId)
      steps.push(ok("cleanup", `Deleted test request ${leaveRequestId}`))
    }

    const allOk = steps.every((s) => s.status !== "error")
    return NextResponse.json({ ok: allOk, leave_request_id: cleanup ? null : leaveRequestId, steps })
  } catch (error: any) {
    // cleanup on unexpected error
    if (cleanup && leaveRequestId) {
      try {
        await admin.from("leave_approvals").delete().eq("leave_request_id", leaveRequestId)
      } catch {
        /* ignore */
      }
      try {
        await admin.from("leave_requests").delete().eq("id", leaveRequestId)
      } catch {
        /* ignore */
      }
    }
    return NextResponse.json({ ok: false, error: error?.message || "Unexpected error", steps }, { status: 500 })
  }
}

/**
 * GET /api/dev/leave-route-diagnostics
 *
 * Validates all leave_approval_role_routes and their resolvers.
 * For each (requester_kind, stage) combination it reports whether
 * the approver can actually be resolved right now.
 *
 * Protected: developer role only.
 */

import { NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import { DEPT_EXECUTIVE_MANAGEMENT, DEPT_CORPORATE_SERVICES } from "@/config/constants"

const DEPARTMENT_NAMES: Record<string, string> = {
  admin_hr_lead: "Admin & HR",
  md: DEPT_EXECUTIVE_MANAGEMENT,
  hcs: DEPT_CORPORATE_SERVICES,
}

type DiagRow = {
  requester_kind: string
  stage_order: number
  approver_role_code: string
  resolved: boolean
  resolved_user_id?: string | null
  resolved_name?: string | null
  fail_reason?: string
}

async function tryResolve(
  admin: any,
  roleCode: string,
  dummyRelieverId = "00000000-0000-0000-0000-000000000000"
): Promise<{ id: string; name: string | null } | null> {
  if (roleCode === "reliever") {
    // Reliever is per-request; for diagnostics just mark as "dynamic"
    return { id: dummyRelieverId, name: "(dynamic — set per request)" }
  }

  if (roleCode === "department_lead") {
    // Department lead also dynamic per requester; mark as such
    return { id: "dynamic", name: "(dynamic — resolved per requester's department)" }
  }

  const departmentName = DEPARTMENT_NAMES[roleCode]
  if (departmentName) {
    // Try to find a profile with is_department_lead=true for this department
    const { data, error } = await admin
      .from("profiles")
      .select("id, full_name, department, lead_departments, is_department_lead")
      .eq("is_department_lead", true)

    if (error) return null

    const match = (data || []).find((p: any) => {
      const managed = Array.isArray(p.lead_departments) ? p.lead_departments : []
      return p.is_department_lead && (p.department === departmentName || managed.includes(departmentName))
    })

    if (!match) return null
    if (
      (data || []).filter((p: any) => {
        const managed = Array.isArray(p.lead_departments) ? p.lead_departments : []
        return p.is_department_lead && (p.department === departmentName || managed.includes(departmentName))
      }).length > 1
    ) {
      return null // conflict
    }
    return { id: match.id, name: match.full_name || null }
  }

  // Fixed role from leave_approver_assignments table
  const now = new Date().toISOString()
  const { data, error } = await admin
    .from("leave_approver_assignments")
    .select(
      "user_id, effective_from, effective_to, is_primary, profiles:profiles!leave_approver_assignments_user_id_fkey(full_name)"
    )
    .eq("approver_role_code", roleCode)
    .eq("is_active", true)
    .eq("scope_type", "global")
    .order("is_primary", { ascending: false })

  if (error || !data?.length) return null

  const valid = (data || []).filter((row: any) => {
    const startsOk = !row.effective_from || row.effective_from <= now
    const endsOk = !row.effective_to || row.effective_to >= now
    return startsOk && endsOk
  })

  if (!valid.length) return null
  const top = valid[0]
  return {
    id: top.user_id,
    name: (top.profiles as any)?.full_name || null,
  }
}

export async function GET() {
  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  const { data: actorProfile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
  if (actorProfile?.role !== "developer") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY
  if (!url || !serviceKey) {
    return NextResponse.json({ error: "SUPABASE_SERVICE_ROLE_KEY not configured" }, { status: 500 })
  }

  const admin = createAdminClient(url, serviceKey, {
    auth: { autoRefreshToken: false, persistSession: false },
  })

  // Fetch all route rows
  const { data: routeRows, error: routeError } = await admin
    .from("leave_approval_role_routes")
    .select("requester_kind, stage_order, approver_role_code, is_active")
    .order("requester_kind")
    .order("stage_order")

  if (routeError) {
    return NextResponse.json({ error: `Failed to load routes: ${routeError.message}` }, { status: 500 })
  }

  const results: DiagRow[] = []

  for (const row of routeRows || []) {
    if (!row.is_active) {
      results.push({
        requester_kind: row.requester_kind,
        stage_order: row.stage_order,
        approver_role_code: row.approver_role_code,
        resolved: false,
        fail_reason: "Stage is inactive (is_active = false)",
      })
      continue
    }

    try {
      const resolved = await tryResolve(admin, row.approver_role_code)
      results.push({
        requester_kind: row.requester_kind,
        stage_order: row.stage_order,
        approver_role_code: row.approver_role_code,
        resolved: resolved !== null,
        resolved_user_id: resolved?.id ?? null,
        resolved_name: resolved?.name ?? null,
        fail_reason: resolved ? undefined : `No active approver found for role "${row.approver_role_code}"`,
      })
    } catch (e: any) {
      results.push({
        requester_kind: row.requester_kind,
        stage_order: row.stage_order,
        approver_role_code: row.approver_role_code,
        resolved: false,
        fail_reason: e?.message || "Unknown error during resolution",
      })
    }
  }

  const broken = results.filter((r) => !r.resolved)
  return NextResponse.json({ results, broken_count: broken.length, total: results.length })
}

/**
 * GET /api/dev/task-route-diagnostics
 *
 * Validates task routing/notification prerequisites:
 * - each department has an active lead (for lead visibility/management)
 * - each department has active members (for department-assigned tasks)
 *
 * Protected: developer role only.
 */

import { NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"

type DiagRow = {
  check_code: "department_lead_coverage" | "department_assignment_target"
  scope: string
  resolved: boolean
  resolved_user_id?: string | null
  resolved_name?: string | null
  fail_reason?: string
}

function getManagedDepartments(profile: any): string[] {
  const managed = Array.isArray(profile?.lead_departments) ? profile.lead_departments.filter(Boolean) : []
  const withPrimary = profile?.department ? [profile.department, ...managed] : managed
  return Array.from(new Set(withPrimary))
}

function isLeadForDepartment(profile: any, departmentName: string): boolean {
  if (!profile?.is_department_lead) return false
  return getManagedDepartments(profile).includes(departmentName)
}

export async function GET() {
  const supabase = await createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  const { data: actorProfile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
  if (actorProfile?.role !== "developer") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY
  if (!url || !serviceKey) {
    return NextResponse.json({ error: "SUPABASE_SERVICE_ROLE_KEY not configured" }, { status: 500 })
  }

  const admin = createAdminClient(url, serviceKey, {
    auth: { autoRefreshToken: false, persistSession: false },
  })

  const [departmentsRes, profilesRes] = await Promise.all([
    admin.from("departments").select("name").order("name"),
    applyAssignableStatusFilter(
      admin
        .from("profiles")
        .select("id, full_name, department, is_department_lead, lead_departments, employment_status"),
      { allowLegacyNullStatus: false }
    ),
  ])

  if (departmentsRes.error) {
    return NextResponse.json({ error: `Failed to load departments: ${departmentsRes.error.message}` }, { status: 500 })
  }
  if (profilesRes.error) {
    return NextResponse.json({ error: `Failed to load profiles: ${profilesRes.error.message}` }, { status: 500 })
  }

  const departments = (departmentsRes.data || []).map((d: any) => d.name).filter(Boolean)
  const profiles = profilesRes.data || []
  const leadProfiles = profiles.filter((p: any) => p.is_department_lead)
  const multiDepartmentLeadIds = new Set(
    leadProfiles.filter((p: any) => getManagedDepartments(p).length > 1).map((p: any) => p.id)
  )
  const rows: DiagRow[] = []

  for (const departmentName of departments) {
    const leadCandidate = profiles.find((p: any) => isLeadForDepartment(p, departmentName))
    const isConflict = Boolean(leadCandidate?.id && multiDepartmentLeadIds.has(leadCandidate.id))
    rows.push({
      check_code: "department_lead_coverage",
      scope: departmentName,
      resolved: Boolean(leadCandidate) && !isConflict,
      resolved_user_id: leadCandidate?.id ?? null,
      resolved_name: leadCandidate?.full_name ?? null,
      fail_reason: !leadCandidate
        ? `No active department lead for "${departmentName}"`
        : isConflict
          ? `${leadCandidate.full_name || leadCandidate.id} is assigned as lead for multiple departments; one person cannot lead more than one department`
          : undefined,
    })
  }

  for (const departmentName of departments) {
    const members = profiles.filter((p: any) => p.department === departmentName)
    rows.push({
      check_code: "department_assignment_target",
      scope: departmentName,
      resolved: members.length > 0,
      resolved_user_id: null,
      resolved_name: null,
      fail_reason:
        members.length > 0 ? undefined : `No active users in "${departmentName}" for department task assignment`,
    })
  }

  const broken = rows.filter((r) => !r.resolved)
  return NextResponse.json({ results: rows, broken_count: broken.length, total: rows.length })
}

