﻿import { NextRequest, NextResponse } from "next/server"
import {
  assertBookingWindow,
  assertNoFleetOverlap,
  assertReason,
  FLEET_ALLOWED_MIME_TYPES,
  FLEET_BLOCKING_STATUSES,
  FLEET_MAX_FILE_SIZE,
