    const data = (bookings || []).map((booking: any) => ({
      ...booking,
      attachments: attachmentsByBooking.get(booking.id) || [],
    }))

    const nowIso = new Date().toISOString()
    const { data: resourceSchedule } = await validationClient
      .from("fleet_bookings")
      .select("id, resource_id, start_at, end_at, status")
      .in("status", [...FLEET_BLOCKING_STATUSES])
      .gte("end_at", nowIso)
      .order("start_at", { ascending: true })
      .limit(500)

    return NextResponse.json({ data, resource_schedule: resourceSchedule || [] })
  } catch (error) {
    const message = error instanceof Error ? error.message : "Internal server error"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  const uploadedPaths: string[] = []
  try {
    const supabase = await createClient()
    const validationClient = getServiceRoleClientOrFallback(supabase)
    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const formData = await request.formData()
    const resourceId = String(formData.get("resource_id") || "").trim()
    const startAt = String(formData.get("start_at") || "").trim()
    const endAt = String(formData.get("end_at") || "").trim()
    const reason = assertReason(String(formData.get("reason") || ""))
    const attachments = formData.getAll("attachments").filter((entry) => entry instanceof File) as File[]

    if (!resourceId || !startAt || !endAt) {
      return NextResponse.json({ error: "resource_id, start_at, and end_at are required" }, { status: 400 })
    }

    const { start, end } = assertBookingWindow(startAt, endAt)
    if (start.getTime() < Date.now()) {
      return NextResponse.json({ error: "Booking start time cannot be in the past" }, { status: 400 })
    }

    const { data: resource, error: resourceError } = await validationClient
      .from("fleet_resources")
      .select("id, is_active")
      .eq("id", resourceId)
      .maybeSingle()

    if (resourceError) {
      return NextResponse.json({ error: "Failed to validate resource" }, { status: 500 })
    }

    if (!resource || !resource.is_active) {
      return NextResponse.json({ error: "Selected resource is unavailable" }, { status: 400 })
    }

    await assertNoFleetOverlap({
      supabase: validationClient,
      resourceId,
      startAt: start.toISOString(),
      endAt: end.toISOString(),
    })

    for (let i = 0; i < attachments.length; i += 1) {
      const file = attachments[i]
      if (!FLEET_ALLOWED_MIME_TYPES.has(file.type)) {
        return NextResponse.json(
          { error: `Unsupported file type for ${file.name}. Only PDF and images are allowed.` },
          { status: 400 }
        )
      }
      if (file.size > FLEET_MAX_FILE_SIZE) {
        return NextResponse.json(
          { error: `${file.name} exceeds max size of ${Math.round(FLEET_MAX_FILE_SIZE / (1024 * 1024))}MB.` },
          { status: 400 }
        )
      }

      const fileName = sanitizeFileName(file.name || `attachment-${i + 1}`)
      const filePath = `${user.id}/${Date.now()}-${i + 1}-${fileName}`

      const { error: uploadError } = await supabase.storage
        .from("fleet_booking_documents")
        .upload(filePath, file, { contentType: file.type, upsert: false })

      if (uploadError) {
        throw new Error(`Failed to upload attachment ${file.name}`)
      }

      uploadedPaths.push(filePath)
    }

    const { data: booking, error: bookingError } = await supabase
      .from("fleet_bookings")
      .insert({
        resource_id: resourceId,
        requester_id: user.id,
        start_at: start.toISOString(),
        end_at: end.toISOString(),
        reason,
        status: "pending",
      })
      .select(
        "id, resource_id, requester_id, start_at, end_at, reason, status, admin_note, reviewed_by, reviewed_at, created_at, updated_at"
      )
      .single()

    if (bookingError || !booking) {
      throw new Error(bookingError?.message || "Failed to create booking")
    }

    if (uploadedPaths.length > 0) {
      const attachmentRows = uploadedPaths.map((filePath, index) => {
        const file = attachments[index]
        return {
          booking_id: booking.id,
          file_name: file.name,
          file_path: filePath,
          mime_type: file.type,
          file_size: file.size,
          uploaded_by: user.id,
        }
      })

      const { error: attachmentError } = await supabase.from("fleet_booking_attachments").insert(attachmentRows)

      if (attachmentError) {
        await validationClient.from("fleet_bookings").delete().eq("id", booking.id)
        throw new Error("Failed to save attachment metadata")
      }
    }

    await writeAuditLog(
      supabase,
      {
        action: "create",
        entityType: "fleet_booking",
        entityId: booking.id,
        newValues: {
          resource_id: booking.resource_id,
          start_at: booking.start_at,
          end_at: booking.end_at,
          status: booking.status,
        },
        context: { actorId: user.id, source: "api", route: "/api/fleet/bookings" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ data: booking }, { status: 201 })
  } catch (error) {
    if (uploadedPaths.length > 0) {
      try {
        const supabase = await createClient()
        await supabase.storage.from("fleet_booking_documents").remove(uploadedPaths)
      } catch {
        // ignore cleanup errors
      }
    }

    const message = error instanceof Error ? error.message : "Internal server error"
    const status = message.toLowerCase().includes("overlap") ? 400 : 500
    return NextResponse.json({ error: message }, { status })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { createClient as createAdminClient } from "@supabase/supabase-js"
import { rateLimit, getClientId } from "@/lib/rate-limit"
import {
  areRequiredDocumentsVerified,
  getLeavePolicy,
  notifyUsers,
  syncAttendanceForApprovedLeave,
} from "@/lib/hr/leave-workflow"
import { getRouteStageByOrder, stageCodeForRole } from "@/lib/hr/leave-routing"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("hr-leave-approve")

function normalizeAction(body: { action?: string; status?: string }) {
  if (body.action === "approve" || body.status === "approved") return "approved"
  if (body.action === "reject" || body.status === "rejected") return "rejected"
  return null
}

function inferCurrentStageCode(leaveRequest: any) {
  return leaveRequest.current_stage_code || leaveRequest.approval_stage
}

function toWorkflowRejectionStage(stageCode: string) {
  if (stageCode === stageCodeForRole("reliever")) return "reliever"
  if (stageCode === stageCodeForRole("department_lead")) return "supervisor"
  return "hr"
}

function humanStage(stageCode: string) {
  switch (stageCode) {
    case "pending_reliever":
      return "Reliever"
    case "pending_department_lead":
      return "Department Lead"
    case "pending_admin_hr_lead":
      return "Admin & HR Lead"
    case "pending_hcs":
      return "HCS"
    case "pending_md":
      return "MD"
    default:
      return stageCode.replaceAll("_", " ")
  }
}

export async function POST(request: NextRequest) {
  const rl = rateLimit(`leave-approve:${getClientId(request)}`, { limit: 30, windowSec: 600 })
  if (!rl.allowed) {
    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 })
  }

  try {
    const supabase = await createClient()

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const supabaseAdmin =
      process.env.NEXT_PUBLIC_SUPABASE_URL && process.env.SUPABASE_SERVICE_ROLE_KEY
        ? createAdminClient(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY, {
            auth: { autoRefreshToken: false, persistSession: false },
          })
        : supabase

    const body = await request.json()
    const { leave_request_id, comments, override_evidence } = body
    const action = normalizeAction(body)

    if (!leave_request_id || !action) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 })
    }

    if (action === "rejected" && !comments?.trim()) {
      return NextResponse.json({ error: "Comments are required when rejecting a leave request" }, { status: 400 })
    }

    const { data: actorProfile } = await supabase
      .from("profiles")
      .select("id, role, full_name, company_email")
      .eq("id", user.id)
      .single()
    const isHRAdmin = ["developer", "admin", "super_admin"].includes(actorProfile?.role)
    const actorName = actorProfile?.full_name || actorProfile?.company_email || "An approver"

    const { data: leaveRequest, error: fetchError } = await supabase
      .from("leave_requests")
      .select("*")
      .eq("id", leave_request_id)
      .single()

    if (fetchError || !leaveRequest) {
      return NextResponse.json({ error: "Leave request not found" }, { status: 404 })
    }

    if (!["pending", "pending_evidence"].includes(leaveRequest.status)) {
      return NextResponse.json({ error: "Only active requests can be processed" }, { status: 400 })
    }

    const stageCode = inferCurrentStageCode(leaveRequest)
    const snapshot = Array.isArray(leaveRequest.route_snapshot) ? leaveRequest.route_snapshot : []

    const currentStageOrder = Number(leaveRequest.current_stage_order || 1)
    const currentStage = getRouteStageByOrder(snapshot, currentStageOrder)

    const expectedApproverId = leaveRequest.current_approver_user_id || currentStage?.approver_user_id
    if (!expectedApproverId) {
      return NextResponse.json({ error: "LEAVE_APPROVER_NOT_CONFIGURED:current_stage" }, { status: 400 })
    }

    if (expectedApproverId !== user.id) {
      return NextResponse.json({ error: "LEAVE_STAGE_NOT_ASSIGNED_TO_ACTOR" }, { status: 403 })
    }

    if (leaveRequest.status === "pending_evidence" && action === "approved" && !isHRAdmin) {
      return NextResponse.json({ error: "Request is awaiting evidence verification before approval." }, { status: 400 })
    }

    const now = new Date().toISOString()

    if (action === "rejected") {
      const { error: updateError } = await supabaseAdmin
        .from("leave_requests")
        .update({
          status: "rejected",
          approval_stage: "rejected",
          current_stage_code: "rejected",
          rejected_reason: comments,
          workflow_rejection_stage: toWorkflowRejectionStage(stageCode),
          reliever_decision_at: stageCode === stageCodeForRole("reliever") ? now : leaveRequest.reliever_decision_at,
          supervisor_decision_at:
            stageCode === stageCodeForRole("department_lead") ? now : leaveRequest.supervisor_decision_at,
          hr_decision_at:
            stageCode === stageCodeForRole("admin_hr_lead") || stageCode === stageCodeForRole("hcs")
              ? now
              : leaveRequest.hr_decision_at,
        })
        .eq("id", leave_request_id)

      if (updateError) {
        return NextResponse.json({ error: `Failed to reject leave request: ${updateError.message}` }, { status: 500 })
      }

      const { error: rejectionAuditError } = await supabaseAdmin.from("leave_approvals").upsert(
        {
          leave_request_id,
          approver_id: user.id,
          approval_level: currentStageOrder,
          status: action,
          comments: comments || null,
          approved_at: now,
          stage_code: stageCode,
          stage_order: currentStageOrder,
          reliever_revision: leaveRequest.reliever_revision || 1,
          superseded: false,
        },
        { onConflict: "leave_request_id,approver_id,approval_level" }
      )
      if (rejectionAuditError) {
        return NextResponse.json(
          { error: `Failed to record rejection audit: ${rejectionAuditError.message}` },
          { status: 500 }
        )
      }

      await notifyUsers(supabaseAdmin, {
        userIds: [leaveRequest.user_id],
        title: "Leave request rejected",
        message: `Your leave request was rejected at ${stageCode.replaceAll("_", " ")}. Reason: ${comments}`,
        actorId: user.id,
              linkUrl: "/leave",
        entityId: leave_request_id,
        emailEvent: "rejected",
      })

      // If a different reliever had already been attached, tell them the commitment is no longer active.
      if (leaveRequest.reliever_id && leaveRequest.reliever_id !== leaveRequest.user_id) {
        await notifyUsers(supabaseAdmin, {
          userIds: [leaveRequest.reliever_id],
          title: "Reliever commitment released",
          message: "This leave request was rejected, so your reliever commitment for it is no longer active.",
          actorId: user.id,
              linkUrl: "/leave",
          entityId: leave_request_id,
          emailEvent: "approval_required",
        })
      }

      await writeAuditLog(
        supabase,
        {
          action: "reject",
          entityType: "leave_request",
          entityId: leave_request_id,
          newValues: { status: "rejected", stage: stageCode, reason: comments },
          context: { actorId: user.id, source: "api", route: "/api/hr/leave/approve" },
        },
        { failOpen: true }
      )

      return NextResponse.json({ message: "Leave request rejected" })
    }

    // Approval history row
    const { error: approvalAuditError } = await supabaseAdmin.from("leave_approvals").upsert(
      {
        leave_request_id,
        approver_id: user.id,
        approval_level: currentStageOrder,
        status: action,
        comments: comments || null,
        approved_at: now,
        stage_code: stageCode,
        stage_order: currentStageOrder,
        reliever_revision: leaveRequest.reliever_revision || 1,
        superseded: false,
      },
      { onConflict: "leave_request_id,approver_id,approval_level" }
    )
    if (approvalAuditError) {
      return NextResponse.json(
        { error: `Failed to record approval audit: ${approvalAuditError.message}` },
        { status: 500 }
      )
    }

    const nextStageOrder = currentStageOrder + 1
    const nextStage = getRouteStageByOrder(snapshot, nextStageOrder)

    if (!nextStage) {
      const policy = await getLeavePolicy(supabase, leaveRequest.leave_type_id)
      const requiredDocs = policy.required_documents || []
      const evidenceStatus = await areRequiredDocumentsVerified(supabase, leave_request_id, requiredDocs)

      if (!evidenceStatus.complete) {
        if (!override_evidence) {
          return NextResponse.json(
            {
              error: `Required evidence not complete. Missing: ${evidenceStatus.missing.join(", ")}`,
              missing_documents: evidenceStatus.missing,
            },
            { status: 400 }
          )
        }

        if (!policy.override_allowed) {
          return NextResponse.json({ error: "Policy does not allow evidence override" }, { status: 400 })
        }

        if (!comments?.trim()) {
          return NextResponse.json({ error: "Override reason is required" }, { status: 400 })
        }
      }

      const { error: updateError } = await supabaseAdmin
        .from("leave_requests")
        .update({
          status: "approved",
          approval_stage: "completed",
          current_stage_code: "completed",
          approved_by: user.id,
          approved_at: now,
          hr_decision_at: now,
          hr_comment: comments || null,
          lead_reconfirm_required: false,
        })
        .eq("id", leave_request_id)

      if (updateError) {
        return NextResponse.json({ error: `Failed to approve leave request: ${updateError.message}` }, { status: 500 })
      }

      await supabaseAdmin.rpc("update_leave_balance", {
        p_user_id: leaveRequest.user_id,
        p_leave_type_id: leaveRequest.leave_type_id,
        p_days: leaveRequest.days_count,
      })

      await syncAttendanceForApprovedLeave(
        supabaseAdmin,
        leaveRequest.user_id,
        leaveRequest.start_date,
        leaveRequest.end_date,
        "set"
      )

      await notifyUsers(supabaseAdmin, {
        userIds: [leaveRequest.user_id],
        title: "Leave approved - proceed on leave",
        message: `${actorName} completed final approval. Start: ${leaveRequest.start_date}, Resume: ${leaveRequest.resume_date}.`,
        actorId: user.id,
              linkUrl: "/leave",
        entityId: leave_request_id,
        emailEvent: "approved",
      })

      if (leaveRequest.reliever_id && leaveRequest.reliever_id !== leaveRequest.user_id) {
        await notifyUsers(supabaseAdmin, {
          userIds: [leaveRequest.reliever_id],
          title: "Reliever commitment is now active",
          message: `This leave is fully approved (${leaveRequest.start_date} to ${leaveRequest.end_date}). You cannot request overlapping leave during this period.`,
          actorId: user.id,
              linkUrl: "/leave",
          entityId: leave_request_id,
          emailEvent: "approval_required",
        })
      }

      await writeAuditLog(
        supabase,
        {
          action: "approve",
          entityType: "leave_request",
          entityId: leave_request_id,
          newValues: { status: "approved", final: true, stage: stageCode },
          context: { actorId: user.id, source: "api", route: "/api/hr/leave/approve" },
        },
        { failOpen: true }
      )

      return NextResponse.json({ message: "Final approval recorded and leave approved" })
    }

    if (!nextStage.approver_user_id) {
      return NextResponse.json({ error: "LEAVE_APPROVER_NOT_CONFIGURED:next_stage_approver" }, { status: 400 })
    }

    const transitionUpdates: Record<string, unknown> = {
      approval_stage: nextStage.stage_code,
      current_stage_code: nextStage.stage_code,
      current_stage_order: nextStage.stage_order,
      current_approver_user_id: nextStage.approver_user_id,
      lead_reconfirm_required:
        stageCode === stageCodeForRole("department_lead") ? false : leaveRequest.lead_reconfirm_required,
    }

    if (stageCode === stageCodeForRole("reliever")) {
      transitionUpdates.reliever_decision_at = now
      transitionUpdates.reliever_comment = comments || null
    }

    if (stageCode === stageCodeForRole("department_lead")) {
      transitionUpdates.supervisor_decision_at = now
      transitionUpdates.supervisor_comment = comments || null
    }

    if (stageCode === stageCodeForRole("admin_hr_lead") || stageCode === stageCodeForRole("hcs")) {
      transitionUpdates.hr_decision_at = now
      transitionUpdates.hr_comment = comments || null
    }

    const { error: updateError } = await supabaseAdmin
      .from("leave_requests")
      .update(transitionUpdates)
      .eq("id", leave_request_id)
    if (updateError) {
      return NextResponse.json({ error: `Failed to advance leave request: ${updateError.message}` }, { status: 500 })
    }

    await notifyUsers(supabaseAdmin, {
      userIds: [leaveRequest.user_id],
      title: `${humanStage(stageCode)} approved your leave request`,
      message: `${actorName} approved at ${humanStage(stageCode)} stage. Next: ${humanStage(nextStage.stage_code)}.`,
      actorId: user.id,
            linkUrl: "/leave",
      entityId: leave_request_id,
      emailEvent: "approval_required",
    })

    await notifyUsers(supabaseAdmin, {
      userIds: [nextStage.approver_user_id],
      title: "Leave request awaiting your approval",
      message: `A leave request is now waiting at ${nextStage.stage_code.replaceAll("_", " ")}.`,
      actorId: user.id,
            linkUrl: "/leave",
      entityId: leave_request_id,
      emailEvent: "approval_required",
    })

    await writeAuditLog(
      supabase,
      {
        action: "approve",
        entityType: "leave_request",
        entityId: leave_request_id,
        newValues: { stage: stageCode, next_stage: nextStage?.stage_code },
        context: { actorId: user.id, source: "api", route: "/api/hr/leave/approve" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ message: "Approval recorded" })
  } catch (error) {
    log.error({ err: String(error) }, "Error in POST /api/hr/leave/approve:")
    return NextResponse.json({ error: error instanceof Error ? error.message : "An error occurred" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("hr-leave-flow")

function canViewFlow(role?: string | null) {
  return ["developer", "super_admin", "admin"].includes(role || "")
}

function canEditFlow(role?: string | null) {
  return ["developer", "super_admin"].includes(role || "")
}

export async function GET() {
  try {
    const supabase = await createClient()
    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const { data: profile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
    if (!canViewFlow(profile?.role)) return NextResponse.json({ error: "Forbidden" }, { status: 403 })

    const [rolesRes, routesRes, assignmentsRes, healthRes] = await Promise.all([
      supabase.from("leave_approver_roles").select("*").order("code"),
      supabase.from("leave_approval_role_routes").select("*").order("requester_kind").order("stage_order"),
      supabase
        .from("leave_approver_assignments")
        .select(
          "id, approver_role_code, user_id, scope_type, scope_value, effective_from, effective_to, is_active, is_primary"
        )
        .order("approver_role_code"),
      supabase.from("leave_routing_health_v").select("*").limit(1),
    ])

    if (rolesRes.error || routesRes.error || assignmentsRes.error || healthRes.error) {
      return NextResponse.json({ error: "Failed to load leave flow configuration" }, { status: 500 })
    }

    return NextResponse.json({
      data: {
        roles: rolesRes.data || [],
        routes: routesRes.data || [],
        assignments: assignmentsRes.data || [],
        health: healthRes.data?.[0] || null,
      },
      permissions: {
        can_edit: canEditFlow(profile?.role),
      },
    })
  } catch (error) {
    log.error({ err: String(error) }, "Error in GET /api/hr/leave/flow:")
    return NextResponse.json({ error: "An error occurred" }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient()
    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const { data: profile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
    if (!canEditFlow(profile?.role)) {
      return NextResponse.json({ error: "Only super admin or developer can edit leave flow" }, { status: 403 })
    }

    const body = await request.json()
    const { roles, routes, assignments } = body || {}

    if (Array.isArray(roles) && roles.length) {
      const payload = roles.map((row: any) => ({
        code: String(row.code),
        name: String(row.name || row.code),
        description: row.description || null,
        resolution_mode: row.resolution_mode || "rule_based",
        resolution_config: row.resolution_config || {},
        is_active: row.is_active ?? true,
      }))
      const { error } = await supabase.from("leave_approver_roles").upsert(payload, { onConflict: "code" })
      if (error) return NextResponse.json({ error: "Failed to save approver roles" }, { status: 500 })
    }

    if (Array.isArray(routes) && routes.length) {
      const payload = routes.map((row: any) => ({
        requester_kind: String(row.requester_kind),
        stage_order: Number(row.stage_order),
        approver_role_code: String(row.approver_role_code),
        is_active: row.is_active ?? true,
      }))

      const { error } = await supabase.from("leave_approval_role_routes").upsert(payload, {
        onConflict: "requester_kind,stage_order",
      })
      if (error) return NextResponse.json({ error: "Failed to save route rows" }, { status: 500 })
    }

    if (Array.isArray(assignments) && assignments.length) {
      const payload = assignments.map((row: any) => ({
        approver_role_code: String(row.approver_role_code),
        user_id: String(row.user_id),
        scope_type: row.scope_type || "global",
        scope_value: row.scope_value || null,
        effective_from: row.effective_from || null,
        effective_to: row.effective_to || null,
        is_active: row.is_active ?? true,
        is_primary: row.is_primary ?? true,
      }))

      const { error } = await supabase.from("leave_approver_assignments").upsert(payload)
      if (error) return NextResponse.json({ error: "Failed to save assignments" }, { status: 500 })
    }

    await writeAuditLog(
      supabase,
      {
        action: "update",
        entityType: "leave_flow_config",
        entityId: "bulk",
        newValues: {
          roles_count: Array.isArray(roles) ? roles.length : 0,
          routes_count: Array.isArray(routes) ? routes.length : 0,
          assignments_count: Array.isArray(assignments) ? assignments.length : 0,
        },
        context: { actorId: user.id, source: "api", route: "/api/hr/leave/flow" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ message: "Leave flow configuration saved" })
  } catch (error) {
    log.error({ err: String(error) }, "Error in POST /api/hr/leave/flow:")
    return NextResponse.json({ error: "An error occurred" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import { writeAuditLog } from "@/lib/audit/write-audit"

async function assertHR(supabase: any, userId: string) {
  const { data } = await supabase.from("profiles").select("role").eq("id", userId).single()
  return ["developer", "admin", "super_admin"].includes(data?.role)
}

export async function GET(request: NextRequest) {
  try {
    const supabase = await createClient()
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const { searchParams } = new URL(request.url)
    const location = searchParams.get("location") || null

    let query = supabase.from("holiday_calendar").select("*").order("holiday_date", { ascending: true })
    if (location) query = query.eq("location", location)

    const { data, error } = await query

    if (error) return NextResponse.json({ error: "Failed to fetch holidays" }, { status: 500 })
    return NextResponse.json({ data: data || [] })
  } catch {
    return NextResponse.json({ error: "An error occurred" }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient()
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const isHR = await assertHR(supabase, user.id)
    if (!isHR) return NextResponse.json({ error: "Forbidden" }, { status: 403 })

    const body = await request.json()
    const payload = Array.isArray(body) ? body : [body]

    const { data, error } = await supabase
      .from("holiday_calendar")
      .upsert(payload, { onConflict: "holiday_date,location" })
      .select()

    if (error) return NextResponse.json({ error: "Failed to save holidays" }, { status: 500 })

    await writeAuditLog(
      supabase,
      {
        action: "create",
        entityType: "holiday",
        entityId: Array.isArray(data) && data[0]?.id ? data[0].id : "bulk",
        newValues: { count: Array.isArray(data) ? data.length : 1 },
        context: { actorId: user.id, source: "api", route: "/api/hr/leave/holidays" },
      },
      { failOpen: true }
    )

    return NextResponse.json({ data, message: "Holidays saved" })
  } catch {
    return NextResponse.json({ error: "An error occurred" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"
import {
  LEAVE_PENDING_STAGES,
  addDays,
  parseISODate,
  syncAttendanceForApprovedLeave,
  toISODate,
} from "@/lib/hr/leave-workflow"
import { logger } from "@/lib/logger"
import { writeAuditLog } from "@/lib/audit/write-audit"

const log = logger("hr-leave-lifecycle")

async function restoreBalance(supabase: any, userId: string, leaveTypeId: string, days: number) {
  const currentYear = new Date().getUTCFullYear()

  const { data: balance } = await supabase
    .from("leave_balances")
    .select("id, used_days")
    .eq("user_id", userId)
    .eq("leave_type_id", leaveTypeId)
    .eq("year", currentYear)
    .single()

  if (!balance) return

  await supabase
    .from("leave_balances")
    .update({ used_days: Math.max(0, Number(balance.used_days || 0) - days) })
    .eq("id", balance.id)
}

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient()

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

    const body = await request.json()
    const { leave_request_id, action, reason, extension_days, early_return_date } = body

    if (!leave_request_id || !action) {
      return NextResponse.json({ error: "leave_request_id and action are required" }, { status: 400 })
    }

    const { data: actorProfile } = await supabase.from("profiles").select("role").eq("id", user.id).single()
    const isHR = ["developer", "admin", "super_admin"].includes(actorProfile?.role)

    const { data: leaveRequest, error: fetchError } = await supabase
      .from("leave_requests")
      .select("*")
      .eq("id", leave_request_id)
      .single()

    if (fetchError || !leaveRequest) {
      return NextResponse.json({ error: "Leave request not found" }, { status: 404 })
    }

    if (action === "withdraw") {
      if (leaveRequest.user_id !== user.id) {
        return NextResponse.json({ error: "Only requester can withdraw leave" }, { status: 403 })
      }

      if (leaveRequest.status !== "pending") {
        return NextResponse.json({ error: "Only pending leave requests can be withdrawn" }, { status: 400 })
      }

      await supabase
        .from("leave_requests")
        .update({
          status: "cancelled",
          approval_stage: "cancelled",
          rejected_reason: reason || "Withdrawn by requester",
        })
        .eq("id", leave_request_id)

      return NextResponse.json({ message: "Leave request withdrawn" })
    }

    if (action === "cancel") {
      const canCancel = leaveRequest.user_id === user.id || isHR
      if (!canCancel) {
        return NextResponse.json({ error: "Only requester or HR can cancel approved leave" }, { status: 403 })
      }

      if (leaveRequest.status !== "approved") {
        return NextResponse.json({ error: "Only approved leave can be cancelled" }, { status: 400 })
      }

      const todayIso = toISODate(new Date())
      if (leaveRequest.start_date <= todayIso && !isHR) {
        return NextResponse.json({ error: "You can only cancel leave before it starts" }, { status: 400 })
      }

      await supabase
        .from("leave_requests")
        .update({ status: "cancelled", approval_stage: "cancelled", rejected_reason: reason || "Cancelled" })
        .eq("id", leave_request_id)

      await restoreBalance(supabase, leaveRequest.user_id, leaveRequest.leave_type_id, leaveRequest.days_count)
      await syncAttendanceForApprovedLeave(
        supabase,
        leaveRequest.user_id,
        leaveRequest.start_date,
        leaveRequest.end_date,
        "clear"
      )

      await writeAuditLog(
        supabase,
        {
          action: "update",
          entityType: "leave_request",
          entityId: leave_request_id,
          newValues: { status: "cancelled", reason },
          context: { actorId: user.id, source: "api", route: "/api/hr/leave/lifecycle" },
        },
        { failOpen: true }
      )

      return NextResponse.json({ message: "Approved leave cancelled" })
    }

    if (action === "extend") {
      if (leaveRequest.user_id !== user.id) {
        return NextResponse.json({ error: "Only requester can request extension" }, { status: 403 })
      }

      const days = Number(extension_days)
      if (!days || days <= 0) {
        return NextResponse.json({ error: "Valid extension_days is required" }, { status: 400 })
      }

      const extensionStart = addDays(parseISODate(leaveRequest.end_date), 1)
      const extensionEnd = addDays(extensionStart, days - 1)
      const resumeDate = addDays(extensionEnd, 1)

      const { data: extensionRequest, error: extensionError } = await supabase
        .from("leave_requests")
        .insert({
          user_id: leaveRequest.user_id,
          leave_type_id: leaveRequest.leave_type_id,
          start_date: toISODate(extensionStart),
          end_date: toISODate(extensionEnd),
          resume_date: toISODate(resumeDate),
          days_count: days,
          reason: reason || `Extension request linked to ${leaveRequest.id}`,
          status: "pending",
          approval_stage: LEAVE_PENDING_STAGES.RELIEVER,
          reliever_id: leaveRequest.reliever_id,
          supervisor_id: leaveRequest.supervisor_id,
          handover_note: leaveRequest.handover_note,
          requested_days_mode: leaveRequest.requested_days_mode || "calendar_days",
          original_request_id: leaveRequest.id,
          request_kind: "extension",
        })
        .select("id")
        .single()

      if (extensionError || !extensionRequest) {
        return NextResponse.json({ error: "Failed to create extension request" }, { status: 500 })
      }

      await writeAuditLog(
        supabase,
        {
          action: "create",
          entityType: "leave_request",
          entityId: extensionRequest.id,
          newValues: { request_kind: "extension", original_request_id: leaveRequest.id, extension_days: days },
          context: { actorId: user.id, source: "api", route: "/api/hr/leave/lifecycle" },
        },
        { failOpen: true }
      )

      return NextResponse.json({ message: "Extension request submitted", data: extensionRequest })
    }

    if (action === "early_return") {
      if (!isHR) {
        return NextResponse.json({ error: "Only HR can process early return" }, { status: 403 })
      }

      if (leaveRequest.status !== "approved") {
        return NextResponse.json({ error: "Early return applies to approved leave only" }, { status: 400 })
      }

      if (!early_return_date) {
        return NextResponse.json({ error: "early_return_date is required" }, { status: 400 })
      }

      const earlyDate = parseISODate(early_return_date)
      const startDate = parseISODate(leaveRequest.start_date)
      const originalEnd = parseISODate(leaveRequest.end_date)

      if (earlyDate < startDate || earlyDate > originalEnd) {
        return NextResponse.json({ error: "early_return_date must be within leave period" }, { status: 400 })
      }

      const newEndDate = toISODate(earlyDate)
      const newResumeDate = toISODate(addDays(earlyDate, 1))
      const newDaysCount = Math.floor((earlyDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24)) + 1
      const delta = leaveRequest.days_count - newDaysCount

      await supabase
        .from("leave_requests")
        .update({
          end_date: newEndDate,
          resume_date: newResumeDate,
          days_count: newDaysCount,
          hr_comment: reason || "Early return processed by HR",
        })
        .eq("id", leave_request_id)

      if (delta > 0) {
        await restoreBalance(supabase, leaveRequest.user_id, leaveRequest.leave_type_id, delta)
        const clearFrom = toISODate(addDays(earlyDate, 1))
        await syncAttendanceForApprovedLeave(supabase, leaveRequest.user_id, clearFrom, leaveRequest.end_date, "clear")
      }

      await writeAuditLog(
        supabase,
        {
          action: "update",
          entityType: "leave_request",
          entityId: leave_request_id,
          newValues: { early_return_date, new_end_date: newEndDate, days_restored: delta },
          context: { actorId: user.id, source: "api", route: "/api/hr/leave/lifecycle" },
        },
        { failOpen: true }
      )

      return NextResponse.json({ message: "Early return processed" })
    }

    return NextResponse.json({ error: "Unsupported lifecycle action" }, { status: 400 })
  } catch (error) {
    log.error({ err: String(error) }, "Error in POST /api/hr/leave/lifecycle:")
    return NextResponse.json({ error: error instanceof Error ? error.message : "An error occurred" }, { status: 500 })
  }
}

