/**
 * GET /api/onedrive/preview
 * Get preview/embed URL for a file
 * Query params:
 *   - path: File path in OneDrive
 */
export async function GET(request: Request) {
  try {
    const supabase = await createClient()

    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }
    const scope = await resolveOneDriveAccessScope(supabase as any, user.id)
    if (!scope) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }

    const onedrive = getOneDriveService()

    if (!onedrive.isEnabled()) {
      return NextResponse.json({ error: "OneDrive integration is not configured" }, { status: 503 })
    }

    const { searchParams } = new URL(request.url)
    const path = searchParams.get("path")

    if (!path) {
      return NextResponse.json({ error: "No path provided" }, { status: 400 })
    }

    if (!isPathAllowed(path, scope) || path === "/Projects") {
      return NextResponse.json({ error: "Forbidden: outside your allowed department folders" }, { status: 403 })
    }

    // Get file info first
    const fileItem = await onedrive.getItem(path)
    const category = getFileCategory(fileItem.mimeType, fileItem.name)

    let previewUrl: string | null = null
    let previewType: "embed" | "image" | "download" = "download"

    // Determine the best preview method based on file type
    switch (category) {
      case "image":
        // For images, use the download URL directly
        previewUrl = await onedrive.getDownloadUrl(path)
        previewType = "image"
        break

      case "document":
      case "spreadsheet":
      case "presentation":
      case "pdf":
        // For Office docs and PDFs, use the embed preview
        try {
          previewUrl = await onedrive.getPreviewUrl(path)
          previewType = "embed"
        } catch {
          // Fallback to download URL if preview fails
          previewUrl = await onedrive.getDownloadUrl(path)
          previewType = "download"
        }
        break

      default:
        // For other files, provide download URL
        previewUrl = await onedrive.getDownloadUrl(path)
        previewType = "download"
    }

    return NextResponse.json({
      data: {
        file: fileItem,
        category,
        previewUrl,
        previewType,
      },
    })
  } catch (error: unknown) {
    log.error({ err: String(error) }, "Error getting preview URL:")
    const message = error instanceof Error ? error.message : "Failed to get preview"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

/**
 * OneDrive API Routes
 * Handles folder listing and file upload operations
 */

import { createServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"
import { NextResponse } from "next/server"
import { getOneDriveService } from "@/lib/onedrive"
import { isPathAllowed, resolveOneDriveAccessScope } from "@/lib/onedrive/access"
import { logger } from "@/lib/logger"

const log = logger("onedrive")

export const dynamic = "force-dynamic"

// Helper function to create Supabase client for auth check
async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!, {
    cookies: {
      getAll() {
        return cookieStore.getAll()
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) => cookieStore.set(name, value, options))
        } catch {
          // Ignore
        }
      },
    },
  })
}

function normalizePath(path: string): string {
  const normalized = `/${path || ""}`.replace(/\/+/g, "/")
  return normalized.length > 1 && normalized.endsWith("/") ? normalized.slice(0, -1) : normalized
}

/**
 * GET /api/onedrive
 * List folder contents from OneDrive
 * Query params:
 *   - path: Folder path to list (default: /)
 *   - search: Optional search query
 */
export async function GET(request: Request) {
  try {
    const supabase = await createClient()

    // Check authentication
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveOneDriveAccessScope(supabase as any, user.id)
    if (!scope) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }

    const onedrive = getOneDriveService()

    // Check if OneDrive is enabled
    if (!onedrive.isEnabled()) {
      return NextResponse.json({ error: "OneDrive integration is not configured" }, { status: 503 })
    }

    const { searchParams } = new URL(request.url)
    const requestedPath = searchParams.get("path") || "/Projects"
    const search = searchParams.get("search")
    const path = normalizePath(requestedPath)

    if (!isPathAllowed(path, scope)) {
      return NextResponse.json({ error: "Forbidden: outside your allowed department folders" }, { status: 403 })
    }

    let files

    if (search) {
      // Search for files
      files = await onedrive.searchFiles(search, path !== "/" ? path : undefined)
    } else {
      // List folder contents
      files = await onedrive.listFolder(path)
    }

    if (!scope.isAdminLike) {
      // When lead views /Projects root, expose only folders for managed departments.
      if (path === "/Projects") {
        const allowedDepartmentNames = new Set(scope.managedDepartments)
        files = files.filter((file) => file.isFolder && allowedDepartmentNames.has(file.name))
      } else {
        files = files.filter((file) => {
          const candidatePath = normalizePath(`${path}/${file.name}`)
          return isPathAllowed(candidatePath, scope)
        })
      }
    }

    // Sort: folders first, then by name
    files.sort((a, b) => {
      if (a.isFolder && !b.isFolder) return -1
      if (!a.isFolder && b.isFolder) return 1
      return a.name.localeCompare(b.name)
    })

    return NextResponse.json({
      data: files,
      path,
      parentPath: path === "/" ? null : path.substring(0, path.lastIndexOf("/")) || "/",
    })
  } catch (error: unknown) {
    log.error({ err: String(error) }, "Error listing OneDrive folder:")
    const message = error instanceof Error ? error.message : "Failed to list folder"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

/**
 * POST /api/onedrive
 * Upload a file to OneDrive
 * Body: FormData with:
 *   - file: The file to upload
 *   - path: Destination folder path
 *   - fileName: Optional custom filename
 */
export async function POST(request: Request) {
  try {
    const supabase = await createClient()

    // Check authentication
    const {
      data: { user },
    } = await supabase.auth.getUser()
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveOneDriveAccessScope(supabase as any, user.id)
    if (!scope) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }

    const onedrive = getOneDriveService()

    if (!onedrive.isEnabled()) {
      return NextResponse.json({ error: "OneDrive integration is not configured" }, { status: 503 })
    }

    const formData = await request.formData()
    const file = formData.get("file") as File | null
    const path = formData.get("path") as string | null
    const customFileName = formData.get("fileName") as string | null

    if (!file) {
      return NextResponse.json({ error: "No file provided" }, { status: 400 })
    }

    if (!path) {
      return NextResponse.json({ error: "No path provided" }, { status: 400 })
    }

    const fileName = customFileName || file.name
    const fullPath = normalizePath(`${path}/${fileName}`)

    if (!isPathAllowed(fullPath, scope) || fullPath === "/Projects") {
      return NextResponse.json({ error: "Forbidden: outside your allowed department folders" }, { status: 403 })
    }

    // Get file content as ArrayBuffer
    const arrayBuffer = await file.arrayBuffer()

    // Upload to OneDrive
    const result = await onedrive.uploadFile(fullPath, arrayBuffer, file.type)

    return NextResponse.json({
      data: {
        id: result.id,
        name: result.name,
        path: fullPath,
        webUrl: result.webUrl,
        size: result.size,
      },
    })
  } catch (error: unknown) {
    log.error({ err: String(error) }, "Error uploading to OneDrive:")
    const message = error instanceof Error ? error.message : "Failed to upload file"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { createServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"
import { NextResponse } from "next/server"
import { getOneDriveService } from "@/lib/onedrive"
import { logger } from "@/lib/logger"
import { getDepartmentScope, resolveAdminScope, normalizeDepartmentName } from "@/lib/admin/rbac"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"

const log = logger("payments-documents")

async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!, {
    cookies: {
      getAll() {
        return cookieStore.getAll()
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) => cookieStore.set(name, value, options))
        } catch {
          // Ignore errors
        }
      },
    },
  })
}

function normalizeDepartment(value: string | null | undefined): string {
  return normalizeDepartmentName(String(value || "").trim()).toLowerCase()
}

function isFinanceDepartment(value: string | null | undefined): boolean {
  return normalizeDepartment(value) === "accounts"
}

async function assertPaymentAccess(
  supabase: Awaited<ReturnType<typeof createClient>>,
  userId: string,
  paymentId: string
) {
  const scope = await resolveAdminScope(supabase as any, userId)
  const { data: profile } = await supabase.from("profiles").select("department").eq("id", userId).single()
  const dataClient = getServiceRoleClientOrFallback(supabase as any)

  const { data: payment } = await dataClient
    .from("department_payments")
    .select("department:departments(name)")
    .eq("id", paymentId)
    .single()

  const paymentDepartment = Array.isArray((payment as any)?.department)
    ? (payment as any)?.department?.[0]?.name
    : (payment as any)?.department?.name

  if (!paymentDepartment) {
    return { allowed: false as const, status: 404, error: "Payment not found" }
  }

  if (scope) {
    const scopedDepartments = getDepartmentScope(scope, "finance")
    if (scopedDepartments) {
      const inScope = scopedDepartments.some(
        (dept) => normalizeDepartment(dept) === normalizeDepartment(paymentDepartment)
      )
      if (!inScope) {
        return { allowed: false as const, status: 403, error: "Forbidden: outside your finance scope" }
      }
    }
    return { allowed: true as const }
  }

  if (!isFinanceDepartment(profile?.department)) {
    return { allowed: false as const, status: 403, error: "Forbidden: finance access required" }
  }

  if (normalizeDepartment(profile?.department) !== normalizeDepartment(paymentDepartment)) {
    return { allowed: false as const, status: 403, error: "Forbidden: Department mismatch" }
  }

  return { allowed: true as const }
}

// GET /api/payments/[id]/documents - List all documents for a payment
export async function GET(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()
    const { id: paymentId } = params
    const { searchParams } = new URL(request.url)
    const includeArchived = searchParams.get("includeArchived") === "true"

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const access = await assertPaymentAccess(supabase, user.id, paymentId)
    if (!access.allowed) {
      return NextResponse.json({ error: access.error }, { status: access.status })
    }

    let query = supabase
      .from("payment_documents")
      .select("*")
      .eq("payment_id", paymentId)
      .order("created_at", { ascending: false })

    if (!includeArchived) {
      query = query.eq("is_archived", false)
    }

    const { data: documents, error } = await query

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 })
    }

    return NextResponse.json({ data: documents })
  } catch (error: any) {
    return NextResponse.json({ error: error?.message || "Internal Server Error" }, { status: 500 })
  }
}

// POST /api/payments/[id]/documents - Upload a new document (with optional replacement)
export async function POST(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()
    const { id: paymentId } = params

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const access = await assertPaymentAccess(supabase, user.id, paymentId)
    if (!access.allowed) {
      return NextResponse.json({ error: access.error }, { status: access.status })
    }

    const formData = await request.formData()
    const file = formData.get("file") as File
    const documentType = formData.get("document_type") as string
    const applicableDate = (formData.get("applicable_date") as string) || null
    const replaceDocumentId = formData.get("replace_document_id") as string | null

    if (!file || !documentType) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 })
    }

    // Upload to Storage
    const sanitizedName = file.name.replace(/[^\x00-\x7F]/g, "")
    const filePath = `${paymentId}/${Date.now()}-${sanitizedName}`

    const { error: uploadError } = await supabase.storage.from("payment_documents").upload(filePath, file)

    if (uploadError) {
      log.error({ err: String(uploadError) }, "Storage upload error:")
      return NextResponse.json({ error: "Failed to upload file to storage" }, { status: 500 })
    }

    // Insert new document record
    const { data: newDocument, error: dbError } = await supabase
      .from("payment_documents")
      .insert({
        payment_id: paymentId,
        document_type: documentType,
        file_name: file.name,
        file_path: filePath,
        file_size: file.size,
        uploaded_by: user.id,
        applicable_date: applicableDate,
        mime_type: file.type,
        is_archived: false,
      })
      .select()
      .single()

    if (dbError) {
      log.error({ err: String(dbError) }, "Database insert error:")
      return NextResponse.json({ error: dbError.message || "Failed to save document record" }, { status: 500 })
    }

    // If replacing an existing document, archive the old one
    if (replaceDocumentId) {
      const { error: archiveError } = await supabase
        .from("payment_documents")
        .update({
          is_archived: true,
          replaced_by: newDocument.id,
          archived_at: new Date().toISOString(),
        })
        .eq("id", replaceDocumentId)

      if (archiveError) {
        log.error({ err: String(archiveError) }, "Error archiving old document:")
        // Don't fail the request, the new document was created successfully
      }
    }

    // Sync to OneDrive if enabled
    try {
      const onedrive = getOneDriveService()
      if (onedrive.isEnabled()) {
        // Get payment details for folder structure
        const { data: payment } = await supabase
          .from("department_payments")
          .select("id, title, department:departments(name)")
          .eq("id", paymentId)
          .single()

        if (payment?.department) {
          const departmentName =
            typeof payment.department === "object" && "name" in payment.department
              ? (payment.department as { name: string }).name
              : "General"

          // Create folder and upload file
          const onedrivePath = onedrive.getPaymentsPath(departmentName, paymentId, file.name)

          // Convert file to Uint8Array
          const arrayBuffer = await file.arrayBuffer()

          await onedrive.uploadFile(onedrivePath, arrayBuffer, file.type)
          log.info(`Synced document to OneDrive: ${onedrivePath}`)
        }
      }
    } catch (onedriveError) {
      // Log but don't fail the request - OneDrive sync is best effort
      log.error({ err: String(onedriveError) }, "OneDrive sync error (non-fatal):")
    }

    return NextResponse.json({ data: newDocument }, { status: 201 })
  } catch (error: unknown) {
    log.error({ err: String(error) }, "Upload handler error:")
    const message = error instanceof Error ? error.message : "Internal Server Error"
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { createServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"
import { NextResponse } from "next/server"
import { getDepartmentScope, resolveAdminScope, normalizeDepartmentName } from "@/lib/admin/rbac"
import { getServiceRoleClientOrFallback } from "@/lib/supabase/admin"
import { writeAuditLog } from "@/lib/audit/write-audit"

async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!, {
    cookies: {
      getAll() {
        return cookieStore.getAll()
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) => cookieStore.set(name, value, options))
        } catch {
          // Ignore errors from Server Components
        }
      },
    },
  })
}

function getRelatedDepartmentName(payment: any): string | null {
  const relation = payment?.department
  if (!relation) return null
  if (Array.isArray(relation)) return relation[0]?.name ?? null
  return relation?.name ?? null
}

function normalizeDepartment(value: string | null | undefined): string {
  return normalizeDepartmentName(String(value || "").trim()).toLowerCase()
}

function isFinanceDepartment(value: string | null | undefined): boolean {
  return normalizeDepartment(value) === "accounts"
}

// GET /api/payments/[id] - Get a single payment
export async function GET(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()
    const { id } = params

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)
    const { data: profile } = await supabase.from("profiles").select("department").eq("id", user.id).single()
    const dataClient = getServiceRoleClientOrFallback(supabase as any)

    const { data: payment, error } = await dataClient
      .from("department_payments")
      .select(
        `
                *,
                department:departments(*),
                documents:payment_documents(*)
            `
      )
      .eq("id", id)
      .single()

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 404 })
    }

    if (scope) {
      const scopedDepartments = getDepartmentScope(scope, "finance")
      if (scopedDepartments) {
        const paymentDepartmentName = getRelatedDepartmentName(payment)
        const isInScope = scopedDepartments.some(
          (dept) => normalizeDepartment(dept) === normalizeDepartment(paymentDepartmentName)
        )
        if (!paymentDepartmentName || !isInScope) {
          return NextResponse.json({ error: "Forbidden: outside your finance scope" }, { status: 403 })
        }
      }
    } else {
      if (!isFinanceDepartment(profile?.department)) {
        return NextResponse.json({ error: "Forbidden: finance access required" }, { status: 403 })
      }
      if (normalizeDepartment(getRelatedDepartmentName(payment)) !== normalizeDepartment(profile?.department)) {
        return NextResponse.json({ error: "Forbidden: Department mismatch" }, { status: 403 })
      }
    }

    return NextResponse.json({ data: payment })
  } catch (error: any) {
    return NextResponse.json({ error: error?.message || "Internal Server Error" }, { status: 500 })
  }
}

// PATCH /api/payments/[id] - Update a payment
export async function PATCH(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()
    const { id } = params
    const body = await request.json()

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)
    const { data: profile } = await supabase.from("profiles").select("department").eq("id", user.id).single()
    const dataClient = getServiceRoleClientOrFallback(supabase as any)

    // Check permissions (scoped admin/lead or department member)
    if (!scope) {
      if (!isFinanceDepartment(profile?.department)) {
        return NextResponse.json({ error: "Forbidden: finance access required" }, { status: 403 })
      }

      const { data: payment } = await dataClient
        .from("department_payments")
        .select("department:departments(name), created_by")
        .eq("id", id)
        .single()

      const paymentDept = getRelatedDepartmentName(payment)
      const userDept = profile?.department

      if (normalizeDepartment(paymentDept) !== normalizeDepartment(userDept)) {
        return NextResponse.json({ error: "Forbidden: Department mismatch" }, { status: 403 })
      }

      // Determine if this is a "status update" or "full edit"
      // Status updates (marking as paid, recording payments) are allowed for all department members
      // Full edits (changing title, amount, etc.) require being the creator
      const bodyKeys = Object.keys(body)
      const allowedStatusKeys = ["status", "amount_paid", "next_payment_due", "last_payment_date"]
      const isStatusUpdate =
        (body.status !== undefined ||
          body.amount_paid !== undefined ||
          body.next_payment_due !== undefined ||
          body.last_payment_date !== undefined) &&
        bodyKeys.every((key) => allowedStatusKeys.includes(key))

      // If it's a full edit (not just status update), enforce creator check
      if (!isStatusUpdate && payment?.created_by !== user.id) {
        return NextResponse.json({ error: "Forbidden: You can only edit payments you created" }, { status: 403 })
      }
    } else if (scope) {
      const { data: payment } = await dataClient
        .from("department_payments")
        .select("department:departments(name), created_by")
        .eq("id", id)
        .single()

      const scopedDepartments = getDepartmentScope(scope, "finance")
      const paymentDept = getRelatedDepartmentName(payment)
      const isInScope = scopedDepartments
        ? scopedDepartments.some((dept) => normalizeDepartment(dept) === normalizeDepartment(paymentDept))
        : false
      if (scopedDepartments && (!paymentDept || !isInScope)) {
        return NextResponse.json({ error: "Forbidden: outside your finance scope" }, { status: 403 })
      }
    }

    // Validate and sync category with payment_type if category is being updated
    if (body.category) {
      if (body.category !== "one-time" && body.category !== "recurring") {
        return NextResponse.json({ error: "Category must be 'one-time' or 'recurring'" }, { status: 400 })
      }
      // Sync payment_type with category
      body.payment_type = body.category
    }

    const { data: updatedPayment, error } = await dataClient
      .from("department_payments")
      .update(body)
      .eq("id", id)
      .select()
      .single()

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 400 })
    }

    await writeAuditLog(
      supabase as any,
      {
        action: "update",
        entityType: "payment",
        entityId: id,
        newValues: body,
        context: { actorId: user.id, source: "api", route: `/api/payments/${id}` },
      },
      { failOpen: true }
    )

    return NextResponse.json({ data: updatedPayment })
  } catch (error: any) {
    return NextResponse.json({ error: error?.message || "Internal Server Error" }, { status: 500 })
  }
}

// DELETE /api/payments/[id] - Delete a payment
export async function DELETE(request: Request, { params }: { params: { id: string } }) {
  try {
    const supabase = await createClient()
    const { id } = params

    const {
      data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const scope = await resolveAdminScope(supabase as any, user.id)
    const { data: profile } = await supabase.from("profiles").select("department").eq("id", user.id).single()
    const dataClient = getServiceRoleClientOrFallback(supabase as any)

    if (scope) {
      const { data: payment } = await dataClient
        .from("department_payments")
        .select("created_by, department:departments(name)")
        .eq("id", id)
        .single()
      const scopedDepartments = getDepartmentScope(scope, "finance")
      const paymentDept = getRelatedDepartmentName(payment)
      const isInScope = scopedDepartments
        ? scopedDepartments.some((dept) => normalizeDepartment(dept) === normalizeDepartment(paymentDept))
        : false
      if (scopedDepartments && (!paymentDept || !isInScope)) {
        return NextResponse.json({ error: "Forbidden: outside your finance scope" }, { status: 403 })
      }
    } else {
      if (!isFinanceDepartment(profile?.department)) {
        return NextResponse.json({ error: "Forbidden: finance access required" }, { status: 403 })
      }

      const { data: payment } = await dataClient.from("department_payments").select("created_by").eq("id", id).single()
      if (!payment || payment.created_by !== user.id) {
        return NextResponse.json({ error: "Forbidden: You can only delete payments you created" }, { status: 403 })
      }
    }

    const { error } = await dataClient.from("department_payments").delete().eq("id", id)

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 400 })
    }

    await writeAuditLog(
      supabase as any,
      {
        action: "delete",
        entityType: "payment",
        entityId: id,
        context: { actorId: user.id, source: "api", route: `/api/payments/${id}` },
      },
      { failOpen: true }
    )

    return NextResponse.json({ success: true })
  } catch (error: any) {
    return NextResponse.json({ error: error?.message || "Internal Server Error" }, { status: 500 })
  }
}

