        <aside
          className={cn(
            "fixed inset-y-0 right-0 z-[60] flex w-64 flex-col border-l border-[var(--admin-sidebar-border)] bg-[var(--admin-sidebar-bg)] shadow-xl transition-transform duration-300 ease-out lg:hidden",
            isMobileMenuOpen ? "translate-x-0" : "translate-x-full"
          )}
        >
          {sidebarJSX}
        </aside>
      </>
    </>
  )
}

"use client"

import { useState } from "react"
import { useDepartments } from "@/hooks/use-departments"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"

interface AdminUserModalProps {
  user: any
  onClose: () => void
  onSave: () => void
}

export function AdminUserModal({ user, onClose, onSave }: AdminUserModalProps) {
  const { departments: DEPARTMENTS } = useDepartments()
  const [formData, setFormData] = useState({
    firstName: user.first_name || "",
    lastName: user.last_name || "",
    department: user.department || "",
    companyRole: user.company_role || "",
    phoneNumber: user.phone_number || "",
  })
  const [isLoading, setIsLoading] = useState(false)

  const handleSave = async () => {
    const supabase = createClient()
    setIsLoading(true)

    // Validate phone number - only digits and + allowed
    const phoneNumber = formData.phoneNumber.replace(/[^0-9+]/g, "")

    try {
      const { error } = await supabase
        .from("profiles")
        .update({
          first_name: formData.firstName,
          last_name: formData.lastName,
          department: formData.department,
          company_role: formData.companyRole,
          phone_number: phoneNumber,
          updated_at: new Date().toISOString(),
        })
        .eq("id", user.id)

      if (error) throw error

      // Log the admin action
      await supabase.from("admin_logs").insert({
        admin_id: (await supabase.auth.getUser()).data.user?.id,
        action: "UPDATE_USER",
        target_user_id: user.id,
        changes: formData,
      })

      toast.success("User updated successfully!")
      onSave()
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to update user"
      toast.error(message)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <Dialog open={true} onOpenChange={onClose}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Edit User</DialogTitle>
          <DialogDescription>Update user information</DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <div className="grid gap-2 sm:grid-cols-2">
            <div>
              <Label htmlFor="firstName">First Name</Label>
              <Input
                id="firstName"
                value={formData.firstName}
                onChange={(e) => setFormData({ ...formData, firstName: e.target.value })}
              />
            </div>
            <div>
              <Label htmlFor="lastName">Last Name</Label>
              <Input
                id="lastName"
                value={formData.lastName}
                onChange={(e) => setFormData({ ...formData, lastName: e.target.value })}
              />
            </div>
          </div>

          <div>
            <Label htmlFor="department">Department</Label>
            <Select
              value={formData.department}
              onValueChange={(value) => setFormData({ ...formData, department: value })}
            >
              <SelectTrigger id="department">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {DEPARTMENTS.map((dept) => (
                  <SelectItem key={dept} value={dept}>
                    {dept}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label htmlFor="companyRole">Company Role</Label>
            <Input
              id="companyRole"
              value={formData.companyRole}
              onChange={(e) => setFormData({ ...formData, companyRole: e.target.value })}
            />
          </div>

          <div>
            <Label htmlFor="phoneNumber">Phone Number</Label>
            <Input
              id="phoneNumber"
              type="tel"
              value={formData.phoneNumber}
              onChange={(e) => {
                // Only allow numbers and + symbol
                const value = e.target.value.replace(/[^0-9+]/g, "")
                setFormData({ ...formData, phoneNumber: value })
              }}
              placeholder="e.g., +2348012345678"
            />
          </div>
        </div>

        <div className="flex gap-2 pt-4">
          <Button onClick={handleSave} loading={isLoading} className="flex-1">
            Save Changes
          </Button>
          <Button onClick={onClose} variant="outline" className="flex-1 bg-transparent">
            Cancel
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState, useEffect } from "react"
import { logger } from "@/lib/logger"

const log = logger("action-tracker-form-dialog")
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"
import { Loader2, Plus, Save, Trash2, X } from "lucide-react"
import { createClient } from "@/lib/supabase/client"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"

interface ActionFormDialogProps {
  isOpen: boolean
  onClose: () => void
  onComplete: () => void
  departments: string[]
  editingAction?: any | null
  defaultDept?: string
  defaultWeek?: number
  defaultYear?: number
}

export function ActionFormDialog({
  isOpen,
  onClose,
  onComplete,
  departments,
  editingAction,
  defaultDept,
  defaultWeek,
  defaultYear,
}: ActionFormDialogProps) {
  const currentOfficeWeek = getCurrentOfficeWeek()
  const [isSaving, setIsSaving] = useState(false)
  const [dept, setDept] = useState("")
  const [week, setWeek] = useState(currentOfficeWeek.week)
  const [year, setYear] = useState(currentOfficeWeek.year)

  // For Bulk Entry
  const [actionItems, setActionItems] = useState<string[]>([])
  const [newItem, setNewItem] = useState("")

  // For Single Edit
  const [singleData, setSingleData] = useState({
    title: "",
    description: "",
    priority: "medium",
    status: "pending",
    due_date: "",
  })

  useEffect(() => {
    if (editingAction) {
      setSingleData({
        title: editingAction.title || "",
        description: editingAction.description || "",
        priority: editingAction.priority || "medium",
        status: editingAction.status || "pending",
        due_date: editingAction.due_date ? new Date(editingAction.due_date).toISOString().split("T")[0] : "",
      })
      setDept(editingAction.department)
      setWeek(editingAction.week_number)
      setYear(editingAction.year)
    } else {
      setDept(defaultDept || departments[0] || "")
      setActionItems([])
      setNewItem("")
      setWeek(defaultWeek || currentOfficeWeek.week)
      setYear(defaultYear || currentOfficeWeek.year)
    }
  }, [
    editingAction,
    isOpen,
    defaultDept,
    departments,
    defaultWeek,
    defaultYear,
    currentOfficeWeek.week,
    currentOfficeWeek.year,
  ])

  const addActionItem = () => {
    if (!newItem.trim()) return
    setActionItems([...actionItems, newItem.trim()])
    setNewItem("")
  }

  const removeActionItem = (index: number) => {
    setActionItems(actionItems.filter((_, i) => i !== index))
  }

  const handleSave = async () => {
    // Validation
    if (!dept) {
      toast.error("Please select a department")
      return
    }

    if (editingAction) {
      if (!singleData.title.trim()) {
        toast.error("Action title is required")
        return
      }
    } else if (actionItems.length === 0 && !newItem.trim()) {
      toast.error("Please add at least one action")
      return
    }

    setIsSaving(true)
    try {
      const supabase = createClient()
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) throw new Error("Not authenticated")

      const finalItems = editingAction ? [singleData.title] : [...actionItems]
      if (!editingAction && newItem.trim()) {
        finalItems.push(newItem.trim())
      }

      if (editingAction) {
        // Update single
        const { error } = await supabase
          .from("tasks")
          .update({
            title: singleData.title,
            description: singleData.description,
            department: dept,
            status: singleData.status,
            week_number: week,
            year: year,
          })
          .eq("id", editingAction.id)
        if (error) throw error
        toast.success("Action updated")
      } else {
        // Insert bulk
        const payloads = finalItems.map((title) => ({
          title,
          department: dept,
          status: "pending",
          week_number: week,
          year: year,
          assigned_by: user.id,
          source_type: "action_item",
          category: "weekly_action",
          assignment_type: "department",
          priority: "medium",
        }))

        const { error } = await supabase.from("tasks").insert(payloads)
        if (error) throw error
        toast.success(`Created ${payloads.length} actions`)

        // Notify Department Members
        const { data: deptMembers } = await supabase
          .from("profiles")
          .select("id")
          .eq("department", dept)
          .neq("id", user.id) // Don't notify self

        if (deptMembers && deptMembers.length > 0) {
          try {
            const { createNotification } = await import("@/lib/notifications")

            // If bulk, send one summary or multiple?
            // Sending one summary is better to avoid spam.
            const title = payloads.length === 1 ? "New Action Item" : `${payloads.length} New Action Items`
            const message =
              payloads.length === 1
                ? `New action added to ${dept}: ${payloads[0].title}`
                : `${payloads.length} new actions added to ${dept} tracker.`

            await Promise.all(
              deptMembers.map((member) =>
                createNotification({
                  userId: member.id,
                  type: "task_assigned", // Using task_assigned generic type
                  category: "tasks",
                  title: title,
                  message: message,
                  priority: "normal",
        linkUrl: `/reports/action-tracker?dept=${dept}`,
                  actorId: user.id,
                  entityType: "task_batch",
                })
              )
            )
          } catch (notifError) {
            log.error("Failed to send action notifications:", notifError)
          }
        }
      }

      onComplete()
      onClose()
    } catch (error: any) {
      toast.error(error.message)
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-h-[90vh] overflow-y-auto sm:max-w-[550px]">
        <DialogHeader>
          <DialogTitle>{editingAction ? "Edit Action" : "Bulk Manual Entry"}</DialogTitle>
          <DialogDescription>
            {editingAction
              ? "Modify this specific departmental action."
              : "Add a list of actions for the selected department. Each will be created as a separate checklist item."}
          </DialogDescription>
        </DialogHeader>

        <div className="grid gap-6 py-4">
          {/* Common Metadata */}
          <div className="bg-muted/30 grid grid-cols-3 gap-4 rounded-lg border p-4">
            <div className="col-span-1 space-y-1.5">
              <Label className="text-muted-foreground text-[10px] font-bold uppercase">Department</Label>
              <Select value={dept} onValueChange={setDept}>
                <SelectTrigger className="h-9">
                  <SelectValue placeholder="Dept" />
                </SelectTrigger>
                <SelectContent>
                  {departments.map((d) => (
                    <SelectItem key={d} value={d}>
                      {d}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-1.5">
              <Label className="text-muted-foreground text-[10px] font-bold uppercase">Week</Label>
              <Input type="number" value={week} onChange={(e) => setWeek(parseInt(e.target.value))} className="h-9" />
            </div>
            <div className="space-y-1.5">
              <Label className="text-muted-foreground text-[10px] font-bold uppercase">Year</Label>
              <Input type="number" value={year} onChange={(e) => setYear(parseInt(e.target.value))} className="h-9" />
            </div>
          </div>

          {editingAction ? (
            /* Single Edit Mode */
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Action Description</Label>
                <Input
                  value={singleData.title}
                  onChange={(e) => setSingleData({ ...singleData, title: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Details (Optional)</Label>
                <Textarea
                  value={singleData.description}
                  onChange={(e) => setSingleData({ ...singleData, description: e.target.value })}
                  className="h-20"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Priority</Label>
                  <Select
                    value={singleData.priority}
                    onValueChange={(v) => setSingleData({ ...singleData, priority: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Low</SelectItem>
                      <SelectItem value="medium">Medium</SelectItem>
                      <SelectItem value="high">High</SelectItem>
                      <SelectItem value="urgent">Urgent</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Status</Label>
                  <Select value={singleData.status} onValueChange={(v) => setSingleData({ ...singleData, status: v })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="pending">Pending</SelectItem>
                      <SelectItem value="not_started">Not Started</SelectItem>
                      <SelectItem value="in_progress">Started</SelectItem>
                      <SelectItem value="completed">Finished</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </div>
          ) : (
            /* Bulk List Entry Mode */
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Add Actions to List</Label>
                <div className="flex gap-2">
                  <Input
                    placeholder="Enter action description and press Add..."
                    value={newItem}
                    onChange={(e) => setNewItem(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && addActionItem()}
                  />
                  <Button type="button" onClick={addActionItem} size="sm" variant="secondary">
                    <Plus className="mr-1 h-4 w-4" /> Add
                  </Button>
                </div>
              </div>

              <div className="bg-muted/10 min-h-[150px] space-y-2 rounded-xl border-2 border-dashed p-3">
                {actionItems.length === 0 ? (
                  <p className="text-muted-foreground py-10 text-center text-sm italic">
                    No actions added yet. Type above and click "Add".
                  </p>
                ) : (
                  <div className="space-y-2">
                    {actionItems.map((item, idx) => (
                      <div
                        key={idx}
                        className="group flex items-center justify-between rounded-lg border bg-white p-2 px-3 shadow-sm"
                      >
                        <span className="text-sm font-medium">
                          {idx + 1}. {item}
                        </span>
                        <Button
                          size="icon"
                          variant="ghost"
                          className="text-destructive h-7 w-7 opacity-0 transition-opacity group-hover:opacity-100"
                          onClick={() => removeActionItem(idx)}
                        >
                          <X className="h-3 w-3" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={onClose} disabled={isSaving}>
            Cancel
          </Button>
          <Button onClick={handleSave} disabled={isSaving} className="gap-2">
            {isSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
            {editingAction ? "Save Changes" : `Submit ${actionItems.length + (newItem ? 1 : 0)} Actions`}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState } from "react"
import { logger } from "@/lib/logger"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"
import { FileSpreadsheet, Loader2, Upload } from "lucide-react"
import * as XLSX from "xlsx"
import { createClient } from "@/lib/supabase/client"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"

const log = logger("action-tracker-excel-import-dialog")

interface ExcelImportDialogProps {
  isOpen: boolean
  onClose: () => void
  onComplete: () => void
  departments: string[]
}

export function ExcelImportDialog({ isOpen, onClose, onComplete, departments }: ExcelImportDialogProps) {
  const currentOfficeWeek = getCurrentOfficeWeek()
  const [file, setFile] = useState<File | null>(null)
  const [isUploading, setIsUploading] = useState(false)
  const [week, setWeek] = useState(currentOfficeWeek.week)
  const [year, setYear] = useState(currentOfficeWeek.year)

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0])
    }
  }

  const handleImport = async () => {
    if (!file) {
      toast.error("Please select a file first")
      return
    }

    setIsUploading(true)
    const reader = new FileReader()

    reader.onload = async (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer)
        const workbook = XLSX.read(data, { type: "array", cellDates: true })
        const firstSheetName = workbook.SheetNames[0]
        const worksheet = workbook.Sheets[firstSheetName]
        const jsonData = XLSX.utils.sheet_to_json(worksheet, { defval: "" }) as any[]

        if (jsonData.length === 0) {
          toast.error("The selected sheet is empty")
          setIsUploading(false)
          return
        }

        const supabase = createClient()
        const {
          data: { user },
        } = await supabase.auth.getUser()

        if (!user) {
          toast.error("User not authenticated")
          setIsUploading(false)
          return
        }

        // Process and insert tasks
        const tasksToInsert = jsonData.map((row) => {
          // Helper to find column by multiple name variants
          const getCol = (names: string[]) => {
            const normalizedNames = names.map((n) => n.toLowerCase())
            const key = Object.keys(row).find((k) => normalizedNames.includes(k.trim().toLowerCase()))
            return key ? row[key] : null
          }

          const title = getCol(["Action Description", "Action", "Description", "Task"]) || "Untitled Action"
          const dept = getCol(["Department", "Dept", "Unit"]) || "Unassigned"
          const priorityRaw = String(getCol(["Priority", "Level"]) || "medium").toLowerCase()
          const priority = ["low", "medium", "high", "urgent"].includes(priorityRaw) ? priorityRaw : "medium"

          let dueDate = null
          const rawDate = getCol(["Due Date", "Deadline", "Date"])
          if (rawDate) {
            const d = new Date(rawDate)
            if (!isNaN(d.getTime())) {
              dueDate = d.toISOString()
            }
          }

          return {
            title: String(title).substring(0, 255),
            description: String(getCol(["Detailed Description", "Notes", "Details"]) || "").substring(0, 1000) || null,
            department: String(dept).substring(0, 100),
            week_number: week,
            year: year,
            assigned_by: user.id,
            status: "pending",
            source_type: "action_item",
            category: "weekly_action",
            assignment_type: "department",
            priority: priority,
          }
        })

        const { error } = await supabase.from("tasks").insert(tasksToInsert)

        if (error) throw error

        toast.success(`Successfully imported ${tasksToInsert.length} actions`)
        onComplete()
        onClose()
      } catch (error: any) {
        log.error("Import error:", error)
        toast.error(`Failed to import: ${error.message}`)
      } finally {
        setIsUploading(false)
      }
    }

    reader.readAsArrayBuffer(file)
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-h-[90vh] w-[95vw] overflow-y-auto sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileSpreadsheet className="h-5 w-5 text-green-600" />
            Import Weekly Actions
          </DialogTitle>
          <DialogDescription>
            Upload an Excel file with columns: Department, Action Description, Priority, and Due Date.
          </DialogDescription>
        </DialogHeader>

        <div className="grid gap-4 py-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Week Number</Label>
              <Input type="number" min="1" max="53" value={week} onChange={(e) => setWeek(parseInt(e.target.value))} />
            </div>
            <div className="space-y-2">
              <Label>Year</Label>
              <Input type="number" value={year} onChange={(e) => setYear(parseInt(e.target.value))} />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="file">Excel File</Label>
            <div className="flex items-center gap-2">
              <Input
                id="file"
                type="file"
                accept=".xlsx, .xls, .csv"
                onChange={handleFileChange}
                className="cursor-pointer"
              />
            </div>
          </div>

          <div className="bg-muted space-y-1 rounded-md p-3 text-xs">
            <p className="text-muted-foreground font-semibold">Supported Column Names:</p>
            <ul className="text-muted-foreground/80 list-inside list-disc">
              <li>Action Description / Action / Description</li>
              <li>Department</li>
              <li>Priority (low, medium, high, urgent)</li>
              <li>Due Date</li>
            </ul>
          </div>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={onClose} disabled={isUploading}>
            Cancel
          </Button>
          <Button onClick={handleImport} disabled={!file || isUploading}>
            {isUploading ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Importing...
              </>
            ) : (
              <>
                <Upload className="mr-2 h-4 w-4" />
                Start Import
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState } from "react"
import { logger } from "@/lib/logger"

const log = logger("action-tracker-export-dialog")
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Label } from "@/components/ui/label"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"
import { Download, Loader2 } from "lucide-react"
import * as XLSX from "xlsx"
import { createClient } from "@/lib/supabase/client"
import { getCurrentISOWeek } from "@/lib/utils"

interface ExportDialogProps {
  isOpen: boolean
  onClose: () => void
  departments: string[]
}

export function ActionTrackerExportDialog({ isOpen, onClose, departments }: ExportDialogProps) {
  const [isExporting, setIsExporting] = useState(false)
  const [period, setPeriod] = useState("week") // week, month, quarter, year
  const [deptFilter, setDeptFilter] = useState("all")
  const [year, setYear] = useState(new Date().getFullYear())
  const [value, setValue] = useState(getCurrentISOWeek()) // Current Week or Month

  const handleExport = async () => {
    setIsExporting(true)
    try {
      const supabase = createClient()
      let query = supabase.from("tasks").select("*").eq("category", "weekly_action").eq("year", year)

      // Time range filtering
      if (period === "week") {
        query = query.eq("week_number", value)
      } else if (period === "month") {
        const start = new Date(year, value - 1, 1)
        const end = new Date(year, value, 0)
        const startWeek = getCurrentISOWeek(start)
        const endWeek = getCurrentISOWeek(end)
        query = query.gte("week_number", startWeek).lte("week_number", endWeek)
      } else if (period === "quarter") {
        const start = new Date(year, (value - 1) * 3, 1)
        const end = new Date(year, value * 3, 0)
        const startWeek = getCurrentISOWeek(start)
        const endWeek = getCurrentISOWeek(end)
        query = query.gte("week_number", startWeek).lte("week_number", endWeek)
      }

      if (deptFilter !== "all") {
        query = query.eq("department", deptFilter)
      }

      const { data, error } = await query
      if (error) throw error

      if (!data || data.length === 0) {
        toast.error("No data found for the selected period")
        return
      }

      const exportData = data.map((t, index) => ({
        "#": index + 1,
        Department: t.department,
        Action: t.title,
        Description: t.description || "",
        Status: t.status,
        Week: t.week_number,
        Year: t.year,
      }))

      const worksheet = XLSX.utils.json_to_sheet(exportData)
      const workbook = XLSX.utils.book_new()
      XLSX.utils.book_append_sheet(workbook, worksheet, "Actions")
      XLSX.writeFile(workbook, `ACOB_Actions_Export_${period}_${value}_${year}.xlsx`)

      toast.success("Export completed")
      onClose()
    } catch (error: any) {
      log.error("Export error:", error)
      toast.error("Export failed")
    } finally {
      setIsExporting(false)
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[400px]">
        <DialogHeader>
          <DialogTitle>Export Action Tracker Data</DialogTitle>
          <DialogDescription>Select the period and department you want to export.</DialogDescription>
        </DialogHeader>

        <div className="grid gap-4 py-4">
          <div className="space-y-2">
            <Label>Time Period</Label>
            <Select value={period} onValueChange={setPeriod}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="week">Specific Week</SelectItem>
                <SelectItem value="month">Specific Month</SelectItem>
                <SelectItem value="quarter">Specific Quarter</SelectItem>
                <SelectItem value="year">Full Year</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Year</Label>
              <Input type="number" value={year} onChange={(e: any) => setYear(parseInt(e.target.value))} />
            </div>
            {period !== "year" && (
              <div className="space-y-2">
                <Label>{period === "week" ? "Week Number" : period === "month" ? "Month" : "Quarter"}</Label>
                <Input
                  type="number"
                  value={value}
                  min={1}
                  max={period === "week" ? 53 : period === "month" ? 12 : 4}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => setValue(parseInt(e.target.value))}
                />
              </div>
            )}
          </div>

          <div className="space-y-2">
            <Label>Department</Label>
            <Select value={deptFilter} onValueChange={setDeptFilter}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Every Department</SelectItem>
                {departments.map((dept) => (
                  <SelectItem key={dept} value={dept}>
                    {dept}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={onClose} disabled={isExporting}>
            Cancel
          </Button>
          <Button onClick={handleExport} disabled={isExporting}>
            {isExporting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Download className="mr-2 h-4 w-4" />}
            Generate Excel
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState } from "react"
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { createClient } from "@/lib/supabase/client"
import { TableSkeleton, QueryError } from "@/components/ui/query-states"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { User, Building, AlertCircle } from "lucide-react"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"
import { SearchableSelect } from "@/components/ui/searchable-select"
import { toast } from "sonner"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"

interface Department {
  id: string
  name: string
  lead_id?: string | null
  lead_name?: string | null
  lead_email?: string | null
}

interface Profile {
  id: string
  first_name: string | null
  last_name: string | null
  email?: string | null
  company_email?: string | null
  role: string
  department: string | null
  is_department_lead: boolean
}

async function fetchDepartmentsWithLeads(): Promise<Department[]> {
  const supabase = createClient()
  const { data: depts, error: deptsError } = await supabase
    .from("departments")
    .select("*")
    .eq("is_active", true)
    .order("name")
  if (deptsError) throw deptsError

  const { data: leads, error: leadsError } = await supabase
    .from("profiles")
    .select("id, first_name, last_name, company_email, department, role")
    .eq("is_department_lead", true)
  if (leadsError) throw leadsError

  return depts.map((d) => {
    const lead = leads.find((l) => l.department === d.name)
    return {
      id: d.id,
      name: d.name,
      lead_id: lead ? lead.id : null,
      lead_name: lead ? `${lead.first_name || ""} ${lead.last_name || ""}`.trim() : null,
      lead_email: lead ? lead.company_email : null,
    }
  })
}

export function DepartmentLeadsManager() {
  const queryClient = useQueryClient()
  const [selectedDept, setSelectedDept] = useState<Department | null>(null)
  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [users, setUsers] = useState<Profile[]>([])
  const [selectedUserId, setSelectedUserId] = useState<string>("")
  const [confirmWarning, setConfirmWarning] = useState<string | null>(null)

  const {
    data: departments = [],
    isLoading,
    isError,
    refetch,
  } = useQuery({
    queryKey: ["department-leads"],
    queryFn: fetchDepartmentsWithLeads,
  })

  const { mutate: assignLead, isPending: isSubmitting } = useMutation({
    mutationFn: async ({ deptId, userId }: { deptId: string; userId: string }) => {
      const supabase = createClient()
      const { error } = await supabase.rpc("assign_department_lead", {
        p_department_id: deptId,
        p_new_lead_id: userId,
      })
      if (error) throw error
    },
    onSuccess: () => {
      const user = users.find((u) => u.id === selectedUserId)
      toast.success(`${user?.first_name || "User"} assigned as lead for ${selectedDept?.name}`)
      setIsDialogOpen(false)
      queryClient.invalidateQueries({ queryKey: ["department-leads"] })
    },
    onError: (error: any) => {
      toast.error(error.message || "Failed to assign lead")
    },
  })

  async function openAssignDialog(dept: Department) {
    setSelectedDept(dept)
    setSelectedUserId("")
    setConfirmWarning(null)

    try {
      const supabase = createClient()
      const baseQuery = supabase
        .from("profiles")
        .select("id, first_name, last_name, company_email, role, department, is_department_lead")
        .neq("role", "visitor")
        .order("first_name")
      const { data, error } = await applyAssignableStatusFilter(baseQuery, { allowLegacyNullStatus: false })

      if (error) {
        toast.error("Failed to load potential leads. Please try again.")
        return
      }

      setUsers(data as Profile[])
      setIsDialogOpen(true)
    } catch {
      toast.error("An unexpected error occurred.")
    }
  }

  async function handleUserSelect(userId: string) {
    setSelectedUserId(userId)
    const user = users.find((u) => u.id === userId)
    if (!user) return

    let warning = null
    if (user.is_department_lead && user.department !== selectedDept?.name) {
      warning = `\u26A0\uFE0F ${user.first_name || "User"} is currently the lead for "${user.department}". Assigning them here will remove them as lead of "${user.department}" (that department will have no lead), and make them lead of "${selectedDept?.name}" instead. Each person can only lead one department.`
    }
    setConfirmWarning(warning)
  }

  function handleAssign() {
    if (!selectedDept || !selectedUserId) return
    assignLead({ deptId: selectedDept.id, userId: selectedUserId })
  }

  return (
    <Card className="mt-6">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Building className="h-5 w-5" />
          Department Leads
        </CardTitle>
        <CardDescription>
          Manage department lead assignments. Each department should have exactly one assigned lead.
        </CardDescription>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <TableSkeleton rows={5} cols={5} />
        ) : isError ? (
          <QueryError message="Could not load department leads." onRetry={refetch} />
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-14">S/N</TableHead>
                <TableHead>Department</TableHead>
                <TableHead>Assigned Lead</TableHead>
                <TableHead>Email</TableHead>
                <TableHead className="text-right">Action</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {departments.map((dept, index) => (
                <TableRow key={dept.id}>
                  <TableCell className="text-muted-foreground">{index + 1}</TableCell>
                  <TableCell className="font-medium">{dept.name}</TableCell>
                  <TableCell>
                    {dept.lead_name ? (
                      <div className="flex items-center gap-2">
                        <Badge variant="default">Lead</Badge>
                        <span>{dept.lead_name}</span>
                      </div>
                    ) : (
                      <span className="text-muted-foreground italic">No Lead Assigned</span>
                    )}
                  </TableCell>
                  <TableCell className="text-muted-foreground">{dept.lead_email || "\u2014"}</TableCell>
                  <TableCell className="text-right">
                    <Button variant="outline" size="sm" onClick={() => openAssignDialog(dept)}>
                      <User className="mr-2 h-4 w-4" />
                      {dept.lead_id ? "Change Lead" : "Assign Lead"}
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}

        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent className="max-h-[90vh] w-[95vw] max-w-lg overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Assign Lead - {selectedDept?.name}</DialogTitle>
              <DialogDescription>Select a user to mark as the lead for this department.</DialogDescription>
            </DialogHeader>

            <div className="grid gap-4 py-4">
              <div className="space-y-2">
                <Label>Select User</Label>
                <SearchableSelect
                  value={selectedUserId}
                  onValueChange={handleUserSelect}
                  placeholder="Search or select a user..."
                  searchPlaceholder="Search users..."
                  portal={false}
                  options={users.map((u) => {
                    const name = `${u.first_name || ""} ${u.last_name || ""}`.trim()
                    const display = name || u.company_email || u.email || "Unknown user"
                    return {
                      value: u.id,
                      label: `${display} (${u.role})`,
                    }
                  })}
                />
              </div>

              {confirmWarning && (
                <Alert variant="destructive">
                  <AlertCircle className="h-4 w-4" />
                  <AlertTitle>Warning</AlertTitle>
                  <AlertDescription>{confirmWarning}</AlertDescription>
                </Alert>
              )}
            </div>

            <DialogFooter>
              <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
                Cancel
              </Button>
              <Button onClick={handleAssign} disabled={!selectedUserId || isSubmitting}>
                {isSubmitting ? "Assigning..." : "Confirm Assignment"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </CardContent>
    </Card>
  )
}

"use client"

import { useState, useEffect } from "react"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { SearchableSelect } from "@/components/ui/searchable-select"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { Loader2, Sparkles } from "lucide-react"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"
import { fetchWeeklyReportLockState, type WeeklyReportLockState } from "@/lib/weekly-report-lock"
import { sanitizeReportText } from "@/lib/export-utils"

interface WeeklyReport {
  id: string
  department: string
  week_number: number
  year: number
  work_done: string
  tasks_new_week: string
  challenges: string
  status: string
  user_id: string
}

interface WeeklyReportAdminDialogProps {
  isOpen: boolean
  onClose: () => void
  report?: WeeklyReport | null
  onSuccess: () => void
  currentUser: {
    id: string
    role: string
    department: string | null
    is_department_lead: boolean
  }
}

const REPORT_TEXT_FIELDS = ["work_done", "tasks_new_week", "challenges"] as const
type ReportTextField = (typeof REPORT_TEXT_FIELDS)[number]

const autoNumberReportText = (text: string): string => {
  const lines = sanitizeReportText(String(text || ""))
    .replace(/\r\n/g, "\n")
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line.length > 0)
    .map((line) => line.replace(/^\s*(?:\d+[.)]\s+|[-*]\s+)/, "").trim())
    .filter((line) => line.length > 0)

  if (lines.length === 0) return ""
  return lines.map((line, index) => `${index + 1}. ${line}`).join("\n")
}

export function WeeklyReportAdminDialog({
  isOpen,
  onClose,
  report,
  onSuccess,
  currentUser,
}: WeeklyReportAdminDialogProps) {
  const [loading, setLoading] = useState(false)
  const [departments, setDepartments] = useState<string[]>([])
  const [isNextWeekActive, setIsNextWeekActive] = useState(false)
  const [lockState, setLockState] = useState<WeeklyReportLockState | null>(null)
  const currentOfficeWeek = getCurrentOfficeWeek()
  const [formData, setFormData] = useState({
    user_id: "",
    department: "",
    week_number: currentOfficeWeek.week,
    year: currentOfficeWeek.year,
    work_done: "",
    tasks_new_week: "",
    challenges: "",
    status: "submitted",
  })

  const supabase = createClient()
  const isLead = currentUser.is_department_lead

  useEffect(() => {
    const fetchMetadata = async () => {
      if (isLead && currentUser.department) {
        setDepartments([currentUser.department])
        return
      }
      const { data: deptData } = await supabase.from("profiles").select("department").not("department", "is", null)
      if (deptData) {
        const uniqueDepts = Array.from(new Set(deptData.map((d) => d.department))).sort()
        setDepartments(uniqueDepts as string[])
      }
    }
    fetchMetadata()
  }, [currentUser.department, isLead])

  useEffect(() => {
    const fetchLockState = async () => {
      const state = await fetchWeeklyReportLockState(supabase, formData.week_number, formData.year)
      setLockState(state)
    }
    fetchLockState()
  }, [formData.week_number, formData.year])

  useEffect(() => {
    const fetchStatus = async () => {
      if (!formData.department) return

      // For "Add Report", prefer existing weekly report content for this dept/week/year.
      // If none exists, fall back to syncing tasks from action items.
      let hasExistingWeeklyReport = false
      if (!report) {
        const { data: existingReport } = await supabase
          .from("weekly_reports")
          .select("user_id, work_done, tasks_new_week, challenges, status")
          .eq("department", formData.department)
          .eq("week_number", formData.week_number)
          .eq("year", formData.year)
          .order("created_at", { ascending: false })
          .limit(1)
          .maybeSingle()

        if (existingReport) {
          hasExistingWeeklyReport = true
          setFormData((prev) => ({
            ...prev,
            user_id: existingReport.user_id || prev.user_id || currentUser.id || "",
            work_done: autoNumberReportText(existingReport.work_done || ""),
            tasks_new_week: autoNumberReportText(existingReport.tasks_new_week || ""),
            challenges: autoNumberReportText(existingReport.challenges || ""),
            status: existingReport.status || prev.status,
          }))
        } else {
          // Critical reset: moving to a week with no report should not keep stale text
          setFormData((prev) => ({
            ...prev,
            user_id: currentUser.id || prev.user_id || "",
            work_done: "",
            tasks_new_week: "",
            challenges: "",
            status: "submitted",
          }))
        }
      }

      const { data } = await supabase
        .from("tasks")
        .select("title, status")
        .eq("category", "weekly_action")
        .eq("department", formData.department)
        .eq("week_number", formData.week_number)
        .eq("year", formData.year)

      if (data) {
        setIsNextWeekActive(data.some((a) => a.status !== "pending"))
        if (data.length > 0 && !report && !hasExistingWeeklyReport) {
          // Only auto-sync tasks from action items when there is no existing weekly report to mirror.
          const syncedText = data.map((a, i) => `${i + 1}. ${a.title}`).join("\n")
          setFormData((prev) => ({ ...prev, tasks_new_week: autoNumberReportText(syncedText) }))
        }
      }
    }
    fetchStatus()
  }, [currentUser.id, formData.department, formData.week_number, formData.year, report])

  useEffect(() => {
    if (report) {
      setFormData({
        user_id: report.user_id,
        department: isLead ? currentUser.department || report.department : report.department,
        week_number: report.week_number,
        year: report.year,
        work_done: autoNumberReportText(report.work_done || ""),
        tasks_new_week: autoNumberReportText(report.tasks_new_week || ""),
        challenges: autoNumberReportText(report.challenges || ""),
        status: report.status || "submitted",
      })
    } else {
      setFormData((prev) => ({
        ...prev,
        user_id: currentUser.id || "",
        department: isLead ? currentUser.department || "" : "",
        week_number: currentOfficeWeek.week,
        year: currentOfficeWeek.year,
        work_done: "",
        tasks_new_week: "",
        challenges: "",
      }))
    }
  }, [currentUser.department, currentUser.id, currentOfficeWeek.week, currentOfficeWeek.year, isLead, report, isOpen])

  const handleSubmit = async () => {
    const state = await fetchWeeklyReportLockState(supabase, formData.week_number, formData.year)
    setLockState(state)
    if (state.isLocked) {
      toast.error("This report week is locked. Ask admin to set a temporary unlock window.")
      return
    }

    if (!formData.department || !formData.work_done) {
      toast.error("Required: Department and Work Done")
      return
    }
    setLoading(true)
    try {
      if (isLead && report && report.user_id !== currentUser.id) {
        throw new Error("You can only edit reports you created")
      }

      const safeFormData = {
        ...formData,
        user_id: isLead ? currentUser.id : formData.user_id,
        department: isLead ? currentUser.department || formData.department : formData.department,
      }

      const { data: savedReport, error: reportError } = await supabase
        .from("weekly_reports")
        .upsert(safeFormData, { onConflict: "department,week_number,year" })
        .select("id")
        .single()
      if (reportError) throw reportError
      void savedReport
      toast.success(report ? "Updated" : "Saved")
      onSuccess()
      onClose()
    } catch (error: any) {
      toast.error(error.message)
    } finally {
      setLoading(false)
    }
  }

  const handleKey = (e: React.KeyboardEvent, field: ReportTextField) => {
    if (e.key === "Enter") {
      const val = formData[field] as string
      const last = val.split("\n").pop() || ""
      const match = last.match(/^(\d+)[\.\)]\s/)
      if (match) {
        e.preventDefault()
        setFormData((p) => ({ ...p, [field]: val + "\n" + (parseInt(match[1]) + 1) + ". " }))
      }
    }
  }

  const handleTextChange = (field: ReportTextField, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: autoNumberReportText(value) }))
  }

  const handleTextPaste = (e: React.ClipboardEvent<HTMLTextAreaElement>, field: ReportTextField) => {
    e.preventDefault()
    const pasted = e.clipboardData.getData("text")
    const current = (formData[field] as string) || ""
    const start = e.currentTarget.selectionStart ?? current.length
    const end = e.currentTarget.selectionEnd ?? current.length
    const merged = `${current.slice(0, start)}${pasted}${current.slice(end)}`
    setFormData((prev) => ({ ...prev, [field]: autoNumberReportText(merged) }))
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-h-[90vh] max-w-4xl overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            {report ? "Edit Weekly Report" : "Create Weekly Report"}
            <Sparkles className="h-4 w-4 text-blue-500" />
          </DialogTitle>
          <DialogDescription>
            {report ? "Update this weekly report's details" : "Add a new departmental weekly report"}
          </DialogDescription>
          {lockState?.isLocked && (
            <p className="text-destructive text-xs">
              Locked after meeting date {lockState.meetingDate}. Editing is now closed for this week.
            </p>
          )}
        </DialogHeader>

        <div className="grid gap-6 py-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Department</Label>
              <SearchableSelect
                value={formData.department}
                onValueChange={(val) => setFormData((p) => ({ ...p, department: val }))}
                options={departments.map((d) => ({ value: d, label: d }))}
                placeholder="Select department"
                disabled={isLead}
              />
            </div>
            <div className="space-y-2">
              <Label>Week / Year</Label>
              <div className="flex gap-2">
                <Input
                  type="number"
                  value={formData.week_number}
                  onChange={(e) =>
                    setFormData((p) => ({ ...p, week_number: parseInt(e.target.value) || p.week_number }))
                  }
                  className="w-1/2"
                />
                <Input
                  type="number"
                  value={formData.year}
                  onChange={(e) => setFormData((p) => ({ ...p, year: parseInt(e.target.value) || p.year }))}
                  className="w-1/2"
                />
              </div>
            </div>
          </div>

          {REPORT_TEXT_FIELDS.map((f) => (
            <div key={f} className="space-y-2">
              <Label className="capitalize">{f.replace(/_/g, " ")}</Label>
              <Textarea
                value={formData[f]}
                onChange={(e) => handleTextChange(f, e.target.value)}
                onPaste={(e) => handleTextPaste(e, f)}
                onKeyDown={(e) => handleKey(e, f)}
                placeholder={`1. ...`}
                rows={4}
                disabled={f === "tasks_new_week" && isNextWeekActive}
              />
              {f === "tasks_new_week" && isNextWeekActive && (
                <p className="text-muted-foreground text-[10px] italic">
                  Locked: Next week's tracker already has activity.
                </p>
              )}
            </div>
          ))}
        </div>

        <div className="flex justify-end gap-3 border-t pt-4">
          <Button variant="outline" onClick={onClose} disabled={loading}>
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={loading || !!lockState?.isLocked}>
            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {report ? "Update Report" : "Create Report"}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

import { Sidebar } from "@/components/sidebar"
import { SidebarContent } from "@/components/sidebar-content"
import { createClient } from "@/lib/supabase/server"
import { resolveAdminScope } from "@/lib/admin/rbac"
import { redirect } from "next/navigation"

interface AppLayoutProps {
  children: React.ReactNode
}

export async function AppLayout({ children }: AppLayoutProps) {
  const supabase = await createClient()
