interface AssetAssignment {
  id: string
  assigned_to?: string
  department?: string
  office_location?: string
  assignment_type?: string
  assigned_at: string
  is_current: boolean
  user?: {
    first_name: string
    last_name: string
  }
}

interface AssignFormState {
  assignment_type: "individual" | "department" | "office"
  assigned_to: string
  department: string
  office_location: string
  assignment_notes: string
  assigned_by: string
