        {/* Divider */}
        <div className="my-4 border-t" />

        {/* Back to Admin */}
        <Link
          href="/admin"
          className={cn(
            "text-muted-foreground hover:bg-muted hover:text-foreground flex items-center rounded-md px-3 py-2 text-sm font-medium transition-colors",
            collapsed && "justify-center px-2"
          )}
