"use client"

import { useState } from "react"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { Input } from "@/components/ui/input"
import { toast } from "sonner"
import { writeAuditLogClient } from "@/lib/audit/client"

interface FeedbackEditModalProps {
  feedback: any
  onClose: () => void
  onSave: (feedback: any) => void
}

export function FeedbackEditModal({ feedback, onClose, onSave }: FeedbackEditModalProps) {
  const [formData, setFormData] = useState({
    feedbackType: feedback.feedback_type,
    title: feedback.title,
    description: feedback.description,
  })
  const [isLoading, setIsLoading] = useState(false)

  const handleSave = async () => {
    const supabase = createClient()
    setIsLoading(true)

    try {
      const { error } = await supabase
        .from("feedback")
        .update({
          feedback_type: formData.feedbackType,
          title: formData.title,
          description: formData.description,
          updated_at: new Date().toISOString(),
        })
        .eq("id", feedback.id)

      if (error) throw error

      // Log audit
      await writeAuditLogClient(
        supabase as any,
        {
          action: "update",
          entityType: "feedback",
          entityId: feedback.id,
          oldValues: {
            feedback_type: feedback.feedback_type,
            title: feedback.title,
            description: feedback.description,
          },
          newValues: {
            feedback_type: formData.feedbackType,
            title: formData.title,
            description: formData.description,
          },
          context: {
            source: "ui",
            route: "/feedback",
          },
        },
        { failOpen: true }
      )

      toast.success("Feedback updated successfully!")
      onSave({
        ...feedback,
        ...formData,
      })
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to update feedback"
      toast.error(message)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <Dialog open={true} onOpenChange={onClose}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Edit Feedback</DialogTitle>
          <DialogDescription>Update your feedback details</DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="feedbackType">Feedback Type</Label>
            <Select
              value={formData.feedbackType}
              onValueChange={(value) => setFormData({ ...formData, feedbackType: value })}
            >
              <SelectTrigger id="feedbackType">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="concern">Concern</SelectItem>
                <SelectItem value="complaint">Complaint</SelectItem>
                <SelectItem value="suggestion">Suggestion</SelectItem>
                <SelectItem value="required_item">Required Item</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="title">Title</Label>
            <Input
              id="title"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="description">Description</Label>
            <Textarea
              id="description"
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              rows={4}
            />
          </div>

          <div className="flex gap-2 pt-4">
            <Button onClick={handleSave} loading={isLoading} className="flex-1">
              Save Changes
            </Button>
            <Button onClick={onClose} variant="outline" className="flex-1 bg-transparent">
              Cancel
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import type React from "react"
import { useState } from "react"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { Input } from "@/components/ui/input"
import { Switch } from "@/components/ui/switch"
import { toast } from "sonner"
import { EyeOff } from "lucide-react"
import { writeAuditLogClient } from "@/lib/audit/client"

interface FeedbackFormProps {
  userId: string
  onFeedbackSubmitted?: (feedback: any) => void
  variant?: "card" | "modal"
}

export function FeedbackForm({ userId, onFeedbackSubmitted, variant = "card" }: FeedbackFormProps) {
  const [formData, setFormData] = useState({
    feedbackType: "",
    title: "",
    description: "",
  })
  const [isAnonymous, setIsAnonymous] = useState(false)
  const [isLoading, setIsLoading] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    const supabase = createClient()
    setIsLoading(true)

    try {
      if (!formData.feedbackType || !formData.title) {
        toast.error("Please fill in all required fields")
        setIsLoading(false)
        return
      }

      // Insert feedback - set user_id to null if anonymous
      const { data, error } = await supabase
        .from("feedback")
        .insert({
          user_id: isAnonymous ? null : userId,
          feedback_type: formData.feedbackType,
          title: formData.title,
          description: formData.description,
          status: "open",
          is_anonymous: isAnonymous,
        })
        .select()

      if (error) throw error

      // Log audit for all feedback - anonymous ones will show as "Anonymous" in the audit log
      if (data && data.length > 0) {
        await writeAuditLogClient(
          supabase as any,
          {
            action: "create",
            entityType: "feedback",
            entityId: data[0].id,
            newValues: {
              feedback_type: formData.feedbackType,
              title: formData.title,
              description: formData.description,
              status: "open",
              is_anonymous: isAnonymous,
            },
            context: {
              source: "ui",
              route: "/feedback",
            },
          },
          { failOpen: true }
        )
      }

      toast.success(isAnonymous ? "Anonymous feedback submitted" : "Feedback submitted successfully!")
      setFormData({
        feedbackType: "",
        title: "",
        description: "",
      })
      setIsAnonymous(false)

      if (onFeedbackSubmitted && data && data.length > 0) {
        onFeedbackSubmitted(data[0])
      }
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to submit feedback"
      toast.error(message)
    } finally {
      setIsLoading(false)
    }
  }

  const form = (
    <form onSubmit={handleSubmit} className="space-y-4">
      {/* Anonymous Toggle */}
      <div className="flex items-center justify-between rounded-lg border p-3">
        <div className="flex items-center gap-2">
          <EyeOff className={`h-4 w-4 ${isAnonymous ? "text-primary" : "text-muted-foreground"}`} />
          <Label htmlFor="anonymous" className="cursor-pointer">
            Submit anonymously
          </Label>
        </div>
        <Switch id="anonymous" checked={isAnonymous} onCheckedChange={setIsAnonymous} />
      </div>

      <div className="space-y-2">
        <Label htmlFor="feedbackType">Feedback Type *</Label>
        <Select
          value={formData.feedbackType}
          onValueChange={(value) => setFormData({ ...formData, feedbackType: value })}
        >
          <SelectTrigger id="feedbackType">
            <SelectValue placeholder="Select type" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="concern">Concern</SelectItem>
            <SelectItem value="complaint">Complaint</SelectItem>
            <SelectItem value="suggestion">Suggestion</SelectItem>
            <SelectItem value="required_item">Required Item</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <div className="space-y-2">
        <Label htmlFor="title">Title *</Label>
        <Input
          id="title"
          value={formData.title}
          onChange={(e) => setFormData({ ...formData, title: e.target.value })}
          placeholder="Brief title of your feedback"
          required
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="description">Description</Label>
        <Textarea
          id="description"
          value={formData.description}
          onChange={(e) => setFormData({ ...formData, description: e.target.value })}
          placeholder="Provide more details about your feedback..."
          rows={4}
        />
      </div>

      <Button type="submit" loading={isLoading} className={variant === "modal" ? "w-full" : "w-full"}>
        {isAnonymous ? "Submit Anonymously" : "Submit Feedback"}
      </Button>
    </form>
  )

  if (variant === "modal") {
    return form
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Submit Feedback</CardTitle>
        <CardDescription>Share your thoughts with us</CardDescription>
      </CardHeader>
      <CardContent>{form}</CardContent>
    </Card>
  )
}

"use client"

import { useState, useMemo } from "react"
import { useQuery } from "@tanstack/react-query"
import { createClient } from "@/lib/supabase/client"
import { QUERY_KEYS } from "@/lib/query-keys"
import { toast } from "sonner"
import { formatName } from "@/lib/utils"
import { writeAuditLogClient } from "@/lib/audit/client"
import { FeedbackFilterBar } from "@/components/feedback/feedback-filter-bar"
import { FeedbackDetailDialog } from "@/components/feedback/feedback-detail-dialog"
import { FeedbackTable } from "@/components/feedback/feedback-table"

interface FeedbackViewerClientProps {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  feedback: any[]
}

interface FeedbackFilterData {
  isDepartmentLead: boolean
  leadDepartments: string[]
  employees: { id: string; first_name: string; last_name: string; department: string }[]
  departments: string[]
}

async function fetchFeedbackFilterData(): Promise<FeedbackFilterData> {
  const supabase = createClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) return { isDepartmentLead: false, leadDepartments: [], employees: [], departments: [] }

  const { data: userProfile } = await supabase
    .from("profiles")
    .select("role, department, is_department_lead, lead_departments")
    .eq("id", user.id)
    .single()

  const scopedDepartments = userProfile?.lead_departments?.length
    ? userProfile.lead_departments
    : userProfile?.department
      ? [userProfile.department]
      : []

  let employeeQuery = supabase
    .from("profiles")
    .select("id, first_name, last_name, department")
    .order("last_name", { ascending: true })

  if (userProfile?.is_department_lead && scopedDepartments.length > 0) {
    employeeQuery = employeeQuery.in("department", scopedDepartments)
  }

  const { data: employeeData } = await employeeQuery
  const employees = (employeeData || []) as { id: string; first_name: string; last_name: string; department: string }[]

  let uniqueDepartments: string[] = []
  if (userProfile?.is_department_lead && scopedDepartments.length > 0) {
    uniqueDepartments = [...scopedDepartments].sort()
  } else {
    uniqueDepartments = Array.from(new Set(employees.map((s) => s.department).filter(Boolean))) as string[]
    uniqueDepartments.sort()
  }

  return {
    isDepartmentLead: Boolean(userProfile?.is_department_lead),
    leadDepartments: scopedDepartments,
    employees,
    departments: uniqueDepartments,
  }
}

export function FeedbackViewerClient({ feedback }: FeedbackViewerClientProps) {
  const [searchQuery, setSearchQuery] = useState("")
  const [selectedType, setSelectedType] = useState("all")
  const [selectedStatus, setSelectedStatus] = useState("all")
  const [departmentFilter, setDepartmentFilter] = useState("all")
  const [employeeFilter, setEmployeeFilter] = useState("all")
  const [nameSortOrder, setNameSortOrder] = useState<"asc" | "desc">("asc")
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [selectedFeedback, setSelectedFeedback] = useState<any | null>(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [isUpdating, setIsUpdating] = useState(false)

  const { data: filterData } = useQuery({
    queryKey: QUERY_KEYS.feedbackViewer(),
    queryFn: fetchFeedbackFilterData,
  })

  const isDepartmentLead = filterData?.isDepartmentLead ?? false
  const employees = filterData?.employees ?? []
  const departments = filterData?.departments ?? []

  const filteredFeedback = useMemo(() => {
    let filtered = feedback

    if (searchQuery) {
      filtered = filtered.filter((item) => {
        const titleMatch = item.title?.toLowerCase().includes(searchQuery.toLowerCase())
        const userMatch =
          item.profiles?.first_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
          item.profiles?.last_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
          item.profiles?.company_email?.toLowerCase().includes(searchQuery.toLowerCase())
        return titleMatch || userMatch
      })
    }

    if (selectedType !== "all") filtered = filtered.filter((item) => item.feedback_type === selectedType)
    if (selectedStatus !== "all") filtered = filtered.filter((item) => item.status === selectedStatus)
    if (departmentFilter !== "all") filtered = filtered.filter((item) => item.profiles?.department === departmentFilter)
    if (employeeFilter !== "all") filtered = filtered.filter((item) => item.user_id === employeeFilter)

    return [...filtered].sort((a, b) => {
      const lastNameA = formatName(a.profiles?.last_name || "").toLowerCase()
      const lastNameB = formatName(b.profiles?.last_name || "").toLowerCase()
      return nameSortOrder === "asc" ? lastNameA.localeCompare(lastNameB) : lastNameB.localeCompare(lastNameA)
    })
  }, [feedback, searchQuery, selectedType, selectedStatus, departmentFilter, employeeFilter, nameSortOrder])

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleViewDetails = (item: any) => {
    setSelectedFeedback(item)
    setIsModalOpen(true)
  }

  const handleUpdateStatus = async (newStatus: string) => {
    if (!selectedFeedback) return
    const supabase = createClient()
    setIsUpdating(true)

    try {
      const { error } = await supabase
        .from("feedback")
        .update({ status: newStatus, updated_at: new Date().toISOString() })
        .eq("id", selectedFeedback.id)

      if (error) throw error

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await writeAuditLogClient(
        supabase as any,
        {
          action: "status_change",
          entityType: "feedback",
          entityId: selectedFeedback.id,
          oldValues: { status: selectedFeedback.status },
          newValues: { status: newStatus },
          metadata: { event: "feedback_status_updated" },
          context: { source: "ui", route: "/admin/feedback" },
        },
        { failOpen: true }
      )

      toast.success("Status updated successfully!")
      setSelectedFeedback({ ...selectedFeedback, status: newStatus })
      window.location.reload()
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to update status"
      toast.error(message)
    } finally {
      setIsUpdating(false)
    }
  }

  const hasActiveFilters =
    !!searchQuery ||
    selectedType !== "all" ||
    selectedStatus !== "all" ||
    departmentFilter !== "all" ||
    employeeFilter !== "all"

  return (
    <div className="space-y-6">
      <FeedbackFilterBar
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        selectedType={selectedType}
        onTypeChange={setSelectedType}
        selectedStatus={selectedStatus}
        onStatusChange={setSelectedStatus}
        departmentFilter={departmentFilter}
        onDepartmentChange={setDepartmentFilter}
        employeeFilter={employeeFilter}
        onEmployeeChange={setEmployeeFilter}
        isDepartmentLead={isDepartmentLead}
        departments={departments}
        employees={employees}
        filteredCount={filteredFeedback.length}
      />

      <FeedbackTable
        items={filteredFeedback}
        nameSortOrder={nameSortOrder}
        onToggleSort={() => setNameSortOrder(nameSortOrder === "asc" ? "desc" : "asc")}
        onView={handleViewDetails}
        hasActiveFilters={hasActiveFilters}
      />

      <FeedbackDetailDialog
        feedback={selectedFeedback}
        isOpen={isModalOpen}
        onOpenChange={setIsModalOpen}
        onUpdateStatus={handleUpdateStatus}
        isUpdating={isUpdating}
      />
    </div>
  )
}

"use client"

import { usePathname } from "next/navigation"
import { Navbar } from "@/components/navbar"
import { AuthHeader } from "@/components/auth-header"

interface HeaderWrapperProps {
  user?: {
    email?: string
    user_metadata?: {
      first_name?: string
    }
  }
  canAccessAdmin?: boolean
}

export function HeaderWrapper({ user, canAccessAdmin = false }: HeaderWrapperProps) {
  const pathname = usePathname()

  // Don't show header on root page (shutdown page)
  if (pathname === "/") {
    return null
  }

  // Don't show header on auth pages
  const isAuthPage = pathname?.startsWith("/auth")
  if (isAuthPage) {
    return null
  }

  const isAdminMode = pathname?.startsWith("/admin")

  return <Navbar user={user} canAccessAdmin={canAccessAdmin} isAdminMode={isAdminMode} />
}

"use client"

import { useState, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { X, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"

interface ImageGalleryProps {
  images: File[]
  selectedIndex: number
  onSelect: (index: number) => void
  onRemove: (index: number) => void
  onClearAll: () => void
}

export function ImageGallery({ images, selectedIndex, onSelect, onRemove, onClearAll }: ImageGalleryProps) {
  const [thumbnails, setThumbnails] = useState<Map<string, string>>(new Map())

  // Generate thumbnails for all images
  useEffect(() => {
    const newThumbnails = new Map<string, string>()
    const promises = images.map((file) => {
      return new Promise<void>((resolve) => {
        const url = URL.createObjectURL(file)
        newThumbnails.set(file.name, url)
        resolve()
      })
    })

    Promise.all(promises).then(() => {
      setThumbnails(newThumbnails)
    })

    // Cleanup function
    return () => {
      thumbnails.forEach((url) => URL.revokeObjectURL(url))
    }
  }, [images])

  if (images.length === 0) return null

  return (
    <div className="border-border bg-card glass-effect space-y-3 rounded-lg border p-4">
      <div className="flex items-center justify-between">
        <p className="text-muted-foreground text-sm font-medium">
          {images.length} image{images.length === 1 ? "" : "s"} uploaded
        </p>
        <Button variant="ghost" size="sm" onClick={onClearAll} className="text-destructive hover:text-destructive h-8">
          <Trash2 className="mr-2 h-4 w-4" />
          Clear All
        </Button>
      </div>

      <div className="flex gap-2 overflow-x-auto pb-2">
        <AnimatePresence mode="popLayout">
          {images.map((file, index) => {
            const thumbnailUrl = thumbnails.get(file.name)
            const isSelected = index === selectedIndex

            return (
              <motion.div
                key={file.name}
                layout
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.8 }}
                transition={{ duration: 0.2 }}
                className="relative flex-shrink-0"
              >
                <button
                  onClick={() => onSelect(index)}
                  className={cn(
                    "bg-muted relative h-20 w-20 overflow-hidden rounded-lg border-2 transition-all hover:scale-105",
                    isSelected ? "border-primary ring-primary ring-2 ring-offset-2" : "border-transparent"
                  )}
                >
                  {thumbnailUrl ? (
                    <img src={thumbnailUrl} alt={file.name} className="h-full w-full object-cover" />
                  ) : (
                    <div className="flex h-full w-full items-center justify-center">
                      <span className="text-muted-foreground text-xs">Loading...</span>
                    </div>
                  )}
                </button>

                {/* Delete button */}
                <button
                  onClick={(e) => {
                    e.stopPropagation()
                    onRemove(index)
                  }}
                  className="bg-destructive text-destructive-foreground hover:bg-destructive/90 absolute -top-2 -right-2 flex h-6 w-6 items-center justify-center rounded-full shadow-md transition-transform hover:scale-110"
                  aria-label="Remove image"
                >
                  <X className="h-3.5 w-3.5" />
                </button>
              </motion.div>
            )
          })}
        </AnimatePresence>
      </div>
    </div>
  )
}

"use client"

import { useCallback, useEffect, useRef, useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Upload, Loader2 } from "lucide-react"
import { toast } from "sonner"
import type { WatermarkConfig } from "@/components/watermark-studio"
import { convertImagesIfNeeded } from "@/lib/convert-image"

interface MediaPreviewProps {
  mediaFile: File | null
  mediaType: "image" | "video" | null
  watermarkPath: string
  config: WatermarkConfig
  processedUrl: string | null
  onUpload: (files: File[], type: "image" | "video") => void
}

const ACCEPTED_VIDEO_TYPES = ["video/mp4", "video/quicktime", "video/webm"]

function isImageFile(file: File): boolean {
  if (file.type && file.type.startsWith("image/")) return true
  const name = file.name || ""
  return /(\.(jpe?g|png|webp|gif|heic|heif|bmp|tiff?|svg))$/i.test(name)
}

function isVideoFile(file: File): boolean {
  if (file.type && ACCEPTED_VIDEO_TYPES.includes(file.type)) return true
  const name = file.name || ""
  return /(\.(mp4|mov|webm))$/i.test(name)
}

export function MediaPreview({
  mediaFile,
  mediaType,
  watermarkPath,
  config,
  processedUrl,
  onUpload,
}: MediaPreviewProps) {
  const [mediaUrl, setMediaUrl] = useState<string | null>(null)
  const [isConverting, setIsConverting] = useState(false)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const videoRef = useRef<HTMLVideoElement>(null)

  useEffect(() => {
    if (mediaFile) {
      const url = URL.createObjectURL(mediaFile)
      setMediaUrl(url)
      return () => URL.revokeObjectURL(url)
    }
  }, [mediaFile])

  useEffect(() => {
    if (!mediaUrl || !canvasRef.current || mediaType !== "image" || processedUrl) return

    const canvas = canvasRef.current
    const ctx = canvas.getContext("2d")
    if (!ctx) return

    const img = new window.Image()
    img.crossOrigin = "anonymous"
    img.src = mediaUrl

    img.onload = () => {
      canvas.width = img.width
      canvas.height = img.height
      ctx.drawImage(img, 0, 0)

      const watermark = new window.Image()
      watermark.crossOrigin = "anonymous"
      watermark.src = watermarkPath

      watermark.onload = () => {
        const watermarkWidth = (img.width * config.size) / 100
        const watermarkHeight = (watermark.height * watermarkWidth) / watermark.width

        const positions = {
          "top-left": { x: 20, y: 20 },
          "top-center": { x: (img.width - watermarkWidth) / 2, y: 20 },
          "top-right": { x: img.width - watermarkWidth - 20, y: 20 },
          "middle-left": { x: 20, y: (img.height - watermarkHeight) / 2 },
          center: {
            x: (img.width - watermarkWidth) / 2,
            y: (img.height - watermarkHeight) / 2,
          },
          "center-down-10": {
            x: (img.width - watermarkWidth) / 2,
            y: (img.height - watermarkHeight) / 2 + img.height * 0.1,
          },
          "center-down-20": {
            x: (img.width - watermarkWidth) / 2,
            y: (img.height - watermarkHeight) / 2 + img.height * 0.2,
          },
          "center-down-25": {
            x: (img.width - watermarkWidth) / 2,
            y: (img.height - watermarkHeight) / 2 + img.height * 0.25,
          },
          "middle-right": {
            x: img.width - watermarkWidth - 20,
            y: (img.height - watermarkHeight) / 2,
          },
          "bottom-left": { x: 20, y: img.height - watermarkHeight - 20 },
          "bottom-center": {
            x: (img.width - watermarkWidth) / 2,
            y: img.height - watermarkHeight - 20,
          },
          "bottom-right": {
            x: img.width - watermarkWidth - 20,
            y: img.height - watermarkHeight - 20,
          },
        }

        const pos = positions[config.position]
        ctx.globalAlpha = config.opacity
        ctx.drawImage(watermark, pos.x, pos.y, watermarkWidth, watermarkHeight)
        ctx.globalAlpha = 1
      }
    }
  }, [mediaUrl, watermarkPath, config, mediaType, processedUrl])

  const handleFiles = useCallback(
    async (list: FileList | File[]) => {
      const files = Array.from(list)
      const images = files.filter((f) => isImageFile(f))
      const videos = files.filter((f) => isVideoFile(f))

      if (videos.length > 1 || (videos.length === 1 && images.length > 0)) {
        toast.error("Invalid selection", {
          description: "Upload either one video or one/more images.",
        })
        return
      }

      if (videos.length === 1) {
        onUpload([videos[0]], "video")
        return
      }

      if (images.length > 0) {
        const MAX = 50
        const selected = images.slice(0, MAX)
        if (images.length > MAX) {
          toast.message("Selection limited", {
            description: `Only the first ${MAX} images will be attached (of ${images.length}).`,
          })
        }

        try {
          setIsConverting(true)
          toast.loading("Converting images...", { id: "preview-image-conversion" })

          // Convert HEIC and other formats if needed
          const convertedImages = await convertImagesIfNeeded(selected)

          toast.dismiss("preview-image-conversion")
          onUpload(convertedImages, "image")
          toast.success("Images attached", {
            description: `${convertedImages.length} image${convertedImages.length === 1 ? "" : "s"} ready to preview/process.`,
          })
        } catch (error) {
          toast.dismiss("preview-image-conversion")
          toast.error("Conversion failed", {
            description: error instanceof Error ? error.message : "Failed to convert images",
          })
        } finally {
          setIsConverting(false)
        }
        return
      }

      toast.error("Invalid file type", {
        description: "Please upload images or a single MP4/MOV/WEBM video.",
      })
    },
    [onUpload]
  )

  const handleDrop = useCallback(
    (e: React.DragEvent<HTMLDivElement>) => {
      e.preventDefault()
      const { files } = e.dataTransfer
      if (files && files.length) handleFiles(files)
    },
    [handleFiles]
  )

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = e.target.files
      if (files && files.length) handleFiles(files)
    },
    [handleFiles]
  )

  if (!mediaFile) {
    return (
      <div className="flex h-full items-center justify-center">
        <motion.div
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          onDrop={handleDrop}
          onDragOver={(e) => e.preventDefault()}
          className="border-border hover:border-muted-foreground relative w-full max-w-2xl cursor-pointer rounded-lg border-2 border-dashed p-12 text-center transition-colors"
          onClick={() => !isConverting && document.getElementById("preview-media-upload")?.click()}
        >
          <input
            id="preview-media-upload"
            type="file"
            multiple
            accept="image/*,video/*"
            className="hidden"
            onChange={handleChange}
            disabled={isConverting}
          />
          {isConverting ? (
            <>
              <Loader2 className="text-muted-foreground mx-auto mb-4 h-16 w-16 animate-spin" />
              <h2 className="text-foreground mb-2 text-xl font-semibold">Converting images...</h2>
              <p className="text-muted-foreground text-sm">Please wait while we process your files</p>
            </>
          ) : (
            <>
              <Upload className="text-muted-foreground mx-auto mb-4 h-16 w-16" />
              <h2 className="text-foreground mb-2 text-xl font-semibold">No media uploaded</h2>
              <p className="text-muted-foreground text-sm">
                Drag & drop or click to upload an image or video to get started
              </p>
              <p className="text-muted-foreground mt-2 text-xs">Supports JPG, PNG, HEIC, MP4, MOV</p>
            </>
          )}
        </motion.div>
      </div>
    )
  }

  return (
    <div className="flex h-full flex-col items-center justify-center gap-6">
      <AnimatePresence mode="wait">
        {processedUrl ? (
          <motion.div
            key="processed"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="w-full max-w-4xl"
          >
            <div className="mb-4">
              <h3 className="text-foreground text-lg font-semibold">Processed Result</h3>
              <p className="text-muted-foreground text-sm">Your watermarked media is ready</p>
            </div>
            <div className="border-border glass-effect overflow-hidden rounded-lg border">
              {mediaType === "image" ? (
                <img src={processedUrl || "/placeholder.svg"} alt="Processed" className="h-auto w-full" />
              ) : (
                <video src={processedUrl} controls className="h-auto w-full" />
              )}
            </div>
          </motion.div>
        ) : (
          <motion.div
            key="preview"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="w-full max-w-4xl"
          >
            <div className="mb-4">
              <h3 className="text-foreground text-lg font-semibold">Live Preview</h3>
              <p className="text-muted-foreground text-sm">Adjust settings to see changes in real-time</p>
            </div>
            <div className="border-border glass-effect overflow-hidden rounded-lg border">
              {mediaType === "image" ? (
                <canvas ref={canvasRef} className="h-auto w-full" />
              ) : (
                <video ref={videoRef} src={mediaUrl || ""} controls className="h-auto w-full" />
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

"use client"

import { useState, useEffect, useRef } from "react"
import { logger } from "@/lib/logger"

const log = logger("notification-bell")
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Input } from "@/components/ui/input"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu"
import {
  Bell,
  CheckCheck,
  X,
  Search,
  Settings,
  AlertCircle,
  CheckCircle,
  Info,
  User,
  Package,
  MessageSquare,
  FileText,
  AlertTriangle,
  Clock,
  ChevronRight,
  Trash2,
} from "lucide-react"
import Link from "next/link"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { QUERY_KEYS } from "@/lib/query-keys"

interface Notification {
  id: string
  user_id: string
  type: string
  category: string
  priority: string
  title: string
  message: string
  data?: any
  action_url?: string | null
  actor_name?: string
  actor_avatar?: string
  read: boolean
  read_at?: string
  created_at: string
}

interface NotificationBellProps {
  isAdmin?: boolean
}

// Notification type icons
const typeIcons = {
  task_assigned: User,
  task_updated: AlertCircle,
  task_completed: CheckCircle,
  mention: MessageSquare,
  feedback: MessageSquare,
  asset_assigned: Package,
  approval_request: FileText,
  approval_granted: CheckCircle,
  system: Settings,
  announcement: AlertTriangle,
}

// Category icons
const categoryIcons = {
  tasks: User,
  assets: Package,
  feedback: MessageSquare,
  approvals: FileText,
  system: Settings,
  mentions: MessageSquare,
}

// Priority colors
const priorityColors = {
  low: "text-gray-500",
  normal: "text-blue-500",
  high: "text-orange-500",
  urgent: "text-red-500",
}

// Format relative time
function formatRelativeTime(dateString: string): string {
  const date = new Date(dateString)
  const now = new Date()
  const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000)

  if (diffInSeconds < 60) return "Just now"
  if (diffInSeconds < 3600) {
    const minutes = Math.floor(diffInSeconds / 60)
    return `${minutes}m ago`
  }
  if (diffInSeconds < 86400) {
    const hours = Math.floor(diffInSeconds / 3600)
    return `${hours}h ago`
  }
  if (diffInSeconds < 604800) {
    const days = Math.floor(diffInSeconds / 86400)
    return `${days}d ago`
  }
  if (diffInSeconds < 2592000) {
    const weeks = Math.floor(diffInSeconds / 604800)
    return `${weeks}w ago`
  }

  return date.toLocaleDateString("en-US", { month: "short", day: "numeric" })
}

// Get initials from name
function getInitials(name?: string): string {
  if (!name) return "?"
  const parts = name.split(" ")
  if (parts.length >= 2) {
    return `${parts[0][0]}${parts[1][0]}`.toUpperCase()
  }
  return name.substring(0, 2).toUpperCase()
}

export function NotificationBell({ isAdmin = false }: NotificationBellProps) {
  const router = useRouter()
  const supabase = createClient()
  const queryClient = useQueryClient()

  // State
  const [isOpen, setIsOpen] = useState(false)
  const [activeTab, setActiveTab] = useState("all")
  const [searchQuery, setSearchQuery] = useState("")

  // Real-time subscription ref
  const subscriptionRef = useRef<any>(null)

  const { data: notifications = [], isLoading } = useQuery({
    queryKey: QUERY_KEYS.notificationBell(),
    queryFn: async () => {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) return []

      const { data, error } = await supabase
        .from("notifications")
        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false })
        .limit(50)

      if (error) throw new Error(error.message)
      return data || []
    },
  })

  const loadNotifications = () => {
    queryClient.invalidateQueries({ queryKey: QUERY_KEYS.notificationBell() })
  }

  // Setup real-time subscription
  useEffect(() => {
    loadNotifications()

    // Subscribe to real-time updates
    const setupSubscription = async () => {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) return

      subscriptionRef.current = supabase
        .channel("notifications")
        .on(
          "postgres_changes",
          {
            event: "*",
            schema: "public",
            table: "notifications",
            filter: `user_id=eq.${user.id}`,
          },
          (payload) => {
            // Invalidate query to refetch updated notifications
            queryClient.invalidateQueries({ queryKey: QUERY_KEYS.notificationBell() })

            // Show toast for new notification
            if (payload.eventType === "INSERT") {
              toast.info(payload.new.title, {
                description: payload.new.message,
                action: payload.new.action_url
                  ? {
                      label: "View",
                      onClick: () => router.push(payload.new.action_url),
                    }
                  : undefined,
              })
            }
          }
        )
        .subscribe()
    }

    setupSubscription()

    return () => {
      if (subscriptionRef.current) {
        subscriptionRef.current.unsubscribe()
      }
    }
  }, [supabase, router])

  // Refresh when dropdown opens
  useEffect(() => {
    if (isOpen) {
      loadNotifications()
    }
  }, [isOpen])

  // Mark as read
  const markAsRead = async (notificationId: string) => {
    try {
      const { error } = await supabase
        .from("notifications")
        .update({ read: true, read_at: new Date().toISOString() })
        .eq("id", notificationId)

      if (error) throw error

      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.notificationBell() })
    } catch (error: any) {
      log.error("Error marking as read:", error)
    }
  }

  // Mark all as read
  const markAllAsRead = async () => {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) return

      const { error } = await supabase.rpc("mark_notifications_read", {
        p_user_id: user.id,
        p_notification_ids: null,
      })

      if (error) throw error

      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.notificationBell() })
      toast.success("All notifications marked as read")
    } catch (error: any) {
      log.error("Error marking all as read:", error)
      toast.error("Failed to mark all as read")
    }
  }

  // Delete notification
  const deleteNotification = async (notificationId: string) => {
    try {
      const { error } = await supabase.from("notifications").delete().eq("id", notificationId)

      if (error) throw error

      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.notificationBell() })
    } catch (error: any) {
      log.error("Error deleting notification:", error)
      toast.error("Failed to delete notification")
    }
  }

  // Handle notification click
  const handleNotificationClick = async (notification: Notification) => {
    // Mark as read if not already
    if (!notification.read) {
      await markAsRead(notification.id)
    }

    // Navigate if there's a link
    if (notification.action_url) {
      setIsOpen(false)
      router.push(notification.action_url)
    }
  }

  // Filter notifications
  const filteredNotifications = notifications.filter((n) => {
    // Tab filter
    if (activeTab === "unread" && n.read) return false
    if (activeTab !== "all" && activeTab !== "unread" && n.category !== activeTab) return false

    // Search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase()
      return (
        n.title.toLowerCase().includes(query) ||
        n.message.toLowerCase().includes(query) ||
        n.actor_name?.toLowerCase().includes(query)
      )
    }

    return true
  })

  // Calculate counts
  const unreadCount = notifications.filter((n) => !n.read).length
  const categoryCounts = {
    all: notifications.length,
    unread: unreadCount,
    tasks: notifications.filter((n) => n.category === "tasks").length,
    assets: notifications.filter((n) => n.category === "assets").length,
    feedback: notifications.filter((n) => n.category === "feedback").length,
    approvals: notifications.filter((n) => n.category === "approvals").length,
    mentions: notifications.filter((n) => n.category === "mentions").length,
    system: notifications.filter((n) => n.category === "system").length,
  }

  if (isLoading) {
    return null
  }

  return (
    <DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          aria-label="Notifications"
          className="hover:bg-muted relative h-10 w-10 rounded-full transition-colors"
        >
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <Badge
              variant="destructive"
              className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center p-0 text-[10px] font-bold"
            >
              {unreadCount > 99 ? "99+" : unreadCount}
            </Badge>
          )}
        </Button>
      </DropdownMenuTrigger>

      <DropdownMenuContent
        align="end"
        className="w-[calc(100vw-2rem)] border-2 p-0 shadow-xl sm:w-[460px]"
        onCloseAutoFocus={(e) => e.preventDefault()}
      >
        {/* Header */}
        <div className="bg-muted/30 flex items-center justify-between border-b p-3">
          <div className="flex items-center gap-2">
            <Bell className="text-foreground h-5 w-5" />
            <h3 className="text-base font-semibold">Notifications</h3>
            {unreadCount > 0 && (
              <Badge variant="secondary" className="px-2 text-xs font-semibold">
                {unreadCount} new
              </Badge>
            )}
          </div>

          <div className="flex items-center gap-2">
            {unreadCount > 0 && (
              <Button variant="ghost" size="sm" className="h-8 text-xs" onClick={markAllAsRead}>
                <CheckCheck className="mr-1 h-4 w-4" />
                Mark all read
              </Button>
            )}

            <Link href={isAdmin ? "/admin/notifications" : "/notifications"}>
              <Button
                variant="ghost"
                size="icon"
                aria-label="Notification settings"
                className="h-8 w-8"
                onClick={() => setIsOpen(false)}
              >
                <Settings className="h-4 w-4" />
              </Button>
            </Link>
          </div>
        </div>

        {/* Search */}
        <div className="border-b p-2.5">
          <div className="relative">
            <Search className="text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2" />
            <Input
              placeholder="Search notifications..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="h-8 pl-9"
            />
          </div>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="h-auto w-full justify-start rounded-none border-b bg-transparent p-0">
            <TabsTrigger
              value="all"
              className="data-[state=active]:border-primary rounded-none border-b-2 border-transparent px-3 py-2 data-[state=active]:bg-transparent data-[state=active]:shadow-none"
            >
              All{" "}
              {categoryCounts.all > 0 && (
                <Badge variant="secondary" className="ml-2 px-1.5 text-xs">
                  {categoryCounts.all}
                </Badge>
              )}
            </TabsTrigger>

            <TabsTrigger
              value="unread"
              className="data-[state=active]:border-primary rounded-none border-b-2 border-transparent px-3 py-2 data-[state=active]:bg-transparent data-[state=active]:shadow-none"
            >
              Unread{" "}
              {categoryCounts.unread > 0 && (
                <Badge variant="destructive" className="ml-2 px-1.5 text-xs">
                  {categoryCounts.unread}
                </Badge>
              )}
            </TabsTrigger>

