"use client"

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import Link from "next/link"
import {
  Bell,
  AlertCircle,
  CheckCircle,
  Info,
  X,
  Clock,
  UserPlus,
  MessageSquare,
  ClipboardList,
  Laptop,
  ArrowRight,
} from "lucide-react"
import { useState } from "react"

interface Notification {
  id: string
  type: "info" | "warning" | "success" | "error"
  title: string
  message: string
  timestamp?: string
  link?: string
  linkText?: string
}

interface NotificationsProps {
  notifications: Notification[]
  title?: string
  showDismiss?: boolean
}

const notificationIcons = {
  info: Info,
  warning: AlertCircle,
  success: CheckCircle,
  error: AlertCircle,
}

const notificationColors = {
  info: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
  warning: "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400",
  success: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
  error: "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400",
}

export function Notifications({ notifications, title = "Notifications", showDismiss = true }: NotificationsProps) {
  const [dismissed, setDismissed] = useState<Set<string>>(new Set())

  if (notifications.length === 0 || notifications.filter((n) => !dismissed.has(n.id)).length === 0) {
    return null
  }

  const visibleNotifications = notifications.filter((n) => !dismissed.has(n.id))

  const handleDismiss = (id: string) => {
    setDismissed(new Set([...Array.from(dismissed), id]))
  }

  return (
    <Card className="border-2 shadow-lg">
      <CardHeader className="bg-muted/30 border-b">
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2">
            <Bell className="text-primary h-5 w-5" />
            {title}
          </CardTitle>
          {visibleNotifications.length > 0 && <Badge variant="secondary">{visibleNotifications.length}</Badge>}
        </div>
      </CardHeader>
      <CardContent className="space-y-3 p-4">
        {visibleNotifications.map((notification) => {
          const Icon = notificationIcons[notification.type]
          return (
            <div
              key={notification.id}
              className={`rounded-lg border-l-4 p-4 ${
                notification.type === "info"
                  ? "border-l-blue-500 bg-blue-50 dark:bg-blue-950/20"
                  : notification.type === "warning"
                    ? "border-l-yellow-500 bg-yellow-50 dark:bg-yellow-950/20"
                    : notification.type === "success"
                      ? "border-l-green-500 bg-green-50 dark:bg-green-950/20"
                      : "border-l-red-500 bg-red-50 dark:bg-red-950/20"
              } relative`}
            >
              {showDismiss && (
                <Button
                  variant="ghost"
                  size="sm"
                  className="absolute top-2 right-2 h-6 w-6 p-0"
                  onClick={() => handleDismiss(notification.id)}
                >
                  <X className="h-4 w-4" />
                </Button>
              )}
              <div className="flex items-start gap-3 pr-8">
                <div className={`rounded-lg p-2 ${notificationColors[notification.type]}`}>
                  <Icon className="h-4 w-4" />
                </div>
                <div className="min-w-0 flex-1">
                  <div className="mb-1 flex items-start justify-between gap-2">
                    <h4 className="text-foreground text-sm font-semibold">{notification.title}</h4>
                    {notification.timestamp && (
                      <span className="text-muted-foreground flex items-center gap-1 text-xs whitespace-nowrap">
                        <Clock className="h-3 w-3" />
                        {notification.timestamp}
                      </span>
                    )}
                  </div>
                  <p className="text-muted-foreground mb-2 text-sm">{notification.message}</p>
                  {notification.link && (
                    <Link href={notification.link}>
                      <Button variant="ghost" size="sm" className="h-7 gap-1 text-xs">
                        {notification.linkText || "View Details"}
                        <ArrowRight className="h-3 w-3" />
                      </Button>
                    </Link>
                  )}
                </div>
              </div>
            </div>
          )
        })}
      </CardContent>
    </Card>
  )
}

/**
 * File Preview Component
 * Modal for previewing different file types from OneDrive
 */

"use client"

import { useState, useEffect } from "react"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Download, ExternalLink, X, Loader2 } from "lucide-react"
import type { FileItem, FileCategory } from "@/lib/onedrive"
import { FileIcon } from "./file-icon"

interface FilePreviewProps {
  file: FileItem | null
  category: FileCategory
  isOpen: boolean
  onClose: () => void
}

interface PreviewData {
  previewUrl: string
  previewType: "embed" | "image" | "download"
}

export function FilePreview({ file, category, isOpen, onClose }: FilePreviewProps) {
  const [previewData, setPreviewData] = useState<PreviewData | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (file && isOpen) {
      fetchPreview()
    } else {
      setPreviewData(null)
      setError(null)
    }
  }, [file, isOpen])

  const fetchPreview = async () => {
    if (!file) return

    setLoading(true)
    setError(null)

    try {
      const response = await fetch(`/api/onedrive/preview?path=${encodeURIComponent(file.path)}`)
      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.error || "Failed to load preview")
      }

      setPreviewData({
        previewUrl: data.data.previewUrl,
        previewType: data.data.previewType,
      })
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to load preview")
    } finally {
      setLoading(false)
    }
  }

  const handleDownload = () => {
    if (!file) return
    window.open(`/api/onedrive/download?path=${encodeURIComponent(file.path)}&redirect=true`, "_blank")
  }

  const handleOpenInOneDrive = () => {
    if (file?.webUrl) {
      window.open(file.webUrl, "_blank")
    }
  }

  const formatFileSize = (bytes: number): string => {
    if (bytes === 0) return "0 B"
    const k = 1024
    const sizes = ["B", "KB", "MB", "GB"]
    const i = Math.floor(Math.log(bytes) / Math.log(k))
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + " " + sizes[i]
  }

  const renderPreviewContent = () => {
    if (loading) {
      return (
        <div className="flex h-96 flex-col items-center justify-center gap-4">
          <Loader2 className="text-muted-foreground h-8 w-8 animate-spin" />
          <p className="text-muted-foreground text-sm">Loading preview...</p>
        </div>
      )
    }

    if (error) {
      return (
        <div className="flex h-96 flex-col items-center justify-center gap-4">
          <FileIcon category={category} size={64} />
          <p className="text-muted-foreground text-sm">{error}</p>
          <Button onClick={handleDownload} variant="outline">
            <Download className="mr-2 h-4 w-4" />
            Download Instead
          </Button>
        </div>
      )
    }

    if (!previewData) {
      return (
        <div className="flex h-96 flex-col items-center justify-center gap-4">
          <FileIcon category={category} size={64} />
          <p className="text-muted-foreground text-sm">Preview not available</p>
        </div>
      )
    }

    switch (previewData.previewType) {
      case "image":
        return (
          <div className="bg-muted/30 flex max-h-[70vh] min-h-96 items-center justify-center overflow-auto rounded-lg">
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={previewData.previewUrl}
              alt={file?.name || "Preview"}
              className="max-h-full max-w-full object-contain"
            />
          </div>
        )

      case "embed":
        return (
          <div className="h-[70vh] w-full overflow-hidden rounded-lg border">
            <iframe
              src={previewData.previewUrl}
              className="h-full w-full"
              title={file?.name || "Document Preview"}
              allowFullScreen
            />
          </div>
        )

      default:
        return (
          <div className="flex h-96 flex-col items-center justify-center gap-4">
            <FileIcon category={category} size={64} />
            <p className="text-muted-foreground text-sm">This file type cannot be previewed in the browser.</p>
            <Button onClick={handleDownload}>
              <Download className="mr-2 h-4 w-4" />
              Download File
            </Button>
          </div>
        )
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="flex max-h-[90vh] w-[95vw] max-w-5xl flex-col overflow-hidden">
        <DialogHeader className="shrink-0">
          <div className="flex items-center justify-between gap-4">
            <div className="flex min-w-0 items-center gap-3">
              <FileIcon category={category} size={28} />
              <div className="min-w-0">
                <DialogTitle className="truncate">{file?.name}</DialogTitle>
                {file && (
                  <p className="text-muted-foreground mt-0.5 text-xs">
                    {formatFileSize(file.size)} • {new Date(file.lastModified).toLocaleDateString()}
                  </p>
                )}
              </div>
            </div>
            <div className="flex shrink-0 items-center gap-2">
              <Button variant="outline" size="sm" onClick={handleOpenInOneDrive} title="Open in OneDrive">
                <ExternalLink className="h-4 w-4" />
              </Button>
              <Button variant="outline" size="sm" onClick={handleDownload}>
                <Download className="h-4 w-4" />
              </Button>
              <Button variant="ghost" size="sm" onClick={onClose}>
                <X className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </DialogHeader>

        <div className="mt-4 flex-1 overflow-auto">{renderPreviewContent()}</div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useEffect, useState } from "react"
import { logger } from "@/lib/logger"

const log = logger("payments-table")
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { QUERY_KEYS } from "@/lib/query-keys"
import { useRouter } from "next/navigation"
import { Plus, Search, Download, CreditCard, Eye, FileSpreadsheet, FileIcon, Printer, ArrowUpDown } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Badge } from "@/components/ui/badge"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { toast } from "sonner"
import { format, parseISO, isValid, differenceInDays, isBefore, startOfDay } from "date-fns"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { createClient } from "@/lib/supabase/client"
import { AdminTablePage } from "@/components/admin/admin-table-page"
import { CreatePaymentDialog } from "./create-payment-dialog"
import { ExportColumnsDialog } from "./export-columns-dialog"
import { ReceiptSelectionDialog } from "./receipt-selection-dialog"
import { PaymentStatsCards } from "./payment-stats-cards"
import { usePaymentExport } from "./use-payment-export"
import type { CreatePaymentFormData } from "./create-payment-dialog"

// Types
interface Payment {
  id: string
  department_id: string
  title: string
  amount: number
  currency: string
  status: "due" | "paid" | "overdue" | "cancelled"
  payment_type: "one-time" | "recurring"
  recurrence_period?: "monthly" | "quarterly" | "yearly"
  next_payment_due?: string
  payment_date?: string
  category: string
  description?: string
  issuer_name?: string
  issuer_phone_number?: string
  issuer_address?: string
  payment_reference?: string
  amount_paid?: number
  created_at: string
  department?: {
    name: string
  }
  documents?: {
    id: string
    document_type: string
    file_path: string
    file_name?: string
    applicable_date?: string
    created_at?: string
  }[]
}

interface Department {
  id: string
  name: string
}

interface Category {
  id: string
  name: string
}

interface PaymentsTableData {
  payments: Payment[]
  departments: Department[]
  categories: Category[]
}

async function fetchPaymentsTableData(): Promise<PaymentsTableData> {
  const [paymentsRes, deptRes, catRes] = await Promise.all([
    fetch("/api/payments"),
    fetch("/api/departments"),
    fetch("/api/payments/categories"),
  ])

  if (!paymentsRes.ok) {
    const data = await paymentsRes.json().catch(() => ({}))
    throw new Error(data?.error ?? "Failed to fetch payments")
  }

  const paymentsJson = await paymentsRes.json()
  const departments: Department[] = deptRes.ok ? ((await deptRes.json()).data ?? []) : []
  const categories: Category[] = catRes.ok ? ((await catRes.json()).data ?? []) : []

  return {
    payments: paymentsJson.data ?? [],
    departments,
    categories,
  }
}

interface PaymentsTableProps {
  initialPayments?: Payment[]
  initialDepartments?: Department[]
  initialCategories?: Category[]
  initialError?: string | null
  currentUser: {
    id: string
    department_id: string | null
    isAdmin: boolean
  }
  /** Base path for detail pages - default "/admin/payments" for admin, "/payments" for users */
  basePath?: string
}

export function PaymentsTable({
  initialPayments = [],
  initialDepartments = [],
  initialCategories = [],
  initialError = null,
  currentUser,
  basePath = currentUser.isAdmin ? "/admin/payments" : "/payments",
}: PaymentsTableProps) {
  const router = useRouter()
  const queryClient = useQueryClient()

  const { data: tableData, isLoading: loading } = useQuery({
    queryKey: QUERY_KEYS.paymentsTable(),
    queryFn: fetchPaymentsTableData,
    initialData:
      initialPayments.length > 0 || initialDepartments.length > 0 || initialCategories.length > 0
        ? { payments: initialPayments, departments: initialDepartments, categories: initialCategories }
        : undefined,
  })

  const payments = tableData?.payments ?? []
  const departments = tableData?.departments ?? []

  // Filters
  const [searchQuery, setSearchQuery] = useState("")
  const [departmentFilter, setDepartmentFilter] = useState("all")
  const [categoryFilter, setCategoryFilter] = useState("all")
  const [statusFilter, setStatusFilter] = useState("all")

  // Sorting
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: "asc" | "desc" }>({
    key: "date",
    direction: "asc",
  })

  // Modal
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [submitting, setSubmitting] = useState(false)
  const [receiptFile, setReceiptFile] = useState<File | null>(null)

  // Receipt Selection Dialog
  const [receiptDialogOpen, setReceiptDialogOpen] = useState(false)
  const [selectedPaymentForReceipt, setSelectedPaymentForReceipt] = useState<Payment | null>(null)

  // Export dialog state
  const [exportDialogOpen, setExportDialogOpen] = useState(false)
  const [exportType, setExportType] = useState<"excel" | "pdf" | null>(null)
  const [selectedColumns, setSelectedColumns] = useState<Record<string, boolean>>({
    "#": true,
    Category: true,
    Title: true,
    Issuer: true,
    Department: true,
    Amount: true,
    "Amount Due": true,
    Currency: true,
    Type: true,
    Status: true,
    "First Payment Date": true,
    "Number of Payments": true,
    "Next Due Date": true,
    Recurrence: false,
    Reference: true,
  })

  const [formData, setFormData] = useState<CreatePaymentFormData>({
    department_id: currentUser.department_id || "",
    category: "",
    title: "",
    description: "",
    amount: "",
    currency: "NGN",
    recurrence_period: "monthly",
    next_payment_due: "",
    payment_date: "",
    issuer_name: "",
    issuer_phone_number: "",
    issuer_address: "",
    payment_reference: "",
    notes: "",
  })

  useEffect(() => {
    if (initialError) {
      toast.error(initialError)
    }
  }, [initialError])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setSubmitting(true)

    try {
      if (
        !formData.department_id ||
        !formData.category ||
        !formData.amount ||
        !formData.title ||
        !formData.issuer_name ||
        !formData.issuer_phone_number
      ) {
        toast.error("Please fill in all required fields (including Issuer Name & Phone)")
        setSubmitting(false)
        return
      }

      if (formData.category === "recurring" && (!formData.recurrence_period || !formData.next_payment_due)) {
        toast.error("Recurring payments require a period and start date")
        setSubmitting(false)
        return
      }

      if (formData.category === "one-time" && !formData.payment_date) {
        toast.error("One-time payments require a payment date")
        setSubmitting(false)
        return
      }

      if (formData.category === "one-time" && !receiptFile) {
        toast.error("One-time payments require a receipt to be uploaded")
        setSubmitting(false)
        return
      }

      const response = await fetch("/api/payments", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...formData,
          amount: parseFloat(formData.amount),
        }),
      })

      if (response.ok) {
        const data = await response.json()
        const paymentId = data.data.id

        if (formData.category === "one-time" && receiptFile) {
          const formDataUpload = new FormData()
          formDataUpload.append("file", receiptFile)
          formDataUpload.append("payment_id", paymentId)
          formDataUpload.append("document_type", "receipt")
          formDataUpload.append("applicable_date", formData.payment_date)

          const uploadResponse = await fetch("/api/payments/documents", {
            method: "POST",
            body: formDataUpload,
          })

          if (!uploadResponse.ok) {
            toast.warning("Payment created, but receipt upload failed. You can upload it later.")
          }
        }

        toast.success("Payment created successfully")
        setIsModalOpen(false)
        setReceiptFile(null)
        setFormData({
          department_id: currentUser.department_id || "",
          category: "",
          title: "",
          description: "",
          amount: "",
          currency: "NGN",
          recurrence_period: "monthly",
          next_payment_due: "",
          payment_date: "",
          issuer_name: "",
          issuer_phone_number: "",
          issuer_address: "",
          payment_reference: "",
          notes: "",
        })
        queryClient.invalidateQueries({ queryKey: QUERY_KEYS.paymentsTable() })
      } else {
        const data = await response.json()
        toast.error(data.error || "Failed to create payment")
      }
    } catch (error) {
      toast.error("Error creating payment")
    } finally {
      setSubmitting(false)
    }
  }

  // Compute dynamic status based on due dates
  const getRealStatus = (p: Payment): "due" | "paid" | "overdue" | "cancelled" => {
    if (p.payment_type === "one-time") return "paid"
    if (p.status === "paid" || p.status === "cancelled") return p.status

    const dateStr = p.payment_type === "recurring" ? p.next_payment_due : p.payment_date
    if (!dateStr) return "due"

    const date = parseISO(dateStr)
    if (!isValid(date)) return "due"

    const today = startOfDay(new Date())
    const daysDiff = differenceInDays(date, today)

    if (isBefore(date, today)) return "overdue"
    if (daysDiff <= 7) return "due"
    return "paid"
  }

  const getAmountDue = (p: Payment) => {
    const status = getRealStatus(p)
    if (status === "paid" || status === "cancelled") return 0
    if (status === "due") return p.amount

    if (status === "overdue") {
      if (p.payment_type === "recurring" && p.next_payment_due && p.recurrence_period) {
        const dueDate = parseISO(p.next_payment_due)
        if (!isValid(dueDate)) return p.amount

        const today = startOfDay(new Date())
        const daysPastDue = Math.abs(differenceInDays(today, dueDate))

        let periodsOverdue = 1
        if (p.recurrence_period === "monthly") periodsOverdue = Math.floor(daysPastDue / 30) + 1
        else if (p.recurrence_period === "quarterly") periodsOverdue = Math.floor(daysPastDue / 90) + 1
        else if (p.recurrence_period === "yearly") periodsOverdue = Math.floor(daysPastDue / 365) + 1

        return p.amount * periodsOverdue
      }
      return p.amount
    }

    return 0
  }

  const processedPayments = payments.map((p) => ({
    ...p,
    status: getRealStatus(p),
    amountDue: getAmountDue(p),
  }))

  const stats = {
    totalDue: processedPayments
      .filter((p) => {
        if (p.status === "overdue") return true
        if (p.status === "due") {
          const dateStr = p.payment_type === "recurring" ? p.next_payment_due : p.payment_date
          if (!dateStr) return true
          return differenceInDays(parseISO(dateStr), new Date()) <= 7
        }
        return false
      })
      .reduce((sum, p) => sum + p.amount, 0),
    totalPaid: processedPayments.reduce((sum, p) => sum + (p.amount_paid || 0), 0),
    countCompleted: processedPayments.filter((p) => p.status === "paid" || (p.amount_paid && p.amount_paid > 0)).length,
    countOverdue: processedPayments.filter((p) => p.status === "overdue").length,
    countDue: processedPayments.filter((p) => p.status === "due").length,
  }

  const filteredPayments = processedPayments.filter((payment) => {
    const matchesSearch =
      payment.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (payment.department?.name || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
      (payment.issuer_name || "").toLowerCase().includes(searchQuery.toLowerCase())

    const matchesDepartment = departmentFilter === "all" || payment.department_id === departmentFilter
    const matchesType = categoryFilter === "all" || payment.payment_type === categoryFilter
    const matchesStatus = statusFilter === "all" || payment.status === statusFilter

    return matchesSearch && matchesDepartment && matchesType && matchesStatus
  })

  const handleSort = (key: string) => {
    let direction: "asc" | "desc" = "asc"
    if (sortConfig && sortConfig.key === key && sortConfig.direction === "asc") {
      direction = "desc"
    }
    setSortConfig({ key, direction })
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const sortedPayments = [...filteredPayments].sort((a, b) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let valA: any = a
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let valB: any = b

    if (sortConfig.key === "category") {
      valA = a.payment_type
      valB = b.payment_type

      if (valA !== valB) {
        return sortConfig.direction === "asc" ? valA.localeCompare(valB) : valB.localeCompare(valA)
      }

      const dateStrA = a.payment_type === "recurring" ? a.next_payment_due : a.payment_date
      const dateStrB = b.payment_type === "recurring" ? b.next_payment_due : b.payment_date

      if (!dateStrA && !dateStrB) return 0
      if (!dateStrA) return 1
      if (!dateStrB) return -1

      return new Date(dateStrA).getTime() - new Date(dateStrB).getTime()
    } else if (sortConfig.key === "date") {
      const dateStrA = a.payment_type === "recurring" ? a.next_payment_due : a.payment_date
      const dateStrB = b.payment_type === "recurring" ? b.next_payment_due : b.payment_date

      if (!dateStrA && !dateStrB) return 0
      if (!dateStrA) return 1
      if (!dateStrB) return -1

      valA = new Date(dateStrA).getTime()
      valB = new Date(dateStrB).getTime()
    } else {
      const statusPriority: Record<string, number> = { overdue: 0, due: 1, paid: 2, cancelled: 3 }
      const statusDiff = statusPriority[a.status] - statusPriority[b.status]
      if (statusDiff !== 0) return statusDiff

      const dateStrA = a.payment_type === "recurring" ? a.next_payment_due : a.payment_date
      const dateStrB = b.payment_type === "recurring" ? b.next_payment_due : b.payment_date

      if (!dateStrA && !dateStrB) return 0
      if (!dateStrA) return 1
      if (!dateStrB) return -1

      valA = new Date(dateStrA).getTime()
      valB = new Date(dateStrB).getTime()
    }

    if (valA < valB) return sortConfig.direction === "asc" ? -1 : 1
    if (valA > valB) return sortConfig.direction === "asc" ? 1 : -1
    return 0
  })

  const { handleExportConfirm } = usePaymentExport(sortedPayments, selectedColumns, () => setExportDialogOpen(false))

  const downloadFile = async (url: string, filename: string) => {
    try {
      const response = await fetch(url)
      if (!response.ok) throw new Error("Failed to fetch file")

      const blob = await response.blob()
      const blobUrl = window.URL.createObjectURL(blob)
      const link = document.createElement("a")
      link.href = blobUrl
      link.download = filename
      link.style.display = "none"
      document.body.appendChild(link)
      link.click()

      setTimeout(() => {
        document.body.removeChild(link)
        window.URL.revokeObjectURL(blobUrl)
      }, 100)
    } catch (error) {
      log.error("Error downloading file:", error)
      throw error
    }
  }

  const handlePrintDocument = async (payment: Payment, type: "invoice" | "receipt") => {
    if (type === "receipt") {
      const receipts = payment.documents?.filter((d) => d.document_type === "receipt") || []
      if (receipts.length > 1) {
        setSelectedPaymentForReceipt(payment)
        setReceiptDialogOpen(true)
        return
      } else if (receipts.length === 1) {
        try {
          const supabase = createClient()
          const { data } = await supabase.storage.from("payment_documents").createSignedUrl(receipts[0].file_path, 3600)
          if (data?.signedUrl) {
            const filename =
              receipts[0].file_name || `receipt_${payment.payment_reference || payment.id.substring(0, 8)}.pdf`
            await downloadFile(data.signedUrl, filename)
            toast.success("Receipt downloaded successfully")
          } else {
            toast.error("Could not get document URL")
          }
        } catch (error) {
          toast.error("Error downloading document")
        }
        return
      }
    }

    const doc = payment.documents?.find((d) => d.document_type === type)
    if (doc) {
      try {
        const supabase = createClient()
        const { data } = await supabase.storage.from("payment_documents").createSignedUrl(doc.file_path, 3600)
        if (data?.signedUrl) {
          const filename = doc.file_name || `${type}_${payment.payment_reference || payment.id.substring(0, 8)}.pdf`
          await downloadFile(data.signedUrl, filename)
          toast.success(`${type.charAt(0).toUpperCase() + type.slice(1)} downloaded successfully`)
        } else {
          toast.error("Could not get document URL")
        }
      } catch (error) {
        toast.error("Error downloading document")
      }
    }
  }

  const handleViewReceipt = async (receiptPath: string) => {
    try {
      const supabase = createClient()
      const { data } = await supabase.storage.from("payment_documents").createSignedUrl(receiptPath, 3600)
      if (data?.signedUrl) {
        setReceiptDialogOpen(false)
        const filename = receiptPath.split("/").pop() || "receipt.pdf"
        await new Promise((resolve) => setTimeout(resolve, 100))
        await downloadFile(data.signedUrl, filename)
        toast.success("Receipt downloaded successfully")
      } else {
        toast.error("Could not get document URL")
      }
    } catch (error) {
      toast.error("Error downloading document")
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "paid":
        return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400"
      case "due":
        return "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400"
      case "overdue":
        return "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400"
      case "cancelled":
        return "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400"
      default:
        return ""
    }
  }

  const formatCurrency = (amount: number, currency: string) => {
    return new Intl.NumberFormat("en-NG", { style: "currency", currency }).format(amount)
  }

  const filterableDepartments = currentUser.isAdmin
    ? departments
    : departments.filter((d) => d.id === currentUser.department_id)

  const isAdminPath = basePath.startsWith("/admin")
  const backLinkHref = isAdminPath ? "/admin" : "/profile"
  const backLinkLabel = isAdminPath ? "Back to Admin" : "Back to Dashboard"

  return (
    <AdminTablePage
      title="Payments"
      description="Manage and track department payments and recurring subscriptions."
      icon={CreditCard}
      backLinkHref={backLinkHref}
      backLinkLabel={backLinkLabel}
      actions={
        <div className="flex gap-2">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" className="flex-1 sm:flex-none" size="sm">
                <Download className="mr-2 h-4 w-4" />
                <span className="text-xs sm:text-sm">Export</span>
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent>
              <DropdownMenuLabel>Export Options</DropdownMenuLabel>
              <DropdownMenuSeparator />
              <DropdownMenuItem
                onClick={() => {
                  setExportType("excel")
                  setExportDialogOpen(true)
                }}
              >
                <FileSpreadsheet className="mr-2 h-4 w-4" /> Excel (XLSX)
              </DropdownMenuItem>
              <DropdownMenuItem
                onClick={() => {
                  setExportType("pdf")
                  setExportDialogOpen(true)
                }}
              >
                <FileIcon className="mr-2 h-4 w-4" /> PDF
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>

          <Button onClick={() => setIsModalOpen(true)} className="flex-1 sm:flex-none" size="sm">
            <Plus className="mr-2 h-4 w-4" />
            <span className="text-xs sm:text-sm">New Payment</span>
          </Button>
        </div>
      }
      stats={<PaymentStatsCards stats={stats} formatCurrency={formatCurrency} />}
      filters={
        <div className="flex flex-col gap-3 md:flex-row md:items-center">
          <div className="relative flex-1">
            <Search className="text-muted-foreground absolute top-2.5 left-2.5 h-4 w-4" />
            <Input
              placeholder="Search payments..."
              className="pl-9 text-sm"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            {currentUser.isAdmin && (
              <Select value={departmentFilter} onValueChange={setDepartmentFilter}>
                <SelectTrigger className="flex-1 sm:w-[180px]">
                  <SelectValue placeholder="Department" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Departments</SelectItem>
                  {filterableDepartments.map((dept) => (
                    <SelectItem key={dept.id} value={dept.id}>
                      {dept.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            )}
            <Select value={categoryFilter} onValueChange={setCategoryFilter}>
              <SelectTrigger className="flex-1 sm:w-[180px]">
                <SelectValue placeholder="Category" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Categories</SelectItem>
                <SelectItem value="one-time">One-time</SelectItem>
                <SelectItem value="recurring">Recurring</SelectItem>
              </SelectContent>
            </Select>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="flex-1 sm:w-[150px]">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Status</SelectItem>
                <SelectItem value="paid">Paid</SelectItem>
                <SelectItem value="due">Due</SelectItem>
                <SelectItem value="overdue">Overdue</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>
      }
    >
      {loading ? (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="bg-muted h-40 animate-pulse rounded-lg border" />
          ))}
        </div>
      ) : sortedPayments.length === 0 ? (
        <div className="flex min-h-[400px] flex-col items-center justify-center rounded-lg border border-dashed text-center">
          <CreditCard className="text-muted-foreground mb-4 h-12 w-12" />
          <h3 className="text-lg font-semibold">No payments found</h3>
          <p className="text-muted-foreground mb-4 text-sm">Get started by creating your first payment record.</p>
          <Button onClick={() => setIsModalOpen(true)}>
            <Plus className="mr-2 h-4 w-4" />
            Add Payment
          </Button>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-md border">
          <Table className="[&_td]:py-2 [&_th]:py-2">
            <TableHeader>
              <TableRow>
                <TableHead className="w-[50px]">S/N</TableHead>
                <TableHead className="hover:bg-muted/50 cursor-pointer" onClick={() => handleSort("category")}>
                  <div className="flex items-center gap-1">
                    Category
                    <ArrowUpDown className="h-4 w-4" />
                  </div>
                </TableHead>
                <TableHead>Title</TableHead>
                <TableHead>Issuer</TableHead>
                <TableHead>Department</TableHead>
                <TableHead>Amount</TableHead>
                <TableHead>Amount Due</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="hover:bg-muted/50 cursor-pointer" onClick={() => handleSort("date")}>
                  <div className="flex items-center gap-1">
                    Date / Next Due
                    <ArrowUpDown className="h-4 w-4" />
                  </div>
                </TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {sortedPayments.map((payment, index) => (
                <TableRow
                  key={payment.id}
                  className="hover:bg-muted/50 cursor-pointer"
                  onClick={() => router.push(`${basePath}/${payment.id}`)}
                >
                  <TableCell className="text-muted-foreground font-medium">{index + 1}</TableCell>
                  <TableCell>
                    <Badge
                      variant="outline"
                      className={
                        payment.payment_type === "recurring"
                          ? "border-blue-300 bg-blue-50 text-blue-700 dark:border-blue-700 dark:bg-blue-900/20 dark:text-blue-400"
                          : "border-green-300 bg-green-50 text-green-700 dark:border-green-700 dark:bg-green-900/20 dark:text-green-400"
                      }
                    >
                      {payment.payment_type === "recurring" ? "Recurring" : "One-time"}
                    </Badge>
                  </TableCell>
                  <TableCell className="font-medium">{payment.title}</TableCell>
                  <TableCell>
                    <div className="flex flex-col">
                      <span className="text-sm font-medium">{payment.issuer_name || "N/A"}</span>
                      <span className="text-muted-foreground text-xs">{payment.issuer_phone_number || ""}</span>
                    </div>
                  </TableCell>
                  <TableCell>{payment.department?.name || "Unknown"}</TableCell>
                  <TableCell>{formatCurrency(payment.amount, payment.currency)}</TableCell>
                  <TableCell>
                    <span
                      className={
                        payment.status === "overdue"
                          ? "font-semibold text-red-600"
                          : payment.status === "due"
                            ? "font-semibold text-yellow-600"
                            : "text-muted-foreground"
                      }
                    >
                      {formatCurrency(payment.amountDue, payment.currency)}
                    </span>
                  </TableCell>
                  <TableCell>
                    <Badge className={getStatusColor(payment.status)} variant="outline">
                      {payment.status}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    {payment.payment_type === "recurring" ? (
                      <span className={payment.status === "overdue" ? "font-medium text-red-500" : ""}>
                        {payment.next_payment_due ? format(parseISO(payment.next_payment_due), "MMM d, yyyy") : "N/A"}
                      </span>
                    ) : (
                      <span>
                        {payment.payment_date ? format(parseISO(payment.payment_date), "MMM d, yyyy") : "N/A"}
                      </span>
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex items-center justify-end gap-1">
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button
                            variant="ghost"
                            size="icon"
                            aria-label="Print payment"
                            onClick={(e) => e.stopPropagation()}
                          >
                            <Printer className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent onClick={(e) => e.stopPropagation()}>
                          <DropdownMenuLabel>Print Options</DropdownMenuLabel>
                          <DropdownMenuSeparator />
                          <DropdownMenuItem
                            disabled={!payment.documents?.some((d) => d.document_type === "invoice")}
                            onClick={() => handlePrintDocument(payment, "invoice")}
                          >
                            Print Invoice
                          </DropdownMenuItem>
                          <DropdownMenuItem
                            disabled={!payment.documents?.some((d) => d.document_type === "receipt")}
                            onClick={() => handlePrintDocument(payment, "receipt")}
                          >
                            Print Receipt
                          </DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                      <Button
                        variant="ghost"
                        size="icon"
                        aria-label="View payment details"
                        onClick={(e) => {
                          e.stopPropagation()
                          router.push(`${basePath}/${payment.id}`)
                        }}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}

      <CreatePaymentDialog
        open={isModalOpen}
        onOpenChange={setIsModalOpen}
        formData={formData}
        onFormDataChange={setFormData}
        onSubmit={handleSubmit}
        submitting={submitting}
        receiptFile={receiptFile}
        onReceiptFileChange={setReceiptFile}
        departments={departments}
        filterableDepartments={filterableDepartments}
        isAdmin={currentUser.isAdmin}
      />

      <ReceiptSelectionDialog
        open={receiptDialogOpen}
        onOpenChange={setReceiptDialogOpen}
        payment={selectedPaymentForReceipt}
        onSelectReceipt={handleViewReceipt}
      />

      <ExportColumnsDialog
        open={exportDialogOpen}
        onOpenChange={setExportDialogOpen}
        exportType={exportType}
        selectedColumns={selectedColumns}
        onColumnChange={setSelectedColumns}
        onConfirm={() => exportType && handleExportConfirm(exportType)}
      />
    </AdminTablePage>
  )
}

"use client"

import { useState, useEffect } from "react"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { createClient } from "@/lib/supabase/client"
import { toast } from "sonner"
import { Loader2, Sparkles } from "lucide-react"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"
import { fetchWeeklyReportLockState, type WeeklyReportLockState } from "@/lib/weekly-report-lock"
import { sanitizeReportText } from "@/lib/export-utils"
import { logger } from "@/lib/logger"

const log = logger("portal-weekly-report-dialog")

interface WeeklyReport {
  id: string
  department: string
  week_number: number
  year: number
  work_done: string
  tasks_new_week: string
  challenges: string
  status: string
  user_id: string
}

interface WeeklyReportDialogProps {
  isOpen: boolean
  onClose: () => void
  onSuccess: () => void
  initialData?: {
    week?: number
    year?: number
    dept?: string
  }
}

const REPORT_TEXT_FIELDS = ["work_done", "tasks_new_week", "challenges"] as const
type ReportTextField = (typeof REPORT_TEXT_FIELDS)[number]

const autoNumberReportText = (text: string): string => {
  const lines = sanitizeReportText(String(text || ""))
    .replace(/\r\n/g, "\n")
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line.length > 0)
    .map((line) => line.replace(/^\s*(?:\d+[.)]\s+|[-*]\s+)/, "").trim())
    .filter((line) => line.length > 0)

  if (lines.length === 0) return ""
  return lines.map((line, index) => `${index + 1}. ${line}`).join("\n")
}

export function WeeklyReportDialog({ isOpen, onClose, onSuccess, initialData }: WeeklyReportDialogProps) {
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)
  const [profile, setProfile] = useState<any>(null)
  const [isNextWeekActive, setIsNextWeekActive] = useState(false)
  const [lockState, setLockState] = useState<WeeklyReportLockState | null>(null)

  const [id, setId] = useState<string | null>(null)
  const currentOfficeWeek = getCurrentOfficeWeek()
  const [formData, setFormData] = useState({
    user_id: "",
    department: "",
    week_number: currentOfficeWeek.week,
    year: currentOfficeWeek.year,
    work_done: "",
    tasks_new_week: "",
    challenges: "",
    status: "submitted",
  })

  const supabase = createClient()

  useEffect(() => {
    if (isOpen) {
      setupDialog()
    }
  }, [isOpen, initialData])

  useEffect(() => {
    const fetchLockState = async () => {
      const state = await fetchWeeklyReportLockState(supabase, formData.week_number, formData.year)
      setLockState(state)
    }
    fetchLockState()
  }, [formData.week_number, formData.year])

  async function setupDialog() {
    setLoading(true)
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) return
      const { data: p } = await supabase.from("profiles").select("*").eq("id", user.id).single()
      setProfile(p)

      const week = initialData?.week || currentOfficeWeek.week
      const year = initialData?.year || currentOfficeWeek.year
      const dept = initialData?.dept || p?.department || ""

      // Fetch existing report
      const { data: existing } = await supabase
        .from("weekly_reports")
        .select("*")
        .eq("week_number", week)
        .eq("year", year)
        .eq("department", dept)
        .maybeSingle()

      setId(existing?.id || null)
      setFormData({
        user_id: user.id || "",
        department: dept,
        week_number: week,
        year: year,
        work_done: autoNumberReportText(existing?.work_done || ""),
        tasks_new_week: autoNumberReportText(existing?.tasks_new_week || ""),
        challenges: autoNumberReportText(existing?.challenges || ""),
        status: "submitted",
      })

      // Meta checks
      const { data: nextActions } = await supabase
        .from("tasks")
        .select("*")
        .eq("category", "weekly_action")
        .eq("department", dept)
        .eq("week_number", week)
        .eq("year", year)
      if (nextActions) {
        setIsNextWeekActive(nextActions.some((a) => a.status !== "pending"))
        if (nextActions.length > 0 && !existing) {
          const syncedText = nextActions.map((a, i) => `${i + 1}. ${a.title}`).join("\n")
          setFormData((prev) => ({ ...prev, tasks_new_week: autoNumberReportText(syncedText) }))
        }
      }
    } catch (error) {
      log.error("Failed to load actions:", error)
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = async () => {
    const state = await fetchWeeklyReportLockState(supabase, formData.week_number, formData.year)
    setLockState(state)
    if (state.isLocked) {
      toast.error("This report week is locked. Contact admin for a temporary unlock.")
      return
    }

    if (!formData.work_done.trim()) {
      toast.error("Please describe work done")
      return
    }
    setSaving(true)
    try {
      const { data: savedReport, error: reportError } = await supabase
        .from("weekly_reports")
        .upsert(formData, { onConflict: "department,week_number,year" })
        .select("id")
        .single()
      if (reportError) throw reportError
      void savedReport
      toast.success("Success")
      onSuccess()
      onClose()
    } catch (error: any) {
      toast.error(error.message)
    } finally {
      setSaving(false)
    }
  }

  const handleKey = (e: React.KeyboardEvent, field: ReportTextField) => {
    if (e.key === "Enter") {
      const val = formData[field] as string
      const last = val.split("\n").pop() || ""
      const match = last.match(/^(\d+)[\.\)]\s/)
      if (match) {
        e.preventDefault()
        setFormData((p) => ({ ...p, [field]: val + "\n" + (parseInt(match[1]) + 1) + ". " }))
      }
    }
  }

  const handleTextChange = (field: ReportTextField, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: autoNumberReportText(value) }))
  }

  const handleTextPaste = (e: React.ClipboardEvent<HTMLTextAreaElement>, field: ReportTextField) => {
    e.preventDefault()
    const pasted = e.clipboardData.getData("text")
    const current = (formData[field] as string) || ""
    const start = e.currentTarget.selectionStart ?? current.length
    const end = e.currentTarget.selectionEnd ?? current.length
    const merged = `${current.slice(0, start)}${pasted}${current.slice(end)}`
    setFormData((prev) => ({ ...prev, [field]: autoNumberReportText(merged) }))
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-h-[90vh] max-w-4xl overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            {id ? "Edit Weekly Report" : "Submit Weekly Report"}
            <Sparkles className="text-primary h-4 w-4" />
          </DialogTitle>
          <DialogDescription>
            Progress update for <span className="text-primary font-semibold">{formData.department}</span> — Week{" "}
            {formData.week_number}, {formData.year}
          </DialogDescription>
          {lockState?.isLocked && (
            <p className="text-destructive text-xs">
              Locked after meeting date {lockState.meetingDate}. Editing is now closed for this week.
            </p>
          )}
        </DialogHeader>

        {loading ? (
          <div className="flex h-[300px] items-center justify-center">
            <Loader2 className="h-8 w-8 animate-spin" />
          </div>
        ) : (
          <div className="grid gap-6 py-4">
            {REPORT_TEXT_FIELDS.map((f) => (
              <div key={f} className="space-y-2">
                <Label className="capitalize">{f.replace(/_/g, " ")}</Label>
                <Textarea
                  value={formData[f]}
                  onChange={(e) => handleTextChange(f, e.target.value)}
                  onPaste={(e) => handleTextPaste(e, f)}
                  onKeyDown={(e) => handleKey(e, f)}
                  placeholder={`1. ...`}
                  rows={4}
                  disabled={f === "tasks_new_week" && isNextWeekActive}
                />
                {f === "tasks_new_week" && isNextWeekActive && (
                  <p className="text-muted-foreground text-[10px] italic">
                    Locked: Next week's tracker is already active.
                  </p>
                )}
              </div>
            ))}
          </div>
        )}

        <div className="flex justify-end gap-3 border-t pt-4">
          <Button variant="outline" onClick={onClose} disabled={saving}>
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={saving || loading || !!lockState?.isLocked}>
            {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {id ? "Update Report" : "Submit Report"}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import Link from "next/link"
import { useMemo, useState } from "react"
import { useQuery } from "@tanstack/react-query"
import { toast } from "sonner"
import { TablePage } from "@/components/admin/admin-table-page"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { SearchableMultiSelect } from "@/components/ui/searchable-multi-select"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { TableSkeleton } from "@/components/ui/query-states"
import { createClient } from "@/lib/supabase/client"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"
import { REPORT_DOC_MAX_SIZE_BYTES, formatLimitMb } from "@/lib/reports/document-upload-limits"
import { buildMeetingDocumentFileName } from "@/lib/reports/meeting-date"
import { Download, Loader2, Pencil, Plus, Presentation, Search, Trash2 } from "lucide-react"

type Employee = {
  id: string
  full_name: string
  department: string | null
}

type KssRosterEntry = {
  id: string
  meeting_week: number
  meeting_year: number
  department: string
  presenter_id: string | null
  created_by: string | null
  notes: string | null
  created_at: string
  meeting_date?: string | null
  is_locked?: boolean
}

type KssDocument = {
  id: string
  meeting_week: number
  meeting_year: number
  meeting_date?: string | null
  document_type: "knowledge_sharing_session"
  department: string | null
  presenter_id: string | null
  file_name: string
  mime_type?: string | null
  signed_url: string | null
  is_locked?: boolean
}

const DOCX_MIME = "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
const PPTX_MIME = "application/vnd.openxmlformats-officedocument.presentationml.presentation"
type UploadPhase = "idle" | "saving" | "converting" | "uploading"

interface Props {
  employees: Employee[]
  backHref: string
  backLabel: string
  title?: string
  readOnly?: boolean
}

function compareWeekYear(aWeek: number, aYear: number, bWeek: number, bYear: number): number {
  if (aYear !== bYear) return aYear - bYear
  return aWeek - bWeek
}

function getFileExtension(fileName: string, mimeType?: string | null): string {
  const lower = (fileName || "").toLowerCase()
  if (lower.endsWith(".pdf")) return "pdf"
  if (lower.endsWith(".pptx")) return "pptx"
  if (lower.endsWith(".ppt")) return "ppt"
  if (mimeType === "application/pdf") return "pdf"
  if (mimeType === "application/vnd.ms-powerpoint") return "ppt"
  if (mimeType === "application/vnd.openxmlformats-officedocument.presentationml.presentation") return "pptx"
  return "pdf"
}

function formatMeetingDate(value?: string | null): string {
  if (!value) return "-"
  const date = new Date(`${value}T00:00:00`)
  if (Number.isNaN(date.getTime())) return "-"
  return date.toLocaleDateString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  })
}

export function KssRosterTable({
  employees,
  backHref,
  backLabel,
  title = "Knowledge Sharing Session",
  readOnly = false,
}: Props) {
  const supabase = createClient()
  const currentOfficeWeek = getCurrentOfficeWeek()
  const defaultWeek = currentOfficeWeek.week
  const defaultYear = currentOfficeWeek.year

  const [showCreate, setShowCreate] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [pendingDeleteRow, setPendingDeleteRow] = useState<KssRosterEntry | null>(null)
  const [downloadingId, setDownloadingId] = useState<string | null>(null)

  const [weekNumber, setWeekNumber] = useState(defaultWeek)
  const [yearNumber, setYearNumber] = useState(defaultYear)
  const [department, setDepartment] = useState("none")
  const [presenterId, setPresenterId] = useState("none")
  const [notes, setNotes] = useState("")
  const [file, setFile] = useState<File | null>(null)
  const [saving, setSaving] = useState(false)
  const [uploadPhase, setUploadPhase] = useState<UploadPhase>("idle")

  const [searchQuery, setSearchQuery] = useState("")
  const [departmentFilter, setDepartmentFilter] = useState("all")
  const [weekFilter, setWeekFilter] = useState("all")
  const [yearFilter, setYearFilter] = useState("all")
  const [timeTypeFilter, setTimeTypeFilter] = useState<string[]>(["current", "past"])

  const weekOptions = Array.from({ length: 53 }, (_, i) => i + 1)
  const yearOptions = [
    currentOfficeWeek.year - 1,
    currentOfficeWeek.year,
    currentOfficeWeek.year + 1,
    currentOfficeWeek.year + 2,
  ]

  const departments = useMemo(() => {
    return Array.from(new Set(employees.map((e) => e.department).filter(Boolean) as string[])).sort((a, b) =>
      a.localeCompare(b)
    )
  }, [employees])

  const presenterOptions = useMemo(() => {
    if (department === "none") return []
    return employees.filter((e) => e.department === department).sort((a, b) => a.full_name.localeCompare(b.full_name))
  }, [department, employees])

  const employeeNameById = useMemo(() => {
    return new Map(employees.map((e) => [e.id, e.full_name]))
  }, [employees])

  const {
    data: roster = [],
    refetch: refetchRoster,
    isLoading: isRosterLoading,
  } = useQuery({
    queryKey: ["kss-roster-table"],
    queryFn: async (): Promise<KssRosterEntry[]> => {
      const res = await fetch("/api/reports/kss-roster")
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to fetch KSS roster")
      return payload.data || []
    },
  })

  const {
    data: docs = [],
    refetch: refetchDocs,
    isLoading: isDocsLoading,
  } = useQuery({
    queryKey: ["kss-documents-table"],
    queryFn: async (): Promise<KssDocument[]> => {
      const res = await fetch(
        "/api/reports/meeting-week-documents?documentType=knowledge_sharing_session&currentOnly=true"
      )
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to fetch KSS documents")
      return payload.data || []
    },
  })

  const { data: selectedWeekLockState } = useQuery({
    queryKey: ["kss-selected-week-lock", weekNumber, yearNumber],
    enabled: !readOnly,
    queryFn: async () => {
      const { data, error } = await supabase.rpc("weekly_report_lock_state", {
        p_week: weekNumber,
        p_year: yearNumber,
      })
      if (error) throw new Error(error.message)
      return Array.isArray(data) && data[0] ? Boolean(data[0].is_locked) : false
    },
  })

  const isSelectedWeekLocked = Boolean(selectedWeekLockState)

  const docByWeekYear = useMemo(() => {
    const map = new Map<string, KssDocument>()
    docs.forEach((d) => map.set(`${d.meeting_year}-${d.meeting_week}`, d))
    return map
  }, [docs])

  const rows = useMemo(() => {
    const q = searchQuery.trim().toLowerCase()

    return roster
      .filter((row) => {
        const compare = compareWeekYear(
          row.meeting_week,
          row.meeting_year,
          currentOfficeWeek.week,
          currentOfficeWeek.year
        )
        const isCurrent = compare === 0
        const isPast = compare < 0
        const isUpcoming = compare > 0
        const includeByTime =
          (isCurrent && timeTypeFilter.includes("current")) ||
          (isPast && timeTypeFilter.includes("past")) ||
          (isUpcoming && timeTypeFilter.includes("upcoming"))
        if (!includeByTime) return false

        if (departmentFilter !== "all" && row.department !== departmentFilter) return false
        if (weekFilter !== "all" && row.meeting_week !== Number(weekFilter)) return false
        if (yearFilter !== "all" && row.meeting_year !== Number(yearFilter)) return false

        if (!q) return true
        const presenterName = row.presenter_id ? (employeeNameById.get(row.presenter_id) || "").toLowerCase() : ""
        return (
          row.department.toLowerCase().includes(q) ||
          presenterName.includes(q) ||
          String(row.meeting_week).includes(q) ||
          String(row.meeting_year).includes(q)
        )
      })
      .sort((a, b) => compareWeekYear(b.meeting_week, b.meeting_year, a.meeting_week, a.meeting_year))
  }, [
    roster,
    timeTypeFilter,
    currentOfficeWeek.week,
    currentOfficeWeek.year,
    departmentFilter,
    weekFilter,
    yearFilter,
    searchQuery,
    employeeNameById,
  ])

  const resetForm = () => {
    setWeekNumber(defaultWeek)
    setYearNumber(defaultYear)
    setDepartment("none")
    setPresenterId("none")
    setNotes("")
    setFile(null)
    setEditingId(null)
    setUploadPhase("idle")
  }

  const openEdit = (row: KssRosterEntry) => {
    const isPastRow =
      compareWeekYear(row.meeting_week, row.meeting_year, currentOfficeWeek.week, currentOfficeWeek.year) < 0
    if (row.is_locked || isPastRow) {
      toast.error(`Week ${row.meeting_week}, ${row.meeting_year} is locked and can no longer be edited`)
      return
    }
    setShowCreate(true)
    setEditingId(row.id)
    setWeekNumber(row.meeting_week)
    setYearNumber(row.meeting_year)
    setDepartment(row.department)
    setPresenterId(row.presenter_id || "none")
    setNotes(row.notes || "")
    setFile(null)
  }

  const handleSave = async () => {
    if (readOnly) {
      toast.error("You can only add or edit from Admin Reports.")
      return
    }
    if (isSelectedWeekLocked) {
      toast.error(`Week ${weekNumber}, ${yearNumber} is locked and can no longer be changed`)
      return
    }
    if (file && file.size > REPORT_DOC_MAX_SIZE_BYTES) {
      toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
      return
    }
    if (department === "none") {
      toast.error("Please select department")
      return
    }
    if (presenterId === "none") {
      toast.error("Please select presenter")
      return
    }

    setSaving(true)
    setUploadPhase("saving")
    try {
      const rosterRes = await fetch("/api/reports/kss-roster", {
        method: editingId ? "PATCH" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(
          editingId
            ? {
                id: editingId,
                department,
                presenterId,
                notes: notes || null,
              }
            : {
                meetingWeek: weekNumber,
                meetingYear: yearNumber,
                department,
                presenterId,
                notes: notes || null,
              }
        ),
      })
      const rosterPayload = await rosterRes.json()
      if (!rosterRes.ok) throw new Error(rosterPayload.error || "Failed to save roster")

      if (file) {
        const requiresConversion = [DOCX_MIME, PPTX_MIME].includes(file.type)
        const fd = new FormData()
        fd.append("file", file)
        fd.append("meetingWeek", String(editingId ? rosterPayload.data.meeting_week : weekNumber))
        fd.append("meetingYear", String(editingId ? rosterPayload.data.meeting_year : yearNumber))
        fd.append("documentType", "knowledge_sharing_session")
        fd.append("department", department)
        fd.append("presenterId", presenterId)
        if (notes.trim()) fd.append("notes", notes.trim())

        if (requiresConversion) {
          setUploadPhase("converting")
        } else {
          setUploadPhase("uploading")
        }

        let phaseTimer: ReturnType<typeof setTimeout> | null = null
        if (requiresConversion) {
          phaseTimer = setTimeout(() => {
            setUploadPhase("uploading")
          }, 1200)
        }

        const uploadRes = await fetch("/api/reports/meeting-week-documents", {
          method: "POST",
          body: fd,
        })
        if (phaseTimer) clearTimeout(phaseTimer)
        setUploadPhase("uploading")
        const uploadPayload = await uploadRes.json()
        if (!uploadRes.ok) throw new Error(uploadPayload.error || "Failed to upload KSS file")
        if (uploadPayload?.converted) {
          toast.success("KSS file uploaded and converted to PDF")
        }
      }

      if (!file || !["docx", "pptx"].includes(getFileExtension(file.name, file.type))) {
        toast.success(editingId ? "KSS updated" : "KSS created")
      }
      resetForm()
      setShowCreate(false)
      await Promise.all([refetchRoster(), refetchDocs()])
    } catch (error: any) {
      toast.error(error?.message || "Failed to save KSS")
    } finally {
      setSaving(false)
      setUploadPhase("idle")
    }
  }

  const handleDelete = async (row: KssRosterEntry) => {
    if (readOnly) {
      toast.error("You can only delete from Admin Reports.")
      return
    }
    const isPastRow =
      compareWeekYear(row.meeting_week, row.meeting_year, currentOfficeWeek.week, currentOfficeWeek.year) < 0
    if (row.is_locked || isPastRow) {
      toast.error(`Week ${row.meeting_week}, ${row.meeting_year} is locked and can no longer be changed`)
      return
    }
    try {
      const doc = docByWeekYear.get(`${row.meeting_year}-${row.meeting_week}`)
      if (doc) {
        const docRes = await fetch(`/api/reports/meeting-week-documents?id=${doc.id}`, { method: "DELETE" })
        const docPayload = await docRes.json()
        if (!docRes.ok) throw new Error(docPayload.error || "Failed to delete KSS file")
      }

      const res = await fetch(`/api/reports/kss-roster?id=${row.id}`, { method: "DELETE" })
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to delete KSS roster")
      toast.success("KSS deleted")
      setPendingDeleteRow(null)
      await Promise.all([refetchRoster(), refetchDocs()])
    } catch (error: any) {
      toast.error(error?.message || "Delete failed")
    }
  }

  const buildDownloadName = (doc: KssDocument, row: KssRosterEntry, presenterName: string): string => {
    const ext = getFileExtension(doc.file_name, doc.mime_type)
    return buildMeetingDocumentFileName({
      documentType: "knowledge_sharing_session",
      meetingDate: doc.meeting_date || `${row.meeting_year}-01-01`,
      meetingWeek: row.meeting_week,
      extension: ext,
      department: row.department,
      presenterName: presenterName === "-" ? "Unknown Presenter" : presenterName,
    })
  }

  const handleDownload = async (doc: KssDocument, row: KssRosterEntry, presenterName: string) => {
    if (!doc.signed_url) return
    setDownloadingId(doc.id)
    try {
      const response = await fetch(doc.signed_url)
      if (!response.ok) throw new Error("Failed to download document")
      const blob = await response.blob()
      const objectUrl = URL.createObjectURL(blob)
      const anchor = document.createElement("a")
      anchor.href = objectUrl
      anchor.download = buildDownloadName(doc, row, presenterName)
      document.body.appendChild(anchor)
      anchor.click()
      anchor.remove()
      URL.revokeObjectURL(objectUrl)
    } catch (error: any) {
      toast.error(error?.message || "Failed to download file")
    } finally {
      setDownloadingId((current) => (current === doc.id ? null : current))
    }
  }

  const saveLabel =
    uploadPhase === "converting"
      ? "Converting..."
      : uploadPhase === "uploading"
        ? "Uploading..."
        : uploadPhase === "saving"
          ? "Saving..."
          : editingId
            ? "Save Changes"
            : "Add KSS"

  return (
    <TablePage
      title={title}
      description="Manage KSS roster and uploaded files by week."
      icon={Presentation}
      backLinkHref={backHref}
      backLinkLabel={backLabel}
      actions={
        readOnly ? null : (
          <Button
            onClick={() => {
              setEditingId(null)
              resetForm()
              setShowCreate(true)
            }}
            disabled={false}
          >
            <Plus className="mr-2 h-4 w-4" /> Add KSS
          </Button>
        )
      }
      filters={
        <div className="space-y-4">
          <div className="relative w-full">
            <Search className="text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2" />
            <Input
              placeholder="Search by department, presenter, week, or year..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10"
            />
          </div>

          <div className="grid grid-cols-2 gap-3 md:grid-cols-4 lg:grid-cols-5">
            <div className="space-y-2">
              <Label>Department</Label>
              <Select value={departmentFilter} onValueChange={setDepartmentFilter}>
                <SelectTrigger>
                  <SelectValue placeholder="All departments" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All departments</SelectItem>
                  {departments.map((dept) => (
                    <SelectItem key={dept} value={dept}>
                      {dept}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Week</Label>
              <Select value={weekFilter} onValueChange={setWeekFilter}>
                <SelectTrigger>
                  <SelectValue placeholder="All weeks" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All weeks</SelectItem>
                  {weekOptions.map((w) => (
                    <SelectItem key={w} value={String(w)}>
                      Week {w}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Year</Label>
              <Select value={yearFilter} onValueChange={setYearFilter}>
                <SelectTrigger>
                  <SelectValue placeholder="All years" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All years</SelectItem>
                  {yearOptions.map((y) => (
                    <SelectItem key={y} value={String(y)}>
                      {y}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="col-span-2 space-y-2 md:col-span-1 lg:col-span-2">
              <Label>Time Type</Label>
              <SearchableMultiSelect
                label="Time Type"
                values={timeTypeFilter}
                options={[
                  { value: "current", label: "Current" },
                  { value: "past", label: "Past" },
                  { value: "upcoming", label: "Upcoming" },
                ]}
                onChange={setTimeTypeFilter}
                placeholder="Time Type"
                searchPlaceholder="Search time type..."
              />
            </div>
          </div>
        </div>
      }
    >
      <div className="space-y-4">
        <AlertDialog open={pendingDeleteRow !== null} onOpenChange={(open) => !open && setPendingDeleteRow(null)}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Delete KSS entry?</AlertDialogTitle>
              <AlertDialogDescription>
                {pendingDeleteRow
                  ? `This will delete the KSS entry for Week ${pendingDeleteRow.meeting_week}, ${pendingDeleteRow.meeting_year} and its linked document (if uploaded). This action cannot be undone.`
                  : "This action cannot be undone."}
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={() => {
                  if (pendingDeleteRow) handleDelete(pendingDeleteRow)
                }}
              >
                Delete
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        <Dialog
          open={showCreate}
          onOpenChange={(open) => {
            setShowCreate(open)
            if (!open) resetForm()
          }}
        >
          <DialogContent className="max-h-[90vh] w-[95vw] max-w-xl overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{editingId ? "Edit KSS" : "Add KSS"}</DialogTitle>
              <DialogDescription>
                Create upcoming KSS rows to auto-populate meeting reminder mail. Upload file now or later.
              </DialogDescription>
            </DialogHeader>

            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label>Week</Label>
                <Select
                  value={String(weekNumber)}
                  onValueChange={(v) => setWeekNumber(Number(v))}
                  disabled={Boolean(editingId) || isSelectedWeekLocked}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {weekOptions.map((w) => (
                      <SelectItem key={w} value={String(w)}>
                        Week {w}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Year</Label>
                <Select
                  value={String(yearNumber)}
                  onValueChange={(v) => setYearNumber(Number(v))}
                  disabled={Boolean(editingId) || isSelectedWeekLocked}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {yearOptions.map((y) => (
                      <SelectItem key={y} value={String(y)}>
                        {y}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Department</Label>
                <Select value={department} onValueChange={setDepartment} disabled={isSelectedWeekLocked}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select department" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Select department</SelectItem>
                    {departments.map((dept) => (
                      <SelectItem key={dept} value={dept}>
                        {dept}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Presenter</Label>
                <Select
                  value={presenterId}
                  onValueChange={setPresenterId}
                  disabled={isSelectedWeekLocked || department === "none"}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select presenter" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Select presenter</SelectItem>
                    {presenterOptions.map((emp) => (
                      <SelectItem key={emp.id} value={emp.id}>
                        {emp.full_name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Notes</Label>
                <Input
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Optional"
                  disabled={isSelectedWeekLocked}
                />
              </div>

              <div className="space-y-2">
                <Label>Upload PDF, PPTX, or DOCX</Label>
                <Input
                  type="file"
                  accept=".pdf,.pptx,.docx,application/pdf,application/vnd.openxmlformats-officedocument.presentationml.presentation,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  onChange={(e) => {
                    const selected = e.target.files?.[0] || null
                    if (selected && selected.size > REPORT_DOC_MAX_SIZE_BYTES) {
                      toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
                      e.currentTarget.value = ""
                      setFile(null)
                      return
                    }
                    if (selected?.type === PPTX_MIME || selected?.type === DOCX_MIME) {
                      toast.info("This file will be converted to PDF before it is stored.")
                    }
                    setFile(selected)
                  }}
                  disabled={isSelectedWeekLocked}
                />
                <p className="text-muted-foreground text-xs">
                  Accepted: PDF, PPTX, DOCX. PPTX and DOCX uploads are converted to PDF before storage. Max file size:{" "}
                  {formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}
                </p>
                {isSelectedWeekLocked ? (
                  <p className="text-muted-foreground text-xs">
                    This week is locked after the meeting grace window, so past KSS records are read-only.
                  </p>
                ) : null}
              </div>
            </div>

            <div className="mt-4 flex gap-2">
              <Button onClick={handleSave} disabled={saving || isSelectedWeekLocked}>
                {saving ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    {saveLabel}
                  </>
                ) : (
                  saveLabel
                )}
              </Button>
              <Button
                variant="outline"
                onClick={() => {
                  resetForm()
                  setShowCreate(false)
                }}
                disabled={saving}
              >
                Cancel
              </Button>
              {readOnly ? (
                <Button variant="secondary" asChild>
                  <Link href="/admin/reports/kss">Open Admin KSS</Link>
                </Button>
              ) : null}
            </div>
          </DialogContent>
        </Dialog>

        <Card>
          <CardContent className="pt-6">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>S/N</TableHead>
                  <TableHead>Department</TableHead>
                  <TableHead>Presenter</TableHead>
                  <TableHead>Meeting Date</TableHead>
                  <TableHead>Week</TableHead>
                  <TableHead>Submitted By</TableHead>
                  <TableHead>Submitted Date</TableHead>
                  <TableHead>Action</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isRosterLoading || isDocsLoading ? (
                  <TableRow>
                    <TableCell colSpan={8} className="p-4">
                      <TableSkeleton rows={4} cols={8} />
                    </TableCell>
                  </TableRow>
                ) : (
                  rows.map((row, index) => {
                    const doc = docByWeekYear.get(`${row.meeting_year}-${row.meeting_week}`)
                    const presenterName = row.presenter_id ? employeeNameById.get(row.presenter_id) || "Unknown" : "-"
                    const isPastRow =
                      compareWeekYear(
                        row.meeting_week,
                        row.meeting_year,
                        currentOfficeWeek.week,
                        currentOfficeWeek.year
                      ) < 0
                    const isActionLocked = isPastRow || Boolean(row.is_locked)
                    const submittedBy = row.created_by ? employeeNameById.get(row.created_by) || "Unknown" : "-"
                    const submittedDate = row.created_at
                      ? new Date(row.created_at).toLocaleString("en-GB", {
                          day: "2-digit",
                          month: "short",
                          year: "numeric",
                          hour: "2-digit",
                          minute: "2-digit",
                        })
                      : "-"

                    return (
                      <TableRow key={row.id}>
                        <TableCell>{index + 1}</TableCell>
                        <TableCell>{row.department}</TableCell>
                        <TableCell>{presenterName}</TableCell>
                        <TableCell>{formatMeetingDate(row.meeting_date || doc?.meeting_date)}</TableCell>
                        <TableCell className="font-medium">{`W${row.meeting_week}`}</TableCell>
                        <TableCell>{submittedBy}</TableCell>
                        <TableCell>{submittedDate}</TableCell>
                        <TableCell>
                          <div className="flex items-center gap-1">
                            {!readOnly && !isActionLocked ? (
                              <Button variant="ghost" size="icon" onClick={() => openEdit(row)} title="Edit">
                                <Pencil className="h-4 w-4" />
                              </Button>
                            ) : null}
                            {!readOnly && !isActionLocked ? (
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setPendingDeleteRow(row)}
                                title="Delete"
                              >
                                <Trash2 className="h-4 w-4 text-red-600" />
                              </Button>
                            ) : null}
                            {doc?.signed_url ? (
                              <Button
                                variant="ghost"
                                size="icon"
                                title="Download"
                                onClick={() => handleDownload(doc, row, presenterName)}
                                disabled={downloadingId === doc.id}
                              >
                                <Download className="h-4 w-4" />
                              </Button>
                            ) : (
                              <Button variant="ghost" size="icon" disabled title="Download">
                                <Download className="h-4 w-4" />
                              </Button>
                            )}
                          </div>
                        </TableCell>
                      </TableRow>
                    )
                  })
                )}

                {!isRosterLoading && !isDocsLoading && rows.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={8} className="text-muted-foreground py-8 text-center">
                      No rows found for current filters.
                    </TableCell>
                  </TableRow>
                ) : null}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>
    </TablePage>
  )
}

"use client"

import { useEffect, useMemo, useState } from "react"
import { useQuery } from "@tanstack/react-query"
import { toast } from "sonner"
import { PageWrapper, PageHeader } from "@/components/layout"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"
import { REPORT_DOC_MAX_SIZE_BYTES, formatLimitMb } from "@/lib/reports/document-upload-limits"
import { BookOpen, CalendarDays, Loader2, Presentation, Upload } from "lucide-react"

const DOCX_MIME = "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
const PPTX_MIME = "application/vnd.openxmlformats-officedocument.presentationml.presentation"

type Employee = {
  id: string
  full_name: string
  department: string | null
}

type KssRosterEntry = {
  id: string
  meeting_week: number
  meeting_year: number
  department: string
  presenter_id: string | null
  notes: string | null
}

type MeetingWeekDocument = {
  id: string
  document_type: "knowledge_sharing_session" | "minutes" | "action_points"
  department: string | null
  file_name: string
  version_no: number
  signed_url: string | null
}

interface Props {
  employees: Employee[]
  backHref: string
  backLabel: string
  title?: string
}

export function MeetingDocumentLibrary({ employees, backHref, backLabel, title = "Meeting Documents" }: Props) {
  const currentOfficeWeek = getCurrentOfficeWeek()
  const [weekNumber, setWeekNumber] = useState(currentOfficeWeek.week)
  const [yearNumber, setYearNumber] = useState(currentOfficeWeek.year)

  const [kssDepartment, setKssDepartment] = useState("none")
  const [kssPresenterId, setKssPresenterId] = useState("none")
  const [kssNotes, setKssNotes] = useState("")
  const [kssFile, setKssFile] = useState<File | null>(null)
  const [minutesFile, setMinutesFile] = useState<File | null>(null)
  const [actionPointsFile, setActionPointsFile] = useState<File | null>(null)

  const [savingRoster, setSavingRoster] = useState(false)
  const [uploadingDocType, setUploadingDocType] = useState<
    "knowledge_sharing_session" | "minutes" | "action_points" | null
  >(null)

  const weekOptions = Array.from({ length: 53 }, (_, i) => i + 1)
  const yearOptions = [currentOfficeWeek.year - 1, currentOfficeWeek.year, currentOfficeWeek.year + 1]

  const departmentOptions = useMemo(() => {
    return Array.from(new Set(employees.map((e) => e.department).filter(Boolean) as string[])).sort((a, b) =>
      a.localeCompare(b)
    )
  }, [employees])

  const kssPresenterOptions = useMemo(() => {
    if (kssDepartment === "none") return []
    return employees
      .filter((e) => e.department === kssDepartment)
      .sort((a, b) => (a.full_name || "").localeCompare(b.full_name || ""))
  }, [employees, kssDepartment])

  const { data: kssRosterForWeek, refetch: refetchRoster } = useQuery({
    queryKey: ["kss-roster-page", weekNumber, yearNumber],
    queryFn: async (): Promise<KssRosterEntry | null> => {
      const res = await fetch(`/api/reports/kss-roster?week=${weekNumber}&year=${yearNumber}`)
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to fetch KSS roster")
      return (payload.data || [])[0] || null
    },
  })

  const { data: meetingDocuments = [], refetch: refetchMeetingDocuments } = useQuery({
    queryKey: ["meeting-week-documents-page", weekNumber, yearNumber],
    queryFn: async (): Promise<MeetingWeekDocument[]> => {
      const res = await fetch(
        `/api/reports/meeting-week-documents?week=${weekNumber}&year=${yearNumber}&currentOnly=true`
      )
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to fetch meeting documents")
      return payload.data || []
    },
  })

  useEffect(() => {
    if (!kssRosterForWeek) {
      setKssDepartment("none")
      setKssPresenterId("none")
      setKssNotes("")
      return
    }
    setKssDepartment(kssRosterForWeek.department || "none")
    setKssPresenterId(kssRosterForWeek.presenter_id || "none")
    setKssNotes(kssRosterForWeek.notes || "")
  }, [kssRosterForWeek])

  const saveKssRoster = async () => {
    if (kssDepartment === "none") {
      toast.error("Please select the presenting department")
      return
    }

    setSavingRoster(true)
    try {
      const res = await fetch("/api/reports/kss-roster", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          meetingWeek: weekNumber,
          meetingYear: yearNumber,
          department: kssDepartment,
          presenterId: kssPresenterId === "none" ? null : kssPresenterId,
          notes: kssNotes || null,
        }),
      })
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to save KSS roster")
      toast.success("KSS roster saved for selected week")
      void refetchRoster()
    } catch (error: any) {
      toast.error(error?.message || "Failed to save KSS roster")
    } finally {
      setSavingRoster(false)
    }
  }

  const uploadMeetingDocument = async (kind: "knowledge_sharing_session" | "minutes" | "action_points") => {
    const file = kind === "knowledge_sharing_session" ? kssFile : kind === "minutes" ? minutesFile : actionPointsFile
    if (!file) {
      toast.error("Please choose a file first")
      return
    }
    if (kind === "knowledge_sharing_session" && kssDepartment === "none") {
      toast.error("Please select KSS department before uploading")
      return
    }
    if (kind === "knowledge_sharing_session" && kssPresenterId === "none") {
      toast.error("Please select KSS presenter before uploading")
      return
    }

    setUploadingDocType(kind)
    try {
      const fd = new FormData()
      fd.append("file", file)
      fd.append("meetingWeek", String(weekNumber))
      fd.append("meetingYear", String(yearNumber))
      fd.append("documentType", kind)
      if (kind === "knowledge_sharing_session") {
        fd.append("department", kssDepartment)
        fd.append("presenterId", kssPresenterId)
        if (kssNotes.trim()) fd.append("notes", kssNotes.trim())
      }

      const res = await fetch("/api/reports/meeting-week-documents", {
        method: "POST",
        body: fd,
      })
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to upload document")

      if (kind === "knowledge_sharing_session") setKssFile(null)
      if (kind === "minutes") setMinutesFile(null)
      if (kind === "action_points") setActionPointsFile(null)

      toast.success(
        payload?.converted ? "Document uploaded and converted to PDF" : "Document uploaded and saved for this week"
      )
      void refetchMeetingDocuments()
    } catch (error: any) {
      toast.error(error?.message || "Failed to upload document")
    } finally {
      setUploadingDocType(null)
    }
  }

  return (
    <PageWrapper maxWidth="full" background="gradient">
      <PageHeader
        title={title}
        description="Upload and store Knowledge Sharing Session, Minutes of Meeting, and Action Points by week."
        icon={Presentation}
        backLink={{ href: backHref, label: backLabel }}
      />

      <div className="space-y-6">
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="flex items-center gap-2 text-lg">
              <CalendarDays className="h-5 w-5 text-green-600" /> Meeting Week
            </CardTitle>
            <CardDescription>Select week and year for roster + uploads</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="flex flex-wrap gap-4">
              <div className="space-y-2">
                <Label>Week</Label>
                <Select value={String(weekNumber)} onValueChange={(v) => setWeekNumber(Number(v))}>
                  <SelectTrigger className="w-[140px]">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {weekOptions.map((w) => (
                      <SelectItem key={w} value={String(w)}>
                        Week {w}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Year</Label>
                <Select value={String(yearNumber)} onValueChange={(v) => setYearNumber(Number(v))}>
                  <SelectTrigger className="w-[120px]">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {yearOptions.map((y) => (
                      <SelectItem key={y} value={String(y)}>
                        {y}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="flex items-center gap-2 text-lg">
              <BookOpen className="h-5 w-5 text-emerald-600" /> KSS Weekly Roster
            </CardTitle>
            <CardDescription>Set department and optional presenter for the selected week.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 md:grid-cols-3">
              <div className="space-y-2">
                <Label>Presenting Department</Label>
                <Select
                  value={kssDepartment}
                  onValueChange={(value) => {
                    setKssDepartment(value)
                    setKssPresenterId("none")
                  }}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select department" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Not selected</SelectItem>
                    {departmentOptions.map((dept) => (
                      <SelectItem key={dept} value={dept}>
                        {dept}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Presenter</Label>
                <Select value={kssPresenterId} onValueChange={setKssPresenterId} disabled={kssDepartment === "none"}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select presenter (required for upload)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Not selected</SelectItem>
                    {kssPresenterOptions.map((emp) => (
                      <SelectItem key={emp.id} value={emp.id}>
                        {emp.full_name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Roster Notes</Label>
                <Input value={kssNotes} onChange={(e) => setKssNotes(e.target.value)} placeholder="Optional note" />
              </div>
            </div>
            <Button onClick={saveKssRoster} disabled={savingRoster}>
              {savingRoster ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              Save Weekly Roster
            </Button>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="flex items-center gap-2 text-lg">
              <Presentation className="h-5 w-5 text-indigo-600" /> Weekly Document Repository
            </CardTitle>
            <CardDescription>Upload weekly files and keep them for reference.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-5">
            <div className="grid gap-4 md:grid-cols-3">
              <div className="space-y-2">
                <Label>Knowledge Sharing Session (PDF/PPTX/DOCX)</Label>
                <Input
                  type="file"
                  accept=".pdf,.pptx,.docx,application/pdf,application/vnd.openxmlformats-officedocument.presentationml.presentation,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  onChange={(e) => {
                    const selected = e.target.files?.[0] || null
                    if (selected && selected.size > REPORT_DOC_MAX_SIZE_BYTES) {
                      toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
                      e.currentTarget.value = ""
                      setKssFile(null)
                      return
                    }
                    if (selected?.type === PPTX_MIME || selected?.type === DOCX_MIME) {
                      toast.info("This file will be converted to PDF before it is stored.")
                    }
                    setKssFile(selected)
                  }}
                />
                <p className="text-muted-foreground text-xs">
                  Accepted: PDF, PPTX, DOCX. PPTX and DOCX uploads are converted to PDF before storage. Max file size:{" "}
                  {formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}
                </p>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => uploadMeetingDocument("knowledge_sharing_session")}
                  disabled={
                    uploadingDocType === "knowledge_sharing_session" ||
                    kssDepartment === "none" ||
                    kssPresenterId === "none"
                  }
                >
                  {uploadingDocType === "knowledge_sharing_session" ? (
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  ) : (
                    <Upload className="mr-2 h-4 w-4" />
                  )}
                  Upload Knowledge Sharing Session
                </Button>
              </div>
              <div className="space-y-2">
                <Label>Minutes of Meeting (PDF/DOCX)</Label>
                <Input
                  type="file"
                  accept=".pdf,.docx,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  onChange={(e) => {
                    const selected = e.target.files?.[0] || null
                    if (selected && selected.size > REPORT_DOC_MAX_SIZE_BYTES) {
                      toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
                      e.currentTarget.value = ""
                      setMinutesFile(null)
                      return
                    }
                    if (selected?.type === DOCX_MIME) {
                      toast.info("This DOCX file will be converted to PDF before it is stored.")
                    }
                    setMinutesFile(selected)
                  }}
                />
                <p className="text-muted-foreground text-xs">
                  Accepted: PDF, DOCX. DOCX uploads are converted to PDF before storage. Max file size:{" "}
                  {formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}
                </p>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => uploadMeetingDocument("minutes")}
                  disabled={uploadingDocType === "minutes"}
                >
                  {uploadingDocType === "minutes" ? (
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  ) : (
                    <Upload className="mr-2 h-4 w-4" />
                  )}
                  Upload Minutes of Meeting
                </Button>
              </div>
              <div className="space-y-2">
                <Label>Action Points (PDF/DOCX)</Label>
                <Input
                  type="file"
                  accept=".pdf,.docx,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  onChange={(e) => {
                    const selected = e.target.files?.[0] || null
                    if (selected && selected.size > REPORT_DOC_MAX_SIZE_BYTES) {
                      toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
                      e.currentTarget.value = ""
                      setActionPointsFile(null)
                      return
                    }
                    if (selected?.type === DOCX_MIME) {
                      toast.info("This DOCX file will be converted to PDF before it is stored.")
                    }
                    setActionPointsFile(selected)
                  }}
                />
                <p className="text-muted-foreground text-xs">
                  Accepted: PDF, DOCX. DOCX uploads are converted to PDF before storage. Max file size:{" "}
                  {formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}
                </p>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => uploadMeetingDocument("action_points")}
                  disabled={uploadingDocType === "action_points"}
                >
                  {uploadingDocType === "action_points" ? (
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  ) : (
                    <Upload className="mr-2 h-4 w-4" />
                  )}
                  Upload Action Points (Manual)
                </Button>
              </div>
            </div>

            <div className="space-y-2">
              <div className="text-muted-foreground text-xs font-medium tracking-wider uppercase">
                Current Week Files
              </div>
              <div className="space-y-2">
                {meetingDocuments.length === 0 ? (
                  <div className="text-muted-foreground rounded border px-3 py-2 text-sm">
                    No documents uploaded for Week {weekNumber}, {yearNumber}.
                  </div>
                ) : (
                  meetingDocuments.map((doc) => (
                    <div key={doc.id} className="flex items-center justify-between rounded border px-3 py-2 text-sm">
                      <div className="min-w-0">
                        <div className="truncate font-medium">{doc.file_name}</div>
                        <div className="text-muted-foreground text-xs">
                          {doc.document_type.replaceAll("_", " ").toUpperCase()}
                          {doc.department ? ` • ${doc.department}` : ""} • v{doc.version_no}
                        </div>
                      </div>
                      {doc.signed_url ? (
                        <a href={doc.signed_url} target="_blank" rel="noreferrer" className="text-green-700 underline">
                          View
                        </a>
                      ) : (
                        <span className="text-muted-foreground text-xs">No link</span>
                      )}
                    </div>
                  ))
                )}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </PageWrapper>
  )
}

"use client"

import Link from "next/link"
import { useMemo, useState } from "react"
import { useQuery } from "@tanstack/react-query"
import { toast } from "sonner"
import { TablePage } from "@/components/admin/admin-table-page"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { TableSkeleton } from "@/components/ui/query-states"
import { createClient } from "@/lib/supabase/client"
import { getCurrentOfficeWeek } from "@/lib/meeting-week"
import { REPORT_DOC_MAX_SIZE_BYTES, formatLimitMb } from "@/lib/reports/document-upload-limits"
import { Download, FileText, Loader2, Pencil, Plus, Search, Trash2 } from "lucide-react"

type DocumentType = "minutes" | "action_points"

type MeetingDocument = {
  id: string
  meeting_week: number
  meeting_year: number
  meeting_date?: string | null
  document_type: DocumentType
  file_name: string
  signed_url: string | null
  created_at: string
  uploaded_by?: string | null
  is_locked?: boolean
}

const DOCX_MIME = "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
type UploadPhase = "idle" | "converting" | "uploading"

interface Props {
  documentType: DocumentType
  title: string
  description: string
  backHref: string
  backLabel: string
  readOnly?: boolean
}

function getAdminReportsHref(documentType: DocumentType): string {
  if (documentType === "minutes") return "/admin/reports/minutes-of-meeting"
  return "/admin/reports/action-points-manual"
}

function compareWeekYear(aWeek: number, aYear: number, bWeek: number, bYear: number): number {
  if (aYear !== bYear) return aYear - bYear
  return aWeek - bWeek
}

function formatMeetingDate(value?: string | null): string {
  if (!value) return "-"
  const date = new Date(`${value}T00:00:00`)
  if (Number.isNaN(date.getTime())) return "-"
  return date.toLocaleDateString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  })
}

export function MeetingDocumentTypeTable({
  documentType,
  title,
  description,
  backHref,
  backLabel,
  readOnly = false,
}: Props) {
  const supabase = createClient()
  const officeWeek = getCurrentOfficeWeek()
  const [showCreate, setShowCreate] = useState(false)
  const [editingDoc, setEditingDoc] = useState<MeetingDocument | null>(null)
  const [pendingDeleteDoc, setPendingDeleteDoc] = useState<MeetingDocument | null>(null)
  const [weekNumber, setWeekNumber] = useState(officeWeek.week)
  const [yearNumber, setYearNumber] = useState(officeWeek.year)
  const [file, setFile] = useState<File | null>(null)
  const [saving, setSaving] = useState(false)
  const [uploadPhase, setUploadPhase] = useState<UploadPhase>("idle")

  const [searchQuery, setSearchQuery] = useState("")
  const [weekFilter, setWeekFilter] = useState("all")
  const [yearFilter, setYearFilter] = useState("all")

  const weekOptions = Array.from({ length: 53 }, (_, i) => i + 1)
  const yearOptions = [officeWeek.year - 1, officeWeek.year, officeWeek.year + 1, officeWeek.year + 2]

  const {
    data: rows = [],
    refetch,
    isLoading,
  } = useQuery({
    queryKey: ["meeting-doc-table", documentType],
    queryFn: async (): Promise<MeetingDocument[]> => {
      const res = await fetch(`/api/reports/meeting-week-documents?documentType=${documentType}&currentOnly=true`)
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Failed to fetch documents")
      return payload.data || []
    },
  })

  const { data: selectedWeekLockState } = useQuery({
    queryKey: ["meeting-doc-selected-week-lock", documentType, weekNumber, yearNumber],
    enabled: !readOnly,
    queryFn: async () => {
      const { data, error } = await supabase.rpc("weekly_report_lock_state", {
        p_week: weekNumber,
        p_year: yearNumber,
      })
      if (error) throw new Error(error.message)
      return Array.isArray(data) && data[0] ? Boolean(data[0].is_locked) : false
    },
  })

  const uploadedByIds = useMemo(
    () => Array.from(new Set(rows.map((row) => row.uploaded_by).filter((value): value is string => Boolean(value)))),
    [rows]
  )

  const { data: uploadedByNameMap = new Map<string, string>() } = useQuery({
    queryKey: ["meeting-doc-uploaded-by", uploadedByIds],
    enabled: uploadedByIds.length > 0,
    queryFn: async () => {
      const { data, error } = await supabase.from("profiles").select("id, full_name").in("id", uploadedByIds)
      if (error) throw new Error(error.message)
      return new Map((data || []).map((row) => [String(row.id), String(row.full_name || "Unknown")]))
    },
  })

  const isSelectedWeekLocked = Boolean(selectedWeekLockState)

  const filteredRows = useMemo(() => {
    const q = searchQuery.trim().toLowerCase()
    return rows
      .filter((row) => {
        // no upcoming rows
        if (compareWeekYear(row.meeting_week, row.meeting_year, officeWeek.week, officeWeek.year) > 0) return false
        if (weekFilter !== "all" && row.meeting_week !== Number(weekFilter)) return false
        if (yearFilter !== "all" && row.meeting_year !== Number(yearFilter)) return false
        if (!q) return true
        return (
          row.file_name.toLowerCase().includes(q) ||
          String(row.meeting_week).includes(q) ||
          String(row.meeting_year).includes(q)
        )
      })
      .sort((a, b) => {
        if (a.meeting_year !== b.meeting_year) return b.meeting_year - a.meeting_year
        return b.meeting_week - a.meeting_week
      })
  }, [rows, searchQuery, weekFilter, yearFilter, officeWeek.week, officeWeek.year])

  const upload = async () => {
    if (readOnly) {
      toast.error("You can only upload from Admin Reports.")
      return
    }
    if (!file) {
      toast.error("Please select a PDF or DOCX file")
      return
    }
    if (file.size > REPORT_DOC_MAX_SIZE_BYTES) {
      toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
      return
    }
    if (isSelectedWeekLocked) {
      toast.error(`Week ${weekNumber}, ${yearNumber} is locked and can no longer be changed`)
      return
    }

    setSaving(true)
    try {
      const requiresConversion = file.type === DOCX_MIME
      const fd = new FormData()
      fd.append("file", file)
      fd.append("meetingWeek", String(weekNumber))
      fd.append("meetingYear", String(yearNumber))
      fd.append("documentType", documentType)

      if (requiresConversion) {
        setUploadPhase("converting")
      } else {
        setUploadPhase("uploading")
      }

      let phaseTimer: ReturnType<typeof setTimeout> | null = null
      if (requiresConversion) {
        phaseTimer = setTimeout(() => {
          setUploadPhase("uploading")
        }, 1200)
      }

      const res = await fetch("/api/reports/meeting-week-documents", { method: "POST", body: fd })
      if (phaseTimer) clearTimeout(phaseTimer)
      setUploadPhase("uploading")
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Upload failed")

      toast.success(payload?.converted ? "Document uploaded and converted to PDF" : "Document uploaded")
      setShowCreate(false)
      setEditingDoc(null)
      setFile(null)
      await refetch()
    } catch (error: any) {
      toast.error(error?.message || "Upload failed")
    } finally {
      setSaving(false)
      setUploadPhase("idle")
    }
  }

  const uploadLabel =
    uploadPhase === "converting" ? "Converting..." : uploadPhase === "uploading" ? "Uploading..." : "Upload"

  const remove = async (id: string) => {
    if (readOnly) {
      toast.error("You can only delete from Admin Reports.")
      return
    }
    const target = rows.find((row) => row.id === id)
    const isPastRow = target
      ? compareWeekYear(target.meeting_week, target.meeting_year, officeWeek.week, officeWeek.year) < 0
      : false
    if (target?.is_locked || isPastRow) {
      toast.error(
        `Week ${target?.meeting_week ?? weekNumber}, ${target?.meeting_year ?? yearNumber} is locked and can no longer be changed`
      )
      return
    }
    try {
      const res = await fetch(`/api/reports/meeting-week-documents?id=${id}`, { method: "DELETE" })
      const payload = await res.json()
      if (!res.ok) throw new Error(payload.error || "Delete failed")
      toast.success("Document deleted")
      setPendingDeleteDoc(null)
      await refetch()
    } catch (error: any) {
      toast.error(error?.message || "Delete failed")
    }
  }

  const handleDownload = async (row: MeetingDocument) => {
    if (!row.signed_url) return
    try {
      const response = await fetch(row.signed_url)
      if (!response.ok) throw new Error("Failed to download document")
      const blob = await response.blob()
      const objectUrl = URL.createObjectURL(blob)
      const anchor = document.createElement("a")
      anchor.href = objectUrl
      anchor.download = row.file_name
      document.body.appendChild(anchor)
      anchor.click()
      anchor.remove()
      URL.revokeObjectURL(objectUrl)
    } catch (error: any) {
      toast.error(error?.message || "Download failed")
    }
  }

  const openEdit = (row: MeetingDocument) => {
    const isPastRow = compareWeekYear(row.meeting_week, row.meeting_year, officeWeek.week, officeWeek.year) < 0
    if (row.is_locked || isPastRow) {
      toast.error(`Week ${row.meeting_week}, ${row.meeting_year} is locked and can no longer be edited`)
      return
    }
    setEditingDoc(row)
    setWeekNumber(row.meeting_week)
    setYearNumber(row.meeting_year)
    setFile(null)
    setUploadPhase("idle")
    setShowCreate(true)
  }

  return (
    <TablePage
      title={title}
      description={description}
      icon={FileText}
      backLinkHref={backHref}
      backLinkLabel={backLabel}
      actions={
        readOnly ? null : (
          <Button
            onClick={() => {
              setEditingDoc(null)
              setWeekNumber(officeWeek.week)
              setYearNumber(officeWeek.year)
              setFile(null)
              setUploadPhase("idle")
              setShowCreate(true)
            }}
          >
            <Plus className="mr-2 h-4 w-4" /> Add
          </Button>
        )
      }
      filters={
        <div className="space-y-4">
          <div className="relative w-full">
            <Search className="text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2" />
            <Input
              placeholder="Search by file name, week, or year..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10"
            />
          </div>

          <div className="grid grid-cols-2 gap-3 md:grid-cols-3 lg:grid-cols-4">
            <div className="space-y-2">
              <Label>Week</Label>
              <Select value={weekFilter} onValueChange={setWeekFilter}>
                <SelectTrigger className="w-[140px]">
                  <SelectValue placeholder="All weeks" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All weeks</SelectItem>
                  {weekOptions.map((w) => (
                    <SelectItem key={w} value={String(w)}>
                      Week {w}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Year</Label>
              <Select value={yearFilter} onValueChange={setYearFilter}>
                <SelectTrigger className="w-[120px]">
                  <SelectValue placeholder="All years" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All years</SelectItem>
                  {yearOptions.map((y) => (
                    <SelectItem key={y} value={String(y)}>
                      {y}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </div>
      }
    >
      <AlertDialog open={pendingDeleteDoc !== null} onOpenChange={(open) => !open && setPendingDeleteDoc(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete document?</AlertDialogTitle>
            <AlertDialogDescription>
              {pendingDeleteDoc
                ? `Delete ${pendingDeleteDoc.document_type.replace("_", " ")} for Week ${pendingDeleteDoc.meeting_week}, ${pendingDeleteDoc.meeting_year}. This action cannot be undone.`
                : "This action cannot be undone."}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                if (pendingDeleteDoc) remove(pendingDeleteDoc.id)
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <Dialog
        open={showCreate}
        onOpenChange={(open) => {
          setShowCreate(open)
          if (!open) {
            setEditingDoc(null)
            setWeekNumber(officeWeek.week)
            setYearNumber(officeWeek.year)
            setFile(null)
            setUploadPhase("idle")
          }
        }}
      >
        <DialogContent className="max-h-[90vh] w-[95vw] max-w-xl overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingDoc ? `Edit ${title}` : title}</DialogTitle>
            <DialogDescription>Upload a PDF or DOCX. DOCX files are converted to PDF before storage.</DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>Week</Label>
              <Select
                value={String(weekNumber)}
                onValueChange={(v) => setWeekNumber(Number(v))}
                disabled={Boolean(editingDoc) || isSelectedWeekLocked}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {weekOptions.map((w) => (
                    <SelectItem key={w} value={String(w)}>
                      Week {w}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Year</Label>
              <Select
                value={String(yearNumber)}
                onValueChange={(v) => setYearNumber(Number(v))}
                disabled={Boolean(editingDoc) || isSelectedWeekLocked}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {yearOptions.map((y) => (
                    <SelectItem key={y} value={String(y)}>
                      {y}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2 md:col-span-2">
              <Label>Upload PDF or DOCX</Label>
              <Input
                type="file"
                accept="application/pdf,.pdf,.docx,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                onChange={(e) => {
                  const selected = e.target.files?.[0] || null
                  if (selected && selected.size > REPORT_DOC_MAX_SIZE_BYTES) {
                    toast.error(`File exceeds max size of ${formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}`)
                    e.currentTarget.value = ""
                    setFile(null)
                    return
                  }
                  if (selected?.type === DOCX_MIME) {
                    toast.info("This DOCX file will be converted to PDF before it is stored.")
                  }
                  setFile(selected)
                }}
                disabled={isSelectedWeekLocked}
              />
              <p className="text-muted-foreground text-xs">
                Accepted: PDF, DOCX. DOCX uploads are converted to PDF before storage. Max file size:{" "}
                {formatLimitMb(REPORT_DOC_MAX_SIZE_BYTES)}
              </p>
              {isSelectedWeekLocked ? (
                <p className="text-muted-foreground text-xs">
                  This week is locked after the meeting grace window, so past records are read-only.
                </p>
              ) : null}
            </div>
          </div>

          <div className="mt-4 flex gap-2">
            <Button onClick={upload} disabled={saving || isSelectedWeekLocked}>
              {saving ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  {uploadLabel}
                </>
              ) : (
                uploadLabel
              )}
            </Button>
            <Button variant="outline" onClick={() => setShowCreate(false)} disabled={saving}>
              Cancel
            </Button>
            {readOnly ? (
              <Button variant="secondary" asChild>
                <Link href={getAdminReportsHref(documentType)}>Open Admin Reports</Link>
              </Button>
            ) : null}
          </div>
        </DialogContent>
      </Dialog>

      <Card>
        <CardContent className="pt-6">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>S/N</TableHead>
                <TableHead>Meeting Date</TableHead>
                <TableHead>Week</TableHead>
                <TableHead>Submitted By</TableHead>
                <TableHead>Submitted Date</TableHead>
                <TableHead>Action</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {isLoading ? (
                <TableRow>
                  <TableCell colSpan={6} className="p-4">
                    <TableSkeleton rows={4} cols={6} />
                  </TableCell>
                </TableRow>
              ) : (
                filteredRows.map((row, index) => {
                  const isPastRow =
                    compareWeekYear(row.meeting_week, row.meeting_year, officeWeek.week, officeWeek.year) < 0
                  const isActionLocked = isPastRow || Boolean(row.is_locked)
                  const submittedDate = row.created_at
                    ? new Date(row.created_at).toLocaleString("en-GB", {
                        day: "2-digit",
                        month: "short",
                        year: "numeric",
                        hour: "2-digit",
                        minute: "2-digit",
                      })
                    : "-"
                  const submittedBy =
                    row.uploaded_by && uploadedByNameMap.has(row.uploaded_by)
                      ? uploadedByNameMap.get(row.uploaded_by)
                      : "-"

                  return (
                    <TableRow key={row.id}>
                      <TableCell>{index + 1}</TableCell>
                      <TableCell>{formatMeetingDate(row.meeting_date)}</TableCell>
                      <TableCell className="font-medium">{`W${row.meeting_week}`}</TableCell>
                      <TableCell>{submittedBy}</TableCell>
                      <TableCell>{submittedDate}</TableCell>
                      <TableCell>
                        <div className="flex items-center gap-1">
                          {!readOnly && !isActionLocked ? (
                            <Button variant="ghost" size="icon" onClick={() => openEdit(row)} title="Edit">
                              <Pencil className="h-4 w-4" />
                            </Button>
                          ) : null}
                          {!readOnly && !isActionLocked ? (
                            <Button variant="ghost" size="icon" onClick={() => setPendingDeleteDoc(row)} title="Delete">
                              <Trash2 className="h-4 w-4 text-red-600" />
                            </Button>
                          ) : null}
                          {row.signed_url ? (
                            <Button variant="ghost" size="icon" title="Download" onClick={() => handleDownload(row)}>
                              <Download className="h-4 w-4" />
                            </Button>
                          ) : (
                            <Button variant="ghost" size="icon" disabled title="Download">
                              <Download className="h-4 w-4" />
                            </Button>
                          )}
                        </div>
                      </TableCell>
                    </TableRow>
                  )
                })
              )}

              {!isLoading && filteredRows.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={6} className="text-muted-foreground py-8 text-center">
                    No documents found for current filters.
                  </TableCell>
                </TableRow>
              ) : null}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </TablePage>
  )
}

"use client"
import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Copy } from "lucide-react"
import { useTheme } from "next-themes"
import { toast } from "sonner"
import Link from "next/link"

interface SignatureCreatorProps {
  profile: any
}

interface FormData {
  firstName: string
  middleName: string
  lastName: string
  companyRole: string
  phoneNumber: string
  companyEmail: string
}

export function SignatureCreator({ profile }: SignatureCreatorProps) {
  const { theme, setTheme } = useTheme()
  const [formData, setFormData] = useState<FormData>({
    firstName: profile?.first_name || "",
    middleName: profile?.other_names || "",
    lastName: profile?.last_name || "",
    companyRole: profile?.company_role || "",
    phoneNumber: profile?.phone_number || "",
    companyEmail: profile?.company_email || "",
  })

  const [emailError, setEmailError] = useState("")
  const [phoneError, setPhoneError] = useState("")

  useEffect(() => {
    if (formData.firstName && formData.lastName) {
      const firstLetter = formData.lastName.charAt(0).toLowerCase()
      const firstName = formData.firstName.toLowerCase().replace(/\s+/g, "")
      const autoEmail = `${firstLetter}.${firstName}@org.acoblighting.com`

      if (
        !formData.companyEmail ||
        formData.companyEmail.endsWith("@org.acoblighting.com") ||
        formData.companyEmail.endsWith("@acoblighting.com")
      ) {
        setFormData((prev) => ({ ...prev, companyEmail: autoEmail }))
      }
    }
  }, [formData.firstName, formData.lastName])

  const formatPhoneNumber = (phone: string) => {
    const digits = phone.replace(/\D/g, "")

    if (digits.startsWith("0") && digits.length === 11) {
      const withoutLeadingZero = digits.substring(1)
      return `+234 ${withoutLeadingZero.substring(
        0,
        3
      )} ${withoutLeadingZero.substring(3, 6)} ${withoutLeadingZero.substring(6)}`
    }

    return phone
  }

  const validateEmail = (email: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    const isValidFormat = emailRegex.test(email)
    const isAllowedDomain = email.endsWith("@org.acoblighting.com") || email.endsWith("@acoblighting.com")
    return isValidFormat && isAllowedDomain
  }

  const validatePhone = (phone: string) => {
    const digits = phone.replace(/\D/g, "")
    return digits.length >= 11
  }

  const formatNameProperly = (name: string) => {
    if (!name) return ""
    // Split by spaces first to preserve word boundaries
    return name
      .split(/\s+/)
      .map((word) => {
        // For each word, handle hyphens separately
        return word
          .split(/-/)
          .map((part) => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
          .join("-")
      })
      .join(" ")
  }

  const generateSignature = () => {
    const formattedFirstName = formatNameProperly(formData.firstName)
    const formattedMiddleName = formData.middleName ? formatNameProperly(formData.middleName) : ""
    const formattedLastName = formatNameProperly(formData.lastName)

    const fullName = `${formattedFirstName}${
      formattedMiddleName ? " " + formattedMiddleName : ""
    } ${formattedLastName}`.trim()
    const formattedPhone = formatPhoneNumber(formData.phoneNumber)

    return `<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; max-width: 1000px; margin: 0; padding: 12px 0; line-height: 1.5;">
  <!-- Thin green line -->
  <div style="color: #000000;">&mdash;&mdash;</div>
  
  <!-- Greeting -->
  <p style="margin: 0 0 4px 0; font-size: 14px; color: #374151; font-style: italic;">Best Regards,</p>

  <!-- Name & Role -->
  <div style="border-bottom: 1.5px solid #e5e7eb; padding-bottom: 6px; margin-bottom: 6px;">
    <p style="margin: 0 0 0 0; line-height: 1; font-size: 20px; font-weight: bold; color: #1f2937; letter-spacing: -0.025em;">${fullName}</p>
    <p style="margin: 0 0 10px 0; font-size: 14px; font-weight: 500; color: #1f2937;">${formData.companyRole}</p>
    
    <!-- Contact details -->
    <div style="font-size: 14px; color: #374151; line-height: 1.3;">
      <div style="margin: 0 0 1px 0;">
        <img src="https://www.acoblighting.com/images/signature/phone.png" width="18" height="18" style="vertical-align: middle; opacity: 0.8; margin-right: 6px; display: inline-block;" alt="Phone" /><a href="tel:${formData.phoneNumber.replace(
