    <p style="margin: 0 0 6px 0; font-style: italic;">This email, including any attachments, contains confidential information intended solely for the recipient(s) named above. If you have received this email in error, please notify the sender immediately and delete the email from your system. Any unauthorized use, disclosure, distribution, or copying of this email is strictly prohibited and may be unlawful.</p>
    <p style="margin: 0 0 4px 0; font-weight: 600; font-style: italic;">ACOB Lighting Technology Limited is a renewable energy company registered under the Laws of the Federal Republic of Nigeria.</p>
    <p style="margin: 0 0 2px 0; font-weight: 600; font-style: italic;">We are a leading provider of solar and energy solutions for homes, businesses, and communities.</p>
    <p style="margin: 0; font-weight: 600; font-style: italic;">Lighting up Nigeria!</p>
  </div>
</div>`
  }

  const copyToClipboard = async () => {
    const signature = generateSignature()
    try {
      await navigator.clipboard.writeText(signature)
      toast.success("Signature copied to clipboard!")
    } catch (err) {
      toast.error("Failed to copy signature")
    }
  }

  const handleInputChange = (field: keyof FormData, value: string) => {
    if (field === "phoneNumber") {
      const numbersOnly = value.replace(/\D/g, "")
      setFormData((prev) => ({ ...prev, [field]: numbersOnly }))

      if (numbersOnly && !validatePhone(numbersOnly)) {
        setPhoneError("Phone number must be at least 11 digits")
      } else {
        setPhoneError("")
      }
      return
    }

    if (field === "companyEmail") {
      setFormData((prev) => ({ ...prev, [field]: value }))

      if (value && !validateEmail(value)) {
        setEmailError("Email must end with @org.acoblighting.com or @acoblighting.com")
      } else {
        setEmailError("")
      }
      return
    }

    setFormData((prev) => ({ ...prev, [field]: value }))
  }

  const isFormValid =
    formData.firstName &&
    formData.lastName &&
    formData.companyRole &&
    formData.phoneNumber &&
    validatePhone(formData.phoneNumber) &&
    formData.companyEmail &&
    validateEmail(formData.companyEmail) &&
    !emailError &&
    !phoneError

  return (
    <div className="grid gap-8 lg:grid-cols-2">
      {/* Form */}
      <Card>
        <CardHeader>
          <CardTitle>Personal Information</CardTitle>
          <CardDescription>Fill in your details to generate your signature</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="firstName">First Name *</Label>
              <Input
                id="firstName"
                value={formData.firstName}
                onChange={(e) => handleInputChange("firstName", e.target.value)}
                placeholder="John"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="middleName">Middle Name</Label>
              <Input
                id="middleName"
                value={formData.middleName}
                onChange={(e) => handleInputChange("middleName", e.target.value)}
                placeholder="Optional"
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="lastName">Last Name *</Label>
            <Input
              id="lastName"
              value={formData.lastName}
              onChange={(e) => handleInputChange("lastName", e.target.value)}
              placeholder="Akpa"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="companyRole">Company Role *</Label>
            <Input
              id="companyRole"
              value={formData.companyRole}
              onChange={(e) => handleInputChange("companyRole", e.target.value)}
              placeholder="IT Support employee"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="phoneNumber">Phone Number *</Label>
            <Input
              id="phoneNumber"
              value={formData.phoneNumber}
              onChange={(e) => handleInputChange("phoneNumber", e.target.value)}
              placeholder="07012345678"
            />
            {phoneError && <p className="text-destructive text-sm">{phoneError}</p>}
          </div>

          <div className="space-y-2">
            <Label htmlFor="companyEmail">Company Email *</Label>
            <Input
              id="companyEmail"
              type="email"
              value={formData.companyEmail}
              onChange={(e) => handleInputChange("companyEmail", e.target.value)}
              placeholder="a.john@org.acoblighting.com"
            />
            {emailError && <p className="text-destructive text-sm">{emailError}</p>}
          </div>

          <div className="flex">
            <Button onClick={copyToClipboard} disabled={!isFormValid} className="flex-1">
              <Copy className="mr-2 h-4 w-4" />
              Copy Signature
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Preview */}
      <Card>
        <CardHeader>
          <CardTitle>Signature Preview</CardTitle>
          <CardDescription>This is how your signature will look</CardDescription>
        </CardHeader>
        <CardContent>
          {isFormValid ? (
            <div
              className="rounded-lg border bg-white p-4 text-sm"
              dangerouslySetInnerHTML={{ __html: generateSignature() }}
            />
          ) : (
            <div className="flex h-64 items-center justify-center rounded-lg border border-dashed">
              <p className="text-muted-foreground">Fill in the required fields to see preview</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import * as React from "react"
import * as SelectPrimitive from "@radix-ui/react-select"
import { Check, ChevronDown, ChevronUp } from "lucide-react"
import { SearchableSelect } from "@/components/ui/searchable-select"

import { cn } from "@/lib/utils"

type SelectProps = React.ComponentPropsWithoutRef<typeof SelectPrimitive.Root>

function getNodeText(node: React.ReactNode): string {
  if (node === null || node === undefined || typeof node === "boolean") return ""
  if (typeof node === "string" || typeof node === "number") return String(node)
  if (Array.isArray(node)) return node.map(getNodeText).join("")
  if (React.isValidElement(node)) return getNodeText(node.props.children)
  return ""
}

function findSelectItems(nodes: React.ReactNode): React.ReactElement[] {
  const items: React.ReactElement[] = []
  React.Children.forEach(nodes, (child) => {
    if (!React.isValidElement(child)) return
    const typeAny = child.type as any
    const isItem =
      typeAny === SelectItem ||
      typeAny?.displayName === SelectItem.displayName ||
      String(typeAny?.displayName || "").includes("SelectItem")
    if (isItem) {
      items.push(child)
      return
    }
    if (child.props?.children) {
      items.push(...findSelectItems(child.props.children))
    }
  })
  return items
}

function findPlaceholder(nodes: React.ReactNode): string | undefined {
  let placeholder: string | undefined
  React.Children.forEach(nodes, (child) => {
    if (!React.isValidElement(child)) return
    const typeAny = child.type as any
    const isValue =
      typeAny === SelectValue ||
      typeAny?.displayName === SelectValue.displayName ||
      String(typeAny?.displayName || "").includes("SelectValue")
    if (isValue && typeof child.props?.placeholder === "string") {
      placeholder = child.props.placeholder
      return
    }
    if (child.props?.children && placeholder === undefined) {
      placeholder = findPlaceholder(child.props.children)
    }
  })
  return placeholder
}

function findTriggerClassName(nodes: React.ReactNode): string | undefined {
  let className: string | undefined
  React.Children.forEach(nodes, (child) => {
    if (!React.isValidElement(child)) return
    const typeAny = child.type as any
    const isTrigger =
      typeAny === SelectTrigger ||
      typeAny?.displayName === SelectTrigger.displayName ||
      String(typeAny?.displayName || "").includes("SelectTrigger")
    if (isTrigger && typeof child.props?.className === "string") {
      className = child.props.className
      return
    }
    if (child.props?.children && className === undefined) {
      className = findTriggerClassName(child.props.children)
    }
  })
  return className
}

const Select = ({
  value,
  defaultValue,
  onValueChange,
  disabled,
  open,
  defaultOpen,
  onOpenChange,
  children,
}: SelectProps & { children?: React.ReactNode }) => {
  const placeholder = findPlaceholder(children)
  const triggerClassName = findTriggerClassName(children)
  const items = findSelectItems(children)
  const options = items.map((item) => {
    const labelText = getNodeText(item.props.children)
    return {
      value: item.props.value as string,
      label: labelText || String(item.props.value),
    }
  })

  // Handle controlled vs uncontrolled - use defaultValue if value is undefined
  const effectiveValue = value !== undefined ? (value as string) : (defaultValue as string | undefined)

  // Properly typed handler that avoids unsafe cast
  const handleValueChange = onValueChange ? (v: string) => onValueChange(v) : undefined

  return (
    <SearchableSelect
      value={effectiveValue ?? ""}
      onValueChange={handleValueChange || (() => {})}
      placeholder={placeholder}
      options={options}
      className={triggerClassName}
      disabled={disabled}
      open={open}
      defaultOpen={defaultOpen}
      onOpenChange={onOpenChange}
    />
  )
}

const SelectGroup = SelectPrimitive.Group

const SelectValue = SelectPrimitive.Value

const SelectTrigger = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Trigger>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Trigger>
>(({ className, children, ...props }, ref) => (
  <SelectPrimitive.Trigger
    ref={ref}
    className={cn(
      "border-input ring-offset-background data-[placeholder]:text-muted-foreground focus:ring-ring flex h-9 w-full items-center justify-between rounded-md border bg-transparent px-3 py-2 text-sm whitespace-nowrap shadow-sm focus:ring-1 focus:outline-none disabled:cursor-not-allowed disabled:opacity-50 [&>span]:line-clamp-1",
      className
    )}
    {...props}
  >
    {children}
    <SelectPrimitive.Icon asChild>
      <ChevronDown className="h-4 w-4 opacity-50" />
    </SelectPrimitive.Icon>
  </SelectPrimitive.Trigger>
))
SelectTrigger.displayName = SelectPrimitive.Trigger.displayName

const SelectScrollUpButton = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.ScrollUpButton>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.ScrollUpButton>
>(({ className, ...props }, ref) => (
  <SelectPrimitive.ScrollUpButton
    ref={ref}
    className={cn("flex cursor-default items-center justify-center py-1", className)}
    {...props}
  >
    <ChevronUp className="h-4 w-4" />
  </SelectPrimitive.ScrollUpButton>
))
SelectScrollUpButton.displayName = SelectPrimitive.ScrollUpButton.displayName

const SelectScrollDownButton = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.ScrollDownButton>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.ScrollDownButton>
>(({ className, ...props }, ref) => (
  <SelectPrimitive.ScrollDownButton
    ref={ref}
    className={cn("flex cursor-default items-center justify-center py-1", className)}
    {...props}
  >
    <ChevronDown className="h-4 w-4" />
  </SelectPrimitive.ScrollDownButton>
))
SelectScrollDownButton.displayName = SelectPrimitive.ScrollDownButton.displayName

const SelectContent = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Content>
>(({ className, children, position = "popper", ...props }, ref) => (
  <SelectPrimitive.Portal>
    <SelectPrimitive.Content
      ref={ref}
      className={cn(
        "bg-popover text-popover-foreground data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 relative z-50 max-h-[--radix-select-content-available-height] min-w-[8rem] origin-[--radix-select-content-transform-origin] overflow-x-hidden overflow-y-auto rounded-md border shadow-md",
        position === "popper" &&
          "data-[side=bottom]:translate-y-1 data-[side=left]:-translate-x-1 data-[side=right]:translate-x-1 data-[side=top]:-translate-y-1",
        className
      )}
      position={position}
      {...props}
    >
      <SelectScrollUpButton />
      <SelectPrimitive.Viewport
        className={cn(
          "p-1",
          position === "popper" &&
            "h-[var(--radix-select-trigger-height)] w-full min-w-[var(--radix-select-trigger-width)]"
        )}
      >
        {children}
      </SelectPrimitive.Viewport>
      <SelectScrollDownButton />
    </SelectPrimitive.Content>
  </SelectPrimitive.Portal>
))
SelectContent.displayName = SelectPrimitive.Content.displayName

const SelectLabel = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Label>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Label>
>(({ className, ...props }, ref) => (
  <SelectPrimitive.Label ref={ref} className={cn("px-2 py-1.5 text-sm font-semibold", className)} {...props} />
))
SelectLabel.displayName = SelectPrimitive.Label.displayName

const SelectItem = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Item>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Item>
>(({ className, children, ...props }, ref) => (
  <SelectPrimitive.Item
    ref={ref}
    className={cn(
      "focus:bg-accent focus:text-accent-foreground relative flex w-full cursor-default items-center rounded-sm py-1.5 pr-8 pl-2 text-sm outline-none select-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
      className
    )}
    {...props}
  >
    <span className="absolute right-2 flex h-3.5 w-3.5 items-center justify-center">
      <SelectPrimitive.ItemIndicator>
        <Check className="h-4 w-4" />
      </SelectPrimitive.ItemIndicator>
    </span>
    <SelectPrimitive.ItemText>{children}</SelectPrimitive.ItemText>
  </SelectPrimitive.Item>
))
SelectItem.displayName = SelectPrimitive.Item.displayName

const SelectSeparator = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Separator>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Separator>
>(({ className, ...props }, ref) => (
  <SelectPrimitive.Separator ref={ref} className={cn("bg-muted -mx-1 my-1 h-px", className)} {...props} />
))
SelectSeparator.displayName = SelectPrimitive.Separator.displayName

export {
  Select,
  SelectGroup,
  SelectValue,
  SelectTrigger,
  SelectContent,
  SelectLabel,
  SelectItem,
  SelectSeparator,
  SelectScrollUpButton,
  SelectScrollDownButton,
}

"use client"

import { useState, useEffect } from "react"
import { useQuery } from "@tanstack/react-query"
import { QUERY_KEYS } from "@/lib/query-keys"
import { Search, Loader2, User, Laptop, Package, ClipboardList, FileText, MessageSquare, X } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"
import { useRouter } from "next/navigation"

interface SearchResult {
  id: string
  type: "profile" | "device" | "asset" | "task" | "documentation" | "feedback"
  title: string
  subtitle?: string
  description?: string
  href: string
  metadata?: Record<string, any>
}

interface UniversalSearchProps {
  isAdminMode?: boolean
}

const typeIcons = {
  profile: User,
  device: Laptop,
  asset: Package,
  task: ClipboardList,
  documentation: FileText,
  feedback: MessageSquare,
}

const typeLabels = {
  profile: "employee",
  device: "Device",
  asset: "Asset",
  task: "Task",
  documentation: "Documentation",
  feedback: "Feedback",
}

async function performSearch(q: string): Promise<SearchResult[]> {
  const response = await fetch(`/api/search?q=${encodeURIComponent(q)}`)
  if (!response.ok) throw new Error("Search failed")
  const data = await response.json()
  return data.results || []
}

export function UniversalSearch({ isAdminMode = false }: UniversalSearchProps) {
  const [open, setOpen] = useState(false)
  const [query, setQuery] = useState("")
  const [debouncedQuery, setDebouncedQuery] = useState("")
  const router = useRouter()

  // Keyboard shortcut: Ctrl+K or Cmd+K
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "k") {
        e.preventDefault()
        setOpen(true)
      }
      if (e.key === "Escape") {
        setOpen(false)
      }
    }

    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [])

  // Debounce query
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedQuery(query)
    }, 300)
    return () => clearTimeout(timer)
  }, [query])

  const { data: results = [], isFetching: loading } = useQuery({
    queryKey: QUERY_KEYS.search(debouncedQuery),
    queryFn: () => performSearch(debouncedQuery),
    enabled: open && debouncedQuery.trim().length > 0,
    staleTime: 30 * 1000,
  })

  const handleResultClick = (result: SearchResult) => {
    router.push(result.href)
    setOpen(false)
    setQuery("")
    setDebouncedQuery("")
  }

  return (
    <>
      <Button
        variant="outline"
        className={cn(
          "text-muted-foreground relative h-10 w-full justify-start text-sm sm:pr-12 md:w-64 lg:w-80",
          isAdminMode &&
            "border-amber-300/70 bg-amber-50/60 text-amber-900 hover:bg-amber-100/70 dark:border-amber-900 dark:bg-amber-950/30 dark:text-amber-200 dark:hover:bg-amber-900/40"
        )}
        onClick={() => setOpen(true)}
      >
        <Search className={cn("mr-2 h-4 w-4", isAdminMode && "text-amber-700 dark:text-amber-300")} />
        <span>Search anything...</span>
        <kbd
          className={cn(
            "bg-muted pointer-events-none absolute top-1.5 right-1.5 hidden h-6 items-center gap-1 rounded border px-1.5 font-mono text-[10px] font-medium opacity-100 select-none sm:flex",
            isAdminMode &&
              "border-amber-300/60 bg-amber-100/70 text-amber-900 dark:border-amber-800 dark:bg-amber-900/60 dark:text-amber-100"
          )}
        >
          <span className="text-xs">⌘</span>K
        </kbd>
      </Button>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className={cn("max-w-2xl p-0", isAdminMode && "border-amber-300/70 dark:border-amber-900")}>
          <DialogHeader className="px-6 pt-6">
            <DialogTitle className={cn(isAdminMode && "text-amber-900 dark:text-amber-200")}>Search</DialogTitle>
          </DialogHeader>
          <div className="px-6 pb-4">
            <div className="relative">
              <Search
                className={cn(
                  "text-muted-foreground absolute top-1/2 left-3 h-4 w-4 -translate-y-1/2",
                  isAdminMode && "text-amber-700 dark:text-amber-300"
                )}
              />
              <Input
                placeholder="Search employee, devices, assets, tasks, documentation, feedback..."
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className={cn(
                  "pl-9",
                  isAdminMode &&
                    "border-amber-300/80 focus-visible:ring-amber-500 dark:border-amber-800 dark:focus-visible:ring-amber-400"
                )}
                autoFocus
              />
              {query && (
                <Button
                  variant="ghost"
                  size="icon"
                  className="absolute top-1/2 right-1 h-7 w-7 -translate-y-1/2"
                  onClick={() => {
                    setQuery("")
                    setDebouncedQuery("")
                  }}
                >
                  <X className="h-4 w-4" />
                </Button>
              )}
            </div>
          </div>

          <div className="max-h-[400px] overflow-y-auto px-6 pb-6">
            {loading && (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="text-muted-foreground h-6 w-6 animate-spin" />
              </div>
            )}

            {!loading && query && results.length === 0 && (
              <div className="text-muted-foreground py-8 text-center text-sm">
                No results found for &quot;{query}&quot;
              </div>
            )}

            {!loading && !query && (
              <div className="text-muted-foreground py-8 text-center text-sm">Start typing to search...</div>
            )}

            {!loading && results.length > 0 && (
              <div className="space-y-1">
                {results.map((result) => {
                  const Icon = typeIcons[result.type]
                  return (
                    <button
                      key={`${result.type}-${result.id}`}
                      onClick={() => handleResultClick(result)}
                      className={cn(
                        "group flex w-full items-center gap-3 rounded-lg border p-3 text-left transition-colors",
                        isAdminMode
                          ? "border-amber-200/80 hover:border-amber-400/80 hover:bg-amber-50 dark:border-amber-900 dark:hover:border-amber-700 dark:hover:bg-amber-950/40"
                          : "hover:bg-accent hover:text-accent-foreground"
                      )}
                    >
                      <div
                        className={cn(
                          "bg-muted flex h-10 w-10 items-center justify-center rounded-md",
                          isAdminMode && "bg-amber-100 text-amber-800 dark:bg-amber-900/40 dark:text-amber-200"
                        )}
                      >
                        <Icon className="h-5 w-5" />
                      </div>
                      <div className="min-w-0 flex-1">
                        <div className="mb-0.5 flex items-center gap-2">
                          <p className="truncate text-sm font-semibold">{result.title}</p>
                          <Badge
                            variant="outline"
                            className={cn(
                              "text-[11px]",
                              isAdminMode &&
                                "border-amber-300 bg-amber-50 text-amber-800 dark:border-amber-800 dark:bg-amber-900/30 dark:text-amber-200"
                            )}
                          >
                            {typeLabels[result.type]}
                          </Badge>
