export function UserFeedbackList({ feedback }: UserFeedbackListProps) {
  const [feedbackList, setFeedbackList] = useState(feedback)
  const [selectedFeedback, setSelectedFeedback] = useState<any>(null)
  const [showEditModal, setShowEditModal] = useState(false)
  const [pendingDeleteId, setPendingDeleteId] = useState<string | null>(null)

  const getTypeColor = (type: string) => {
    switch (type) {
      case "concern":
        return "bg-yellow-100 text-yellow-800"
      case "complaint":
        return "bg-red-100 text-red-800"
      case "suggestion":
        return "bg-blue-100 text-blue-800"
      case "required_item":
        return "bg-purple-100 text-purple-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "open":
        return "bg-green-100 text-green-800"
      case "in_progress":
        return "bg-blue-100 text-blue-800"
      case "resolved":
        return "bg-purple-100 text-purple-800"
      case "closed":
        return "bg-gray-100 text-gray-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  const handleDelete = async (id: string) => {
    const supabase = createClient()

    try {
      // Get feedback details before deleting for audit log
      const feedbackToDelete = feedbackList.find((item) => item.id === id)

      const { error } = await supabase.from("feedback").delete().eq("id", id)

      if (error) throw error

      // Log audit
      if (feedbackToDelete) {
        await writeAuditLogClient(
          supabase as any,
          {
            action: "delete",
            entityType: "feedback",
            entityId: id,
            oldValues: {
              feedback_type: feedbackToDelete.feedback_type,
              title: feedbackToDelete.title,
              description: feedbackToDelete.description,
              status: feedbackToDelete.status,
            },
            context: {
              source: "ui",
              route: "/feedback",
            },
          },
          { failOpen: true }
        )
      }

      setFeedbackList(feedbackList.filter((item) => item.id !== id))
      toast.success("Feedback deleted successfully!")
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : "Failed to delete feedback"
      toast.error(message)
    }
  }

  const handleEdit = (item: any) => {
    setSelectedFeedback(item)
    setShowEditModal(true)
  }

  const handleSaveEdit = (updatedFeedback: any) => {
    setFeedbackList(feedbackList.map((item) => (item.id === updatedFeedback.id ? updatedFeedback : item)))
    setShowEditModal(false)
    setSelectedFeedback(null)
  }

  if (feedbackList.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Your Feedback</CardTitle>
          <CardDescription>No feedback submitted yet</CardDescription>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground text-sm">
            Submit your first feedback using the form on the left to get started.
          </p>
        </CardContent>
      </Card>
    )
  }

  return (
    <>
      <Card>
        <CardHeader>
          <CardTitle>Your Feedback</CardTitle>
          <CardDescription>Total: {feedbackList.length} items</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {feedbackList.map((item) => (
            <div key={item.id} className="space-y-3 rounded-lg border p-4">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <h3 className="text-foreground font-semibold">{item.title}</h3>
                  <p className="text-muted-foreground mt-1 text-sm">{item.description}</p>
                </div>
                <div className="flex gap-2">
                  <Button variant="ghost" size="sm" onClick={() => handleEdit(item)}>
                    <Edit2 className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setPendingDeleteId(item.id)}
                    aria-label="Delete feedback"
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </div>
              </div>

              <div className="flex flex-wrap gap-2">
                <Badge className={getTypeColor(item.feedback_type)}>{item.feedback_type.replace("_", " ")}</Badge>
                <Badge className={getStatusColor(item.status)}>{item.status.replace("_", " ")}</Badge>
              </div>

              <p className="text-muted-foreground text-xs">
                {new Date(item.created_at).toLocaleDateString()} at {new Date(item.created_at).toLocaleTimeString()}
              </p>
            </div>
          ))}
        </CardContent>
      </Card>

      {showEditModal && selectedFeedback && (
        <FeedbackEditModal
          feedback={selectedFeedback}
          onClose={() => {
            setShowEditModal(false)
            setSelectedFeedback(null)
          }}
          onSave={handleSaveEdit}
        />
      )}

      <AlertDialog open={pendingDeleteId !== null} onOpenChange={(open) => !open && setPendingDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Feedback</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this feedback? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                if (pendingDeleteId) handleDelete(pendingDeleteId)
                setPendingDeleteId(null)
              }}
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  )
}

import { useCallback, useState } from "react"

export type AsyncStateStatus = "idle" | "loading" | "success" | "empty" | "error"

export function useAsyncState<T>(initialData: T | null = null) {
  const [status, setStatus] = useState<AsyncStateStatus>("idle")
  const [data, setData] = useState<T | null>(initialData)
  const [error, setError] = useState<string | null>(null)

  const run = useCallback(async (fn: () => Promise<T>) => {
    setStatus("loading")
    setError(null)
    try {
      const result = await fn()
      setData(result)
      if (Array.isArray(result) && result.length === 0) {
        setStatus("empty")
      } else {
        setStatus("success")
      }
      return result
    } catch (e: any) {
      setError(e?.message || "Request failed")
      setStatus("error")
      throw e
    }
  }, [])

  return { status, data, error, run, setData, setStatus }
}

"use client"

import { useQuery, useQueryClient } from "@tanstack/react-query"
import { createBrowserClient } from "@supabase/ssr"
import { QUERY_KEYS } from "@/lib/query-keys"

/**
 * Fetches departments directly from the `departments` table so the UI
 * is never out-of-sync with the database.
 *
 * Returns a sorted list of department *names* (strings) which is the
 * shape every consumer currently expects.
 */
async function fetchDepartmentNames(): Promise<string[]> {
  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  )
  const { data, error } = await supabase.from("departments").select("name").eq("is_active", true).order("name")

  if (error) throw error
  return (data ?? []).map((d) => d.name)
}

export function useDepartments() {
  const queryClient = useQueryClient()

  const {
    data: departments = [],
    isLoading,
    error,
    refetch,
  } = useQuery({
    queryKey: QUERY_KEYS.departments(),
    queryFn: fetchDepartmentNames,
    staleTime: 5 * 60 * 1000,
  })

  /** Force a fresh fetch (e.g. after creating a new department). */
  const refetchDepts = async () => {
    await queryClient.invalidateQueries({ queryKey: QUERY_KEYS.departments() })
  }

  return {
    departments,
    isLoading,
    error: error ? (error instanceof Error ? error.message : "Failed to fetch departments") : null,
    refetch: refetchDepts,
  }
}

import * as React from "react"

import type { ToastActionElement, ToastProps } from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) => (t.id === action.toast.id ? { ...t, ...action.toast } : t)),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

