export const exportToPPTX = async (
  report: WeeklyReport,
  mode: WeeklyPptxMode = "full",
  theme: WeeklyPptxTheme = "light",
  meetingDate?: string
) => {
  const PptxConstructor = await loadPptxGenJS()
  const pres = new PptxConstructor()
  pres.layout = "LAYOUT_WIDE"

  // Slide 1 — Cover
  const coverSlide = addCoverSlide(pres, report.week_number, report.year, report.department, theme)
  applyWeeklySlideTransition(coverSlide)

  if (mode === "compact") {
    renderDepartmentCompactSlides(pres, report, undefined, 3, theme)
  } else {
    const departmentPlan = buildDepartmentPptxPlan(report)
    // Slides 2+ — Department title + full-mode content slides
    renderDepartmentWeeklySlides(pres, departmentPlan, undefined, 2, theme)
  }

  await pres.writeFile({
    fileName: buildWeeklyReportFilename({
      week: report.week_number,
      year: report.year,
      meetingDate,
      extension: "pptx",
      department: report.department,
      theme,
    }),
  })
}

export const exportAllToPPTX = async (
  reports: WeeklyReport[],
  week: number,
  year: number,
  mode: WeeklyPptxMode = "full",
  theme: WeeklyPptxTheme = "light",
  meetingDate?: string
) => {
  const PptxConstructor = await loadPptxGenJS()
  const pres = new PptxConstructor()
  pres.layout = "LAYOUT_WIDE"

  const sortedReports = sortReportsByDepartment(reports)
  const departments = sortedReports.map((entry) => entry.department)

  // Slide 1 — Cover
  const coverSlide = addCoverSlide(pres, week, year, undefined, theme)
  applyWeeklySlideTransition(coverSlide)

  let pageCursor = 3
  const departmentStartPages: number[] = []
  if (mode === "compact") {
    sortedReports.forEach((_report) => {
      departmentStartPages.push(pageCursor)
      pageCursor += 2
    })
  } else {
    const departmentPlans = sortedReports.map((report) => buildDepartmentPptxPlan(report))
    departmentPlans.forEach((entry) => {
      departmentStartPages.push(pageCursor)
      entry.startPage = pageCursor
      pageCursor += entry.totalSlides
    })
  }

  // Slide 2 — Dept index
  const indexSlide = addDeptIndexSlide(
    pres,
    departments,
    week,
    year,
    (index) => departmentStartPages[index] ?? 3 + index * 2,
    theme
  )
  applyWeeklySlideTransition(indexSlide)

  if (mode === "compact") {
    sortedReports.forEach((report, idx) => {
      renderDepartmentCompactSlides(
        pres,
        report,
        sortedReports[idx + 1]?.department,
        departmentStartPages[idx] + 1,
        theme
      )
    })
  } else {
    const departmentPlans = sortedReports.map((report, idx) => {
      const entry = buildDepartmentPptxPlan(report)
      entry.startPage = departmentStartPages[idx]
      return entry
    })
    departmentPlans.forEach((departmentPlan, idx) => {
      renderDepartmentWeeklySlides(
        pres,
        departmentPlan,
        departmentPlans[idx + 1]?.report.department,
        departmentPlan.startPage,
        theme
      )
    })
  }

  await pres.writeFile({
    fileName: buildWeeklyReportFilename({
      week,
      year,
      meetingDate,
      extension: "pptx",
      allDepartments: true,
      theme,
    }),
  })
}

﻿import { canAccessAdminSection, resolveAdminScope } from "@/lib/admin/rbac"

export const FLEET_BLOCKING_STATUSES = ["pending", "approved"] as const
export const FLEET_ALLOWED_MIME_TYPES = new Set([
  "application/pdf",
  "image/jpeg",
  "image/jpg",
  "image/png",
  "image/webp",
])
export const FLEET_MAX_FILE_SIZE = 10 * 1024 * 1024

export function sanitizeFileName(name: string): string {
  return name
    .replace(/[^\x00-\x7F]/g, "")
    .replace(/[^a-zA-Z0-9._-]/g, "_")
    .slice(0, 140)
}

export function assertReason(reason: string): string {
  const normalized = String(reason || "").trim()
  if (normalized.length < 10) {
    throw new Error("Reason must be at least 10 characters")
  }
  return normalized
}

export function assertBookingWindow(startAt: string, endAt: string): { start: Date; end: Date } {
  const start = new Date(startAt)
  const end = new Date(endAt)

  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
    throw new Error("Invalid booking date/time")
  }

  if (end.getTime() <= start.getTime()) {
    throw new Error("End time must be after start time")
  }

  return { start, end }
}

export async function assertNoFleetOverlap(params: {
  supabase: any
  resourceId: string
  startAt: string
  endAt: string
  excludeBookingId?: string
}) {
  const { supabase, resourceId, startAt, endAt, excludeBookingId } = params

  let query = supabase
    .from("fleet_bookings")
    .select("id, start_at, end_at, status")
    .eq("resource_id", resourceId)
    .in("status", [...FLEET_BLOCKING_STATUSES])
    .lt("start_at", endAt)
    .gt("end_at", startAt)
    .limit(1)

  if (excludeBookingId) {
    query = query.neq("id", excludeBookingId)
  }

  const { data, error } = await query
  if (error) {
    throw new Error("Failed to validate booking overlap")
  }

  if (Array.isArray(data) && data.length > 0) {
    throw new Error("This resource is already booked for the selected date/time")
  }
}

export async function canManageFleet(supabase: any, userId: string): Promise<boolean> {
  const scope = await resolveAdminScope(supabase as any, userId)
  if (!scope) return false
  return canAccessAdminSection(scope, "hr")
}

import { createClient } from "@/lib/supabase/server"
import { sendNotificationEmail, DEFAULT_NOTIFICATION_SENDER } from "@/lib/notifications/email-gateway"
import { withSubjectPrefix } from "@/lib/notifications/subject-policy"
import { isSystemNotificationChannelEnabled, resolveChannelEligibleUserIds } from "@/lib/notifications/delivery-policy"

interface HelpDeskMailPayload {
  userIds: string[]
  subject: string
  title: string
  message: string
  ticketNumber: string
  ctaPath?: string
}

function buildEmailHtml(payload: HelpDeskMailPayload) {
const ctaUrl = `${process.env.NEXT_PUBLIC_SITE_URL || "https://erp.acoblighting.com"}${payload.ctaPath || "/help-desk"}`

  return `
  <div style="font-family:Arial,sans-serif;max-width:620px;margin:0 auto;padding:24px;border:1px solid #e5e7eb;border-radius:10px;">
    <h2 style="margin:0 0 12px;color:#0f172a;">${payload.title}</h2>
    <p style="margin:0 0 16px;color:#334155;line-height:1.6;">${payload.message}</p>
    <p style="margin:0 0 20px;color:#0f172a;"><strong>Ticket:</strong> ${payload.ticketNumber}</p>
    <a href="${ctaUrl}" style="display:inline-block;background:#166534;color:#fff;padding:10px 14px;text-decoration:none;border-radius:8px;">Open Help Desk</a>
  </div>
  `
}

export async function sendHelpDeskMail(payload: HelpDeskMailPayload) {
  // Temporarily disabled during ERP stabilization/testing.
  if (process.env.HELP_DESK_EMAIL_ENABLED !== "true") return

  const apiKey = process.env.RESEND_API_KEY
  if (!apiKey) return

  const overrideRecipient = process.env.HELP_DESK_TEST_RECIPIENT?.trim().toLowerCase()
  if (overrideRecipient) {
    const supabase = await createClient()
    const systemEnabled = await isSystemNotificationChannelEnabled(supabase, "help_desk", "email")
    if (!systemEnabled) return

    await sendNotificationEmail({
      from: DEFAULT_NOTIFICATION_SENDER,
      to: [overrideRecipient],
      subject: withSubjectPrefix("Help Desk", payload.subject),
      html: buildEmailHtml(payload),
    })
    return
  }

  const uniqueIds = Array.from(new Set(payload.userIds.filter(Boolean)))
  if (!uniqueIds.length) return

  const supabase = await createClient()
  const allowedUserIds = await resolveChannelEligibleUserIds(supabase, {
    userIds: uniqueIds,
    notificationKey: "help_desk",
    channel: "email",
  })
  if (!allowedUserIds.length) return

  const { data: profiles } = await supabase
    .from("profiles")
    .select("id, company_email, additional_email")
    .in("id", allowedUserIds)

  const recipients = Array.from(
    new Set(
      (profiles || [])
        .flatMap((p: any) => [p.company_email, p.additional_email])
        .filter((email: any) => typeof email === "string" && email.trim())
        .map((email: string) => email.toLowerCase())
    )
  )

  if (!recipients.length) return

  await sendNotificationEmail({
    from: DEFAULT_NOTIFICATION_SENDER,
    to: recipients,
    subject: withSubjectPrefix("Help Desk", payload.subject),
    html: buildEmailHtml(payload),
  })
}

import { toast } from "sonner"

import { logger } from "@/lib/logger"

const log = logger("lib-hooks-useDataExport")


interface ExportOptions {
  filename: string
  sheetName?: string
}

export function useDataExport<T extends Record<string, any>>() {
  const exportToExcel = async (data: T[], options: ExportOptions) => {
    try {
      if (data.length === 0) {
        toast.error("No data to export")
        return
      }

      const XLSX = await import("xlsx")
      const { default: saveAs } = await import("file-saver")

      const ws = XLSX.utils.json_to_sheet(data)
      const wb = XLSX.utils.book_new()
      XLSX.utils.book_append_sheet(wb, ws, options.sheetName || "Sheet1")

      // Auto-size columns
      const maxWidth = 50
      const cols = Object.keys(data[0] || {}).map((key) => ({
        wch: Math.min(Math.max(key.length, ...data.map((row) => String(row[key]).length)), maxWidth),
      }))
      ws["!cols"] = cols

      const excelBuffer = XLSX.write(wb, { bookType: "xlsx", type: "array" })
      const blob = new Blob([excelBuffer], {
        type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      })
      saveAs(blob, `${options.filename}.xlsx`)
      toast.success("Excel file exported successfully")
    } catch (error) {
      log.error("Error exporting to Excel:", error)
      toast.error("Failed to export to Excel")
    }
  }

  const exportToPDF = async (data: T[], columns: { header: string; key: keyof T }[], options: ExportOptions) => {
    try {
      if (data.length === 0) {
        toast.error("No data to export")
        return
      }

      const { jsPDF } = await import("jspdf")
      const autoTable = (await import("jspdf-autotable")).default

      const doc = new jsPDF()

      const tableData = data.map((row) => columns.map((col) => String(row[col.key] || "")))

      autoTable(doc, {
        head: [columns.map((col) => col.header)],
        body: tableData,
        styles: { fontSize: 8 },
        headStyles: { fillColor: [71, 85, 105] },
      })

      doc.save(`${options.filename}.pdf`)
      toast.success("PDF file exported successfully")
    } catch (error) {
      log.error("Error exporting to PDF:", error)
      toast.error("Failed to export to PDF")
    }
  }

  const exportToWord = async (data: T[], columns: { header: string; key: keyof T }[], options: ExportOptions) => {
    try {
      if (data.length === 0) {
        toast.error("No data to export")
        return
      }

      const { Document, Packer, Paragraph, TextRun, Table, TableCell, TableRow, WidthType } = await import("docx")
      const { default: saveAs } = await import("file-saver")

      const headerRow = new TableRow({
        children: columns.map(
          (col) =>
            new TableCell({
              children: [new Paragraph({ children: [new TextRun({ text: col.header, bold: true })] })],
              width: { size: 100 / columns.length, type: WidthType.PERCENTAGE },
            })
        ),
      })

      const dataRows = data.map(
        (row) =>
          new TableRow({
            children: columns.map(
              (col) =>
                new TableCell({
                  children: [new Paragraph(String(row[col.key] || ""))],
                  width: { size: 100 / columns.length, type: WidthType.PERCENTAGE },
                })
            ),
          })
      )

      const table = new Table({
        width: { size: 100, type: WidthType.PERCENTAGE },
        rows: [headerRow, ...dataRows],
      })

      const doc = new Document({
        sections: [{ children: [table] }],
      })

      const blob = await Packer.toBlob(doc)
      saveAs(blob, `${options.filename}.docx`)
      toast.success("Word document exported successfully")
    } catch (error) {
      log.error("Error exporting to Word:", error)
      toast.error("Failed to export to Word")
    }
  }

  return { exportToExcel, exportToPDF, exportToWord }
}

import { notifyUsers } from "@/lib/hr/leave-workflow"
import { applyAssignableStatusFilter } from "@/lib/workforce/assignment-policy"
import { DEPT_EXECUTIVE_MANAGEMENT, DEPT_CORPORATE_SERVICES } from "@/config/constants"

type SupabaseClient = any

export const REQUESTER_KINDS = ["employee", "dept_lead", "admin_hr_lead", "hcs", "md"] as const
export type RequesterKind = (typeof REQUESTER_KINDS)[number]

export interface ResolvedRouteStage {
  stage_order: number
  approver_role_code: string
  approver_user_id: string
  stage_code: string
}

const DEPARTMENT_NAMES = {
  adminHr: "Admin & HR",
  md: DEPT_EXECUTIVE_MANAGEMENT,
  hcs: DEPT_CORPORATE_SERVICES,
} as const

function hasLeadForDepartment(profile: any, departmentName: string) {
  if (!profile) return false
  const managed = Array.isArray(profile.lead_departments) ? profile.lead_departments : []
  return Boolean(
    profile.is_department_lead && (profile.department === departmentName || managed.includes(departmentName))
  )
}

export function stageCodeForRole(roleCode: string) {
  switch (roleCode) {
    case "reliever":
      return "pending_reliever"
    case "department_lead":
      return "pending_department_lead"
    case "admin_hr_lead":
      return "pending_admin_hr_lead"
    case "md":
      return "pending_md"
    case "hcs":
      return "pending_hcs"
    default:
      return `pending_${roleCode}`
  }
}

export function classifyRequesterKind(profile: any): RequesterKind {
  if (hasLeadForDepartment(profile, DEPARTMENT_NAMES.md)) return "md"
  if (hasLeadForDepartment(profile, DEPARTMENT_NAMES.hcs)) return "hcs"
  if (hasLeadForDepartment(profile, DEPARTMENT_NAMES.adminHr)) return "admin_hr_lead"
  if (profile?.is_department_lead) return "dept_lead"
  return "employee"
}

async function resolveProfileByDepartmentLead(
  supabase: SupabaseClient,
  departmentName: string
): Promise<{ id: string } | null> {
  const { data, error } = await supabase
    .from("profiles")
    .select("id, department, lead_departments, is_department_lead")
    .eq("is_department_lead", true)

  if (error) throw new Error(`Failed to resolve ${departmentName} lead`)

  const matches = (data || []).filter((profile: any) => hasLeadForDepartment(profile, departmentName))
  if (matches.length > 1) throw new Error(`LEAVE_APPROVER_CONFLICT:${departmentName}`)
  return matches[0] || null
}

async function resolveDepartmentHeadById(
  supabase: SupabaseClient,
  departmentId: string
): Promise<{ id: string } | null> {
  const { data: department, error: departmentError } = await supabase
    .from("departments")
    .select("department_head_id")
    .eq("id", departmentId)
    .single()

  if (departmentError) throw new Error("Failed to resolve department lead")
  if (!department?.department_head_id) return null

  const profileQueryById = supabase.from("profiles").select("id").eq("id", department.department_head_id)
  const { data: profile, error: profileError } = await applyAssignableStatusFilter(profileQueryById, {
    allowLegacyNullStatus: false,
  }).single()

  if (profileError || !profile?.id) return null
  return { id: profile.id }
}

async function resolveDepartmentHeadByName(
  supabase: SupabaseClient,
  departmentName: string
): Promise<{ id: string } | null> {
  const { data: department, error: departmentError } = await supabase
    .from("departments")
    .select("id, department_head_id")
    .eq("name", departmentName)
    .limit(2)

  if (departmentError) throw new Error("Failed to resolve department lead")
  if (!department || department.length === 0) return null
  if (department.length > 1) throw new Error(`LEAVE_APPROVER_CONFLICT:${departmentName}`)

  const departmentHeadId = department[0]?.department_head_id
  if (!departmentHeadId) return null

  const profileQueryByName = supabase.from("profiles").select("id").eq("id", departmentHeadId)
  const { data: profile, error: profileError } = await applyAssignableStatusFilter(profileQueryByName, {
    allowLegacyNullStatus: false,
  }).single()

  if (profileError || !profile?.id) return null
  return { id: profile.id }
}

async function resolveRequesterDepartmentLead(
  supabase: SupabaseClient,
  requester: { department_id?: string | null; department?: string | null }
): Promise<{ id: string } | null> {
  if (requester.department_id) {
    const departmentHead = await resolveDepartmentHeadById(supabase, requester.department_id)
    if (departmentHead) return departmentHead

    const { data: leadByDeptId, error: leadByDeptIdError } = await supabase
      .from("profiles")
      .select("id")
      .eq("department_id", requester.department_id)
      .eq("is_department_lead", true)
      .limit(2)

    if (leadByDeptIdError) throw new Error("Failed to resolve department lead")
    if ((leadByDeptId || []).length > 1) throw new Error("LEAVE_APPROVER_CONFLICT:department_lead")
    if ((leadByDeptId || []).length === 1) return leadByDeptId[0]
  }

  if (requester.department) {
    const departmentHead = await resolveDepartmentHeadByName(supabase, requester.department)
    if (departmentHead) return departmentHead

    return resolveProfileByDepartmentLead(supabase, requester.department)
  }

  return null
}

async function resolveFixedRoleAssignee(supabase: SupabaseClient, roleCode: string): Promise<{ id: string } | null> {
  const now = new Date().toISOString()

  const { data, error } = await supabase
    .from("leave_approver_assignments")
    .select("user_id, effective_from, effective_to, is_primary")
    .eq("approver_role_code", roleCode)
    .eq("is_active", true)
    .eq("scope_type", "global")
    .order("is_primary", { ascending: false })

  if (error) throw new Error(`Failed to resolve ${roleCode} assignment`)

  const valid = (data || []).filter((row: any) => {
    const startsOk = !row.effective_from || row.effective_from <= now
    const endsOk = !row.effective_to || row.effective_to >= now
    return startsOk && endsOk
  })

  if (valid.length > 1 && valid.filter((x: any) => x.is_primary).length > 1) {
    throw new Error(`LEAVE_APPROVER_CONFLICT:${roleCode}`)
  }

  return valid.length ? { id: valid[0].user_id } : null
}

async function resolveRoleApprover(
  supabase: SupabaseClient,
  roleCode: string,
  context: {
    requester: any
    relieverId: string
  }
): Promise<{ id: string } | null> {
  if (roleCode === "reliever") {
    return { id: context.relieverId }
  }

  if (roleCode === "department_lead") {
    return resolveRequesterDepartmentLead(supabase, context.requester)
  }

  if (roleCode === "admin_hr_lead") {
    return resolveProfileByDepartmentLead(supabase, DEPARTMENT_NAMES.adminHr)
  }

  if (roleCode === "md") {
    return resolveProfileByDepartmentLead(supabase, DEPARTMENT_NAMES.md)
  }

  if (roleCode === "hcs") {
    return resolveProfileByDepartmentLead(supabase, DEPARTMENT_NAMES.hcs)
  }

  return resolveFixedRoleAssignee(supabase, roleCode)
}

export async function loadRouteRows(supabase: SupabaseClient, requesterKind: RequesterKind) {
  const { data, error } = await supabase
    .from("leave_approval_role_routes")
    .select("stage_order, approver_role_code, is_active")
    .eq("requester_kind", requesterKind)
    .eq("is_active", true)
    .order("stage_order", { ascending: true })

  if (error) throw new Error("Failed to load leave route configuration")
  return data || []
}

export async function buildResolvedRouteSnapshot(params: {
  supabase: SupabaseClient
  requester: any
  requesterId: string
  requesterKind: RequesterKind
  relieverId: string
}) {
  const { supabase, requester, requesterId, requesterKind, relieverId } = params

  const routeRows = await loadRouteRows(supabase, requesterKind)
  if (!routeRows.length) {
    throw new Error(`LEAVE_APPROVER_NOT_CONFIGURED:route:${requesterKind}`)
  }

  const resolved: ResolvedRouteStage[] = []

  for (const row of routeRows) {
    const approver = await resolveRoleApprover(supabase, row.approver_role_code, {
      requester,
      relieverId,
    })

    if (!approver?.id) {
      throw new Error(`LEAVE_APPROVER_NOT_CONFIGURED:${row.approver_role_code}`)
    }

    if (approver.id === requesterId) {
      continue
    }

    const prev = resolved[resolved.length - 1]
    if (prev && prev.approver_user_id === approver.id) {
      continue
    }

    resolved.push({
      stage_order: resolved.length + 1,
      approver_role_code: row.approver_role_code,
      approver_user_id: approver.id,
      stage_code: stageCodeForRole(row.approver_role_code),
    })
  }

  if (!resolved.length) {
    throw new Error("LEAVE_APPROVER_NOT_CONFIGURED:empty_route")
  }

  return resolved
}

export function getRouteStageByOrder(snapshot: any, stageOrder: number): ResolvedRouteStage | null {
  if (!Array.isArray(snapshot)) return null
  return (
    snapshot
      .map((row) => ({
        stage_order: Number(row.stage_order),
        approver_role_code: String(row.approver_role_code),
        approver_user_id: String(row.approver_user_id),
        stage_code: String(row.stage_code),
      }))
      .find((row) => row.stage_order === stageOrder) || null
  )
}

