export async function syncAttendanceForApprovedLeave(
  supabase: SupabaseClient,
  userId: string,
  startDate: string,
  endDate: string,
  mode: "set" | "clear"
) {
  const start = parseISODate(startDate)
  const end = parseISODate(endDate)

  if (mode === "set") {
    const rows = []
    let current = new Date(start)

    while (current <= end) {
      rows.push({
        user_id: userId,
        date: toISODate(current),
        status: "on_leave",
        notes: "Auto-generated from approved leave",
      })
      current = addDays(current, 1)
    }

    if (rows.length) {
      await supabase.from("attendance_records").upsert(rows, { onConflict: "user_id,date", ignoreDuplicates: false })
    }

    return
  }

  await supabase
    .from("attendance_records")
    .delete()
    .eq("user_id", userId)
    .eq("status", "on_leave")
    .gte("date", startDate)
    .lte("date", endDate)
}

const OFFICE_WEEK_ANCHOR_YEAR = 2026
const OFFICE_WEEK_ANCHOR_MONTH_INDEX = 0 // January
const OFFICE_WEEK_ANCHOR_DAY = 12

function getOfficeYearStart(year: number): Date {
  return new Date(year, OFFICE_WEEK_ANCHOR_MONTH_INDEX, OFFICE_WEEK_ANCHOR_DAY)
}

function addDays(date: Date, days: number): Date {
  const next = new Date(date)
  next.setDate(next.getDate() + days)
  return next
}

export function getWeeksInOfficeYear(year: number): number {
  const start = getOfficeYearStart(year)
  const nextStart = getOfficeYearStart(year + 1)
  const diffMs = nextStart.getTime() - start.getTime()
  return Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000))
}

export function getOfficeWeekFromDate(date: Date): { week: number; year: number } {
  const input = new Date(date)
  let year = input.getFullYear()
  let yearStart = getOfficeYearStart(year)

  if (input < yearStart) {
    year -= 1
    yearStart = getOfficeYearStart(year)
  }

  const diffMs = input.getTime() - yearStart.getTime()
  const week = Math.floor(diffMs / (7 * 24 * 60 * 60 * 1000)) + 1

  return { week, year }
}

export function getCurrentOfficeWeek(date: Date = new Date()): { week: number; year: number } {
  return getOfficeWeekFromDate(date)
}

export function getOfficeWeekMonday(week: number, year: number): Date {
  const yearStart = getOfficeYearStart(year)
  return addDays(yearStart, (week - 1) * 7)
}

export function formatOfficeDateWithOrdinal(date: Date): string {
  const day = date.getDate()
  const suffix = [1, 21, 31].includes(day) ? "st" : [2, 22].includes(day) ? "nd" : [3, 23].includes(day) ? "rd" : "th"
  const month = date.toLocaleString("en-GB", { month: "long" })
  return `${day}${suffix} ${month}, ${date.getFullYear()}`
}

/**
 * Notification Helper Library
 * Utility functions for creating and managing notifications
 */

import { createClient } from "@/lib/supabase/client"

import { logger } from "@/lib/logger"

const log = logger("lib-notifications")


interface CreateNotificationParams {
  userId: string
  type:
    | "task_assigned"
    | "task_updated"
    | "task_completed"
    | "mention"
    | "feedback"
    | "asset_assigned"
    | "approval_request"
    | "approval_granted"
    | "approval_rejected"
    | "system"
    | "announcement"
  category: "tasks" | "assets" | "feedback" | "approvals" | "system" | "mentions"
  title: string
  message: string
  priority?: "low" | "normal" | "high" | "urgent"
  linkUrl?: string
  actorId?: string
  entityType?: string
  entityId?: string
  richContent?: any
}

/**
 * Create a notification using the database function
 */
export async function createNotification(params: CreateNotificationParams) {
  const supabase = createClient()

  try {
    const { data, error } = await supabase.rpc("create_notification", {
      p_user_id: params.userId,
      p_type: params.type,
      p_category: params.category,
      p_title: params.title,
      p_message: params.message,
      p_priority: params.priority || "normal",
      p_link_url: params.linkUrl || null,
      p_actor_id: params.actorId || null,
      p_entity_type: params.entityType || null,
      p_entity_id: params.entityId || null,
      p_rich_content: params.richContent || null,
    })

    if (error) {
      log.error("RPC Error creating notification:", error)
      // Fallback to direct insertion if RPC fails
      const { data: insertData, error: insertError } = await supabase
        .from("notifications")
        .insert({
          user_id: params.userId,
          type: params.type,
          title: params.title,
          message: params.message,
          priority: params.priority || "normal",
          action_url: params.linkUrl || null,
          data: {
            category: params.category,
            actor_id: params.actorId,
            entity_type: params.entityType,
            entity_id: params.entityId,
            rich_content: params.richContent,
          },
        })
        .select()
        .single()

      if (insertError) throw insertError
      return insertData?.id
    }

    return data
  } catch (error) {
    log.error("Error creating notification:", error)
    throw error
  }
}

